export type Currency = 'CUP' | 'USD';
export type PaymentMethod = 'Efectivo' | 'Transferencia';
export type ReceptionType = 'Consignación' | 'Compra Directa';

export interface GroupingPrice {
  id: string;
  label: string; // e.g., "Estuche de 6u", "Palet"
  quantity: number; // units included
  price: number;
  currency: Currency;
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  description: string;
  categoryId: string;
  supplierId: string;
  receptionType: ReceptionType;
  unitPrice: number;
  unitCurrency: Currency;
  costPrice?: number; 
  groupings: GroupingPrice[];
  stock: number;
  minStock: number;
  expiryDate: string;
  receivedDate: string;
  isOffer?: boolean;
  offerPrice?: number;
  offerDescription?: string;
  unitsSoldFromConsignment?: number; // Track for payments
}

export interface Supplier {
  id: string;
  name: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  isConsignee: boolean;
  pendingBalanceCup: number;
  pendingBalanceUsd: number;
}

export interface Client {
  id: string;
  name: string;
  phone: string;
  email: string;
}

export interface SaleItem {
  id: string;
  productId: string;
  productName: string;
  groupingId?: string; 
  groupingLabel?: string;
  quantity: number; // how many of (unit or grouping)
  price: number;
  total: number;
  currency: Currency;
  unitQuantity: number; // calculated base units for inventory
}

export interface Transaction {
  id: string;
  date: string;
  clientId: string;
  clientName: string;
  items: SaleItem[];
  totalCup: number;
  totalUsd: number;
  paymentMethod: PaymentMethod;
  status: 'Solicitud' | 'Despachado' | 'Anulado';
  invoiceNumber: string;
}

export interface SupplierPayment {
  id: string;
  supplierId: string;
  date: string;
  amount: number;
  currency: Currency;
  type: 'Liquidación Consignación' | 'Pago Compra Directa';
  notes?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'error' | 'success';
  date: string;
  read: boolean;
}

export interface DailyClosing {
  date: string;
  totalSalesCup: number;
  totalSalesUsd: number;
  cashCup: number;
  transferCup: number;
  cashUsd: number;
  transferUsd: number;
  transactionsCount: number;
}

import React, { useMemo } from 'react';
import { 
  TrendingUp, 
  DollarSign, 
  Package, 
  AlertCircle,
  Clock,
  ArrowUpRight,
  ShieldCheck,
  CreditCard,
  Layers,
  BarChart3
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell,
  AreaChart,
  Area
} from 'recharts';
import { Product, Transaction, Supplier } from '../types';

interface DashboardProps {
  products: Product[];
  transactions: Transaction[];
  suppliers: Supplier[];
}

const Dashboard: React.FC<DashboardProps> = ({ products, transactions, suppliers }) => {
  const lowStockProducts = products.filter(p => p.stock <= p.minStock);
  const nearingExpiry = products.filter(p => {
    const diff = new Date(p.expiryDate).getTime() - new Date().getTime();
    const days = diff / (1000 * 3600 * 24);
    return days <= 60 && days > 0;
  });

  const totalSalesCup = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((a, b) => a + b.totalCup, 0), [transactions]);
  const totalSalesUsd = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((a, b) => a + b.totalUsd, 0), [transactions]);

  const debtToSuppliersCup = useMemo(() => suppliers.reduce((acc, s) => acc + s.pendingBalanceCup, 0), [suppliers]);
  const debtToSuppliersUsd = useMemo(() => suppliers.reduce((acc, s) => acc + s.pendingBalanceUsd, 0), [suppliers]);

  const stats = [
    { label: 'Ventas Totales CUP', value: totalSalesCup.toLocaleString(), icon: TrendingUp, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { label: 'Ventas Totales USD', value: totalSalesUsd.toLocaleString(), icon: DollarSign, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Stock Crítico', value: lowStockProducts.length, icon: AlertCircle, color: 'text-rose-600', bg: 'bg-rose-50' },
    { label: 'Vencimientos < 60d', value: nearingExpiry.length, icon: Clock, color: 'text-amber-600', bg: 'bg-amber-50' },
  ];

  const chartData = useMemo(() => {
    const days = ['Dom', 'Lun', 'Mar', 'Mie', 'Jue', 'Vie', 'Sab'];
    const data = days.map(d => ({ name: d, ventas: 0 }));
    transactions.forEach(t => {
      const dayIndex = new Date(t.date).getDay();
      data[dayIndex].ventas += t.totalUsd;
    });
    return data;
  }, [transactions]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-10">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((stat, idx) => (
          <div key={idx} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex items-center group hover:shadow-md transition-shadow">
            <div className={`p-4 rounded-2xl ${stat.bg} ${stat.color} mr-4 group-hover:scale-110 transition-transform`}>
              <stat.icon size={24} />
            </div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{stat.label}</p>
              <p className="text-2xl font-black text-gray-800 tracking-tight">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest flex items-center gap-2">
                <BarChart3 className="text-[#8B5E3C]" size={18} /> Histórico de Ventas (USD)
              </h3>
              <span className="text-xs font-bold text-gray-400 bg-gray-50 px-3 py-1 rounded-full">Semana Actual</span>
            </div>
            <div className="h-72">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorVentas" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#8B5E3C" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#8B5E3C" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f1f1" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 700, fill: '#9ca3af'}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 700, fill: '#9ca3af'}} />
                  <Tooltip 
                    cursor={{stroke: '#8B5E3C', strokeWidth: 2}} 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }} 
                  />
                  <Area type="monotone" dataKey="ventas" stroke="#8B5E3C" strokeWidth={4} fillOpacity={1} fill="url(#colorVentas)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
              <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-4">Stock Crítico (Detalle)</h4>
              <div className="space-y-3">
                {lowStockProducts.slice(0, 3).map(p => (
                  <div key={p.id} className="flex justify-between items-center p-3 bg-red-50 rounded-2xl">
                    <span className="text-xs font-bold text-red-800">{p.name}</span>
                    <span className="text-xs font-black text-red-600">{p.stock} u.</span>
                  </div>
                ))}
                {lowStockProducts.length === 0 && <p className="text-xs text-gray-400 italic">No hay alertas de stock.</p>}
              </div>
            </div>
            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
              <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-4">Próximos Vencimientos</h4>
              <div className="space-y-3">
                {nearingExpiry.slice(0, 3).map(p => (
                  <div key={p.id} className="flex justify-between items-center p-3 bg-amber-50 rounded-2xl">
                    <span className="text-xs font-bold text-amber-800">{p.name}</span>
                    <span className="text-[9px] font-black text-amber-600 uppercase">{p.expiryDate}</span>
                  </div>
                ))}
                {nearingExpiry.length === 0 && <p className="text-xs text-gray-400 italic">No hay vencimientos próximos.</p>}
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-[#8B5E3C] p-8 rounded-[40px] shadow-2xl shadow-[#8B5E3C]/20 text-white relative overflow-hidden flex flex-col justify-between min-h-[350px]">
            <div className="absolute -top-10 -right-10 w-48 h-48 bg-white/10 rounded-full blur-3xl"></div>
            <div>
              <h3 className="text-xs font-black uppercase tracking-widest mb-8 flex items-center gap-2">
                 <ShieldCheck size={18} /> Liquidez y Caja
              </h3>
              <div className="space-y-6">
                <div>
                  <p className="text-[10px] text-white/50 font-bold uppercase tracking-tighter">Disponible CUP</p>
                  <p className="text-4xl font-black tabular-nums">{totalSalesCup.toLocaleString()} <span className="text-sm font-medium opacity-50">CUP</span></p>
                </div>
                <div>
                  <p className="text-[10px] text-white/50 font-bold uppercase tracking-tighter">Disponible USD</p>
                  <p className="text-4xl font-black tabular-nums">{totalSalesUsd.toLocaleString()} <span className="text-sm font-medium opacity-50">USD</span></p>
                </div>
              </div>
            </div>
            <div className="mt-8 pt-6 border-t border-white/10">
               <div className="flex justify-between items-end">
                  <div>
                    <span className="text-[10px] font-bold opacity-50 block uppercase">Flujo semanal</span>
                    <span className="text-xl font-black flex items-center gap-1 text-emerald-400"><ArrowUpRight size={20} /> +18.4%</span>
                  </div>
                  <CreditCard size={32} className="opacity-20" />
               </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
            <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-4">Deuda a Proveedores</h4>
            <div className="space-y-4">
              <div className="flex justify-between items-center">
                <span className="text-sm font-bold text-gray-600">Total CUP</span>
                <span className="text-lg font-black text-rose-600">{debtToSuppliersCup.toLocaleString()}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm font-bold text-gray-600">Total USD</span>
                <span className="text-lg font-black text-rose-600">{debtToSuppliersUsd.toLocaleString()}</span>
              </div>
              <div className="pt-4 border-t border-gray-50 flex justify-between items-center">
                 <div className="flex -space-x-2">
                   {suppliers.slice(0, 3).map((s, i) => (
                     <div key={i} className={`w-8 h-8 rounded-full border-2 border-white flex items-center justify-center text-[10px] font-bold text-white bg-gray-300`} style={{backgroundColor: ['#8B5E3C', '#D4A373', '#E9EDC6'][i % 3]}}>
                       {s.name.charAt(0)}
                     </div>
                   ))}
                 </div>
                 <span className="text-[10px] font-bold text-gray-400">Ver Detalles de Pago</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import { 
  Product, Supplier, Client, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, ReceptionType, SaleItem 
} from './types';
import { 
  Package, Plus, Search, Trash2, Edit2, Share2, 
  UserPlus, ShoppingBag, X, ArrowDownCircle, ArrowUpCircle, Tag,
  ChevronRight, Printer, FileText, CheckCircle2, AlertTriangle, Filter
} from 'lucide-react';
import { generateSocialMediaPost } from './services/geminiService';
import { LOGO_URL, CATEGORIES } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>([]);
  const [suppliers, setSuppliers] = useState<Supplier[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [socialContent, setSocialContent] = useState<string>('');
  const [isSocialLoading, setIsSocialLoading] = useState(false);

  // Modals / Selection
  const [showProductModal, setShowProductModal] = useState<{show: boolean, product?: Product}>({show: false});
  const [showSupplierModal, setShowSupplierModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  // Persistence
  useEffect(() => {
    const keys = ['products', 'suppliers', 'clients', 'transactions'];
    keys.forEach(key => {
      const saved = localStorage.getItem(`pati_v2_${key}`);
      if (saved) {
        if (key === 'products') setProducts(JSON.parse(saved));
        if (key === 'suppliers') setSuppliers(JSON.parse(saved));
        if (key === 'clients') setClients(JSON.parse(saved));
        if (key === 'transactions') setTransactions(JSON.parse(saved));
      }
    });
  }, []);

  useEffect(() => { localStorage.setItem('pati_v2_products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('pati_v2_suppliers', JSON.stringify(suppliers)); }, [suppliers]);
  useEffect(() => { localStorage.setItem('pati_v2_clients', JSON.stringify(clients)); }, [clients]);
  useEffect(() => { localStorage.setItem('pati_v2_transactions', JSON.stringify(transactions)); }, [transactions]);

  // Monitor stock and expiry
  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Bajo', message: `${p.name} en nivel crítico (${p.stock} u.)`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / (86400000));
      if (days <= 60 && days > 0) {
        newNotifs.push({ id: `exp-${p.id}`, title: 'Vencimiento Próximo', message: `${p.name} vence en ${days} días.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  const generateSKU = () => {
    const prefix = 'PT';
    const num = Math.floor(1000 + Math.random() * 9000);
    const sku = `${prefix}-${num}`;
    return products.some(p => p.sku === sku) ? generateSKU() : sku;
  };

  const handleCreateSale = (sale: Transaction) => {
    setTransactions([sale, ...transactions]);
    if (sale.status === 'Despachado') {
      const updatedProducts = products.map(p => {
        const soldUnits = sale.items
          .filter(item => item.productId === p.id)
          .reduce((acc, item) => acc + item.unitQuantity, 0);

        if (soldUnits > 0) {
          // If consignment, track sold units for payment
          const newSoldConsignment = p.receptionType === 'Consignación' 
            ? (p.unitsSoldFromConsignment || 0) + soldUnits 
            : p.unitsSoldFromConsignment;

          // Update supplier balance if needed (for consignment we pay after sale)
          if (p.receptionType === 'Consignación') {
            const supplier = suppliers.find(s => s.id === p.supplierId);
            if (supplier) {
              const saleTotalForThisProduct = sale.items
                .filter(item => item.productId === p.id)
                .reduce((acc, item) => acc + item.total, 0);

              // Simplistic debt calc: if it's sold, we owe a portion or the whole agreed cost
              // Here we just increase the pending balance
              setSuppliers(prev => prev.map(s => s.id === supplier.id ? {
                ...s,
                pendingBalanceCup: p.unitCurrency === 'CUP' ? s.pendingBalanceCup + saleTotalForThisProduct : s.pendingBalanceCup,
                pendingBalanceUsd: p.unitCurrency === 'USD' ? s.pendingBalanceUsd + saleTotalForThisProduct : s.pendingBalanceUsd,
              } : s));
            }
          }

          return { ...p, stock: p.stock - soldUnits, unitsSoldFromConsignment: newSoldConsignment };
        }
        return p;
      });
      setProducts(updatedProducts);
    }
    setShowSaleModal(false);
  };

  // --- SUB-COMPONENTS ---

  const ProductForm = ({ initialData, onSave, onCancel }: { initialData?: Product, onSave: (p: Product) => void, onCancel: () => void }) => {
    const [groupings, setGroupings] = useState<GroupingPrice[]>(initialData?.groupings || []);
    const [tempGrouping, setTempGrouping] = useState({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency });
    const [generatedSku] = useState(initialData?.sku || generateSKU());

    const addGrouping = () => {
      if (tempGrouping.label && tempGrouping.quantity > 0) {
        setGroupings([...groupings, { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) }]);
        setTempGrouping({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency });
      }
    };

    const handleSubmit = (e: React.FormEvent<HTMLFormElement>) => {
      e.preventDefault();
      const fd = new FormData(e.currentTarget);
      const isOffer = fd.get('isOffer') === 'on';
      const p: Product = {
        id: initialData?.id || Math.random().toString(36).substr(2, 9),
        name: fd.get('name') as string,
        sku: generatedSku,
        description: fd.get('description') as string,
        categoryId: fd.get('categoryId') as string,
        supplierId: fd.get('supplierId') as string,
        receptionType: fd.get('receptionType') as ReceptionType,
        unitPrice: parseFloat(fd.get('unitPrice') as string),
        unitCurrency: fd.get('unitCurrency') as Currency,
        groupings: groupings,
        stock: parseInt(fd.get('stock') as string),
        minStock: parseInt(fd.get('minStock') as string),
        expiryDate: fd.get('expiryDate') as string,
        receivedDate: initialData?.receivedDate || new Date().toISOString().split('T')[0],
        isOffer: isOffer,
        offerPrice: isOffer ? parseFloat(fd.get('offerPrice') as string || '0') : undefined,
      };
      onSave(p);
    };

    return (
      <form onSubmit={handleSubmit} className="p-8 overflow-y-auto space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Código (Auto-generado)</label>
            <div className="w-full p-3 bg-gray-100 border rounded-xl font-mono text-gray-600">{generatedSku}</div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Nombre Comercial</label>
            <input name="name" defaultValue={initialData?.name} required className="w-full p-3 bg-gray-50 border rounded-xl focus:ring-2 focus:ring-[#8B5E3C] outline-none" />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Proveedor</label>
            <select name="supplierId" defaultValue={initialData?.supplierId} className="w-full p-3 bg-gray-50 border rounded-xl">
              {suppliers.map(s => <option key={s.id} value={s.id}>{s.name} {s.isConsignee ? '(Consignatario)' : ''}</option>)}
              {suppliers.length === 0 && <option disabled>Cree un proveedor primero</option>}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tipo Recepción</label>
            <select name="receptionType" defaultValue={initialData?.receptionType} className="w-full p-3 bg-gray-50 border rounded-xl">
              <option value="Consignación">Consignación</option>
              <option value="Compra Directa">Compra Directa</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Precio Unitario de Venta</label>
            <div className="flex gap-2">
              <input name="unitPrice" type="number" step="0.01" defaultValue={initialData?.unitPrice} required className="flex-1 p-3 bg-gray-50 border rounded-xl" />
              <select name="unitCurrency" defaultValue={initialData?.unitCurrency} className="w-24 p-3 bg-gray-50 border rounded-xl font-bold">
                <option value="CUP">CUP</option>
                <option value="USD">USD</option>
              </select>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Stock (Actual / Mínimo)</label>
            <div className="flex gap-2">
              <input name="stock" type="number" defaultValue={initialData?.stock} required className="flex-1 p-3 bg-gray-50 border rounded-xl" placeholder="Existencia" />
              <input name="minStock" type="number" defaultValue={initialData?.minStock} required className="flex-1 p-3 bg-gray-50 border rounded-xl" placeholder="Alerta Stock" />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Fecha de Vencimiento</label>
            <input name="expiryDate" type="date" defaultValue={initialData?.expiryDate} required className="w-full p-3 bg-gray-50 border rounded-xl" />
          </div>
          <div className="flex items-center space-x-6">
            <label className="flex items-center gap-3 cursor-pointer group">
              <input name="isOffer" type="checkbox" defaultChecked={initialData?.isOffer} className="w-6 h-6 rounded-lg accent-[#8B5E3C] border-gray-300" />
              <span className="text-xs font-black text-gray-700 uppercase tracking-widest group-hover:text-[#8B5E3C] transition-colors">En Oferta</span>
            </label>
            {initialData?.isOffer && (
               <input name="offerPrice" type="number" defaultValue={initialData?.offerPrice} placeholder="Precio Oferta" className="p-2 bg-red-50 border border-red-100 rounded-lg text-xs font-bold" />
            )}
          </div>
        </div>

        <div className="border-t border-dashed pt-6">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-xs font-black text-[#8B5E3C] uppercase tracking-widest flex items-center gap-2">
              <Layers size={14} /> Agrupaciones de Venta (Opcional)
            </h3>
            <p className="text-[10px] text-gray-400">Ej: Estuches, Cajas, Palets</p>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3 mb-6">
            <input placeholder="Nombre (Ej: Caja 12u)" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} />
            <input placeholder="Cant. Unid" type="number" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 0})} />
            <div className="flex gap-1">
