      const newItem: SaleItem = {
        id: Math.random().toString(36).substr(2, 9),
        productId: product.id,
        productName: product.name,
        groupingId: grouping?.id,
        groupingLabel: grouping?.label,
        quantity: 1,
        price,
        total: price,
        currency,
        unitQuantity: unitQty
      };
      setCart([...cart, newItem]);
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
    const totalUsd = cart.filter(i => i.currency === 'USD').reduce((a, b) => a + b.total, 0);

    const finish = () => {
      const sale: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        date: new Date().toISOString(),
        clientId: selectedClient?.id || 'Publico-Gral',
        clientName: selectedClient?.name || 'Venta al Público',
        items: cart,
        totalCup,
        totalUsd,
        paymentMethod,
        status,
        invoiceNumber: `F-${Date.now().toString().slice(-6)}`
