        <div className="flex justify-end gap-3 pt-8 mt-4 border-t sticky bottom-0 bg-white pb-2">
          <button type="button" onClick={onCancel} className="px-6 py-2 text-gray-400 font-black uppercase text-[10px] tracking-widest">Cancelar</button>
          <button type="submit" className="px-10 py-4 bg-[#8B5E3C] text-white font-black rounded-2xl uppercase text-[10px] tracking-[0.2em] shadow-xl shadow-[#8B5E3C]/20 hover:-translate-y-1 transition-all">Guardar Producto</button>
        </div>
      </form>
