  const SalesModal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [selectedClient, setSelectedClient] = useState<Client | null>(null);
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');
    const [status, setStatus] = useState<'Solicitud' | 'Despachado'>('Solicitud');

    const filtered = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()) || p.sku.toLowerCase().includes(search.toLowerCase()));

    const addToCart = (product: Product, grouping?: GroupingPrice) => {
      const price = grouping ? grouping.price : product.unitPrice;
      const currency = grouping ? grouping.currency : product.unitCurrency;
      const unitQty = grouping ? grouping.quantity : 1;

      const newItem: SaleItem = {
        id: Math.random().toString(36).substr(2, 9),
        productId: product.id,
        productName: product.name,
        groupingId: grouping?.id,
        groupingLabel: grouping?.label,
        quantity: 1,
        price,
        total: price,
        currency,
        unitQuantity: unitQty
      };
      setCart([...cart, newItem]);
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
    const totalUsd = cart.filter(i => i.currency === 'USD').reduce((a, b) => a + b.total, 0);

    const finish = () => {
      const sale: Transaction = {
        id: Math.random().toString(36).substr(2, 9),
        date: new Date().toISOString(),
        clientId: selectedClient?.id || 'Publico-Gral',
        clientName: selectedClient?.name || 'Venta al Público',
        items: cart,
        totalCup,
        totalUsd,
        paymentMethod,
        status,
        invoiceNumber: `F-${Date.now().toString().slice(-6)}`
      };
      handleCreateSale(sale);
    };

    return (
      <div className="fixed inset-0 bg-black/70 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
