              <h2 className="text-xl font-black uppercase tracking-tight text-[#8B5E3C]">Punto de Venta</h2>
              <button onClick={() => setShowSaleModal(false)} className="p-2 hover:bg-white rounded-full"><X /></button>
            </div>
            <div className="relative mb-6">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input 
                autoFocus
                className="w-full pl-12 pr-4 py-4 bg-white border-0 shadow-sm rounded-2xl outline-none focus:ring-2 focus:ring-[#8B5E3C] font-medium" 
                placeholder="Escanee o busque producto..." 
                value={search}
                onChange={e => setSearch(e.target.value)}
              />
            </div>
            <div className="flex-1 overflow-y-auto space-y-3 pr-2">
              {filtered.map(p => (
                <div key={p.id} className="bg-white p-5 rounded-[24px] shadow-sm border border-gray-100 hover:shadow-md transition-shadow group">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h4 className="font-black text-gray-800 uppercase tracking-tighter text-sm">{p.name}</h4>
                      <p className="text-[10px] text-gray-400 font-bold uppercase">{p.sku} • Stock: {p.stock} u.</p>
                    </div>
                    <button onClick={() => addToCart(p)} className="p-2 bg-[#8B5E3C]/10 text-[#8B5E3C] rounded-xl hover:bg-[#8B5E3C] hover:text-white transition-colors">
                      <Plus size={18} />
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    <span className="px-3 py-1 bg-gray-50 text-gray-600 text-[10px] font-black rounded-lg">Base: {p.unitPrice}{p.unitCurrency}</span>
                    {p.groupings.map(g => (
                      <button key={g.id} onClick={() => addToCart(p, g)} className="px-3 py-1 bg-amber-50 text-[#8B5E3C] text-[10px] font-black rounded-lg hover:bg-[#8B5E3C] hover:text-white transition-colors">
                        {g.label}: {g.price}{g.currency}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Right: Cart & Checkout */}
          <div className="w-1/2 flex flex-col p-8 bg-white">
            <h3 className="text-xs font-black uppercase tracking-[0.2em] text-gray-400 mb-8">Resumen del Pedido</h3>
            <div className="flex-1 overflow-y-auto space-y-4 mb-8">
              {cart.map((item, idx) => (
                <div key={item.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl">
                  <div className="flex items-center gap-4">
                     <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center font-black text-[#8B5E3C] border shadow-sm">{idx + 1}</div>
                     <div>
                       <p className="font-black text-xs uppercase tracking-tight text-gray-800">{item.productName}</p>
                       <p className="text-[10px] font-bold text-gray-400 uppercase">{item.groupingLabel || 'Unidad individual'}</p>
                     </div>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-sm text-gray-800">{item.total.toLocaleString()} {item.currency}</p>
                    <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-[10px] font-black text-red-400 uppercase tracking-widest hover:text-red-600">Eliminar</button>
                  </div>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-50">
                  <ShoppingBag size={48} className="mb-4" />
                  <p className="font-black uppercase tracking-widest text-xs">El carrito está vacío</p>
                </div>
