            <div className="space-y-6 pt-6 border-t">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Método Pago</label>
                  <select className="w-full p-3 bg-gray-50 border rounded-xl font-bold text-xs" onChange={e => setPaymentMethod(e.target.value as PaymentMethod)}>
