                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tipo Operación</label>
                  <select className="w-full p-3 bg-gray-50 border rounded-xl font-bold text-xs" onChange={e => setStatus(e.target.value as any)}>
                    <option value="Solicitud">Pre-factura (Solicitud)</option>
                    <option value="Despachado">Venta Final (Despacho)</option>
                  </select>
                </div>
              </div>
              <div className="bg-[#8B5E3C] p-6 rounded-[30px] text-white flex justify-between items-center shadow-xl shadow-[#8B5E3C]/30">
                <div>
                  <p className="text-[10px] font-black uppercase opacity-60">Total a Pagar</p>
                  <div className="space-y-1">
                    <p className="text-3xl font-black tabular-nums">{totalCup.toLocaleString()} <span className="text-xs opacity-50">CUP</span></p>
                    {totalUsd > 0 && <p className="text-xl font-black tabular-nums opacity-80">{totalUsd.toLocaleString()} <span className="text-xs opacity-50">USD</span></p>}
                  </div>
                </div>
                <button 
                  disabled={cart.length === 0}
                  onClick={finish}
                  className="bg-white text-[#8B5E3C] px-8 py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-lg hover:-translate-y-1 active:translate-y-0 transition-all disabled:opacity-50"
                >
                  Procesar
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const InvoiceView = ({ transaction, onClose }: { transaction: Transaction, onClose: () => void }) => (
    <div className="fixed inset-0 bg-white z-[200] overflow-y-auto p-10 md:p-20 flex flex-col items-center print:p-0">
