        <div className="flex justify-between items-start mb-12 border-b pb-8">
          <div className="flex flex-col items-center">
             <img src={LOGO_URL} alt="PaTí Logo" className="h-24 w-auto object-contain mb-4" />
             <div className="text-center">
               <h1 className="text-2xl font-black uppercase tracking-widest text-[#8B5E3C]">COMPROBANTE</h1>
               <p className="text-xs text-gray-400 font-bold uppercase">{transaction.status === 'Solicitud' ? 'FACTURA PROFORMA' : 'FACTURA DE VENTA'}</p>
             </div>
          </div>
          <div className="text-right space-y-2">
            <p className="text-sm font-black text-gray-800">No: <span className="text-lg text-[#8B5E3C]">{transaction.invoiceNumber}</span></p>
            <p className="text-xs font-bold text-gray-400 uppercase">Fecha: {new Date(transaction.date).toLocaleDateString()}</p>
