        <div className="mb-10 grid grid-cols-2 gap-8">
           <div>
             <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Cliente</h4>
             <p className="font-black text-gray-800 uppercase tracking-tight">{transaction.clientName}</p>
           </div>
           <div className="text-right">
             <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Estado</h4>
             <span className={`px-4 py-1 rounded-full text-[10px] font-black uppercase ${transaction.status === 'Despachado' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{transaction.status}</span>
