           <div className="w-64 space-y-3">
              <div className="flex justify-between items-center text-sm">
                <span className="text-gray-400 font-bold uppercase tracking-widest">Total CUP</span>
                <span className="font-black text-gray-800">{transaction.totalCup.toLocaleString()}</span>
