      </div>
    </div>
  );

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      notifications={notifications}
      onNotificationRead={(id) => setNotifications(n => n.map(x => x.id === id ? {...x, read: true} : x))}
    >
      {activeTab === 'dashboard' && <Dashboard products={products} transactions={transactions} suppliers={suppliers} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div className="relative flex-1 w-full max-w-lg">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input className="w-full pl-12 pr-4 py-4 bg-white border-0 shadow-sm rounded-3xl outline-none focus:ring-2 focus:ring-[#8B5E3C] font-medium" placeholder="Buscar por SKU, nombre o proveedor..." />
            </div>
            <div className="flex gap-3 w-full md:w-auto">
              <button onClick={async () => {
                setIsSocialLoading(true);
                const content = await generateSocialMediaPost(products.filter(p => p.isOffer || products.indexOf(p) < 5));
                setSocialContent(content || "Error");
                setIsSocialLoading(false);
              }} className="flex-1 md:flex-none flex items-center justify-center gap-3 bg-blue-600 text-white px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-transform hover:-translate-y-1">
                {isSocialLoading ? 'Generando...' : <><Share2 size={16} /> Redes Sociales</>}
              </button>
              <button onClick={() => setShowProductModal({show: true})} className="flex-1 md:flex-none flex items-center justify-center gap-3 bg-[#8B5E3C] text-white px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-[#8B5E3C]/20 transition-transform hover:-translate-y-1">
                <Plus size={16} /> Nuevo Producto
              </button>
            </div>
          </div>

          {socialContent && (
            <div className="bg-white border border-blue-50 p-8 rounded-[32px] relative shadow-xl shadow-blue-500/5 animate-in slide-in-from-top-4">
              <button onClick={() => setSocialContent('')} className="absolute top-6 right-6 text-gray-300 hover:text-red-500 transition-colors"><X size={24} /></button>
              <div className="flex items-center gap-3 text-blue-600 font-black uppercase text-xs tracking-widest mb-6"><Share2 size={18} /> Social Media Assistant</div>
              <p className="text-gray-600 whitespace-pre-wrap text-sm leading-relaxed mb-6 font-medium italic">"{socialContent}"</p>
              <button onClick={() => {navigator.clipboard.writeText(socialContent); alert('Copiado!');}} className="px-8 py-3 bg-blue-600 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-blue-700 transition-colors shadow-lg shadow-blue-600/20">Copiar Texto</button>
            </div>
          )}

          <div className="bg-white rounded-[40px] shadow-sm border border-gray-100 overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-50/50 border-b border-gray-100">
                  <tr className="text-[10px] uppercase text-gray-400 font-black tracking-[0.2em]">
                    <th className="px-8 py-6">Producto & Info</th>
                    <th className="px-8 py-6">Stock Real</th>
                    <th className="px-8 py-6">Estructura Precios</th>
                    <th className="px-8 py-6">Tipo</th>
                    <th className="px-8 py-6 text-right">Acciones</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {products.map(p => (
                    <tr key={p.id} className="group hover:bg-gray-50/50 transition-colors">
                      <td className="px-8 py-6">
                        <div className="flex items-center gap-4">
                          <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-black text-xs ${p.stock <= p.minStock ? 'bg-rose-400' : 'bg-[#D4A373]'}`}>
                            {p.name.charAt(0).toUpperCase()}
                          </div>
                          <div>
                            <div className="font-black text-gray-800 uppercase tracking-tighter text-sm mb-0.5">{p.name}</div>
                            <div className="flex items-center gap-2">
                               <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest bg-gray-100 px-1.5 py-0.5 rounded">{p.sku}</span>
                               <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">{suppliers.find(s=>s.id===p.supplierId)?.name}</span>
                            </div>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className={`text-sm font-black tabular-nums ${p.stock <= p.minStock ? 'text-rose-500' : 'text-gray-700'}`}>{p.stock} <span className="text-[10px] opacity-40">U.</span></div>
                        <div className="w-24 h-1.5 bg-gray-100 rounded-full mt-2 overflow-hidden">
                          <div 
                            className={`h-full rounded-full transition-all duration-1000 ${p.stock <= p.minStock ? 'bg-rose-500' : 'bg-emerald-500'}`} 
                            style={{ width: `${Math.min(100, (p.stock / (p.minStock * 3)) * 100)}%` }}
                          />
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex flex-wrap gap-2">
                          <span className="px-3 py-1 bg-[#8B5E3C]/10 text-[#8B5E3C] text-[9px] font-black rounded-lg uppercase tracking-widest">Base: {p.unitPrice}{p.unitCurrency}</span>
                          {p.groupings.map(g => (
                            <span key={g.id} className="px-3 py-1 bg-gray-100 text-gray-500 text-[9px] font-black rounded-lg uppercase tracking-widest">{g.label}: {g.price}{g.currency}</span>
                          ))}
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex flex-col gap-1.5">
                           <span className={`w-fit px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-[0.1em] ${p.receptionType === 'Consignación' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>{p.receptionType}</span>
                           {p.isOffer && <span className="w-fit px-3 py-1 bg-rose-100 text-rose-700 rounded-full text-[8px] font-black uppercase tracking-[0.1em] flex items-center gap-1"><Tag size={8} /> Oferta Activa</span>}
                        </div>
                      </td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button onClick={() => setShowProductModal({show: true, product: p})} className="p-2 text-gray-400 hover:text-blue-600 transition-colors"><Edit2 size={18} /></button>
                          <button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-2 text-gray-400 hover:text-rose-600 transition-colors"><Trash2 size={18} /></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            {products.length === 0 && (
              <div className="p-20 text-center flex flex-col items-center">
                 <Package size={48} className="text-gray-100 mb-4" />
                 <p className="font-black uppercase tracking-widest text-gray-300 text-xs">No hay productos en el catálogo</p>
              </div>
            )}
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
              <div className="bg-white p-10 rounded-[40px] border border-gray-100 shadow-sm flex flex-col justify-between">
                 <div>
                   <h2 className="text-2xl font-black text-gray-800 uppercase tracking-tight mb-2">Ingreso de Mercancía</h2>
                   <p className="text-sm text-gray-400 font-medium mb-10">Cargue productos al sistema o actualice el stock de los existentes para consignación o compra directa.</p>
                 </div>
                 <button onClick={() => setShowProductModal({show: true})} className="w-full bg-[#8B5E3C] text-white py-6 rounded-3xl font-black uppercase text-xs tracking-widest shadow-2xl shadow-[#8B5E3C]/20 hover:-translate-y-2 active:translate-y-0 transition-all flex items-center justify-center gap-4">
                   <ArrowDownCircle size={24} /> Iniciar Proceso de Recepción
                 </button>
              </div>
              <div className="bg-gray-900 p-10 rounded-[40px] text-white shadow-2xl relative overflow-hidden">
                 <div className="absolute top-0 right-0 p-10 opacity-10"><Package size={120} /></div>
                 <h3 className="text-xs font-black uppercase tracking-widest mb-10 text-gray-400">Últimas entradas</h3>
                 <div className="space-y-4">
                    {products.slice().sort((a,b) => b.receivedDate.localeCompare(a.receivedDate)).slice(0, 4).map(p => (
                      <div key={p.id} className="flex justify-between items-center p-5 bg-white/5 rounded-3xl hover:bg-white/10 transition-colors border border-white/5">
                        <div className="flex items-center gap-4">
                          <div className="w-10 h-10 bg-white/10 rounded-2xl flex items-center justify-center font-black text-xs">{p.stock}</div>
                          <div>
                            <p className="font-black text-xs uppercase tracking-tight">{p.name}</p>
                            <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">{p.receivedDate}</p>
                          </div>
                        </div>
                        <span className="text-[9px] font-black uppercase tracking-widest px-2 py-1 bg-[#8B5E3C] rounded-lg">OK</span>
                      </div>
                    ))}
                    {products.length === 0 && <p className="text-gray-500 italic text-sm">Sin registros recientes.</p>}
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="md:col-span-2 bg-white rounded-[40px] border border-gray-100 shadow-sm overflow-hidden">
               <div className="p-8 border-b flex justify-between items-center">
                  <h3 className="font-black text-gray-800 uppercase tracking-widest text-xs">Historial de Transacciones</h3>
                  <button onClick={() => setShowSaleModal(true)} className="bg-[#8B5E3C] text-white px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:-translate-y-1 transition-transform">
                    <Plus size={16} /> Nueva Venta
                  </button>
               </div>
               <div className="overflow-x-auto">
                 <table className="w-full text-left">
                    <thead className="bg-gray-50/50 border-b">
                      <tr className="text-[9px] font-black uppercase text-gray-400 tracking-[0.2em]">
                        <th className="px-8 py-4">ID / Fecha</th>
                        <th className="px-8 py-4">Cliente</th>
                        <th className="px-8 py-4">Importe</th>
                        <th className="px-8 py-4">Estado</th>
                        <th className="px-8 py-4 text-right">Comprobante</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-50">
                      {transactions.map(t => (
                        <tr key={t.id} className="group hover:bg-gray-50/50 transition-colors">
                          <td className="px-8 py-5">
                             <div className="font-black text-gray-800 text-xs">{t.invoiceNumber}</div>
                             <div className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">{new Date(t.date).toLocaleDateString()}</div>
                          </td>
                          <td className="px-8 py-5">
                             <div className="font-black text-gray-700 text-xs uppercase tracking-tighter">{t.clientName}</div>
                             <div className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">{t.paymentMethod}</div>
                          </td>
                          <td className="px-8 py-5">
                             <div className="font-black text-gray-800 text-xs tabular-nums">
                               {t.totalCup > 0 ? `${t.totalCup.toLocaleString()} CUP` : `${t.totalUsd.toLocaleString()} USD`}
                             </div>
                          </td>
                          <td className="px-8 py-5">
                             <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${t.status === 'Despachado' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{t.status}</span>
                          </td>
                          <td className="px-8 py-5 text-right">
                             <button onClick={() => setSelectedInvoice(t)} className="p-2 text-gray-300 hover:text-[#8B5E3C] transition-colors"><FileText size={18} /></button>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                 </table>
                 {transactions.length === 0 && <div className="p-10 text-center text-gray-300 text-xs font-black uppercase tracking-widest">No hay ventas registradas</div>}
               </div>
            </div>

            <div className="space-y-6">
               <div className="bg-amber-50 p-8 rounded-[40px] border border-amber-100 shadow-sm shadow-amber-200/20">
                  <h4 className="text-[10px] font-black uppercase text-amber-800 tracking-widest mb-6 flex items-center gap-2"><Filter size={14} /> Solicitudes Pendientes</h4>
                  <div className="space-y-4">
                     {transactions.filter(t => t.status === 'Solicitud').map(t => (
                        <div key={t.id} className="p-5 bg-white rounded-3xl border border-amber-100 shadow-sm flex justify-between items-center group">
                           <div>
                              <p className="font-black text-gray-800 text-xs">{t.invoiceNumber}</p>
                              <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest">{t.totalCup.toLocaleString()} CUP</p>
                           </div>
                           <button onClick={() => {
                             setTransactions(transactions.map(x => x.id === t.id ? {...x, status: 'Despachado'} : x));
                             handleCreateSale({...t, status: 'Despachado'});
                           }} className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl hover:bg-emerald-600 hover:text-white transition-all shadow-sm">
                              <CheckCircle2 size={18} />
                           </button>
                        </div>
                     ))}
                     {transactions.filter(t => t.status === 'Solicitud').length === 0 && <p className="text-amber-600/50 italic text-[10px] text-center font-bold">Sin pre-facturas pendientes</p>}
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'suppliers' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="flex justify-between items-center">
              <div>
                <h2 className="text-2xl font-black text-gray-800 uppercase tracking-tight">Gestión de Contactos</h2>
                <p className="text-sm text-gray-400 font-medium">Proveedores y clientes para la logística de la tienda.</p>
              </div>
              <button onClick={() => setShowSupplierModal(true)} className="bg-[#8B5E3C] text-white px-8 py-4 rounded-3xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-[#8B5E3C]/20 flex items-center gap-3 transition-transform hover:-translate-y-1">
                <UserPlus size={18}/> Nuevo Contacto
              </button>
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
              {suppliers.map(s => (
                <div key={s.id} className="bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm group hover:shadow-xl transition-all flex flex-col justify-between">
                   <div>
                     <div className="flex justify-between items-start mb-6">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-white ${s.isConsignee ? 'bg-purple-400' : 'bg-blue-400'}`}>
                           {s.name.charAt(0).toUpperCase()}
                        </div>
                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-1 rounded-lg ${s.isConsignee ? 'bg-purple-50 text-purple-600' : 'bg-blue-50 text-blue-600'}`}>
                          {s.isConsignee ? 'Consignatario' : 'Venta Directa'}
                        </span>
                     </div>
                     <h3 className="font-black text-gray-800 text-sm uppercase tracking-tight mb-2 group-hover:text-[#8B5E3C] transition-colors">{s.name}</h3>
                     <div className="space-y-2 text-[10px] font-bold text-gray-400 uppercase tracking-widest">
                        <p className="flex items-center gap-2"><ArrowDownCircle size={12} className="text-gray-300" /> {s.phone}</p>
                        <p className="flex items-center gap-2"><ArrowUpCircle size={12} className="text-gray-300" /> {s.email || 'SIN EMAIL'}</p>
                     </div>
                   </div>
                   <div className="mt-8 pt-6 border-t border-gray-50">
                      <div className="flex justify-between items-center">
                         <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Balance</span>
                         <span className="text-sm font-black text-rose-500 tabular-nums">{s.pendingBalanceCup.toLocaleString()} <span className="text-[8px] opacity-50">CUP</span></span>
                      </div>
                   </div>
                </div>
              ))}
              {suppliers.length === 0 && <div className="col-span-full py-20 bg-white rounded-[40px] border-2 border-dashed border-gray-100 flex flex-col items-center justify-center">
                 <UserPlus size={48} className="text-gray-100 mb-4" />
                 <p className="font-black uppercase tracking-widest text-gray-300 text-xs">Aún no hay proveedores registrados</p>
              </div>}
           </div>
        </div>
      )}

      {showSaleModal && <SalesModal />}
      {selectedInvoice && <InvoiceView transaction={selectedInvoice} onClose={() => setSelectedInvoice(null)} />}

      {/* MODAL: PRODUCT */}
      {showProductModal.show && (
        <div className="fixed inset-0 bg-black/70 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-4xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-gray-50/50">
              <h2 className="text-xl font-black text-gray-800 uppercase tracking-tight flex items-center gap-3">
                 <div className="w-10 h-10 bg-[#8B5E3C] rounded-2xl flex items-center justify-center text-white"><Package size={20} /></div>
                 {showProductModal.product ? 'Actualizar Ficha de Producto' : 'Nueva Recepción de Mercancía'}
              </h2>
              <button onClick={() => setShowProductModal({show: false})} className="p-3 hover:bg-white rounded-full transition-colors"><X size={24} /></button>
            </div>
            <ProductForm 
              initialData={showProductModal.product} 
              onSave={(p) => {
                if(showProductModal.product) {
                  setProducts(products.map(x => x.id === p.id ? p : x));
                } else {
                  setProducts([...products, p]);
                }
                setShowProductModal({show: false});
              }}
              onCancel={() => setShowProductModal({show: false})}
            />
          </div>
        </div>
      )}

      {/* MODAL: SUPPLIER */}
      {showSupplierModal && (
        <div className="fixed inset-0 bg-black/70 z-[160] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-md shadow-2xl overflow-hidden p-10 animate-in zoom-in-95 duration-200">
            <h2 className="text-xl font-black mb-8 uppercase tracking-tight text-[#8B5E3C]">Registro de Contacto</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              const s: Supplier = {
                id: Math.random().toString(36).substr(2, 9),
                name: fd.get('name') as string,
                contactName: fd.get('contact') as string,
                phone: fd.get('phone') as string,
                email: fd.get('email') as string,
                address: '',
                isConsignee: fd.get('type') === 'Consignatario',
                pendingBalanceCup: 0,
                pendingBalanceUsd: 0
              };
              setSuppliers([...suppliers, s]);
              setShowSupplierModal(false);
            }} className="space-y-5">
               <div className="space-y-1">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Empresa / Nombre</label>
                 <input name="name" required className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-[#8B5E3C]" />
               </div>
               <div className="space-y-1">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Teléfono Directo</label>
                 <input name="phone" required className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-[#8B5E3C]" />
               </div>
               <div className="space-y-1">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Correo Electrónico</label>
                 <input name="email" type="email" className="w-full p-4 bg-gray-50 border rounded-2xl outline-none focus:ring-2 focus:ring-[#8B5E3C]" />
               </div>
               <div className="space-y-1">
                 <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tipo de Relación</label>
                 <select name="type" className="w-full p-4 bg-gray-50 border rounded-2xl font-bold text-xs">
                    <option>Consignatario</option>
                    <option>Venta Directa</option>
                 </select>
               </div>
               <div className="flex gap-4 pt-6">
                  <button type="button" onClick={() => setShowSupplierModal(false)} className="flex-1 font-black uppercase text-[10px] tracking-widest text-gray-400">Descartar</button>
                  <button type="submit" className="flex-1 bg-[#8B5E3C] text-white py-4 rounded-2xl font-black uppercase text-[10px] tracking-widest shadow-xl shadow-[#8B5E3C]/20">Confirmar</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

export type Currency = 'CUP' | 'USD';
export type PaymentMethod = 'Efectivo' | 'Transferencia';
export type ReceptionType = 'Consignación' | 'Compra Directa';

export interface GroupingPrice {
  id: string;
  label: string; // e.g., "Estuche de 6u", "Palet"
  quantity: number; // units included
  price: number;
  currency: Currency;
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  description: string;
  categoryId: string;
  supplierId: string;
  receptionType: ReceptionType;
  unitPrice: number;
  unitCurrency: Currency;
  costPrice?: number; 
  groupings: GroupingPrice[];
  stock: number;
  minStock: number;
  expiryDate: string;
  receivedDate: string;
  isOffer?: boolean;
  offerPrice?: number;
  offerDescription?: string;
  unitsSoldFromConsignment?: number; // Track for payments
}

export interface Contact {
  id: string;
  name: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  type: 'Proveedor' | 'Cliente';
  isConsignee?: boolean; // Solo para proveedores
  pendingBalanceCup: number;
  pendingBalanceUsd: number;
}

export interface Supplier extends Contact {}
export interface Client extends Contact {}

export interface SaleItem {
  id: string;
  productId: string;
  productName: string;
  groupingId?: string; 
  groupingLabel?: string;
  quantity: number; 
  price: number;
  total: number;
  currency: Currency;
  unitQuantity: number; 
}

export interface Transaction {
  id: string;
  date: string;
  clientId: string;
  clientName: string;
  items: SaleItem[];
  totalCup: number;
  totalUsd: number;
  paymentMethod: PaymentMethod;
  status: 'Solicitud' | 'Despachado' | 'Anulado';
  invoiceNumber: string;
}

export interface SupplierPayment {
  id: string;
  supplierId: string;
  date: string;
  amount: number;
  currency: Currency;
  type: 'Liquidación Consignación' | 'Pago Compra Directa';
  notes?: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'error' | 'success';
  date: string;
  read: boolean;
}

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, ReceptionType, SaleItem 
} from './types';
import { 
  Package, Plus, Search, Trash2, Edit2, Share2, 
  UserPlus, ShoppingBag, X, ArrowDownCircle, ArrowUpCircle, Tag,
  ChevronRight, Printer, FileText, CheckCircle2, AlertTriangle, Filter,
  Layers, MapPin, Phone, Mail, User
} from 'lucide-react';
import { generateSocialMediaPost } from './services/geminiService';
import { LOGO_URL } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [socialContent, setSocialContent] = useState<string>('');
  const [isSocialLoading, setIsSocialLoading] = useState(false);
  const [contactFilter, setContactFilter] = useState<'Todos' | 'Proveedor' | 'Cliente'>('Todos');

  const [showProductModal, setShowProductModal] = useState<{show: boolean, product?: Product}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  // Separar para compatibilidad con código anterior
  const suppliers = contacts.filter(c => c.type === 'Proveedor');
  const clients = contacts.filter(c => c.type === 'Cliente');

  useEffect(() => {
    const keys = ['products', 'contacts', 'transactions'];
    keys.forEach(key => {
      const saved = localStorage.getItem(`pati_v2_${key}`);
      if (saved) {
        if (key === 'products') setProducts(JSON.parse(saved));
        if (key === 'contacts') setContacts(JSON.parse(saved));
        if (key === 'transactions') setTransactions(JSON.parse(saved));
      }
    });
  }, []);

  useEffect(() => { localStorage.setItem('pati_v2_products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('pati_v2_contacts', JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem('pati_v2_transactions', JSON.stringify(transactions)); }, [transactions]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Bajo', message: `${p.name} en nivel crítico (${p.stock} u.)`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / (86400000));
      if (days <= 60 && days > 0) {
        newNotifs.push({ id: `exp-${p.id}`, title: 'Vencimiento Próximo', message: `${p.name} vence en ${days} días.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  const generateSKU = () => {
    const prefix = 'PT';
    const num = Math.floor(1000 + Math.random() * 9000);
    const sku = `${prefix}-${num}`;
    return products.some(p => p.sku === sku) ? generateSKU() : sku;
  };

  const handleCreateSale = (sale: Transaction) => {
    setTransactions([sale, ...transactions]);
    if (sale.status === 'Despachado') {
      const updatedProducts = products.map(p => {
        const soldUnits = sale.items
          .filter(item => item.productId === p.id)
          .reduce((acc, item) => acc + item.unitQuantity, 0);

        if (soldUnits > 0) {
          if (p.receptionType === 'Consignación') {
            const supplier = contacts.find(s => s.id === p.supplierId);
            if (supplier) {
              const saleTotalForThisProduct = sale.items
                .filter(item => item.productId === p.id)
                .reduce((acc, item) => acc + item.total, 0);

              setContacts(prev => prev.map(s => s.id === supplier.id ? {
                ...s,
                pendingBalanceCup: p.unitCurrency === 'CUP' ? s.pendingBalanceCup + saleTotalForThisProduct : s.pendingBalanceCup,
                pendingBalanceUsd: p.unitCurrency === 'USD' ? s.pendingBalanceUsd + saleTotalForThisProduct : s.pendingBalanceUsd,
              } : s));
            }
          }
          return { ...p, stock: p.stock - soldUnits, unitsSoldFromConsignment: (p.unitsSoldFromConsignment || 0) + soldUnits };
        }
        return p;
      });
      setProducts(updatedProducts);
    }
    setShowSaleModal(false);
  };

  const ProductForm = ({ initialData, onSave, onCancel }: { initialData?: Product, onSave: (p: Product) => void, onCancel: () => void }) => {
    const [groupings, setGroupings] = useState<GroupingPrice[]>(initialData?.groupings || []);
    const [tempGrouping, setTempGrouping] = useState({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency });
    const [generatedSku] = useState(initialData?.sku || generateSKU());

    const addGrouping = () => {
      if (tempGrouping.label && tempGrouping.quantity > 0) {
        setGroupings([...groupings, { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) }]);
        setTempGrouping({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency });
      }
    };

    return (
      <form onSubmit={(e) => {
        e.preventDefault();
        const fd = new FormData(e.currentTarget);
        const isOffer = fd.get('isOffer') === 'on';
        onSave({
          id: initialData?.id || Math.random().toString(36).substr(2, 9),
          name: fd.get('name') as string,
          sku: generatedSku,
          description: fd.get('description') as string,
          categoryId: fd.get('categoryId') as string,
          supplierId: fd.get('supplierId') as string,
          receptionType: fd.get('receptionType') as ReceptionType,
          unitPrice: parseFloat(fd.get('unitPrice') as string),
          unitCurrency: fd.get('unitCurrency') as Currency,
          groupings: groupings,
          stock: parseInt(fd.get('stock') as string),
          minStock: parseInt(fd.get('minStock') as string),
          expiryDate: fd.get('expiryDate') as string,
          receivedDate: initialData?.receivedDate || new Date().toISOString().split('T')[0],
          isOffer: isOffer,
          offerPrice: isOffer ? parseFloat(fd.get('offerPrice') as string || '0') : undefined,
        });
      }} className="p-8 overflow-y-auto space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Código</label>
            <div className="w-full p-3 bg-gray-100 border rounded-xl font-mono text-gray-600">{generatedSku}</div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Nombre Comercial</label>
            <input name="name" defaultValue={initialData?.name} required className="w-full p-3 bg-gray-50 border rounded-xl" />
          </div>
          <div className="space-y-1">
            <div className="flex justify-between items-center">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Proveedor</label>
              <button type="button" onClick={() => setShowContactModal(true)} className="text-[9px] font-black text-[#8B5E3C] uppercase tracking-widest hover:underline">+ Nuevo Proveedor</button>
            </div>
            <select name="supplierId" defaultValue={initialData?.supplierId} className="w-full p-3 bg-gray-50 border rounded-xl">
              {suppliers.map(s => <option key={s.id} value={s.id}>{s.name} {s.isConsignee ? '(Consignación)' : ''}</option>)}
              {suppliers.length === 0 && <option disabled>Cree un proveedor primero</option>}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tipo Recepción</label>
            <select name="receptionType" defaultValue={initialData?.receptionType} className="w-full p-3 bg-gray-50 border rounded-xl">
              <option value="Consignación">Consignación</option>
              <option value="Compra Directa">Compra Directa</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Precio Unitario</label>
            <div className="flex gap-2">
              <input name="unitPrice" type="number" step="0.01" defaultValue={initialData?.unitPrice} required className="flex-1 p-3 bg-gray-50 border rounded-xl" />
              <select name="unitCurrency" defaultValue={initialData?.unitCurrency} className="w-24 p-3 bg-gray-50 border rounded-xl font-bold">
                <option value="CUP">CUP</option>
                <option value="USD">USD</option>
              </select>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Stock (Actual/Min)</label>
            <div className="flex gap-2">
              <input name="stock" type="number" defaultValue={initialData?.stock} required className="flex-1 p-3 bg-gray-50 border rounded-xl" />
              <input name="minStock" type="number" defaultValue={initialData?.minStock} required className="flex-1 p-3 bg-gray-50 border rounded-xl" />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Fecha Vencimiento</label>
            <input name="expiryDate" type="date" defaultValue={initialData?.expiryDate} required className="w-full p-3 bg-gray-50 border rounded-xl" />
          </div>
          <div className="flex items-center space-x-6">
            <label className="flex items-center gap-3 cursor-pointer group">
              <input name="isOffer" type="checkbox" defaultChecked={initialData?.isOffer} className="w-6 h-6 rounded-lg accent-[#8B5E3C] border-gray-300" />
              <span className="text-xs font-black text-gray-700 uppercase tracking-widest group-hover:text-[#8B5E3C]">En Oferta</span>
            </label>
          </div>
        </div>

        <div className="border-t border-dashed pt-6">
          <h3 className="text-xs font-black text-[#8B5E3C] uppercase tracking-widest mb-4 flex items-center gap-2"><Layers size={14} /> Agrupaciones de Venta</h3>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3 mb-6">
            <input placeholder="Nombre" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} />
            <input placeholder="Cant" type="number" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 0})} />
            <input placeholder="Precio" type="number" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} />
            <button type="button" onClick={addGrouping} className="bg-gray-100 p-3 rounded-xl text-xs font-black uppercase">Añadir</button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {groupings.map(g => (
              <div key={g.id} className="flex justify-between items-center p-3 bg-white border rounded-2xl">
                <span className="font-black text-xs uppercase">{g.label} ({g.quantity}u)</span>
                <div className="flex items-center gap-4">
                  <span className="font-black text-[#8B5E3C]">{g.price} {g.currency}</span>
                  <button type="button" onClick={() => setGroupings(groupings.filter(x => x.id !== g.id))} className="text-red-400"><Trash2 size={16} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="flex justify-end gap-3 pt-8 mt-4 border-t sticky bottom-0 bg-white">
          <button type="button" onClick={onCancel} className="px-6 py-2 text-gray-400 font-black uppercase text-[10px]">Cancelar</button>
          <button type="submit" className="px-10 py-4 bg-[#8B5E3C] text-white font-black rounded-2xl uppercase text-[10px] shadow-xl">Guardar</button>
        </div>
      </form>
    );
  };

  const SalesModal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [selectedClient, setSelectedClient] = useState<string>('Publico-Gral');
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');
    const [status, setStatus] = useState<'Solicitud' | 'Despachado'>('Solicitud');

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
    const totalUsd = cart.filter(i => i.currency === 'USD').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/70 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[40px] w-full max-w-6xl h-[90vh] overflow-hidden flex shadow-2xl">
          <div className="w-1/2 border-r flex flex-col p-8 bg-gray-50/50">
            <div className="mb-6 flex justify-between items-center">
              <h2 className="text-xl font-black uppercase text-[#8B5E3C]">Punto de Venta</h2>
              <button onClick={() => setShowSaleModal(false)} className="p-2"><X /></button>
            </div>
            <input className="w-full p-4 bg-white border rounded-2xl mb-6 outline-none" placeholder="Buscar producto..." value={search} onChange={e => setSearch(e.target.value)} />
            <div className="flex-1 overflow-y-auto space-y-3">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-5 rounded-[24px] border border-gray-100">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h4 className="font-black text-xs uppercase">{p.name}</h4>
                      <p className="text-[9px] text-gray-400 font-bold">STOCK: {p.stock} U.</p>
                    </div>
                    <button onClick={() => setCart([...cart, { id: Math.random().toString(), productId: p.id, productName: p.name, quantity: 1, price: p.unitPrice, total: p.unitPrice, currency: p.unitCurrency, unitQuantity: 1 }])} className="p-2 bg-[#8B5E3C]/10 text-[#8B5E3C] rounded-xl"><Plus size={18} /></button>
                  </div>
                  <div className="flex gap-2">
                    {p.groupings.map(g => (
                      <button key={g.id} onClick={() => setCart([...cart, { id: Math.random().toString(), productId: p.id, productName: p.name, groupingId: g.id, groupingLabel: g.label, quantity: 1, price: g.price, total: g.price, currency: g.currency, unitQuantity: g.quantity }])} className="px-2 py-1 bg-amber-50 text-[9px] font-black rounded-lg">{g.label}: {g.price}</button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-8 bg-white">
            <h3 className="text-xs font-black uppercase text-gray-400 mb-8">Resumen</h3>
            <div className="flex-1 overflow-y-auto space-y-4 mb-8">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl">
                  <div>
                    <p className="font-black text-xs uppercase">{item.productName}</p>
                    <p className="text-[9px] font-bold text-gray-400">{item.groupingLabel || 'Unidad'}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-sm">{item.total} {item.currency}</p>
                    <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-[9px] text-red-400 font-black uppercase">Eliminar</button>
                  </div>
                </div>
              ))}
            </div>
            <div className="space-y-6 pt-6 border-t">
              <select className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold" onChange={e => setSelectedClient(e.target.value)}>
                <option value="Publico-Gral">Venta al Público General</option>
                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
              <div className="grid grid-cols-2 gap-4">
                <select className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setPaymentMethod(e.target.value as PaymentMethod)}><option>Efectivo</option><option>Transferencia</option></select>
                <select className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setStatus(e.target.value as any)}><option value="Solicitud">Pre-factura</option><option value="Despachado">Venta Final</option></select>
              </div>
              <div className="bg-[#8B5E3C] p-6 rounded-[30px] text-white flex justify-between items-center">
                <div>
                   <p className="text-[10px] font-black opacity-60">TOTAL</p>
                   <p className="text-2xl font-black">{totalCup.toLocaleString()} CUP</p>
                   {totalUsd > 0 && <p className="text-lg font-black">{totalUsd.toLocaleString()} USD</p>}
                </div>
                <button disabled={cart.length === 0} onClick={() => handleCreateSale({ id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient, clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart, totalCup, totalUsd, paymentMethod, status, invoiceNumber: `F-${Date.now().toString().slice(-6)}` })} className="bg-white text-[#8B5E3C] px-8 py-4 rounded-2xl font-black uppercase text-xs">Confirmar</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={(id) => setNotifications(n => n.map(x => x.id === id ? {...x, read: true} : x))}>
      {activeTab === 'dashboard' && <Dashboard products={products} transactions={transactions} suppliers={suppliers} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8">
          <div className="flex justify-between items-center">
            <h2 className="text-2xl font-black text-gray-800 uppercase">Catálogo de Productos</h2>
            <button onClick={() => setShowProductModal({show: true})} className="bg-[#8B5E3C] text-white px-6 py-4 rounded-2xl font-black text-xs uppercase tracking-widest">+ Nuevo Producto</button>
          </div>
          <div className="bg-white rounded-[40px] shadow-sm border overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-gray-50/50 border-b">
                <tr className="text-[10px] uppercase text-gray-400 font-black tracking-widest">
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6">Existencia</th>
                  <th className="px-8 py-6">Precios</th>
                  <th className="px-8 py-6">Origen</th>
                  <th className="px-8 py-6 text-right">Acción</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50/30">
                    <td className="px-8 py-6">
                      <p className="font-black text-sm uppercase">{p.name}</p>
                      <p className="text-[9px] font-black text-gray-400">{p.sku}</p>
                    </td>
                    <td className="px-8 py-6 font-black text-sm">{p.stock} u.</td>
                    <td className="px-8 py-6 flex flex-wrap gap-2">
                      <span className="px-2 py-1 bg-gray-100 text-[9px] font-black rounded">{p.unitPrice}{p.unitCurrency}</span>
                      {p.groupings.map(g => <span key={g.id} className="px-2 py-1 bg-amber-50 text-[#8B5E3C] text-[9px] font-black rounded">{g.label}: {g.price}</span>)}
                    </td>
                    <td className="px-8 py-6">
                       <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${p.receptionType === 'Consignación' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>{p.receptionType}</span>
                    </td>
                    <td className="px-8 py-6 text-right">
                       <button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="text-red-400"><Trash2 size={18} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'suppliers' && (
        <div className="space-y-8 animate-in fade-in">
           <div className="flex justify-between items-center">
              <div>
                <h2 className="text-2xl font-black text-gray-800 uppercase">Directorio de Contactos</h2>
                <p className="text-sm text-gray-400">Proveedores y clientes con su información de contacto y dirección completa.</p>
              </div>
              <button onClick={() => setShowContactModal(true)} className="bg-[#8B5E3C] text-white px-8 py-4 rounded-3xl font-black text-xs uppercase tracking-widest shadow-xl">+ Nuevo Contacto</button>
           </div>

           <div className="flex gap-4 mb-8 bg-white p-2 rounded-2xl border w-fit">
              {['Todos', 'Proveedor', 'Cliente'].map((f: any) => (
                <button key={f} onClick={() => setContactFilter(f)} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${contactFilter === f ? 'bg-[#8B5E3C] text-white shadow-lg' : 'text-gray-400 hover:text-gray-800'}`}>{f}</button>
              ))}
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {contacts.filter(c => contactFilter === 'Todos' || c.type === contactFilter).map(c => (
                <div key={c.id} className="bg-white p-8 rounded-[40px] border shadow-sm flex flex-col justify-between">
                   <div>
                     <div className="flex justify-between mb-6">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center font-black text-white ${c.type === 'Proveedor' ? 'bg-purple-400' : 'bg-blue-400'}`}>{c.name.charAt(0)}</div>
                        <span className={`text-[8px] font-black uppercase px-2 py-1 rounded-lg ${c.type === 'Proveedor' ? 'bg-purple-50 text-purple-600' : 'bg-blue-50 text-blue-600'}`}>{c.type} {c.isConsignee ? '(Consig.)' : ''}</span>
                     </div>
                     <h3 className="font-black text-gray-800 text-sm uppercase mb-4">{c.name}</h3>
                     <div className="space-y-3">
                        <p className="text-[10px] font-bold text-gray-400 uppercase flex items-center gap-2"><Phone size={12} /> {c.phone}</p>
                        <p className="text-[10px] font-bold text-gray-400 uppercase flex items-center gap-2"><Mail size={12} /> {c.email || 'NO ASIGNADO'}</p>
                        <p className="text-[10px] font-bold text-gray-500 uppercase flex items-center gap-2 bg-gray-50 p-3 rounded-xl"><MapPin size={12} className="shrink-0" /> {c.address}</p>
                     </div>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {showSaleModal && <SalesModal />}
      {selectedInvoice && <InvoiceView transaction={selectedInvoice} onClose={() => setSelectedInvoice(null)} />}

      {showProductModal.show && (
        <div className="fixed inset-0 bg-black/70 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-4xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center">
              <h2 className="text-xl font-black uppercase text-gray-800">Recepción de Mercancía</h2>
              <button onClick={() => setShowProductModal({show: false})}><X size={24} /></button>
            </div>
            <ProductForm 
              initialData={showProductModal.product} 
              onSave={(p) => {
                if(showProductModal.product) setProducts(products.map(x => x.id === p.id ? p : x));
                else setProducts([...products, p]);
                setShowProductModal({show: false});
              }}
              onCancel={() => setShowProductModal({show: false})}
            />
          </div>
        </div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/70 z-[160] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-md shadow-2xl p-10">
            <h2 className="text-xl font-black mb-8 uppercase text-[#8B5E3C]">Nuevo Contacto</h2>
