                <button disabled={cart.length === 0} onClick={() => handleCreateSale({ id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient, clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart, totalCup, totalUsd, paymentMethod, status, invoiceNumber: `F-${Date.now().toString().slice(-6)}` })} className="bg-white text-[#8B5E3C] px-8 py-4 rounded-2xl font-black uppercase text-xs">Confirmar</button>
