              setContacts([...contacts, {
                id: Math.random().toString(36).substr(2, 9),
                name: fd.get('name') as string,
                contactName: fd.get('contact') as string,
                phone: fd.get('phone') as string,
                email: fd.get('email') as string,
                address: fd.get('address') as string,
                type: fd.get('type') as any,
                isConsignee: fd.get('isConsignee') === 'on',
                pendingBalanceCup: 0,
                pendingBalanceUsd: 0
              }]);
              setShowContactModal(false);
            }} className="space-y-5">
               <input name="name" placeholder="Empresa / Nombre" required className="w-full p-4 bg-gray-50 border rounded-2xl outline-none" />
               <input name="phone" placeholder="Teléfono" required className="w-full p-4 bg-gray-50 border rounded-2xl outline-none" />
               <input name="address" placeholder="Dirección Completa (Obligatorio)" required className="w-full p-4 bg-gray-50 border rounded-2xl outline-none" />
               <select name="type" className="w-full p-4 bg-gray-50 border rounded-2xl font-bold text-xs">
                  <option value="Proveedor">Es Proveedor</option>
                  <option value="Cliente">Es Cliente</option>
               </select>
               <label className="flex items-center gap-3">
                  <input type="checkbox" name="isConsignee" className="w-5 h-5 accent-[#8B5E3C]" />
                  <span className="text-[10px] font-black uppercase">Es Consignatario</span>
               </label>
               <div className="flex gap-4 pt-6">
                  <button type="button" onClick={() => setShowContactModal(false)} className="flex-1 font-black uppercase text-[10px]">Cerrar</button>
                  <button type="submit" className="flex-1 bg-[#8B5E3C] text-white py-4 rounded-2xl font-black uppercase text-[10px]">Guardar</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

