const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [socialContent, setSocialContent] = useState<string>('');
  const [isSocialLoading, setIsSocialLoading] = useState(false);
  const [contactFilter, setContactFilter] = useState<'Todos' | 'Proveedor' | 'Cliente'>('Todos');

  const [showProductModal, setShowProductModal] = useState<{show: boolean, product?: Product}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  const suppliers = contacts.filter(c => c.type === 'Proveedor');
  const clients = contacts.filter(c => c.type === 'Cliente');

  useEffect(() => {
    const keys = ['products', 'contacts', 'transactions'];
    keys.forEach(key => {
      const saved = localStorage.getItem(`pati_v2_${key}`);
      if (saved) {
        if (key === 'products') setProducts(JSON.parse(saved));
        if (key === 'contacts') setContacts(JSON.parse(saved));
        if (key === 'transactions') setTransactions(JSON.parse(saved));
      }
    });
  }, []);

  useEffect(() => { localStorage.setItem('pati_v2_products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('pati_v2_contacts', JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem('pati_v2_transactions', JSON.stringify(transactions)); }, [transactions]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Bajo', message: `${p.name} en nivel crítico (${p.stock} u.)`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / (86400000));
      if (days <= 60 && days > 0) {
        newNotifs.push({ id: `exp-${p.id}`, title: 'Vencimiento Próximo', message: `${p.name} vence en ${days} días.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  const generateSKU = () => {
    const prefix = 'PT';
    const num = Math.floor(1000 + Math.random() * 9000);
    const sku = `${prefix}-${num}`;
    return products.some(p => p.sku === sku) ? generateSKU() : sku;
  };

  const handleCreateSale = (sale: Transaction) => {
    setTransactions([sale, ...transactions]);
    if (sale.status === 'Despachado') {
      const updatedProducts = products.map(p => {
        const soldUnits = sale.items
          .filter(item => item.productId === p.id)
          .reduce((acc, item) => acc + item.unitQuantity, 0);

        if (soldUnits > 0) {
          if (p.receptionType === 'Consignación') {
            const supplier = contacts.find(s => s.id === p.supplierId);
            if (supplier) {
              const saleTotalForThisProduct = sale.items
                .filter(item => item.productId === p.id)
                .reduce((acc, item) => acc + item.total, 0);

              setContacts(prev => prev.map(s => s.id === supplier.id ? {
                ...s,
                pendingBalanceCup: p.unitCurrency === 'CUP' ? s.pendingBalanceCup + saleTotalForThisProduct : s.pendingBalanceCup,
                pendingBalanceUsd: p.unitCurrency === 'USD' ? s.pendingBalanceUsd + saleTotalForThisProduct : s.pendingBalanceUsd,
              } : s));
            }
          }
          return { ...p, stock: p.stock - soldUnits, unitsSoldFromConsignment: (p.unitsSoldFromConsignment || 0) + soldUnits };
        }
        return p;
      });
      setProducts(updatedProducts);
    }
    setShowSaleModal(false);
  };

  const ProductForm = ({ initialData, onSave, onCancel }: { initialData?: Product, onSave: (p: Product) => void, onCancel: () => void }) => {
    const [groupings, setGroupings] = useState<GroupingPrice[]>(initialData?.groupings || []);
    const [tempGrouping, setTempGrouping] = useState({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency });
    const [generatedSku] = useState(initialData?.sku || generateSKU());

    const addGrouping = () => {
      if (tempGrouping.label && tempGrouping.quantity > 0) {
        setGroupings([...groupings, { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) }]);
        setTempGrouping({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency });
      }
    };

    return (
      <form onSubmit={(e) => {
        e.preventDefault();
        const fd = new FormData(e.currentTarget);
        const isOffer = fd.get('isOffer') === 'on';
        onSave({
          id: initialData?.id || Math.random().toString(36).substr(2, 9),
          name: fd.get('name') as string,
          sku: generatedSku,
          description: fd.get('description') as string,
          categoryId: fd.get('categoryId') as string,
          supplierId: fd.get('supplierId') as string,
          receptionType: fd.get('receptionType') as ReceptionType,
          unitPrice: parseFloat(fd.get('unitPrice') as string),
          unitCurrency: fd.get('unitCurrency') as Currency,
          groupings: groupings,
          stock: parseInt(fd.get('stock') as string),
          minStock: parseInt(fd.get('minStock') as string),
          expiryDate: fd.get('expiryDate') as string,
          receivedDate: initialData?.receivedDate || new Date().toISOString().split('T')[0],
          isOffer: isOffer,
          offerPrice: isOffer ? parseFloat(fd.get('offerPrice') as string || '0') : undefined,
        });
      }} className="p-8 overflow-y-auto space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Código</label>
            <div className="w-full p-3 bg-gray-100 border rounded-xl font-mono text-gray-600">{generatedSku}</div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Nombre Comercial</label>
            <input name="name" defaultValue={initialData?.name} required className="w-full p-3 bg-gray-50 border rounded-xl outline-none focus:ring-2 focus:ring-[#8B5E3C]" />
          </div>
          <div className="space-y-1">
            <div className="flex justify-between items-center">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Proveedor</label>
              <button type="button" onClick={() => setShowContactModal(true)} className="text-[9px] font-black text-[#8B5E3C] uppercase tracking-widest hover:underline">+ Nuevo Proveedor</button>
            </div>
            <select name="supplierId" defaultValue={initialData?.supplierId} className="w-full p-3 bg-gray-50 border rounded-xl">
              {suppliers.map(s => <option key={s.id} value={s.id}>{s.name} {s.isConsignee ? '(Consignación)' : ''}</option>)}
              {suppliers.length === 0 && <option disabled>Cree un proveedor primero</option>}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tipo Recepción</label>
            <select name="receptionType" defaultValue={initialData?.receptionType} className="w-full p-3 bg-gray-50 border rounded-xl">
              <option value="Consignación">Consignación</option>
              <option value="Compra Directa">Compra Directa</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Precio Unitario</label>
            <div className="flex gap-2">
              <input name="unitPrice" type="number" step="0.01" defaultValue={initialData?.unitPrice} required className="flex-1 p-3 bg-gray-50 border rounded-xl outline-none" />
              <select name="unitCurrency" defaultValue={initialData?.unitCurrency} className="w-24 p-3 bg-gray-50 border rounded-xl font-bold">
                <option value="CUP">CUP</option>
                <option value="USD">USD</option>
              </select>
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Stock (Actual/Min)</label>
            <div className="flex gap-2">
              <input name="stock" type="number" defaultValue={initialData?.stock} required className="flex-1 p-3 bg-gray-50 border rounded-xl outline-none" placeholder="Stock Actual" />
              <input name="minStock" type="number" defaultValue={initialData?.minStock} required className="flex-1 p-3 bg-gray-50 border rounded-xl outline-none" placeholder="Stock Mínimo" />
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Fecha Vencimiento</label>
            <input name="expiryDate" type="date" defaultValue={initialData?.expiryDate} required className="w-full p-3 bg-gray-50 border rounded-xl outline-none" />
          </div>
          <div className="flex items-center space-x-6">
            <label className="flex items-center gap-3 cursor-pointer group">
              <input name="isOffer" type="checkbox" defaultChecked={initialData?.isOffer} className="w-6 h-6 rounded-lg accent-[#8B5E3C] border-gray-300" />
              <span className="text-xs font-black text-gray-700 uppercase tracking-widest group-hover:text-[#8B5E3C]">En Oferta</span>
            </label>
          </div>
        </div>

        <div className="border-t border-dashed pt-6">
          <h3 className="text-xs font-black text-[#8B5E3C] uppercase tracking-widest mb-4 flex items-center gap-2"><Layers size={14} /> Agrupaciones de Venta</h3>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-3 mb-6">
            <input placeholder="Nombre (Ej: Caja 12u)" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} />
            <input placeholder="Unidades" type="number" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 0})} />
            <input placeholder="Precio" type="number" className="p-3 bg-gray-50 border rounded-xl text-sm" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} />
            <button type="button" onClick={addGrouping} className="bg-gray-100 p-3 rounded-xl text-xs font-black uppercase hover:bg-gray-200">Añadir</button>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            {groupings.map(g => (
              <div key={g.id} className="flex justify-between items-center p-3 bg-white border rounded-2xl shadow-sm">
                <span className="font-black text-xs uppercase text-gray-700">{g.label} ({g.quantity}u)</span>
                <div className="flex items-center gap-4">
                  <span className="font-black text-[#8B5E3C]">{g.price} {g.currency}</span>
                  <button type="button" onClick={() => setGroupings(groupings.filter(x => x.id !== g.id))} className="text-red-400 hover:text-red-600 transition-colors"><Trash2 size={16} /></button>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="flex justify-end gap-3 pt-8 mt-4 border-t sticky bottom-0 bg-white">
          <button type="button" onClick={onCancel} className="px-6 py-2 text-gray-400 font-black uppercase text-[10px] tracking-widest">Cancelar</button>
          <button type="submit" className="px-10 py-4 bg-[#8B5E3C] text-white font-black rounded-2xl uppercase text-[10px] shadow-xl shadow-[#8B5E3C]/20 hover:-translate-y-1 transition-transform">Guardar Producto</button>
        </div>
      </form>
    );
  };

  const SalesModal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [selectedClient, setSelectedClient] = useState<string>('Publico-Gral');
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');
    const [status, setStatus] = useState<'Solicitud' | 'Despachado'>('Solicitud');

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
    const totalUsd = cart.filter(i => i.currency === 'USD').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/70 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[40px] w-full max-w-6xl h-[90vh] overflow-hidden flex shadow-2xl">
          <div className="w-1/2 border-r flex flex-col p-8 bg-gray-50/50">
            <div className="mb-6 flex justify-between items-center">
              <h2 className="text-xl font-black uppercase text-[#8B5E3C]">Punto de Venta</h2>
              <button onClick={() => setShowSaleModal(false)} className="p-2 hover:bg-white rounded-full"><X /></button>
            </div>
            <div className="relative mb-6">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
              <input className="w-full pl-12 pr-4 py-4 bg-white border rounded-2xl outline-none focus:ring-2 focus:ring-[#8B5E3C]" placeholder="Buscar producto..." value={search} onChange={e => setSearch(e.target.value)} />
            </div>
            <div className="flex-1 overflow-y-auto space-y-3 pr-2">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()) || p.sku.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-5 rounded-[24px] border border-gray-100 hover:shadow-md transition-shadow">
                  <div className="flex justify-between items-start mb-4">
                    <div>
                      <h4 className="font-black text-xs uppercase text-gray-800">{p.name}</h4>
                      <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Existencia: {p.stock} U. • {p.sku}</p>
                    </div>
                    <button onClick={() => setCart([...cart, { id: Math.random().toString(), productId: p.id, productName: p.name, quantity: 1, price: p.unitPrice, total: p.unitPrice, currency: p.unitCurrency, unitQuantity: 1 }])} className="p-2 bg-[#8B5E3C]/10 text-[#8B5E3C] rounded-xl hover:bg-[#8B5E3C] hover:text-white transition-colors"><Plus size={18} /></button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {p.groupings.map(g => (
                      <button key={g.id} onClick={() => setCart([...cart, { id: Math.random().toString(), productId: p.id, productName: p.name, groupingId: g.id, groupingLabel: g.label, quantity: 1, price: g.price, total: g.price, currency: g.currency, unitQuantity: g.quantity }])} className="px-3 py-1 bg-amber-50 text-[9px] font-black rounded-lg text-[#8B5E3C] hover:bg-[#8B5E3C] hover:text-white transition-colors">{g.label}: {g.price} {g.currency}</button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-8 bg-white">
            <h3 className="text-xs font-black uppercase text-gray-400 mb-8 tracking-widest">Resumen del Pedido</h3>
            <div className="flex-1 overflow-y-auto space-y-4 mb-8">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl">
                  <div>
                    <p className="font-black text-xs uppercase text-gray-800">{item.productName}</p>
                    <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">{item.groupingLabel || 'Unidad Individual'}</p>
                  </div>
                  <div className="text-right">
                    <p className="font-black text-sm text-gray-800">{item.total.toLocaleString()} {item.currency}</p>
                    <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-[9px] text-red-400 font-black uppercase tracking-widest hover:text-red-600">Eliminar</button>
                  </div>
                </div>
              ))}
              {cart.length === 0 && (
                <div className="h-full flex flex-col items-center justify-center opacity-30">
                  <ShoppingBag size={48} className="mb-4" />
                  <p className="font-black uppercase text-[10px] tracking-widest">Carrito vacío</p>
                </div>
              )}
            </div>
            <div className="space-y-6 pt-6 border-t">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Cliente</label>
                <select className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={selectedClient} onChange={e => setSelectedClient(e.target.value)}>
                  <option value="Publico-Gral">Venta al Público General</option>
                  {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Método</label>
                  <select className="w-full p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setPaymentMethod(e.target.value as PaymentMethod)}><option>Efectivo</option><option>Transferencia</option></select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Operación</label>
                  <select className="w-full p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setStatus(e.target.value as any)}><option value="Solicitud">Pre-factura</option><option value="Despachado">Venta Final</option></select>
                </div>
              </div>
              <div className="bg-[#8B5E3C] p-6 rounded-[30px] text-white flex justify-between items-center shadow-xl shadow-[#8B5E3C]/30">
                <div>
                   <p className="text-[10px] font-black uppercase opacity-60 tracking-widest">Total</p>
                   <p className="text-2xl font-black tabular-nums">{totalCup.toLocaleString()} CUP</p>
                   {totalUsd > 0 && <p className="text-lg font-black tabular-nums opacity-80">{totalUsd.toLocaleString()} USD</p>}
                </div>
                <button disabled={cart.length === 0} onClick={() => handleCreateSale({ id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient, clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart, totalCup, totalUsd, paymentMethod, status, invoiceNumber: `F-${Date.now().toString().slice(-6)}` })} className="bg-white text-[#8B5E3C] px-10 py-4 rounded-2xl font-black uppercase text-xs tracking-widest shadow-lg hover:-translate-y-1 transition-transform disabled:opacity-50">Procesar</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
