      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <h2 className="text-2xl font-black text-gray-800 uppercase tracking-tight">Catálogo de Productos</h2>
            <div className="flex gap-3 w-full md:w-auto">
              <button onClick={async () => {
                setIsSocialLoading(true);
                const content = await generateSocialMediaPost(products.filter(p => p.isOffer || products.indexOf(p) < 5));
                setSocialContent(content || "Error");
                setIsSocialLoading(false);
              }} className="flex-1 md:flex-none flex items-center justify-center gap-3 bg-blue-600 text-white px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-transform hover:-translate-y-1 shadow-lg shadow-blue-500/20">
                {isSocialLoading ? 'Generando...' : <><Share2 size={16} /> Redes Sociales</>}
              </button>
              <button onClick={() => setShowProductModal({show: true})} className="flex-1 md:flex-none flex items-center justify-center gap-3 bg-[#8B5E3C] text-white px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-[#8B5E3C]/20 transition-transform hover:-translate-y-1">
                <Plus size={16} /> Nuevo Producto
              </button>
            </div>
          </div>

          {socialContent && (
            <div className="bg-white border border-blue-50 p-8 rounded-[32px] relative shadow-xl shadow-blue-500/5 animate-in slide-in-from-top-4">
              <button onClick={() => setSocialContent('')} className="absolute top-6 right-6 text-gray-300 hover:text-red-500 transition-colors"><X size={24} /></button>
              <div className="flex items-center gap-3 text-blue-600 font-black uppercase text-xs tracking-widest mb-6"><Share2 size={18} /> Social Media Assistant</div>
              <p className="text-gray-600 whitespace-pre-wrap text-sm leading-relaxed mb-6 font-medium italic">"{socialContent}"</p>
              <button onClick={() => {navigator.clipboard.writeText(socialContent); alert('Copiado!');}} className="px-8 py-3 bg-blue-600 text-white text-[10px] font-black uppercase tracking-widest rounded-xl hover:bg-blue-700 transition-colors">Copiar Texto</button>
            </div>
          )}

          <div className="bg-white rounded-[40px] shadow-sm border overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-gray-50/50 border-b">
                  <tr className="text-[10px] uppercase text-gray-400 font-black tracking-widest">
                    <th className="px-8 py-6">Producto</th>
                    <th className="px-8 py-6">Existencia</th>
                    <th className="px-8 py-6">Estructura Precios</th>
                    <th className="px-8 py-6">Origen</th>
                    <th className="px-8 py-6 text-right">Acción</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {products.map(p => (
                    <tr key={p.id} className="group hover:bg-gray-50/30 transition-colors">
                      <td className="px-8 py-6">
                        <p className="font-black text-sm uppercase text-gray-800">{p.name}</p>
                        <p className="text-[9px] font-black text-gray-400 tracking-widest uppercase">{p.sku}</p>
                      </td>
                      <td className="px-8 py-6">
                        <span className={`font-black text-sm ${p.stock <= p.minStock ? 'text-red-500' : 'text-gray-700'}`}>{p.stock} u.</span>
                        {p.stock <= p.minStock && <div className="text-[8px] font-black text-red-400 uppercase tracking-widest mt-1">Stock Bajo</div>}
                      </td>
                      <td className="px-8 py-6">
                        <div className="flex flex-wrap gap-2">
                          <span className="px-2 py-1 bg-gray-100 text-[9px] font-black rounded uppercase tracking-widest">Base: {p.unitPrice}{p.unitCurrency}</span>
                          {p.groupings.map(g => <span key={g.id} className="px-2 py-1 bg-amber-50 text-[#8B5E3C] text-[9px] font-black rounded uppercase tracking-widest">{g.label}: {g.price}</span>)}
                        </div>
                      </td>
                      <td className="px-8 py-6">
                         <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${p.receptionType === 'Consignación' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>{p.receptionType}</span>
                      </td>
                      <td className="px-8 py-6 text-right">
                         <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-2 text-gray-300 hover:text-red-500 transition-colors"><Trash2 size={18} /></button>
                         </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
            <div className="bg-white p-12 rounded-[50px] border border-gray-100 shadow-sm flex flex-col justify-between items-start">
              <div>
                <h2 className="text-3xl font-black text-gray-800 uppercase tracking-tight mb-4">Ingreso de Mercancía</h2>
                <p className="text-gray-400 font-medium mb-12 max-w-md">Cargue nuevos productos al catálogo o actualice el inventario existente para consignatarios y compras directas.</p>
              </div>
              <button onClick={() => setShowProductModal({show: true})} className="w-full bg-[#8B5E3C] text-white py-8 rounded-[30px] font-black uppercase text-xs tracking-[0.2em] shadow-2xl shadow-[#8B5E3C]/20 hover:-translate-y-2 transition-all flex items-center justify-center gap-4">
                <ArrowDownCircle size={24} /> Iniciar Proceso de Recepción
              </button>
            </div>
            <div className="bg-gray-900 p-12 rounded-[50px] text-white shadow-2xl relative overflow-hidden">
               <div className="absolute top-0 right-0 p-10 opacity-10"><Package size={140} /></div>
               <h3 className="text-[10px] font-black uppercase tracking-[0.3em] mb-10 text-gray-400">Últimas entradas al sistema</h3>
               <div className="space-y-4">
                  {products.slice().sort((a,b) => b.receivedDate.localeCompare(a.receivedDate)).slice(0, 4).map(p => (
                    <div key={p.id} className="flex justify-between items-center p-6 bg-white/5 rounded-3xl border border-white/5 hover:bg-white/10 transition-colors">
                      <div className="flex items-center gap-4">
                        <div className="w-12 h-12 bg-[#8B5E3C]/20 rounded-2xl flex items-center justify-center font-black text-xs text-[#8B5E3C]">{p.stock}</div>
                        <div>
                          <p className="font-black text-xs uppercase tracking-tight">{p.name}</p>
                          <p className="text-[9px] text-gray-500 font-bold uppercase tracking-widest">Recibido: {p.receivedDate}</p>
                        </div>
                      </div>
                      <span className="text-[8px] font-black uppercase tracking-widest px-3 py-1 bg-[#8B5E3C] rounded-full">Procesado</span>
                    </div>
                  ))}
                  {products.length === 0 && <p className="text-gray-600 italic text-sm text-center py-10">Sin movimientos recientes de inventario.</p>}
               </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
              <div className="xl:col-span-2 space-y-8">
                 <div className="bg-white rounded-[40px] border border-gray-100 shadow-sm overflow-hidden">
                    <div className="p-8 border-b flex justify-between items-center">
                       <h3 className="font-black text-gray-800 uppercase tracking-widest text-[10px]">Registro de Ventas y Despachos</h3>
                       <button onClick={() => setShowSaleModal(true)} className="bg-[#8B5E3C] text-white px-8 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:-translate-y-1 transition-transform flex items-center gap-2">
                          <Plus size={16} /> Nueva Venta
                       </button>
                    </div>
                    <div className="overflow-x-auto">
                       <table className="w-full text-left">
                          <thead className="bg-gray-50/50 border-b">
                             <tr className="text-[9px] font-black uppercase text-gray-400 tracking-[0.2em]">
                                <th className="px-8 py-5">Nro Factura</th>
                                <th className="px-8 py-5">Cliente</th>
                                <th className="px-8 py-5 text-right">Importe</th>
                                <th className="px-8 py-5 text-center">Estado</th>
                                <th className="px-8 py-5 text-right">Ver</th>
                             </tr>
                          </thead>
                          <tbody className="divide-y divide-gray-50">
                             {transactions.map(t => (
                                <tr key={t.id} className="hover:bg-gray-50/30 transition-colors">
                                   <td className="px-8 py-6">
                                      <p className="font-black text-xs text-gray-800 tracking-tight">{t.invoiceNumber}</p>
                                      <p className="text-[9px] font-bold text-gray-400">{new Date(t.date).toLocaleDateString()}</p>
                                   </td>
                                   <td className="px-8 py-6 font-black text-xs text-gray-700 uppercase">{t.clientName}</td>
                                   <td className="px-8 py-6 text-right tabular-nums">
                                      <p className="font-black text-xs">{t.totalCup > 0 ? `${t.totalCup.toLocaleString()} CUP` : `${t.totalUsd.toLocaleString()} USD`}</p>
                                   </td>
                                   <td className="px-8 py-6 text-center">
                                      <span className={`px-4 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${t.status === 'Despachado' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{t.status}</span>
                                   </td>
                                   <td className="px-8 py-6 text-right">
                                      <button onClick={() => setSelectedInvoice(t)} className="p-2 text-gray-300 hover:text-[#8B5E3C] transition-colors"><FileText size={20} /></button>
                                   </td>
                                </tr>
                             ))}
                          </tbody>
                       </table>
                       {transactions.length === 0 && <div className="p-20 text-center text-gray-300 uppercase font-black tracking-widest text-[10px]">Sin transacciones registradas</div>}
                    </div>
                 </div>
              </div>

              <div className="space-y-8">
                 <div className="bg-amber-50 p-10 rounded-[40px] border border-amber-100 shadow-sm">
                    <h4 className="text-[10px] font-black uppercase text-amber-800 tracking-[0.2em] mb-8 flex items-center gap-2"><Filter size={16} /> Pre-facturas en espera</h4>
                    <div className="space-y-4">
                       {transactions.filter(t => t.status === 'Solicitud').map(t => (
                          <div key={t.id} className="p-6 bg-white rounded-3xl border border-amber-100 shadow-sm flex justify-between items-center group hover:scale-105 transition-transform">
                             <div>
                                <p className="font-black text-gray-800 text-xs">{t.invoiceNumber}</p>
                                <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest">{t.totalCup.toLocaleString()} CUP</p>
                             </div>
                             <button onClick={() => {
                                setTransactions(transactions.map(x => x.id === t.id ? {...x, status: 'Despachado'} : x));
                                handleCreateSale({...t, status: 'Despachado'});
                             }} className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl hover:bg-emerald-600 hover:text-white transition-all shadow-sm">
                                <CheckCircle2 size={20} />
                             </button>
                          </div>
                       ))}
                       {transactions.filter(t => t.status === 'Solicitud').length === 0 && <p className="text-amber-800/30 italic text-[10px] text-center font-bold py-10">Todo despachado</p>}
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'suppliers' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h2 className="text-2xl font-black text-gray-800 uppercase tracking-tight">Directorio de Contactos</h2>
                <p className="text-sm text-gray-400 font-medium tracking-tight">Proveedores (consignatarios o directos) y Clientes registrados.</p>
              </div>
              <button onClick={() => setShowContactModal(true)} className="bg-[#8B5E3C] text-white px-8 py-4 rounded-3xl font-black text-[10px] uppercase tracking-widest shadow-xl shadow-[#8B5E3C]/20 flex items-center gap-3 hover:-translate-y-1 transition-transform">
                <UserPlus size={18}/> Nuevo Contacto
              </button>
           </div>

           <div className="flex gap-3 bg-white p-2 rounded-2xl border border-gray-100 w-fit">
              {['Todos', 'Proveedor', 'Cliente'].map((f: any) => (
                <button key={f} onClick={() => setContactFilter(f)} className={`px-6 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${contactFilter === f ? 'bg-[#8B5E3C] text-white shadow-lg shadow-[#8B5E3C]/20' : 'text-gray-400 hover:text-gray-800'}`}>{f}</button>
              ))}
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {contacts.filter(c => contactFilter === 'Todos' || c.type === contactFilter).map(c => (
                <div key={c.id} className="bg-white p-8 rounded-[40px] border border-gray-100 shadow-sm group hover:shadow-xl transition-all flex flex-col justify-between h-[320px]">
                   <div>
                     <div className="flex justify-between items-start mb-6">
                        <div className={`w-14 h-14 rounded-2xl flex items-center justify-center font-black text-white text-xl shadow-lg ${c.type === 'Proveedor' ? 'bg-purple-500 shadow-purple-500/20' : 'bg-blue-500 shadow-blue-500/20'}`}>
                           {c.name.charAt(0).toUpperCase()}
                        </div>
                        <span className={`text-[8px] font-black uppercase tracking-widest px-3 py-1 rounded-full ${c.type === 'Proveedor' ? 'bg-purple-50 text-purple-600' : 'bg-blue-50 text-blue-600'}`}>
                          {c.type} {c.isConsignee ? '(Consig.)' : ''}
                        </span>
                     </div>
                     <h3 className="font-black text-gray-800 text-sm uppercase tracking-tight mb-4 group-hover:text-[#8B5E3C] transition-colors">{c.name}</h3>
