export default App;

export type Currency = 'CUP' | 'USD';
export type PaymentMethod = 'Efectivo' | 'Transferencia';
export type ReceptionType = 'Consignación' | 'Compra Directa';

export interface GroupingPrice {
  id: string;
  label: string; // e.g., "Estuche de 6u", "Palet"
  quantity: number; // units included in one group
  price: number;
  currency: Currency;
  minOrderQuantity?: number; // Minimum groups needed for this price (e.g., more than 3)
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  description: string;
  categoryId: string;
  supplierId: string;
  receptionType: ReceptionType;
  unitPrice: number;
  unitCurrency: Currency;
  costPrice?: number; 
  groupings: GroupingPrice[];
  stock: number;
  minStock: number;
  expiryDate: string;
  receivedDate: string;
  isOffer?: boolean;
  offerPrice?: number;
  offerDescription?: string;
  unitsSoldFromConsignment?: number; // Track for payments
}

export interface Contact {
  id: string;
  name: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  type: 'Proveedor' | 'Cliente';
  isConsignee?: boolean; // Solo para proveedores
  pendingBalanceCup: number;
  pendingBalanceUsd: number;
}

export interface SaleItem {
  id: string;
  productId: string;
  productName: string;
  groupingId?: string; 
  groupingLabel?: string;
  quantity: number; // Number of items/groups
  price: number;
  total: number;
  currency: Currency;
  unitQuantity: number; // How many single units per item/group
}

export interface Transaction {
  id: string;
  date: string;
  clientId: string;
  clientName: string;
  items: SaleItem[];
  totalCup: number;
  totalUsd: number;
  paymentMethod: PaymentMethod;
  status: 'Solicitud' | 'Despachado' | 'Anulado';
  invoiceNumber: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'error' | 'success';
  date: string;
  read: boolean;
}

