const ProductForm = ({ initialData, suppliers, onSave, onCancel, onAddSupplier }: { 
  initialData?: Product, 
  suppliers: Contact[], 
  onSave: (p: Product) => void, 
  onCancel: () => void,
  onAddSupplier: (currentFormData: Partial<Product>) => void
}) => {
  const [formData, setFormData] = useState<Partial<Product>>(initialData || {
    receptionType: 'Consignación',
    unitCurrency: 'CUP',
    groupings: [],
    stock: 0,
    minStock: 0,
    receivedDate: new Date().toISOString().split('T')[0]
  });

  const [tempGrouping, setTempGrouping] = useState({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency, minOrderQuantity: 0 });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value, type } = e.target;
    const val = type === 'number' ? parseFloat(value) : value;
    setFormData(prev => ({ ...prev, [name]: val }));
  };

  const addGrouping = () => {
    if (tempGrouping.label && tempGrouping.quantity > 0) {
      const updatedGroupings = [...(formData.groupings || []), { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) }];
      setFormData({ ...formData, groupings: updatedGroupings });
      setTempGrouping({ label: '', quantity: 0, price: 0, currency: 'CUP' as Currency, minOrderQuantity: 0 });
    }
  };

  return (
    <div className="p-8 overflow-y-auto space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Nombre Comercial</label>
          <input name="name" value={formData.name || ''} onChange={handleChange} required className="w-full p-3 bg-gray-50 border rounded-xl" />
        </div>
        <div className="space-y-1">
          <div className="flex justify-between items-center">
            <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Proveedor</label>
            <button type="button" onClick={() => onAddSupplier(formData)} className="text-[9px] font-black text-[#8B5E3C] uppercase tracking-widest hover:underline">+ Nuevo Proveedor</button>
          </div>
          <select name="supplierId" value={formData.supplierId || ''} onChange={handleChange} className="w-full p-3 bg-gray-50 border rounded-xl">
            <option value="" disabled>Seleccione proveedor</option>
            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name} {s.isConsignee ? '(Consig.)' : ''}</option>)}
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Precio Unitario</label>
          <div className="flex gap-2">
            <input name="unitPrice" type="number" step="0.01" value={formData.unitPrice || ''} onChange={handleChange} required className="flex-1 p-3 bg-gray-50 border rounded-xl" />
            <select name="unitCurrency" value={formData.unitCurrency} onChange={handleChange} className="w-24 p-3 bg-gray-50 border rounded-xl font-bold">
              <option value="CUP">CUP</option>
              <option value="USD">USD</option>
            </select>
          </div>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Stock / Mínimo</label>
          <div className="flex gap-2">
            <input name="stock" type="number" value={formData.stock || ''} onChange={handleChange} required className="flex-1 p-3 bg-gray-50 border rounded-xl" placeholder="Actual" />
            <input name="minStock" type="number" value={formData.minStock || ''} onChange={handleChange} required className="flex-1 p-3 bg-gray-50 border rounded-xl" placeholder="Mínimo" />
          </div>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Vencimiento</label>
          <input name="expiryDate" type="date" value={formData.expiryDate || ''} onChange={handleChange} required className="w-full p-3 bg-gray-50 border rounded-xl" />
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Recepción</label>
          <select name="receptionType" value={formData.receptionType} onChange={handleChange} className="w-full p-3 bg-gray-50 border rounded-xl">
            <option value="Consignación">Consignación</option>
            <option value="Compra Directa">Compra Directa</option>
          </select>
        </div>
      </div>

      <div className="border-t border-dashed pt-6">
        <h3 className="text-xs font-black text-[#8B5E3C] uppercase tracking-widest mb-4">Agrupaciones y Ofertas por Volumen</h3>
        <div className="grid grid-cols-1 md:grid-cols-5 gap-2 mb-4">
          <input placeholder="Nombre (Caja...)" className="p-3 bg-gray-50 border rounded-xl text-xs" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} />
          <input placeholder="U. por grupo" type="number" className="p-3 bg-gray-50 border rounded-xl text-xs" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 0})} />
          <input placeholder="Precio" type="number" className="p-3 bg-gray-50 border rounded-xl text-xs" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} />
          <input placeholder="Mín. p/precio (ej: +3)" type="number" className="p-3 bg-gray-50 border rounded-xl text-xs" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value) || 0})} />
          <button type="button" onClick={addGrouping} className="bg-gray-100 p-3 rounded-xl text-[10px] font-black uppercase">Añadir</button>
