            </div>
            <div className="space-y-6 pt-6 border-t">
              <select className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={selectedClient} onChange={e => setSelectedClient(e.target.value)}>
                <option value="Publico-Gral">Público General</option>
                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
              <div className="grid grid-cols-2 gap-4">
                <select className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setPaymentMethod(e.target.value as any)}><option>Efectivo</option><option>Transferencia</option></select>
                <select className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setStatus(e.target.value as any)}><option value="Solicitud">Pre-factura</option><option value="Despachado">Venta Final</option></select>
              </div>
              <div className="bg-[#8B5E3C] p-6 rounded-[30px] text-white flex justify-between items-center shadow-xl shadow-[#8B5E3C]/30">
                <div><p className="text-[10px] font-black uppercase opacity-60">Total</p><p className="text-2xl font-black">{totalCup.toLocaleString()} CUP</p></div>
                <button disabled={cart.length === 0} onClick={() => handleCreateSale({ id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient, clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart, totalCup, totalUsd, paymentMethod, status, invoiceNumber: `F-${Date.now().toString().slice(-6)}` })} className="bg-white text-[#8B5E3C] px-8 py-4 rounded-2xl font-black uppercase text-xs">Pagar</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={(id) => setNotifications(n => n.map(x => x.id === id ? {...x, read: true} : x))}>
      {activeTab === 'dashboard' && <Dashboard products={products} transactions={transactions} suppliers={suppliers} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-center">
            <h2 className="text-2xl font-black text-gray-800 uppercase tracking-tight">Catálogo de Productos</h2>
            <button onClick={() => setProductModal({show: true})} className="bg-[#8B5E3C] text-white px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest">+ Nuevo Producto</button>
          </div>
          <div className="bg-white rounded-[40px] shadow-sm border overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-gray-50/50 border-b">
                <tr className="text-[10px] uppercase text-gray-400 font-black tracking-widest">
                  <th className="px-8 py-6">Producto</th>
                  <th className="px-8 py-6">Existencia</th>
                  <th className="px-8 py-6">Precios</th>
                  <th className="px-8 py-6">Origen</th>
                  <th className="px-8 py-6 text-right">Acción</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50/30">
                    <td className="px-8 py-6"><p className="font-black text-sm uppercase">{p.name}</p><p className="text-[9px] font-black text-gray-400">{p.sku}</p></td>
                    <td className="px-8 py-6 font-black text-sm">{p.stock} u.</td>
                    <td className="px-8 py-6 flex flex-wrap gap-2">
                      <span className="px-2 py-1 bg-gray-100 text-[9px] font-black rounded">{p.unitPrice}{p.unitCurrency}</span>
                      {p.groupings.map(g => <span key={g.id} className="px-2 py-1 bg-amber-50 text-[#8B5E3C] text-[9px] font-black rounded">{g.label}: {g.price}</span>)}
                    </td>
                    <td className="px-8 py-6"><span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase ${p.receptionType === 'Consignación' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>{p.receptionType}</span></td>
                    <td className="px-8 py-6 text-right">
                       <div className="flex justify-end gap-2">
                          <button onClick={() => setProductModal({show: true, product: p})} className="p-2 text-[#8B5E3C] hover:bg-amber-50 rounded-xl"><Edit2 size={18} /></button>
                          <button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-2 text-red-400 hover:bg-red-50 rounded-xl"><Trash2 size={18} /></button>
                       </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="bg-white p-20 rounded-[50px] border flex flex-col items-center text-center">
           <ArrowDownCircle size={64} className="text-[#8B5E3C] mb-6" />
           <h2 className="text-3xl font-black uppercase mb-4">Recepción de Mercancía</h2>
           <p className="text-gray-400 mb-10 max-w-sm">Registre nuevas facturas, productos en consignación o compras directas.</p>
           <button onClick={() => setProductModal({show: true})} className="bg-[#8B5E3C] text-white px-12 py-6 rounded-[30px] font-black uppercase text-xs tracking-widest shadow-2xl">Iniciar Recepción</button>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="space-y-8">
           <div className="flex justify-between items-center"><h2 className="text-2xl font-black uppercase">Ventas y Pedidos</h2><button onClick={() => setShowSaleModal(true)} className="bg-[#8B5E3C] text-white px-8 py-4 rounded-3xl font-black uppercase text-xs">+ Nueva Venta</button></div>
           <div className="bg-white rounded-[40px] border overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-gray-50/50 border-b text-[9px] font-black uppercase text-gray-400">
                    <tr className="tracking-widest"><th className="px-8 py-5">Factura</th><th className="px-8 py-5">Cliente</th><th className="px-8 py-5 text-right">Importe</th><th className="px-8 py-5 text-center">Estado</th><th className="px-8 py-5 text-right">Ver</th></tr>
                 </thead>
                 <tbody className="divide-y divide-gray-50 text-xs font-black">
                    {transactions.map(t => (
                       <tr key={t.id} className="hover:bg-gray-50/30">
                          <td className="px-8 py-6">{t.invoiceNumber}</td>
                          <td className="px-8 py-6">{t.clientName}</td>
                          <td className="px-8 py-6 text-right">{t.totalCup.toLocaleString()} CUP</td>
                          <td className="px-8 py-6 text-center"><span className={`px-3 py-1 rounded-full text-[8px] ${t.status === 'Despachado' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{t.status}</span></td>
                          <td className="px-8 py-6 text-right"><button onClick={() => setSelectedInvoice(t)}><FileText size={18}/></button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {activeTab === 'suppliers' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="flex justify-between items-center"><h2 className="text-2xl font-black uppercase">Directorio de Contactos</h2><button onClick={() => setShowContactModal(true)} className="bg-[#8B5E3C] text-white px-8 py-4 rounded-3xl font-black text-[10px] uppercase shadow-xl">+ Nuevo Contacto</button></div>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {contacts.filter(c => contactFilter === 'Todos' || c.type === contactFilter).map(c => (
                <div key={c.id} className="bg-white p-8 rounded-[40px] border shadow-sm flex flex-col justify-between h-[280px]">
                   <div className="flex justify-between mb-4"><div className="w-12 h-12 bg-[#8B5E3C] text-white rounded-2xl flex items-center justify-center font-black text-xl">{c.name.charAt(0)}</div><span className="text-[8px] font-black uppercase px-2 py-1 bg-gray-50 rounded-lg">{c.type}</span></div>
                   <h3 className="font-black text-gray-800 text-sm uppercase mb-4">{c.name}</h3>
                   <p className="text-[10px] font-bold text-gray-400 uppercase flex items-center gap-2 mb-2"><Phone size={12}/> {c.phone}</p>
                   <p className="text-[10px] font-black text-gray-600 uppercase flex items-center gap-2 bg-gray-50 p-3 rounded-xl"><MapPin size={12}/> {c.address}</p>
                </div>
              ))}
           </div>
        </div>
      )}

      {showSaleModal && <SalesModal />}
      {selectedInvoice && <InvoiceView transaction={selectedInvoice} onClose={() => setSelectedInvoice(null)} />}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/70 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-4xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-gray-50/50">
              <h2 className="text-xl font-black uppercase text-gray-800">Ficha de Producto</h2>
              <button onClick={() => setProductModal({show: false})}><X size={24} /></button>
            </div>
            <ProductForm 
              initialData={productModal.product || (productModal.draft as Product)} 
              suppliers={suppliers}
              onAddSupplier={(draft) => {
                setProductModal({...productModal, draft});
                setShowContactModal(true);
              }}
              onSave={(p) => {
                const updatedProduct = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `PT-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? updatedProduct : x));
                else setProducts([...products, updatedProduct]);
                setProductModal({show: false});
              }}
              onCancel={() => setProductModal({show: false})}
            />
          </div>
        </div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/70 z-[160] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-md shadow-2xl p-10">
            <h2 className="text-xl font-black mb-10 uppercase text-[#8B5E3C]">Nuevo Contacto</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              const newId = Math.random().toString(36).substr(2, 9);
              const newContact: Contact = {
                id: newId,
                name: fd.get('name') as string,
                contactName: fd.get('name') as string,
                phone: fd.get('phone') as string,
                email: '',
                address: fd.get('address') as string,
                type: fd.get('type') as any,
                isConsignee: fd.get('isConsignee') === 'on',
                pendingBalanceCup: 0,
                pendingBalanceUsd: 0
              };
              setContacts([...contacts, newContact]);
              // Si estamos en medio de una recepción, actualizar el draft con el nuevo proveedor
              if (productModal.show && newContact.type === 'Proveedor') {
                setProductModal(prev => ({...prev, draft: { ...prev.draft, supplierId: newId }}));
              }
              setShowContactModal(false);
            }} className="space-y-6">
               <input name="name" required placeholder="Nombre Comercial" className="w-full p-4 bg-gray-50 border rounded-2xl" />
               <input name="phone" required placeholder="Teléfono" className="w-full p-4 bg-gray-50 border rounded-2xl" />
               <textarea name="address" required placeholder="Dirección Física" className="w-full p-4 bg-gray-50 border rounded-2xl h-24" />
               <div className="grid grid-cols-2 gap-4">
                  <select name="type" className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs"><option value="Proveedor">Proveedor</option><option value="Cliente">Cliente</option></select>
                  <label className="flex items-center gap-3"><input type="checkbox" name="isConsignee" className="w-6 h-6 accent-[#8B5E3C]" /><span className="text-[10px] font-black uppercase">Consignatario</span></label>
               </div>
               <div className="flex gap-4 pt-4">
                  <button type="button" onClick={() => setShowContactModal(false)} className="flex-1 text-[10px] font-black uppercase text-gray-400">Cerrar</button>
                  <button type="submit" className="flex-1 bg-[#8B5E3C] text-white py-4 rounded-2xl font-black uppercase text-[10px]">Guardar</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React, { useMemo } from 'react';
import { 
  TrendingUp, 
  DollarSign, 
  Package, 
  AlertCircle,
  Clock,
  ArrowUpRight,
  ShieldCheck,
  CreditCard,
  Layers,
  BarChart3
} from 'lucide-react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer,
  Cell,
  AreaChart,
  Area
} from 'recharts';
// Change Supplier to Contact to fix the import error (Supplier is not exported from types.ts)
import { Product, Transaction, Contact } from '../types';

interface DashboardProps {
  products: Product[];
  transactions: Transaction[];
  // Change Supplier to Contact to match the definitions in types.ts
  suppliers: Contact[];
}

const Dashboard: React.FC<DashboardProps> = ({ products, transactions, suppliers }) => {
  const lowStockProducts = products.filter(p => p.stock <= p.minStock);
  const nearingExpiry = products.filter(p => {
    const diff = new Date(p.expiryDate).getTime() - new Date().getTime();
    const days = diff / (1000 * 3600 * 24);
    return days <= 60 && days > 0;
  });

  const totalSalesCup = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((a, b) => a + b.totalCup, 0), [transactions]);
  const totalSalesUsd = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((a, b) => a + b.totalUsd, 0), [transactions]);

  const debtToSuppliersCup = useMemo(() => suppliers.reduce((acc, s) => acc + s.pendingBalanceCup, 0), [suppliers]);
  const debtToSuppliersUsd = useMemo(() => suppliers.reduce((acc, s) => acc + s.pendingBalanceUsd, 0), [suppliers]);

  const stats = [
    { label: 'Ventas Totales CUP', value: totalSalesCup.toLocaleString(), icon: TrendingUp, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { label: 'Ventas Totales USD', value: totalSalesUsd.toLocaleString(), icon: DollarSign, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Stock Crítico', value: lowStockProducts.length, icon: AlertCircle, color: 'text-rose-600', bg: 'bg-rose-50' },
    { label: 'Vencimientos < 60d', value: nearingExpiry.length, icon: Clock, color: 'text-amber-600', bg: 'bg-amber-50' },
  ];

  const chartData = useMemo(() => {
    const days = ['Dom', 'Lun', 'Mar', 'Mie', 'Jue', 'Vie', 'Sab'];
    const data = days.map(d => ({ name: d, ventas: 0 }));
    transactions.forEach(t => {
      const dayIndex = new Date(t.date).getDay();
      data[dayIndex].ventas += t.totalUsd;
    });
    return data;
  }, [transactions]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500 pb-10">
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        {stats.map((stat, idx) => (
          <div key={idx} className="bg-white p-6 rounded-3xl shadow-sm border border-gray-100 flex items-center group hover:shadow-md transition-shadow">
            <div className={`p-4 rounded-2xl ${stat.bg} ${stat.color} mr-4 group-hover:scale-110 transition-transform`}>
              <stat.icon size={24} />
            </div>
            <div>
              <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">{stat.label}</p>
              <p className="text-2xl font-black text-gray-800 tracking-tight">{stat.value}</p>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
            <div className="flex justify-between items-center mb-8">
              <h3 className="text-sm font-black text-gray-800 uppercase tracking-widest flex items-center gap-2">
                <BarChart3 className="text-[#8B5E3C]" size={18} /> Histórico de Ventas (USD)
              </h3>
              <span className="text-xs font-bold text-gray-400 bg-gray-50 px-3 py-1 rounded-full">Semana Actual</span>
            </div>
            <div className="h-72">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorVentas" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#8B5E3C" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#8B5E3C" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f1f1" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 700, fill: '#9ca3af'}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fontSize: 12, fontWeight: 700, fill: '#9ca3af'}} />
                  <Tooltip 
                    cursor={{stroke: '#8B5E3C', strokeWidth: 2}} 
                    contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 25px rgba(0,0,0,0.1)' }} 
                  />
                  <Area type="monotone" dataKey="ventas" stroke="#8B5E3C" strokeWidth={4} fillOpacity={1} fill="url(#colorVentas)" />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
              <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-4">Stock Crítico (Detalle)</h4>
              <div className="space-y-3">
                {lowStockProducts.slice(0, 3).map(p => (
                  <div key={p.id} className="flex justify-between items-center p-3 bg-red-50 rounded-2xl">
                    <span className="text-xs font-bold text-red-800">{p.name}</span>
                    <span className="text-xs font-black text-red-600">{p.stock} u.</span>
                  </div>
                ))}
                {lowStockProducts.length === 0 && <p className="text-xs text-gray-400 italic">No hay alertas de stock.</p>}
              </div>
            </div>
            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
              <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-4">Próximos Vencimientos</h4>
              <div className="space-y-3">
                {nearingExpiry.slice(0, 3).map(p => (
                  <div key={p.id} className="flex justify-between items-center p-3 bg-amber-50 rounded-2xl">
                    <span className="text-xs font-bold text-amber-800">{p.name}</span>
                    <span className="text-[9px] font-black text-amber-600 uppercase">{p.expiryDate}</span>
                  </div>
                ))}
                {nearingExpiry.length === 0 && <p className="text-xs text-gray-400 italic">No hay vencimientos próximos.</p>}
              </div>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-[#8B5E3C] p-8 rounded-[40px] shadow-2xl shadow-[#8B5E3C]/20 text-white relative overflow-hidden flex flex-col justify-between min-h-[350px]">
            <div className="absolute -top-10 -right-10 w-48 h-48 bg-white/10 rounded-full blur-3xl"></div>
            <div>
              <h3 className="text-xs font-black uppercase tracking-widest mb-8 flex items-center gap-2">
                 <ShieldCheck size={18} /> Liquidez y Caja
              </h3>
              <div className="space-y-6">
                <div>
                  <p className="text-[10px] text-white/50 font-bold uppercase tracking-tighter">Disponible CUP</p>
                  <p className="text-4xl font-black tabular-nums">{totalSalesCup.toLocaleString()} <span className="text-sm font-medium opacity-50">CUP</span></p>
                </div>
                <div>
                  <p className="text-[10px] text-white/50 font-bold uppercase tracking-tighter">Disponible USD</p>
                  <p className="text-4xl font-black tabular-nums">{totalSalesUsd.toLocaleString()} <span className="text-sm font-medium opacity-50">USD</span></p>
                </div>
              </div>
            </div>
            <div className="mt-8 pt-6 border-t border-white/10">
               <div className="flex justify-between items-end">
                  <div>
                    <span className="text-[10px] font-bold opacity-50 block uppercase">Flujo semanal</span>
                    <span className="text-xl font-black flex items-center gap-1 text-emerald-400"><ArrowUpRight size={20} /> +18.4%</span>
                  </div>
