const App: React.FC = () => {
  // INICIALIZADORES PEREZOSOS PARA PERSISTENCIA REAL
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage(STORAGE_KEYS.PRODUCTS, []));
  const [contacts, setContacts] = useState<Contact[]>(() => loadFromStorage(STORAGE_KEYS.CONTACTS, []));
  const [transactions, setTransactions] = useState<Transaction[]>(() => loadFromStorage(STORAGE_KEYS.TRANSACTIONS, []));
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [socialContent, setSocialContent] = useState<string>('');
  const [isSocialLoading, setIsSocialLoading] = useState(false);
  const [contactFilter, setContactFilter] = useState<'Todos' | 'Proveedor' | 'Cliente'>('Todos');

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, draft?: Partial<Product>}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  // EFECTOS DE GUARDADO AUTOMÁTICO
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Bajo', message: `${p.name} en nivel crítico`, type: 'warning', date: new Date().toISOString(), read: false });
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / 86400000);
      if (days <= 60 && days > 0) newNotifs.push({ id: `exp-${p.id}`, title: 'Vencimiento Próximo', message: `${p.name} vence en ${days} días`, type: 'error', date: new Date().toISOString(), read: false });
    });
    setNotifications(newNotifs);
  }, [products]);

  const handleCreateSale = (sale: Transaction) => {
    setTransactions([sale, ...transactions]);
    if (sale.status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const soldUnits = sale.items.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
        return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
      }));
    }
    setShowSaleModal(false);
  };

  const suppliers = contacts.filter(c => c.type === 'Proveedor');
  const clients = contacts.filter(c => c.type === 'Cliente');

  // Función de Backup
  const exportData = () => {
    const fullBackup = { products, contacts, transactions, timestamp: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(fullBackup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `backup_pati_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const data = JSON.parse(event.target?.result as string);
          if (data.products && data.contacts && data.transactions) {
            setProducts(data.products);
            setContacts(data.contacts);
            setTransactions(data.transactions);
            alert('Backup restaurado con éxito.');
          }
        } catch (err) {
          alert('Error al leer el archivo de backup.');
        }
      };
      reader.readAsText(file);
    }
  };

  // --- Modal de Ventas (Punto de Venta) ---
  const SalesModal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [selectedClient, setSelectedClient] = useState<string>('Publico-Gral');
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');
    const [status, setStatus] = useState<'Solicitud' | 'Despachado'>('Solicitud');

    const updateCartQty = (id: string, delta: number) => {
      setCart(cart.map(item => {
        if (item.id === id) {
          const newQty = Math.max(1, item.quantity + delta);
          return { ...item, quantity: newQty, total: newQty * item.price };
        }
        return item;
      }));
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
    const totalUsd = cart.filter(i => i.currency === 'USD').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/70 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[40px] w-full max-w-6xl h-[90vh] overflow-hidden flex shadow-2xl">
          <div className="w-1/2 border-r flex flex-col p-8 bg-gray-50/50">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-black uppercase text-[#8B5E3C]">Punto de Venta</h2>
              <button onClick={() => setShowSaleModal(false)} className="p-2"><X /></button>
            </div>
            <input className="w-full p-4 bg-white border rounded-2xl mb-6 outline-none" placeholder="Buscar..." value={search} onChange={e => setSearch(e.target.value)} />
            <div className="flex-1 overflow-y-auto space-y-3">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-5 rounded-3xl border border-gray-100">
                  <div className="flex justify-between items-start mb-4">
                    <div><h4 className="font-black text-xs uppercase">{p.name}</h4><p className="text-[9px] text-gray-400 font-bold uppercase">STOCK: {p.stock} U.</p></div>
                    <button onClick={() => setCart([...cart, { id: Math.random().toString(), productId: p.id, productName: p.name, quantity: 1, price: p.unitPrice, total: p.unitPrice, currency: p.unitCurrency, unitQuantity: 1 }])} className="p-2 bg-[#8B5E3C]/10 text-[#8B5E3C] rounded-xl"><Plus size={18} /></button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {p.groupings.map(g => (
                      <button key={g.id} onClick={() => setCart([...cart, { id: Math.random().toString(), productId: p.id, productName: p.name, groupingId: g.id, groupingLabel: g.label, quantity: 1, price: g.price, total: g.price, currency: g.currency, unitQuantity: g.quantity }])} className="px-3 py-1 bg-amber-50 text-[9px] font-black rounded-lg text-[#8B5E3C]">{g.label} ({g.price}) {g.minOrderQuantity ? `+${g.minOrderQuantity}` : ''}</button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-8 bg-white">
            <h3 className="text-xs font-black uppercase text-gray-400 mb-8">Resumen Pedido</h3>
            <div className="flex-1 overflow-y-auto space-y-4 mb-8">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-4 bg-gray-50 rounded-2xl">
                  <div className="flex-1">
                    <p className="font-black text-xs uppercase">{item.productName}</p>
                    <p className="text-[9px] font-bold text-gray-400 uppercase">{item.groupingLabel || 'Unidad'}</p>
                  </div>
                  <div className="flex items-center gap-4">
                    <div className="flex items-center bg-white rounded-xl border p-1">
                       <button onClick={() => updateCartQty(item.id, -1)} className="p-1 text-gray-400"><Minus size={14}/></button>
                       <span className="w-8 text-center font-black text-xs">{item.quantity}</span>
                       <button onClick={() => updateCartQty(item.id, 1)} className="p-1 text-[#8B5E3C]"><Plus size={14}/></button>
                    </div>
                    <div className="text-right w-24">
                      <p className="font-black text-xs">{item.total.toLocaleString()} {item.currency}</p>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-[9px] text-red-400 font-black uppercase">Borrar</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
            <div className="space-y-6 pt-6 border-t">
              <select className="w-full p-4 bg-gray-50 border rounded-2xl text-xs font-bold" value={selectedClient} onChange={e => setSelectedClient(e.target.value)}>
                <option value="Publico-Gral">Público General</option>
                {clients.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
              <div className="grid grid-cols-2 gap-4">
                <select className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setPaymentMethod(e.target.value as any)}><option>Efectivo</option><option>Transferencia</option></select>
                <select className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs" onChange={e => setStatus(e.target.value as any)}><option value="Solicitud">Pre-factura</option><option value="Despachado">Venta Final</option></select>
              </div>
              <div className="bg-[#8B5E3C] p-6 rounded-[30px] text-white flex justify-between items-center shadow-xl shadow-[#8B5E3C]/30">
                <div><p className="text-[10px] font-black uppercase opacity-60">Total</p><p className="text-2xl font-black">{totalCup.toLocaleString()} CUP</p></div>
                <button disabled={cart.length === 0} onClick={() => handleCreateSale({ id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient, clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart, totalCup, totalUsd, paymentMethod, status, invoiceNumber: `F-${Date.now().toString().slice(-6)}` })} className="bg-white text-[#8B5E3C] px-8 py-4 rounded-2xl font-black uppercase text-xs">Pagar</button>
