                const updatedProduct = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `PT-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? updatedProduct : x));
                else setProducts([...products, updatedProduct]);
                setProductModal({show: false});
              }}
              onCancel={() => setProductModal({show: false})}
            />
          </div>
        </div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/70 z-[160] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-md shadow-2xl p-10">
