              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              const newId = Math.random().toString(36).substr(2, 9);
              const newContact: Contact = {
                id: newId,
                name: fd.get('name') as string,
                contactName: fd.get('name') as string,
                phone: fd.get('phone') as string,
                email: '',
                address: fd.get('address') as string,
                type: fd.get('type') as any,
                isConsignee: fd.get('isConsignee') === 'on',
                pendingBalanceCup: 0,
                pendingBalanceUsd: 0
              };
              setContacts([...contacts, newContact]);
              if (productModal.show && newContact.type === 'Proveedor') {
                setProductModal(prev => ({...prev, draft: { ...prev.draft, supplierId: newId }}));
              }
              setShowContactModal(false);
            }} className="space-y-6">
               <input name="name" required placeholder="Nombre Comercial" className="w-full p-4 bg-gray-50 border rounded-2xl" />
               <input name="phone" required placeholder="Teléfono" className="w-full p-4 bg-gray-50 border rounded-2xl" />
               <textarea name="address" required placeholder="Dirección Física" className="w-full p-4 bg-gray-50 border rounded-2xl h-24" />
               <div className="grid grid-cols-2 gap-4">
                  <select name="type" className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs"><option value="Proveedor">Proveedor</option><option value="Cliente">Cliente</option></select>
                  <label className="flex items-center gap-3"><input type="checkbox" name="isConsignee" className="w-6 h-6 accent-[#8B5E3C]" /><span className="text-[10px] font-black uppercase">Consignatario</span></label>
               </div>
               <div className="flex gap-4 pt-4">
                  <button type="button" onClick={() => setShowContactModal(false)} className="flex-1 text-[10px] font-black uppercase text-gray-400">Cerrar</button>
                  <button type="submit" className="flex-1 bg-[#8B5E3C] text-white py-4 rounded-2xl font-black uppercase text-[10px]">Guardar</button>
               </div>
            </form>
          </div>
        </div>
      )}
    </Layout>
  );
};

