          <p className="text-[9px] text-gray-400 font-bold uppercase">Seleccione "Guardar como PDF" en el destino de impresión</p>
        </div>
      </div>
    </div>
  );
};

const ProductForm = ({ initialData, suppliers, onSave, onCancel, onAddSupplier }: { 
  initialData?: Product, 
  suppliers: Contact[], 
  onSave: (p: Product) => void, 
  onCancel: () => void,
  onAddSupplier: (currentFormData: Partial<Product>) => void
}) => {
  const [formData, setFormData] = useState<Partial<Product>>(initialData || {
    receptionType: 'Consignación',
    unitCurrency: 'CUP',
    groupings: [],
    stock: 0,
    minStock: 0,
    receivedDate: new Date().toISOString().split('T')[0]
  });

  const [tempGrouping, setTempGrouping] = useState<GroupingPrice & { isEditing?: boolean }>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' as Currency, minOrderQuantity: 0 });

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value, type } = e.target;
    const val = type === 'number' ? parseFloat(value) : value;
    setFormData(prev => ({ ...prev, [name]: val }));
  };

  const addOrUpdateGrouping = () => {
    if (tempGrouping.label && tempGrouping.quantity > 0) {
      let updatedGroupings;
      if (tempGrouping.id && formData.groupings?.find(g => g.id === tempGrouping.id)) {
        updatedGroupings = formData.groupings.map(g => g.id === tempGrouping.id ? tempGrouping : g);
      } else {
        updatedGroupings = [...(formData.groupings || []), { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) }];
      }
      setFormData({ ...formData, groupings: updatedGroupings });
      setTempGrouping({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' as Currency, minOrderQuantity: 0 });
    }
  };

  return (
    <div className="p-8 overflow-y-auto space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Nombre del Producto</label>
          <input name="name" value={formData.name || ''} onChange={handleChange} required className="w-full p-4 bg-[#F5F5DC]/10 border rounded-2xl text-sm font-bold" />
        </div>
        <div className="space-y-1">
          <div className="flex justify-between items-center"><label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Proveedor</label><button type="button" onClick={() => onAddSupplier(formData)} className="text-[9px] font-black text-[#AF6E4D] uppercase hover:underline">+ Nuevo</button></div>
          <select name="supplierId" value={formData.supplierId || ''} onChange={handleChange} className="w-full p-4 bg-[#F5F5DC]/10 border rounded-2xl text-sm font-bold">
            <option value="" disabled>Seleccione...</option>
            {suppliers.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Precio Base (Unidad)</label>
          <div className="flex gap-2">
            <input name="unitPrice" type="number" step="0.01" value={formData.unitPrice || ''} onChange={handleChange} required className="flex-1 p-4 bg-[#F5F5DC]/10 border rounded-2xl" />
            <select name="unitCurrency" value={formData.unitCurrency} onChange={handleChange} className="w-24 p-4 bg-gray-50 border rounded-2xl font-bold">
              <option value="CUP">CUP</option>
              <option value="USD">USD</option>
            </select>
          </div>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Existencia Actual / Mínima</label>
          <div className="flex gap-2">
            <input name="stock" type="number" value={formData.stock || ''} onChange={handleChange} required className="flex-1 p-4 bg-[#F5F5DC]/10 border rounded-2xl" />
            <input name="minStock" type="number" value={formData.minStock || ''} onChange={handleChange} required className="flex-1 p-4 bg-[#F5F5DC]/10 border rounded-2xl" />
          </div>
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Fecha Vencimiento</label>
          <input name="expiryDate" type="date" value={formData.expiryDate || ''} onChange={handleChange} required className="w-full p-4 bg-[#F5F5DC]/10 border rounded-2xl" />
        </div>
        <div className="space-y-1">
          <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Tipo de Entrada</label>
          <select name="receptionType" value={formData.receptionType} onChange={handleChange} className="w-full p-4 bg-[#F5F5DC]/10 border rounded-2xl">
            <option value="Consignación">Consignación</option>
            <option value="Compra Directa">Compra Directa</option>
          </select>
        </div>
      </div>

      <div className="border-t border-dashed pt-6 bg-[#FAFAFA] p-6 rounded-[32px]">
        <h3 className="text-[10px] font-black text-[#5D4037] uppercase tracking-widest mb-4">Gestión de Agrupaciones (Cajas, Estuches, Palets)</h3>
        <div className="grid grid-cols-1 md:grid-cols-5 gap-2 mb-4 items-end">
          <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Descripción</label><input placeholder="Ej: Caja x24" className="w-full p-3 bg-white border rounded-xl text-xs" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} /></div>
          <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">U. por Grupo</label><input type="number" className="w-full p-3 bg-white border rounded-xl text-xs" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 0})} /></div>
          <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Precio Grupo</label><input type="number" className="w-full p-3 bg-white border rounded-xl text-xs" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} /></div>
          <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Mín. Venta</label><input type="number" className="w-full p-3 bg-white border rounded-xl text-xs" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value) || 0})} /></div>
          <button type="button" onClick={addOrUpdateGrouping} className="bg-[#AF6E4D] text-white p-3 rounded-xl text-[10px] font-black uppercase h-11">{tempGrouping.id ? 'Actualizar' : 'Añadir'}</button>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {formData.groupings?.map(g => (
            <div key={g.id} className="flex justify-between items-center p-4 bg-white border rounded-2xl shadow-sm border-[#D7CCC8]/30">
              <div>
                <span className="font-black text-[11px] uppercase text-[#5D4037]">{g.label} ({g.quantity}u)</span>
                {g.minOrderQuantity ? <p className="text-[8px] font-black text-[#AF6E4D] uppercase">Mínimo: {g.minOrderQuantity}</p> : null}
              </div>
              <div className="flex items-center gap-3">
                <span className="font-black text-[#8D6E63] text-xs">{g.price} {g.currency}</span>
                <button type="button" onClick={() => setTempGrouping(g)} className="text-gray-400 hover:text-[#AF6E4D]"><Edit2 size={14} /></button>
                <button type="button" onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-300"><Trash2 size={14} /></button>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="flex justify-end gap-3 pt-8 border-t bg-white sticky bottom-0">
        <button onClick={onCancel} className="px-6 py-2 text-gray-400 font-black uppercase text-[10px]">Cerrar</button>
        <button onClick={() => onSave(formData as Product)} className="px-10 py-4 bg-[#5D4037] text-white font-black rounded-2xl uppercase text-[10px] shadow-xl">Guardar Producto</button>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage(STORAGE_KEYS.PRODUCTS, []));
  const [contacts, setContacts] = useState<Contact[]>(() => loadFromStorage(STORAGE_KEYS.CONTACTS, []));
  const [transactions, setTransactions] = useState<Transaction[]>(() => loadFromStorage(STORAGE_KEYS.TRANSACTIONS, []));
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, draft?: Partial<Product>}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);

  useEffect(() => {
    // Al entrar a Recepción, abrir modal directamente
    if (activeTab === 'reception') {
       setProductModal({ show: true });
    }
  }, [activeTab]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Crítico', message: `${p.name} requiere reposición urgente.`, type: 'warning', date: new Date().toISOString(), read: false });
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / 86400000);
      if (days <= 60 && days > 0) newNotifs.push({ id: `exp-${p.id}`, title: 'Vencimiento', message: `${p.name} vence en ${days} días.`, type: 'error', date: new Date().toISOString(), read: false });
    });
    setNotifications(newNotifs);
  }, [products]);

  const handleCreateSale = (sale: Transaction) => {
    setTransactions([sale, ...transactions]);
    if (sale.status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const soldUnits = sale.items.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
        return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
      }));
    }
    setShowSaleModal(false);
  };

  const exportData = () => {
    const fullBackup = { products, contacts, transactions, timestamp: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(fullBackup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `backup_${STORE_NAME.replace(' ', '_')}_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        try {
          const data = JSON.parse(event.target?.result as string);
          if (data.products && data.contacts) {
            setProducts(data.products);
            setContacts(data.contacts);
            setTransactions(data.transactions || []);
            alert('Base de datos restaurada correctamente.');
          }
        } catch (err) { alert('Archivo no válido.'); }
      };
      reader.readAsText(file);
    }
  };

  const SalesModal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [selectedClient, setSelectedClient] = useState<string>('Publico-Gral');
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');
    const [status, setStatus] = useState<'Solicitud' | 'Despachado'>('Solicitud');

    const addToCart = (p: Product, grouping?: GroupingPrice) => {
      const initialQty = grouping?.minOrderQuantity || 1;
      const newItem: SaleItem = {
        id: Math.random().toString(),
        productId: p.id,
        productName: p.name,
        groupingId: grouping?.id,
        groupingLabel: grouping?.label,
        quantity: initialQty,
        price: grouping ? grouping.price : p.unitPrice,
        total: (grouping ? grouping.price : p.unitPrice) * initialQty,
        currency: grouping ? grouping.currency : p.unitCurrency,
        unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
    };

    const updateCartQty = (id: string, delta: number) => {
      setCart(cart.map(item => {
        if (item.id === id) {
          // Si es una agrupación con mínimo, no permitir bajar de ese mínimo
          const minRequired = products.find(p => p.id === item.productId)?.groupings.find(g => g.id === item.groupingId)?.minOrderQuantity || 1;
          const newQty = Math.max(minRequired, item.quantity + delta);
          return { ...item, quantity: newQty, total: newQty * item.price };
        }
        return item;
      }));
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
    const totalUsd = cart.filter(i => i.currency === 'USD').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/70 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[40px] w-full max-w-6xl h-[90vh] overflow-hidden flex shadow-2xl">
          <div className="w-1/2 border-r flex flex-col p-8 bg-[#FAFAFA]">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-black uppercase text-[#5D4037]">Punto de Venta</h2>
              <button onClick={() => setShowSaleModal(false)} className="p-2"><X /></button>
            </div>
            <div className="relative mb-6">
               <Search className="absolute left-4 top-4 text-gray-300" size={18} />
               <input className="w-full pl-12 p-4 bg-white border rounded-2xl outline-none text-sm font-bold" placeholder="Buscar producto..." value={search} onChange={e => setSearch(e.target.value)} />
            </div>
            <div className="flex-1 overflow-y-auto space-y-3 pr-2">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-5 rounded-[32px] border border-[#D7CCC8]/30 hover:border-[#AF6E4D] transition-all group">
                  <div className="flex justify-between items-start mb-4">
                    <div><h4 className="font-black text-xs uppercase text-[#5D4037]">{p.name}</h4><p className="text-[9px] text-[#AF6E4D] font-black uppercase">DISPONIBLE: {p.stock} U.</p></div>
                    <button onClick={() => addToCart(p)} className="p-2 bg-[#5D4037] text-white rounded-xl shadow-md group-hover:scale-110 transition-transform"><Plus size={16} /></button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {p.groupings.map(g => (
                      <button key={g.id} onClick={() => addToCart(p, g)} className="px-4 py-2 bg-[#F5F5DC] text-[9px] font-black rounded-xl text-[#5D4037] hover:bg-[#D7CCC8] transition-colors">
                        {g.label} ({g.price} {g.currency}) {g.minOrderQuantity ? <span className="text-[#AF6E4D] ml-1">MÍN: {g.minOrderQuantity}</span> : ''}
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-8 bg-white">
            <h3 className="text-[10px] font-black uppercase text-gray-400 mb-8 tracking-widest">Resumen de Operación</h3>
            <div className="flex-1 overflow-y-auto space-y-4 mb-8">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-5 bg-[#FAFAFA] rounded-3xl border border-[#D7CCC8]/10">
                  <div className="flex-1">
                    <p className="font-black text-xs uppercase text-[#5D4037]">{item.productName}</p>
                    <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{item.groupingLabel || 'Venta Unitaria'}</p>
                  </div>
                  <div className="flex items-center gap-6">
                    <div className="flex items-center bg-white rounded-2xl border p-1 shadow-sm">
                       <button onClick={() => updateCartQty(item.id, -1)} className="p-2 text-gray-300 hover:text-rose-400"><Minus size={14}/></button>
                       <span className="w-10 text-center font-black text-sm text-[#5D4037]">{item.quantity}</span>
                       <button onClick={() => updateCartQty(item.id, 1)} className="p-2 text-[#5D4037] hover:text-[#AF6E4D]"><Plus size={14}/></button>
                    </div>
                    <div className="text-right w-24">
                      <p className="font-black text-xs text-[#5D4037]">{item.total.toLocaleString()} {item.currency}</p>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-[8px] text-rose-300 font-black uppercase hover:text-rose-500">Eliminar</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
            <div className="space-y-6 pt-6 border-t">
              <div className="grid grid-cols-2 gap-4">
                 <select className="w-full p-4 bg-[#FAFAFA] border rounded-2xl text-xs font-black uppercase" value={selectedClient} onChange={e => setSelectedClient(e.target.value)}>
                    <option value="Publico-Gral">Público General</option>
                    {contacts.filter(c=>c.type==='Cliente').map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                 </select>
                 <select className="p-4 bg-[#FAFAFA] border rounded-2xl font-black text-xs uppercase" onChange={e => setPaymentMethod(e.target.value as any)}>
                    <option>Efectivo</option><option>Transferencia</option>
                 </select>
              </div>
              <select className="w-full p-4 bg-[#F5F5DC] border rounded-2xl font-black text-xs uppercase text-[#5D4037]" onChange={e => setStatus(e.target.value as any)}>
                <option value="Solicitud">Pre-factura / Solicitud</option>
                <option value="Despachado">Venta Final / Despacho</option>
              </select>
              <div className="bg-[#5D4037] p-8 rounded-[40px] text-white flex justify-between items-center shadow-2xl shadow-[#5D4037]/40 border border-white/10">
                <div><p className="text-[10px] font-black uppercase opacity-60 tracking-widest mb-1">Total a Pagar</p><p className="text-3xl font-black tabular-nums">{totalCup.toLocaleString()} <span className="text-sm opacity-50">CUP</span></p></div>
                <button disabled={cart.length === 0} onClick={() => handleCreateSale({ id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient, clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart, totalCup, totalUsd, paymentMethod, status, invoiceNumber: `F-${Date.now().toString().slice(-6)}` })} className="bg-[#AF6E4D] text-white px-10 py-5 rounded-3xl font-black uppercase text-xs shadow-xl active:scale-95 transition-transform">Finalizar</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={(id) => setNotifications(n => n.map(x => x.id === id ? {...x, read: true} : x))}>
      {activeTab === 'dashboard' && <Dashboard products={products} transactions={transactions} suppliers={contacts.filter(c=>c.type==='Proveedor')} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-center">
            <h2 className="text-2xl font-black text-[#5D4037] uppercase tracking-tight">Inventario de Mercancía</h2>
            <button onClick={() => setProductModal({show: true})} className="bg-[#5D4037] text-white px-8 py-5 rounded-[24px] font-black text-[11px] uppercase tracking-widest shadow-xl">+ Nuevo Producto</button>
          </div>
          <div className="bg-white rounded-[40px] shadow-sm border border-[#D7CCC8]/20 overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/30 border-b">
                <tr className="text-[10px] uppercase text-gray-400 font-black tracking-widest">
                  <th className="px-8 py-6">Ficha Producto</th>
                  <th className="px-8 py-6">Stock</th>
                  <th className="px-8 py-6">Agrupaciones Activas</th>
                  <th className="px-8 py-6">Gestión</th>
                  <th className="px-8 py-6 text-right">Acciones</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50 text-[#5D4037]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-gray-50/50">
                    <td className="px-8 py-6"><p className="font-black text-sm uppercase">{p.name}</p><p className="text-[9px] font-black text-gray-300">ID: {p.sku}</p></td>
                    <td className="px-8 py-6">
                       <span className={`text-sm font-black ${p.stock <= p.minStock ? 'text-rose-500' : ''}`}>{p.stock} u.</span>
                       <p className="text-[9px] text-gray-300 font-bold uppercase">MÍN: {p.minStock}</p>
                    </td>
                    <td className="px-8 py-6 flex flex-wrap gap-2">
                      <span className="px-3 py-1 bg-[#FAFAFA] text-[9px] font-black rounded-lg border border-[#D7CCC8]/30">UNID: {p.unitPrice}</span>
                      {p.groupings.map(g => <span key={g.id} className="px-3 py-1 bg-[#F5F5DC] text-[#5D4037] text-[9px] font-black rounded-lg border border-[#D7CCC8]/50">{g.label}: {g.price}</span>)}
                    </td>
                    <td className="px-8 py-6"><span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase ${p.receptionType === 'Consignación' ? 'bg-[#AF6E4D]/10 text-[#AF6E4D]' : 'bg-[#5D4037]/10 text-[#5D4037]'}`}>{p.receptionType}</span></td>
                    <td className="px-8 py-6 text-right">
                       <div className="flex justify-end gap-3">
                          <button onClick={() => setProductModal({show: true, product: p})} className="p-3 bg-[#F5F5DC] text-[#5D4037] rounded-2xl hover:bg-[#D7CCC8] transition-colors"><Edit2 size={16} /></button>
                          <button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-3 bg-rose-50 text-rose-300 rounded-2xl hover:bg-rose-100 transition-colors"><Trash2 size={16} /></button>
                       </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="space-y-8">
           <div className="flex justify-between items-center"><h2 className="text-2xl font-black uppercase text-[#5D4037]">Ventas y Facturación</h2><button onClick={() => setShowSaleModal(true)} className="bg-[#5D4037] text-white px-8 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl">+ Crear Venta</button></div>
           <div className="bg-white rounded-[40px] border border-[#D7CCC8]/20 overflow-hidden">
              <table className="w-full text-left">
                 <thead className="bg-[#F5F5DC]/30 border-b text-[10px] font-black uppercase text-gray-400">
                    <tr className="tracking-widest"><th className="px-8 py-6">Folio</th><th className="px-8 py-6">Cliente</th><th className="px-8 py-6 text-right">Monto (CUP)</th><th className="px-8 py-6 text-center">Estado</th><th className="px-8 py-6 text-right">Doc</th></tr>
                 </thead>
                 <tbody className="divide-y divide-gray-50 text-xs font-black text-[#5D4037]">
                    {transactions.map(t => (
                       <tr key={t.id} className="hover:bg-gray-50/50">
                          <td className="px-8 py-7">{t.invoiceNumber}</td>
                          <td className="px-8 py-7 uppercase">{t.clientName}</td>
                          <td className="px-8 py-7 text-right tabular-nums">{t.totalCup.toLocaleString()}</td>
                          <td className="px-8 py-7 text-center"><span className={`px-4 py-1.5 rounded-full text-[9px] ${t.status === 'Despachado' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>{t.status}</span></td>
                          <td className="px-8 py-7 text-right"><button onClick={() => setSelectedInvoice(t)} className="p-3 bg-gray-50 rounded-2xl text-[#AF6E4D]"><FileText size={18}/></button></td>
