      )}

      {activeTab === 'maintenance' && (
        <div className="flex flex-col items-center justify-center py-24 bg-white rounded-[50px] border border-[#D7CCC8]/20 shadow-sm">
           <Database size={72} className="text-[#5D4037] mb-8" />
           <h2 className="text-3xl font-black uppercase mb-4 text-[#5D4037]">Mantenimiento de Datos</h2>
           <p className="text-gray-400 mb-12 max-w-md text-center text-sm font-medium">Gestione copias de seguridad de {STORE_NAME}. Puede exportar su inventario, clientes y ventas a un archivo para restaurarlos en otro dispositivo.</p>
           <div className="flex flex-col sm:flex-row gap-5">
              <button onClick={exportData} className="bg-[#5D4037] text-white px-12 py-6 rounded-[30px] font-black uppercase text-xs flex items-center gap-3 shadow-2xl shadow-[#5D4037]/30 hover:scale-105 transition-transform"><Download size={20}/> Exportar Backup</button>
              <label className="bg-[#F5F5DC] text-[#5D4037] px-12 py-6 rounded-[30px] font-black uppercase text-xs flex items-center gap-3 cursor-pointer hover:bg-[#D7CCC8] transition-colors border border-[#D7CCC8]"><Upload size={20}/> Importar Backup <input type="file" className="hidden" accept=".json" onChange={importData} /></label>
           </div>
        </div>
      )}

      {showSaleModal && <SalesModal />}
      {selectedInvoice && <InvoiceView transaction={selectedInvoice} onClose={() => setSelectedInvoice(null)} />}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/70 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-4xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="p-8 border-b flex justify-between items-center bg-[#F5F5DC]/20">
              <h2 className="text-xl font-black uppercase text-[#5D4037]">Ficha Técnica de Mercancía</h2>
              <button onClick={() => { setProductModal({show: false}); setActiveTab('inventory'); }}><X size={24} /></button>
            </div>
            <ProductForm 
              initialData={productModal.product || (productModal.draft as Product)} 
              suppliers={contacts.filter(c=>c.type==='Proveedor')}
              onAddSupplier={(draft) => { setProductModal({...productModal, draft}); setShowContactModal(true); }}
              onSave={(p) => {
                const updatedProduct = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `PT-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? updatedProduct : x));
                else setProducts([...products, updatedProduct]);
                setProductModal({show: false});
                setActiveTab('inventory');
              }}
              onCancel={() => { setProductModal({show: false}); setActiveTab('inventory'); }}
            />
          </div>
        </div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/70 z-[160] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[40px] w-full max-w-md shadow-2xl p-10">
            <h2 className="text-xl font-black mb-10 uppercase text-[#5D4037]">Registro de Contacto</h2>
            <form onSubmit={(e) => {
              e.preventDefault();
              const fd = new FormData(e.currentTarget);
              const newId = Math.random().toString(36).substr(2, 9);
              const newContact: Contact = { id: newId, name: fd.get('name') as string, contactName: fd.get('name') as string, phone: fd.get('phone') as string, email: '', address: fd.get('address') as string, type: fd.get('type') as any, isConsignee: fd.get('isConsignee') === 'on', pendingBalanceCup: 0, pendingBalanceUsd: 0 };
              setContacts([...contacts, newContact]);
              if (productModal.show && newContact.type === 'Proveedor') { setProductModal(prev => ({...prev, draft: { ...prev.draft, supplierId: newId }})); }
              setShowContactModal(false);
            }} className="space-y-6">
               <input name="name" required placeholder="Nombre o Razón Social" className="w-full p-4 bg-gray-50 border rounded-2xl" />
               <input name="phone" required placeholder="Teléfono de Contacto" className="w-full p-4 bg-gray-50 border rounded-2xl" />
               <textarea name="address" required placeholder="Dirección de Entrega / Fiscal" className="w-full p-4 bg-gray-50 border rounded-2xl h-24" />
               <div className="grid grid-cols-2 gap-4">
                  <select name="type" className="p-4 bg-gray-50 border rounded-2xl font-bold text-xs uppercase"><option value="Proveedor">Proveedor</option><option value="Cliente">Cliente</option></select>
                  <label className="flex items-center gap-3"><input type="checkbox" name="isConsignee" className="w-6 h-6 accent-[#5D4037]" /><span className="text-[10px] font-black uppercase text-gray-400">Consigna</span></label>
               </div>
               <div className="flex gap-4 pt-4">
                  <button type="button" onClick={() => setShowContactModal(false)} className="flex-1 text-[10px] font-black uppercase text-gray-300">Cancelar</button>
                  <button type="submit" className="flex-1 bg-[#5D4037] text-white py-4 rounded-2xl font-black uppercase text-[10px]">Guardar</button>
               </div>
            </form>
          </div>
        </div>
      )}

      {/* Proveedores y Clientes Tab */}
      {activeTab === 'suppliers' && (
        <div className="space-y-8">
           <div className="flex justify-between items-center"><h2 className="text-2xl font-black uppercase text-[#5D4037]">Cartera de Contactos</h2><button onClick={() => setShowContactModal(true)} className="bg-[#5D4037] text-white px-8 py-5 rounded-[24px] font-black text-[10px] uppercase shadow-xl">+ Nuevo</button></div>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {contacts.map(c => (
                <div key={c.id} className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-sm flex flex-col justify-between h-[280px] hover:shadow-md transition-shadow">
                   <div className="flex justify-between mb-4"><div className="w-12 h-12 bg-[#5D4037] text-white rounded-2xl flex items-center justify-center font-black text-xl">{c.name.charAt(0)}</div><span className="text-[9px] font-black uppercase px-3 py-1 bg-[#F5F5DC] text-[#5D4037] rounded-lg border border-[#D7CCC8]/50">{c.type}</span></div>
                   <h3 className="font-black text-[#5D4037] text-sm uppercase mb-4">{c.name}</h3>
                   <div className="space-y-3">
                      <p className="text-[10px] font-bold text-gray-400 uppercase flex items-center gap-2"><Phone size={14} className="text-[#AF6E4D]"/> {c.phone}</p>
                      <p className="text-[10px] font-black text-[#8D6E63] uppercase flex items-center gap-2 bg-[#FAFAFA] p-3 rounded-2xl border border-[#D7CCC8]/10"><MapPin size={14} className="text-[#AF6E4D]"/> {c.address}</p>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

