export const STORE_NAME = "Mercado PaTí";

export const CATEGORIES = [
  { id: '1', name: 'Alimentos' },
  { id: '2', name: 'Bebidas' },
  { id: '3', name: 'Hogar' },
  { id: '4', name: 'Aseo' },
  { id: '5', name: 'Otros' },
];

export const COLORS = {
  primary: '#5D4037',    // Marrón Oscuro
  secondary: '#8D6E63',  // Carmelita
  caramel: '#AF6E4D',    // Caramelo
  beige: '#F5F5DC',      // Beige
  accent: '#D7CCC8',     // Beige Claro
  background: '#FAFAFA', // Blanco Nube
};

import React, { useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  PieChart, Pie, Cell, LineChart, Line, Legend
} from 'recharts';
import { 
  TrendingUp, Package, AlertTriangle, 
  DollarSign, PieChart as PieIcon, 
  ArrowDownRight, ShoppingCart, Calendar,
  Briefcase, Receipt
} from 'lucide-react';
import { Product, Transaction, Contact, Currency } from '../types';
import { COLORS, CATEGORIES } from '../constants';

interface StatisticsProps {
  products: Product[];
  transactions: Transaction[];
  contacts: Contact[];
}

const Statistics: React.FC<StatisticsProps> = ({ products, transactions, contacts }) => {
  // 1. Rentabilidad y Liquidez
  const totalSalesCup = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((acc, t) => acc + t.totalCup, 0), [transactions]);
  const totalSalesUsd = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((acc, t) => acc + t.totalUsd, 0), [transactions]);

  // 2. Inventario de Lento Movimiento (Sin ventas en los últimos 30 días y con stock)
  const slowMovingProducts = useMemo(() => {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    return products.filter(p => {
      const hasSales = transactions.some(t => 
        t.status === 'Despachado' && 
        new Date(t.date) > thirtyDaysAgo && 
        t.items.some(i => i.productId === p.id)
      );
      return !hasSales && p.stock > 0;
    }).slice(0, 5);
  }, [products, transactions]);

  // 3. Ventas por Categoría
  const salesByCategory = useMemo(() => {
    const data: Record<string, number> = {};
    transactions.filter(t => t.status === 'Despachado').forEach(t => {
      t.items.forEach(item => {
        const product = products.find(p => p.id === item.productId);
        const catName = CATEGORIES.find(c => c.id === product?.categoryId)?.name || 'Sin Categoría';
        data[catName] = (data[catName] || 0) + item.total;
      });
    });
    return Object.entries(data).map(([name, value]) => ({ name, value }));
  }, [transactions, products]);

  // 4. Próximos a Vencer (Reporte Detallado)
  const expiryReport = useMemo(() => {
    return products
      .filter(p => {
        const diff = new Date(p.expiryDate).getTime() - new Date().getTime();
        return (diff / (1000 * 3600 * 24)) <= 60;
      })
      .sort((a, b) => new Date(a.expiryDate).getTime() - new Date(b.expiryDate).getTime());
  }, [products]);

  // 5. Deuda a Proveedores (Consignatarios vs Directos)
  const supplierDebts = useMemo(() => {
    const consignmentDebt = contacts.filter(c => c.type === 'Proveedor' && c.isConsignee).reduce((acc, c) => acc + c.pendingBalanceCup, 0);
    const directDebt = contacts.filter(c => c.type === 'Proveedor' && !c.isConsignee).reduce((acc, c) => acc + c.pendingBalanceCup, 0);
    return [
      { name: 'Consignación', value: consignmentDebt, color: COLORS.caramel },
      { name: 'Compra Directa', value: directDebt, color: COLORS.primary }
    ];
  }, [contacts]);

  return (
    <div className="space-y-8 animate-in fade-in duration-700 pb-16">
      {/* Resumen de KPIs Financieros */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-sm">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-emerald-50 text-emerald-600 rounded-2xl"><TrendingUp size={24}/></div>
            <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Ventas Totales CUP</h4>
          </div>
          <p className="text-3xl font-black text-[#5D4037]">{totalSalesCup.toLocaleString()} <span className="text-sm font-bold opacity-30">CUP</span></p>
          <div className="mt-4 flex items-center text-[10px] font-black text-emerald-500 gap-1">
            <ArrowDownRight size={14} className="rotate-180" /> +12% vs mes anterior
          </div>
        </div>

        <div className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-sm">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-[#5D4037]/10 text-[#5D4037] rounded-2xl"><DollarSign size={24}/></div>
            <h4 className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Ventas Totales USD</h4>
          </div>
          <p className="text-3xl font-black text-[#5D4037]">{totalSalesUsd.toLocaleString()} <span className="text-sm font-bold opacity-30">USD</span></p>
          <div className="mt-4 flex items-center text-[10px] font-black text-[#AF6E4D] gap-1">
             <Calendar size={14} /> Ciclo de 30 días
          </div>
        </div>

        <div className="bg-[#5D4037] p-8 rounded-[40px] shadow-2xl text-white">
          <div className="flex items-center gap-4 mb-4">
            <div className="p-3 bg-white/10 text-white rounded-2xl"><Receipt size={24}/></div>
            <h4 className="text-[10px] font-black uppercase text-white/40 tracking-widest">Rentabilidad Estimada</h4>
          </div>
          <p className="text-3xl font-black">{(totalSalesCup * 0.25).toLocaleString()} <span className="text-sm font-bold opacity-30">CUP</span></p>
          <p className="text-[9px] mt-4 font-black uppercase tracking-tighter text-[#AF6E4D]">Cálculo basado en margen operativo del 25%</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Gráfico de Ventas por Categoría */}
        <div className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-sm">
          <h3 className="text-xs font-black text-[#5D4037] uppercase tracking-widest mb-8 flex items-center gap-2">
            <PieIcon size={18} className="text-[#AF6E4D]" /> Ventas por Categoría (CUP)
          </h3>
          <div className="h-72">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesByCategory} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f0f0f0" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 900, fill: '#8D6E63'}} width={100} />
                <Tooltip cursor={{fill: '#fcfcfc'}} contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.05)'}} />
                <Bar dataKey="value" fill={COLORS.caramel} radius={[0, 10, 10, 0]} barSize={20} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Productos de Lento Movimiento */}
        <div className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-sm">
          <div className="flex justify-between items-center mb-8">
            <h3 className="text-xs font-black text-[#5D4037] uppercase tracking-widest flex items-center gap-2">
              <Package size={18} className="text-[#AF6E4D]" /> Lento Movimiento (Ofertas Sugeridas)
            </h3>
            <span className="text-[9px] font-black bg-rose-50 text-rose-500 px-3 py-1 rounded-full uppercase">Acción Requerida</span>
          </div>
          <div className="space-y-4">
            {slowMovingProducts.map(p => (
              <div key={p.id} className="flex justify-between items-center p-4 bg-[#FAFAFA] rounded-2xl border border-[#D7CCC8]/10 hover:border-[#AF6E4D] transition-colors group">
                <div>
                  <p className="text-[11px] font-black text-[#5D4037] uppercase">{p.name}</p>
                  <p className="text-[9px] text-gray-400 font-bold uppercase">STOCK: {p.stock} U. • SIN VENTAS 30D</p>
                </div>
                <button className="text-[9px] font-black text-[#AF6E4D] uppercase tracking-widest border border-[#AF6E4D]/20 px-3 py-1 rounded-lg group-hover:bg-[#AF6E4D] group-hover:text-white transition-all">Crear Oferta</button>
              </div>
            ))}
            {slowMovingProducts.length === 0 && <p className="text-center py-10 text-[10px] font-black text-gray-300 uppercase tracking-widest">Todo el inventario fluye correctamente</p>}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Reporte de Vencimientos */}
        <div className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-sm">
          <h3 className="text-xs font-black text-[#5D4037] uppercase tracking-widest mb-8 flex items-center gap-2">
            <AlertTriangle size={18} className="text-rose-400" /> Próximos Vencimientos (60 días)
          </h3>
          <div className="overflow-x-auto">
            <table className="w-full text-left">
              <thead>
                <tr className="text-[9px] font-black text-gray-400 uppercase tracking-widest border-b">
                  <th className="pb-4">Producto</th>
                  <th className="pb-4">Fecha</th>
                  <th className="pb-4 text-right">Días Restantes</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-50">
                {expiryReport.map(p => {
                   const diff = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / 86400000);
                   return (
                    <tr key={p.id} className="text-[10px] font-black text-[#5D4037]">
                      <td className="py-4 uppercase">{p.name}</td>
                      <td className="py-4">{p.expiryDate}</td>
                      <td className="py-4 text-right">
                        <span className={`px-2 py-1 rounded-lg ${diff < 15 ? 'bg-rose-50 text-rose-500' : 'bg-amber-50 text-amber-600'}`}>
                          {diff} Días
                        </span>
                      </td>
                    </tr>
                   );
                })}
              </tbody>
            </table>
          </div>
        </div>

        {/* Distribución de Pasivos (Deuda a Proveedores) */}
        <div className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-sm">
          <h3 className="text-xs font-black text-[#5D4037] uppercase tracking-widest mb-8 flex items-center gap-2">
            <Briefcase size={18} className="text-[#AF6E4D]" /> Distribución de Pasivos (Proveedores)
          </h3>
          <div className="h-64 flex items-center">
            <div className="flex-1 h-full">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={supplierDebts}
                    innerRadius={60}
                    outerRadius={80}
                    paddingAngle={5}
                    dataKey="value"
                  >
                    {supplierDebts.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="flex-1 space-y-4">
              {supplierDebts.map((entry, idx) => (
                <div key={idx} className="flex items-center gap-3">
                  <div className="w-3 h-3 rounded-full" style={{backgroundColor: entry.color}}></div>
                  <div>
                    <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest">{entry.name}</p>
                    <p className="text-sm font-black text-[#5D4037]">{entry.value.toLocaleString()} CUP</p>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Statistics;

