              <tr className="border-b-2 border-gray-100 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                <th className="py-4 text-left">Descripción</th>
                <th className="py-4 text-center">Cant</th>
                <th className="py-4 text-right">Precio</th>
                <th className="py-4 text-right">Total</th>
