              {transaction.totalCup > 0 && <p className="text-xl font-black text-gray-800">{transaction.totalCup.toLocaleString()} CUP</p>}
              {transaction.totalUsd > 0 && <p className="text-lg font-black text-gray-800">{transaction.totalUsd.toLocaleString()} USD</p>}
