                      <p className="text-[10px] font-black text-[#8D6E63] uppercase flex items-center gap-2 bg-[#FAFAFA] p-3 rounded-2xl border border-[#D7CCC8]/10"><MapPin size={14} className="text-[#AF6E4D]"/> {c.address}</p>
