      setCart([...cart, newItem]);
    };

    const updateCartQty = (id: string, delta: number) => {
      setCart(cart.map(item => {
        if (item.id === id) {
          const minRequired = products.find(p => p.id === item.productId)?.groupings.find(g => g.id === item.groupingId)?.minOrderQuantity || 1;
          const newQty = Math.max(minRequired, item.quantity + delta);
          return { ...item, quantity: newQty, total: newQty * item.price };
        }
        return item;
      }));
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
