                    <div><h4 className="font-black text-[13px] uppercase text-[#3E2723] tracking-tighter">{p.name}</h4><p className="text-[9px] text-[#AF6E4D] font-black uppercase mt-1">Existencia: {p.stock} U.</p></div>
                    <button onClick={() => addToCart(p)} className="p-3 bg-[#3E2723] text-white rounded-2xl shadow-lg active:scale-95 transition-all"><Plus size={18} /></button>
