import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, ReceptionType, SaleItem 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, Share2, 
  UserPlus, ShoppingBag, X, ArrowDownCircle,
  Printer, FileText, CheckCircle2,
  MapPin, Phone, Minus, Download, Upload, Save, Database,
  ArrowRight, Heart, Star, Facebook, Instagram, Mail, Info,
  Wallet, ShoppingCart, Truck, Calendar, Tag, Layers
} from 'lucide-react';
import { generateSocialMediaPost } from './services/geminiService';
import { LOGO_URL, STORE_NAME, COLORS, CATEGORIES } from './constants';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions'
};

const loadFromStorage = <T,>(key: string, defaultValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage(STORAGE_KEYS.PRODUCTS, []));
  const [contacts, setContacts] = useState<Contact[]>(() => loadFromStorage(STORAGE_KEYS.CONTACTS, []));
  const [transactions, setTransactions] = useState<Transaction[]>(() => loadFromStorage(STORAGE_KEYS.TRANSACTIONS, []));
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, draft?: Partial<Product>}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  const exportData = () => {
    const data = { products, contacts, transactions };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        alert('Base de datos restaurada.');
      } catch (err) { alert('Error al importar.'); }
    };
    reader.readAsText(file);
  };

  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);

  useEffect(() => {
    if (activeTab === 'reception') { setProductModal({ show: true }); }
  }, [activeTab]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `${p.name} necesita reposición.`, type: 'warning', date: new Date().toISOString(), read: false });
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / 86400000);
      if (days <= 60 && days > 0) newNotifs.push({ id: `exp-${p.id}`, title: 'Próximo a Vencer', message: `${p.name} vence en ${days} días.`, type: 'error', date: new Date().toISOString(), read: false });
    });
    setNotifications(newNotifs);
  }, [products]);

  // --- Formulario de Producto (Recepción FULL) ---
  const ProductForm = ({ initialData, suppliers, onSave, onCancel, onAddSupplier }: { 
    initialData?: Product, 
    suppliers: Contact[], 
    onSave: (p: Product) => void, 
    onCancel: () => void,
    onAddSupplier: (currentFormData: Partial<Product>) => void
  }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      receptionType: 'Consignación',
      unitCurrency: 'CUP',
      groupings: [],
      stock: 0,
      minStock: 0,
      receivedDate: new Date().toISOString().split('T')[0],
      categoryId: '1'
    });

    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP', minOrderQuantity: 0 });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
      const { name, value, type } = e.target;
      const val = type === 'number' ? parseFloat(value) : value;
      setFormData(prev => ({ ...prev, [name]: val }));
    };

    const addGrouping = () => {
      if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
      const newGrouping = { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) };
      setFormData({ ...formData, groupings: [...(formData.groupings || []), newGrouping] });
      setTempGrouping({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP', minOrderQuantity: 0 });
    };

    return (
      <div className="p-10 overflow-y-auto space-y-10 custom-scrollbar">
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Nombre del Producto</label>
            <input name="name" value={formData.name || ''} onChange={handleChange} required className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm outline-none focus:ring-2 focus:ring-[#AF6E4D]/20" />
          </div>
          <div className="space-y-2">
