            <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Precio Unitario</label>
            <div className="flex gap-3">
              <input name="unitPrice" type="number" step="0.01" value={formData.unitPrice || ''} onChange={handleChange} required className="flex-1 p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold" />
              <select name="unitCurrency" value={formData.unitCurrency} onChange={handleChange} className="w-24 p-5 bg-[#F5F5DC] border border-[#D7CCC8]/30 rounded-[24px] font-bold text-xs">
