            <div className="space-y-2"><label className="text-[8px] font-black uppercase text-gray-400">Cant. Unid</label><input type="number" className="w-full p-4 bg-white border rounded-2xl text-xs font-bold" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 0})} /></div>
