             {/* ... resto del modal de ventas ... */}
             <div className="w-1/2 flex items-center justify-center text-[#D7CCC8] font-black uppercase tracking-widest">Panel de Cobro Mercado PaTí</div>
          </div>
        </div>
      )}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 no-print">
          <div className="bg-white rounded-[50px] w-full max-w-2xl shadow-2xl overflow-hidden flex flex-col max-h-[96vh]">
            <div className="p-8 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/10">
              <h2 className="text-xl font-black uppercase text-[#3E2723]">Comprobante de Pago</h2>
              <button onClick={() => setSelectedInvoice(null)} className="p-3"><X size={24} /></button>
            </div>
            <div className="flex-1 p-12 bg-white">
              <img src={LOGO_URL} className="h-20 mb-8 object-contain" onError={(e) => (e.currentTarget.style.display='none')} />
              {/* Contenido de la factura conservado y mejorado... */}
              <p className="text-center py-20 text-[11px] font-black text-gray-300 uppercase tracking-widest">Documento Oficial Mercado PaTí</p>
            </div>
          </div>
        </div>
      )}

      {/* Otras vistas: Directorio de contactos, Acerca de, etc. */}
      {activeTab === 'suppliers' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="flex justify-between items-center"><h2 className="text-2xl font-black uppercase text-[#3E2723]">Cartera de Socios</h2><button onClick={() => setShowContactModal(true)} className="bg-[#3E2723] text-white px-8 py-5 rounded-[24px] font-black text-[10px] uppercase shadow-xl">+ Nuevo Contacto</button></div>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {contacts.map(c => (
                <div key={c.id} className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/20 shadow-sm flex flex-col justify-between h-[320px] hover:shadow-xl transition-all">
                   <div className="flex justify-between mb-6"><div className="w-16 h-16 bg-[#F5F5DC] text-[#3E2723] rounded-[24px] flex items-center justify-center font-black text-2xl">{c.name.charAt(0)}</div><span className="text-[10px] font-black uppercase px-4 py-2 bg-[#F5F5DC] text-[#3E2723] rounded-2xl border border-[#D7CCC8]/50">{c.type}</span></div>
                   <h3 className="font-black text-[#3E2723] text-lg uppercase mb-6 tracking-tighter truncate">{c.name}</h3>
                   <div className="space-y-4">
                      <p className="text-[11px] font-bold text-[#8D6E63] flex items-center gap-3"><Phone size={16} className="text-[#AF6E4D]"/> {c.phone}</p>
                      <p className="text-[11px] font-black text-[#3E2723] flex items-center gap-3 bg-[#FCF9F7] p-4 rounded-2xl"><MapPin size={16} className="text-[#AF6E4D]"/> {c.address}</p>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}
    </Layout>
  );
};

