import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, ReceptionType, SaleItem 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, Share2, 
  UserPlus, ShoppingBag, X, ArrowDownCircle,
  Printer, FileText, CheckCircle2,
  MapPin, Phone, Minus, Download, Upload, Save, Database,
  ArrowRight, Heart, Star, Facebook, Instagram, Mail, Info,
  Wallet, ShoppingCart, Truck, Calendar, Tag, Layers, Package
} from 'lucide-react';
import { generateSocialMediaPost } from './services/geminiService';
import { LOGO_URL, STORE_NAME, COLORS, CATEGORIES } from './constants';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions'
};

const loadFromStorage = <T,>(key: string, defaultValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage(STORAGE_KEYS.PRODUCTS, []));
  const [contacts, setContacts] = useState<Contact[]>(() => loadFromStorage(STORAGE_KEYS.CONTACTS, []));
  const [transactions, setTransactions] = useState<Transaction[]>(() => loadFromStorage(STORAGE_KEYS.TRANSACTIONS, []));
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, draft?: Partial<Product>}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  // Persistencia
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);

  // Gestión de Notificaciones
  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `${p.name} necesita reposición urgente (${p.stock} u).`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / 86400000);
      if (days <= 60 && days > 0) {
        newNotifs.push({ id: `exp-${p.id}`, title: 'Próximo a Vencer', message: `${p.name} vence en ${days} días.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // Exportar / Importar
  const exportData = () => {
    const data = { products, contacts, transactions, timestamp: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const importData = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        alert('Restauración completa exitosa.');
      } catch (err) { alert('Error en el archivo de respaldo.'); }
    };
    reader.readAsText(file);
  };

  // --- COMPONENTE: FORMULARIO DE PRODUCTO (RECEPCIÓN FULL) ---
  const ProductForm = ({ initialData, suppliers, onSave, onCancel, onAddSupplier }: { 
    initialData?: Product, 
    suppliers: Contact[], 
    onSave: (p: Product) => void, 
    onCancel: () => void,
    onAddSupplier: (currentFormData: Partial<Product>) => void
  }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      receptionType: 'Consignación',
      unitCurrency: 'CUP',
      groupings: [],
      stock: 0,
      minStock: 0,
      receivedDate: new Date().toISOString().split('T')[0],
      categoryId: '1'
    });

    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP', minOrderQuantity: 0 });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
      const { name, value, type } = e.target;
      const val = type === 'number' ? parseFloat(value) : value;
      setFormData(prev => ({ ...prev, [name]: val }));
    };

    const addGrouping = () => {
      if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
      const newGrouping = { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) };
      setFormData({ ...formData, groupings: [...(formData.groupings || []), newGrouping] });
      setTempGrouping({ id: '', label: '', quantity: 0, price: 0, currency: (formData.unitCurrency as Currency) || 'CUP', minOrderQuantity: 0 });
    };

    const removeGrouping = (id: string) => {
      setFormData({ ...formData, groupings: (formData.groupings || []).filter(g => g.id !== id) });
    };

    return (
      <div className="flex flex-col h-full">
        <div className="flex-1 overflow-y-auto p-10 space-y-10 custom-scrollbar">
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Nombre Comercial</label>
              <input name="name" value={formData.name || ''} onChange={handleChange} required className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm outline-none focus:border-[#AF6E4D] transition-colors" placeholder="Ej: Café Serrano 250g" />
            </div>
            <div className="space-y-2">
              <div className="flex justify-between items-center">
                <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Proveedor</label>
                <button type="button" onClick={() => onAddSupplier(formData)} className="text-[9px] font-black text-[#3E2723] uppercase hover:underline">+ Nuevo Socio</button>
              </div>
              <select name="supplierId" value={formData.supplierId || ''} onChange={handleChange} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm">
                <option value="">Seleccione Proveedor...</option>
                {suppliers.map(s => <option key={s.id} value={s.id}>{s.name} {s.isConsignee ? '(Consignación)' : ''}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Categoría</label>
              <select name="categoryId" value={formData.categoryId || '1'} onChange={handleChange} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm">
                {CATEGORIES.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Precio por Unidad (Venta)</label>
              <div className="flex gap-3">
                <input name="unitPrice" type="number" step="0.01" value={formData.unitPrice || ''} onChange={handleChange} required className="flex-1 p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm" />
                <select name="unitCurrency" value={formData.unitCurrency} onChange={handleChange} className="w-24 p-5 bg-[#F5F5DC] border border-[#D7CCC8]/30 rounded-[24px] font-bold text-xs">
                  <option value="CUP">CUP</option>
                  <option value="USD">USD</option>
                </select>
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Existencia Total (U)</label>
              <input name="stock" type="number" value={formData.stock || ''} onChange={handleChange} required className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm" placeholder="0" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Mínimo en Almacén</label>
              <input name="minStock" type="number" value={formData.minStock || ''} onChange={handleChange} required className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm" placeholder="Aviso bajo stock" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Vencimiento</label>
              <input name="expiryDate" type="date" value={formData.expiryDate || ''} onChange={handleChange} required className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest">Modalidad de Recepción</label>
              <select name="receptionType" value={formData.receptionType} onChange={handleChange} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-sm font-bold shadow-sm">
                <option value="Consignación">Consignación (Pago post-venta)</option>
                <option value="Compra Directa">Compra Directa (Liquidado)</option>
              </select>
            </div>
          </div>

          <div className="bg-[#F5F5DC]/40 p-8 rounded-[40px] border border-[#D7CCC8]/60 space-y-6">
            <div className="flex items-center gap-4 mb-4">
               <Layers size={22} className="text-[#AF6E4D]" />
               <h3 className="text-xs font-black text-[#3E2723] uppercase tracking-widest">Gestión de Agrupaciones Ilimitadas</h3>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
              <div className="space-y-2"><label className="text-[8px] font-black uppercase text-gray-400">Etiqueta (Ej: Caja x24)</label><input placeholder="Descripción..." className="w-full p-4 bg-white border border-[#D7CCC8]/40 rounded-2xl text-xs font-bold" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} /></div>
              <div className="space-y-2"><label className="text-[8px] font-black uppercase text-gray-400">Contenido (U)</label><input type="number" className="w-full p-4 bg-white border border-[#D7CCC8]/40 rounded-2xl text-xs font-bold" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value) || 0})} /></div>
              <div className="space-y-2"><label className="text-[8px] font-black uppercase text-gray-400">Precio Pack</label><input type="number" className="w-full p-4 bg-white border border-[#D7CCC8]/40 rounded-2xl text-xs font-bold" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value) || 0})} /></div>
              <div className="space-y-2"><label className="text-[8px] font-black uppercase text-gray-400">Venta Mín. Packs</label><input type="number" className="w-full p-4 bg-white border border-[#D7CCC8]/40 rounded-2xl text-xs font-bold" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value) || 0})} /></div>
              <button type="button" onClick={addGrouping} className="bg-[#AF6E4D] text-white p-4 rounded-2xl text-[10px] font-black uppercase shadow-lg hover:bg-[#3E2723] transition-all">+ Añadir Grupo</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mt-6">
              {formData.groupings?.map(g => (
                <div key={g.id} className="bg-white p-5 rounded-[24px] border border-[#D7CCC8]/30 flex justify-between items-center shadow-sm hover:border-[#AF6E4D] transition-all">
                  <div>
                    <p className="text-[11px] font-black text-[#3E2723] uppercase">{g.label} ({g.quantity}u)</p>
                    <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">PvP: {g.price} {g.currency} {g.minOrderQuantity ? `| Mín: ${g.minOrderQuantity}p` : ''}</p>
                  </div>
                  <button type="button" onClick={() => removeGrouping(g.id)} className="p-2 text-rose-300 hover:text-rose-500 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
              {(!formData.groupings || formData.groupings.length === 0) && <p className="col-span-full py-6 text-center text-[10px] text-gray-400 font-black uppercase tracking-widest opacity-40 italic">Solo venta unitaria configurada</p>}
            </div>
          </div>
        </div>
        <div className="p-8 border-t bg-white flex justify-end gap-4 shadow-2xl">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs hover:text-rose-400 transition-colors">Descartar Cambios</button>
          <button onClick={() => onSave(formData as Product)} className="px-12 py-5 bg-[#3E2723] text-white font-black rounded-[24px] uppercase text-xs shadow-2xl shadow-[#3E2723]/40 hover:scale-[1.02] transition-all flex items-center gap-3">
             <Save size={18}/> {initialData ? 'Actualizar Ficha' : 'Registrar en PaTí'}
          </button>
        </div>
      </div>
    );
  };

  // --- PUNTO DE VENTA (VENTAS FUNCIONAL) ---
  const SalesModal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [selectedClient, setSelectedClient] = useState<string>('Publico-Gral');
    const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');
    const [status, setStatus] = useState<'Solicitud' | 'Despachado'>('Solicitud');

    const addToCart = (p: Product, grouping?: GroupingPrice) => {
      const existing = cart.find(i => i.productId === p.id && i.groupingId === grouping?.id);
      if (existing) {
        setCart(cart.map(i => (i.id === existing.id ? { ...i, quantity: i.quantity + 1, total: (i.quantity + 1) * i.price } : i)));
        return;
      }
      const initialQty = grouping?.minOrderQuantity || 1;
      const newItem: SaleItem = {
        id: Math.random().toString(), productId: p.id, productName: p.name, groupingId: grouping?.id, groupingLabel: grouping?.label,
        quantity: initialQty, price: grouping ? grouping.price : p.unitPrice, total: (grouping ? grouping.price : p.unitPrice) * initialQty,
        currency: grouping ? grouping.currency : p.unitCurrency, unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
    };

    const updateCartQty = (id: string, delta: number) => {
      setCart(cart.map(item => {
        if (item.id === id) {
          const minRequired = products.find(p => p.id === item.productId)?.groupings.find(g => g.id === item.groupingId)?.minOrderQuantity || 1;
          const newQty = Math.max(minRequired, item.quantity + delta);
          return { ...item, quantity: newQty, total: newQty * item.price };
        }
        return item;
      }));
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);
    const totalUsd = cart.filter(i => i.currency === 'USD').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/80 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[60px] w-full max-w-7xl h-[94vh] overflow-hidden flex shadow-2xl animate-in zoom-in-95 duration-300">
          {/* LADO IZQUIERDO: CATÁLOGO */}
          <div className="w-1/2 border-r border-[#D7CCC8]/30 flex flex-col p-10 bg-[#FCF9F7]">
            <div className="flex justify-between items-center mb-8">
              <div className="flex items-center gap-4">
                 <ShoppingCart className="text-[#AF6E4D]" size={32} />
                 <h2 className="text-2xl font-black uppercase text-[#3E2723] tracking-tighter">Terminal de Ventas</h2>
              </div>
              <button onClick={() => setShowSaleModal(false)} className="p-3 bg-white shadow-sm rounded-full hover:bg-rose-50 transition-colors"><X size={20}/></button>
            </div>
            <div className="relative mb-8">
               <Search className="absolute left-6 top-6 text-[#D7CCC8]" size={20} />
               <input className="w-full pl-16 p-6 bg-white border border-[#D7CCC8]/30 rounded-[32px] outline-none text-sm font-bold shadow-sm focus:border-[#AF6E4D]" placeholder="Escriba para buscar en PaTí..." value={search} onChange={e => setSearch(e.target.value)} />
            </div>
            <div className="flex-1 overflow-y-auto space-y-4 pr-3 custom-scrollbar">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-6 rounded-[32px] border border-[#D7CCC8]/20 hover:border-[#AF6E4D] transition-all group shadow-sm flex flex-col gap-4">
                  <div className="flex justify-between items-start">
                    <div>
                       <h4 className="font-black text-sm uppercase text-[#3E2723] tracking-tighter">{p.name}</h4>
                       <span className={`inline-block mt-2 px-3 py-1 rounded-full text-[9px] font-black uppercase ${p.stock > p.minStock ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-500'}`}>Stock: {p.stock} u.</span>
                    </div>
                    <button onClick={() => addToCart(p)} className="p-3 bg-[#3E2723] text-white rounded-2xl shadow-lg active:scale-90 transition-all hover:bg-[#AF6E4D]">+ Unid</button>
                  </div>
                  <div className="flex flex-wrap gap-2 pt-2 border-t border-dashed">
                    {p.groupings.map(g => (
                      <button key={g.id} onClick={() => addToCart(p, g)} className="px-5 py-3 bg-[#F5F5DC] text-[9px] font-black rounded-xl text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white transition-all border border-[#D7CCC8]/30 uppercase flex flex-col items-center">
                        <span className="opacity-60">{g.label}</span>
                        <span>{g.price} {g.currency}</span>
                      </button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
          {/* LADO DERECHO: CARRITO */}
          <div className="w-1/2 flex flex-col p-10 bg-white">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-8 tracking-[0.4em]">Resumen de Despacho</h3>
            <div className="flex-1 overflow-y-auto space-y-4 mb-8 custom-scrollbar">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 group animate-in slide-in-from-right-4">
                  <div className="flex-1">
                    <p className="font-black text-xs uppercase text-[#3E2723]">{item.productName}</p>
                    <p className="text-[9px] font-bold text-[#AF6E4D] uppercase mt-1">{item.groupingLabel || 'Venta Unitaria'}</p>
                    <p className="text-[10px] text-gray-400 font-bold mt-1">PvP: {item.price} {item.currency}</p>
                  </div>
                  <div className="flex items-center gap-6">
                    <div className="flex items-center bg-white rounded-2xl border border-[#D7CCC8]/30 p-2 shadow-sm">
                       <button onClick={() => updateCartQty(item.id, -1)} className="p-2 text-[#D7CCC8] hover:text-rose-400"><Minus size={14}/></button>
                       <span className="w-12 text-center font-black text-sm text-[#3E2723]">{item.quantity}</span>
                       <button onClick={() => updateCartQty(item.id, 1)} className="p-2 text-[#3E2723] hover:text-[#AF6E4D]"><Plus size={14}/></button>
                    </div>
                    <div className="text-right w-32">
                      <p className="font-black text-sm text-[#3E2723]">{item.total.toLocaleString()} {item.currency}</p>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-[8px] text-rose-300 font-black uppercase hover:text-rose-500 transition-colors">Remover</button>
                    </div>
                  </div>
                </div>
              ))}
              {cart.length === 0 && (
                 <div className="h-full flex flex-col items-center justify-center text-[#D7CCC8] opacity-30 space-y-6">
                   <Package size={80} strokeWidth={1}/>
                   <p className="text-xs font-black uppercase tracking-[0.3em]">Seleccione productos para facturar</p>
                 </div>
              )}
            </div>
            <div className="space-y-6 pt-8 border-t border-[#D7CCC8]/30">
              <div className="grid grid-cols-2 gap-4">
                 <select className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-xs font-black uppercase shadow-sm" value={selectedClient} onChange={e => setSelectedClient(e.target.value)}>
                    <option value="Publico-Gral">Público General</option>
                    {contacts.filter(c=>c.type==='Cliente').map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                 </select>
                 <select className="p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] font-black text-xs uppercase shadow-sm" value={paymentMethod} onChange={e => setPaymentMethod(e.target.value as any)}>
                    <option value="Efectivo">Efectivo</option><option value="Transferencia">Transferencia</option>
                 </select>
              </div>
              <select className="w-full p-5 bg-[#F5F5DC] border border-[#D7CCC8]/40 rounded-[24px] font-black text-xs uppercase text-[#3E2723] shadow-inner" value={status} onChange={e => setStatus(e.target.value as any)}>
                <option value="Solicitud">Generar Pre-Factura (Proforma)</option>
                <option value="Despachado">Finalizar Venta (Despacho)</option>
              </select>
              <div className="bg-[#3E2723] p-10 rounded-[48px] text-white flex justify-between items-center shadow-2xl shadow-[#3E2723]/30 border border-white/5">
                <div>
                   <p className="text-[10px] font-black uppercase opacity-40 tracking-[0.2em] mb-2">Total a Cobrar</p>
                   {totalCup > 0 && <p className="text-4xl font-black tabular-nums tracking-tighter">{totalCup.toLocaleString()} <span className="text-sm opacity-30 ml-2">CUP</span></p>}
                   {totalUsd > 0 && <p className="text-2xl font-black tabular-nums tracking-tighter mt-2">{totalUsd.toLocaleString()} <span className="text-sm opacity-30 ml-2">USD</span></p>}
                </div>
                <button disabled={cart.length === 0} onClick={() => {
                   const transaction: Transaction = {
                      id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient,
                      clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart,
                      totalCup, totalUsd, paymentMethod, status, invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
                   };
                   handleCreateSale(transaction);
                }} className="bg-[#AF6E4D] text-white px-12 py-7 rounded-[32px] font-black uppercase text-xs shadow-xl active:scale-95 transition-all hover:bg-white hover:text-[#3E2723] disabled:opacity-20 disabled:pointer-events-none">Procesar Pago</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const handleCreateSale = (sale: Transaction) => {
    setTransactions([sale, ...transactions]);
    if (sale.status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const soldUnits = sale.items.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
        return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
      }));
    }
    setShowSaleModal(false);
    setSelectedInvoice(sale); // Mostrar factura al finalizar
  };

  // --- Vistas Principales ---
  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={(id) => setNotifications(n => n.map(x => x.id === id ? {...x, read: true} : x))}>
      {activeTab === 'home' && (
         <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700 h-full">
            <div className="relative h-96 rounded-[60px] overflow-hidden shadow-2xl group border-4 border-white">
               <img src="https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&q=80&w=1200" className="w-full h-full object-cover brightness-[0.4] transition-transform duration-[2s] group-hover:scale-105" />
               <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-8">
                  <div className="bg-white/20 backdrop-blur-md p-8 rounded-[40px] border border-white/40 mb-10 shadow-2xl">
                    <img src={LOGO_URL} alt={STORE_NAME} className="h-32 w-auto object-contain drop-shadow-2xl" />
                  </div>
                  <h2 className="text-5xl font-black text-white uppercase tracking-tighter mb-4">Mercado PaTí</h2>
                  <p className="text-white/80 text-xl font-medium max-w-2xl leading-relaxed">Excelencia en consignación y ventas minoristas.</p>
               </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {[
                { icon: ShoppingBag, label: 'Transacciones Hoy', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0])).length, color: 'bg-amber-50 text-amber-600' },
                { icon: Database, label: 'Unidades en Almacén', value: products.reduce((acc, p) => acc + p.stock, 0), color: 'bg-[#5D4037]/10 text-[#5D4037]' },
                { icon: UserPlus, label: 'Soberanía de Socios', value: contacts.filter(c => c.type === 'Proveedor').length, color: 'bg-emerald-50 text-emerald-600' }
              ].map((item, idx) => (
                <div key={idx} className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm flex flex-col justify-between hover:shadow-xl transition-all h-64">
                   <div className={`w-16 h-16 ${item.color} rounded-[24px] flex items-center justify-center mb-6 shadow-inner`}><item.icon size={28} /></div>
                   <div>
                      <p className="text-[11px] font-black uppercase text-gray-400 tracking-[0.3em] mb-2">{item.label}</p>
                      <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{item.value.toLocaleString()}</p>
                   </div>
                </div>
              ))}
            </div>
         </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-end"><h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario PaTí</h2><button onClick={() => { setProductModal({show: true}); }} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-[#3E2723]/30">+ Registrar Producto</button></div>
          <div className="bg-white rounded-[50px] shadow-sm border border-[#D7CCC8]/20 overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b text-[10px] uppercase text-[#AF6E4D] font-black tracking-widest">
                <tr><th className="px-10 py-8">Catálogo / SKU</th><th className="px-10 py-8">Nivel de Stock</th><th className="px-10 py-8">Estructura Comercial</th><th className="px-10 py-8 text-right">Gestión</th></tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8"><p className="font-black text-sm uppercase tracking-tighter">{p.name}</p><p className="text-[10px] font-black text-[#D7CCC8] uppercase mt-1">{p.sku}</p></td>
