    const addToCart = (p: Product, grouping?: GroupingPrice) => {
      const existing = cart.find(i => i.productId === p.id && i.groupingId === grouping?.id);
      if (existing) {
        setCart(cart.map(i => (i.id === existing.id ? { ...i, quantity: i.quantity + 1, total: (i.quantity + 1) * i.price } : i)));
        return;
      }
      const initialQty = grouping?.minOrderQuantity || 1;
      const newItem: SaleItem = {
        id: Math.random().toString(), productId: p.id, productName: p.name, groupingId: grouping?.id, groupingLabel: grouping?.label,
        quantity: initialQty, price: grouping ? grouping.price : p.unitPrice, total: (grouping ? grouping.price : p.unitPrice) * initialQty,
        currency: grouping ? grouping.currency : p.unitCurrency, unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
