                 <select className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] text-xs font-black uppercase shadow-sm" value={selectedClient} onChange={e => setSelectedClient(e.target.value)}>
                    <option value="Publico-Gral">Público General</option>
                    {contacts.filter(c=>c.type==='Cliente').map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                 </select>
                 <select className="p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[24px] font-black text-xs uppercase shadow-sm" value={paymentMethod} onChange={e => setPaymentMethod(e.target.value as any)}>
                    <option value="Efectivo">Efectivo</option><option value="Transferencia">Transferencia</option>
                 </select>
              </div>
              <select className="w-full p-5 bg-[#F5F5DC] border border-[#D7CCC8]/40 rounded-[24px] font-black text-xs uppercase text-[#3E2723] shadow-inner" value={status} onChange={e => setStatus(e.target.value as any)}>
                <option value="Solicitud">Generar Pre-Factura (Proforma)</option>
                <option value="Despachado">Finalizar Venta (Despacho)</option>
              </select>
              <div className="bg-[#3E2723] p-10 rounded-[48px] text-white flex justify-between items-center shadow-2xl shadow-[#3E2723]/30 border border-white/5">
                <div>
                   <p className="text-[10px] font-black uppercase opacity-40 tracking-[0.2em] mb-2">Total a Cobrar</p>
                   {totalCup > 0 && <p className="text-4xl font-black tabular-nums tracking-tighter">{totalCup.toLocaleString()} <span className="text-sm opacity-30 ml-2">CUP</span></p>}
                   {totalUsd > 0 && <p className="text-2xl font-black tabular-nums tracking-tighter mt-2">{totalUsd.toLocaleString()} <span className="text-sm opacity-30 ml-2">USD</span></p>}
                </div>
                <button disabled={cart.length === 0} onClick={() => {
                   const transaction: Transaction = {
                      id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient,
                      clientName: contacts.find(c=>c.id===selectedClient)?.name || 'Público Gral', items: cart,
                      totalCup, totalUsd, paymentMethod, status, invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
                   };
                   handleCreateSale(transaction);
                }} className="bg-[#AF6E4D] text-white px-12 py-7 rounded-[32px] font-black uppercase text-xs shadow-xl active:scale-95 transition-all hover:bg-white hover:text-[#3E2723] disabled:opacity-20 disabled:pointer-events-none">Procesar Pago</button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  const handleCreateSale = (sale: Transaction) => {
    setTransactions([sale, ...transactions]);
    if (sale.status === 'Despachado') {
      setProducts(prev => prev.map(p => {
        const soldUnits = sale.items.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
        return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
      }));
    }
    setShowSaleModal(false);
    setSelectedInvoice(sale); // Mostrar factura al finalizar
  };

  // --- Vistas Principales ---
  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={(id) => setNotifications(n => n.map(x => x.id === id ? {...x, read: true} : x))}>
      {activeTab === 'home' && (
         <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-700 h-full">
            <div className="relative h-96 rounded-[60px] overflow-hidden shadow-2xl group border-4 border-white">
               <img src="https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&q=80&w=1200" className="w-full h-full object-cover brightness-[0.4] transition-transform duration-[2s] group-hover:scale-105" />
               <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-8">
                  <div className="bg-white/20 backdrop-blur-md p-8 rounded-[40px] border border-white/40 mb-10 shadow-2xl">
                    <img src={LOGO_URL} alt={STORE_NAME} className="h-32 w-auto object-contain drop-shadow-2xl" />
                  </div>
                  <h2 className="text-5xl font-black text-white uppercase tracking-tighter mb-4">Mercado PaTí</h2>
                  <p className="text-white/80 text-xl font-medium max-w-2xl leading-relaxed">Excelencia en consignación y ventas minoristas.</p>
               </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {[
                { icon: ShoppingBag, label: 'Transacciones Hoy', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0])).length, color: 'bg-amber-50 text-amber-600' },
                { icon: Database, label: 'Unidades en Almacén', value: products.reduce((acc, p) => acc + p.stock, 0), color: 'bg-[#5D4037]/10 text-[#5D4037]' },
                { icon: UserPlus, label: 'Soberanía de Socios', value: contacts.filter(c => c.type === 'Proveedor').length, color: 'bg-emerald-50 text-emerald-600' }
              ].map((item, idx) => (
                <div key={idx} className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm flex flex-col justify-between hover:shadow-xl transition-all h-64">
                   <div className={`w-16 h-16 ${item.color} rounded-[24px] flex items-center justify-center mb-6 shadow-inner`}><item.icon size={28} /></div>
                   <div>
                      <p className="text-[11px] font-black uppercase text-gray-400 tracking-[0.3em] mb-2">{item.label}</p>
                      <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{item.value.toLocaleString()}</p>
                   </div>
                </div>
              ))}
            </div>
         </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-end"><h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario PaTí</h2><button onClick={() => { setProductModal({show: true}); }} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-[#3E2723]/30">+ Registrar Producto</button></div>
          <div className="bg-white rounded-[50px] shadow-sm border border-[#D7CCC8]/20 overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b text-[10px] uppercase text-[#AF6E4D] font-black tracking-widest">
                <tr><th className="px-10 py-8">Catálogo / SKU</th><th className="px-10 py-8">Nivel de Stock</th><th className="px-10 py-8">Estructura Comercial</th><th className="px-10 py-8 text-right">Gestión</th></tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8"><p className="font-black text-sm uppercase tracking-tighter">{p.name}</p><p className="text-[10px] font-black text-[#D7CCC8] uppercase mt-1">{p.sku}</p></td>
                    <td className="px-10 py-8"><span className={`text-lg font-black ${p.stock <= p.minStock ? 'text-rose-500 animate-pulse' : ''}`}>{p.stock} <span className="text-[10px] opacity-30 uppercase">U.</span></span><p className="text-[9px] text-[#D7CCC8] font-bold uppercase mt-1">Límite: {p.minStock}</p></td>
                    <td className="px-10 py-8 flex flex-wrap gap-2">
                       <span className="px-4 py-2 bg-[#FCF9F7] text-[10px] font-black rounded-xl border border-[#D7CCC8]/30 uppercase text-[#3E2723]">Base: {p.unitPrice} {p.unitCurrency}</span>
                       {p.groupings.map(g => <span key={g.id} className="px-4 py-2 bg-[#F5F5DC] text-[#3E2723] text-[10px] font-black rounded-xl border border-[#D7CCC8]/50 uppercase">{g.label}: {g.price}</span>)}
                    </td>
                    <td className="px-10 py-8 text-right">
                       <div className="flex justify-end gap-3"><button onClick={() => setProductModal({show: true, product: p})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#AF6E4D] hover:text-white transition-all shadow-sm"><Edit2 size={18} /></button><button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-4 bg-rose-50 text-rose-300 rounded-2xl hover:bg-rose-500 hover:text-white transition-all shadow-sm"><Trash2 size={18} /></button></div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}

      {activeTab === 'sales' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="flex justify-between items-end"><h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter">Ventas y Facturas</h2><button onClick={() => setShowSaleModal(true)} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black uppercase text-xs shadow-2xl shadow-[#3E2723]/30 tracking-widest">+ Punto de Venta</button></div>
           <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-sm">
              <table className="w-full text-left">
                 <thead className="bg-[#F5F5DC]/40 border-b text-[10px] font-black uppercase text-[#AF6E4D] tracking-widest">
                    <tr><th className="px-10 py-8">Nro Doc</th><th className="px-10 py-8">Cliente Receptor</th><th className="px-10 py-8 text-right">Importe Cobrado</th><th className="px-10 py-8 text-center">Estado Logístico</th><th className="px-10 py-8 text-right">Acción</th></tr>
                 </thead>
                 <tbody className="divide-y divide-[#D7CCC8]/10 text-xs font-black text-[#3E2723]">
                    {transactions.map(t => (
                       <tr key={t.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                          <td className="px-10 py-8">{t.invoiceNumber}</td>
                          <td className="px-10 py-8 uppercase tracking-tighter">{t.clientName}</td>
                          <td className="px-10 py-8 text-right tabular-nums text-sm">{t.totalCup.toLocaleString()} <span className="text-[10px] opacity-40">CUP</span></td>
                          <td className="px-10 py-8 text-center"><span className={`px-5 py-2 rounded-full text-[10px] uppercase shadow-sm ${t.status === 'Despachado' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>{t.status}</span></td>
                          <td className="px-10 py-8 text-right"><button onClick={() => setSelectedInvoice(t)} className="p-4 bg-[#F5F5DC] rounded-2xl text-[#AF6E4D] hover:bg-[#3E2723] hover:text-white transition-all shadow-sm"><FileText size={20}/></button></td>
                       </tr>
                    ))}
                 </tbody>
              </table>
           </div>
        </div>
      )}

      {/* MODALES */}
      {showSaleModal && <SalesModal />}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/80 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[94vh] flex flex-col animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6">
                 <Truck size={32} className="text-[#AF6E4D]" />
                 <div>
                    <h2 className="text-2xl font-black uppercase text-[#3E2723] tracking-tighter">{productModal.product ? 'Actualización de Ficha' : 'Recepción Técnica de Mercancía'}</h2>
                    <p className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.2em] mt-1">Configuración al Full Mercado PaTí</p>
                 </div>
              </div>
              <button onClick={() => setProductModal({show: false})} className="p-3 hover:bg-rose-50 text-rose-400 rounded-full transition-all"><X size={32} /></button>
            </div>
            <ProductForm 
              initialData={productModal.product} 
              suppliers={contacts.filter(c => c.type === 'Proveedor')} 
              onAddSupplier={(draft) => { setProductModal({...productModal, draft}); setShowContactModal(true); }}
              onSave={(p) => {
                const newP = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `SKU-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? newP : x));
                else setProducts([...products, newP]);
                setProductModal({show: false});
              }}
              onCancel={() => setProductModal({show: false})}
            />
          </div>
        </div>
      )}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md no-print animate-in fade-in duration-300">
          <div className="bg-white rounded-[60px] w-full max-w-3xl shadow-2xl overflow-hidden flex flex-col max-h-[96vh]">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-5">
                <Printer size={32} className="text-[#3E2723]" />
                <h2 className="text-2xl font-black uppercase text-[#3E2723] tracking-tighter">Documento Comercial</h2>
              </div>
              <button onClick={() => setSelectedInvoice(null)} className="p-3 hover:bg-gray-100 rounded-full transition-all"><X size={32} /></button>
            </div>
            <div id="pati-invoice" className="flex-1 overflow-y-auto p-16 bg-white print:p-0">
              <div className="flex justify-between items-start mb-16">
                <div className="flex flex-col gap-6">
                  <div className="bg-[#3E2723] p-6 rounded-[32px] w-fit shadow-xl">
                    <img src={LOGO_URL} alt={STORE_NAME} className="h-24 w-auto object-contain brightness-[100]" onError={(e) => (e.currentTarget.style.display='none')} />
                  </div>
                  <div>
                    <h3 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">{STORE_NAME}</h3>
                    <p className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-widest mt-1">Suministros y Consignación</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className="text-[10px] font-black text-[#D7CCC8] uppercase tracking-widest mb-1">Folio Operativo</p>
                  <p className="text-xl font-black text-[#3E2723] mb-8">{selectedInvoice.invoiceNumber}</p>
                  <p className="text-[10px] font-black text-[#D7CCC8] uppercase tracking-widest mb-1">Fecha Emisión</p>
                  <p className="text-sm font-black text-[#3E2723] uppercase">{new Date(selectedInvoice.date).toLocaleDateString()}</p>
                </div>
              </div>
              <div className="mb-12 p-8 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/20">
                 <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-2">Cliente / Socio Comercial</p>
                 <p className="text-lg font-black text-[#3E2723] uppercase tracking-tighter">{selectedInvoice.clientName}</p>
              </div>
              <table className="w-full mb-16 text-left">
                <thead>
                  <tr className="border-b-4 border-[#3E2723] text-[10px] font-black text-[#D7CCC8] uppercase tracking-widest"><th className="py-6">Detalle Mercancía</th><th className="py-6 text-center">Cant</th><th className="py-6 text-right">PvP</th><th className="py-6 text-right">Subtotal</th></tr>
                </thead>
                <tbody className="divide-y-2 divide-[#F5F5DC]">
                  {selectedInvoice.items.map((item, idx) => (
                    <tr key={idx} className="text-sm font-bold text-[#3E2723]">
                      <td className="py-8 uppercase leading-tight"><p className="font-black text-[#3E2723]">{item.productName}</p>{item.groupingLabel && <p className="text-[9px] text-[#AF6E4D] uppercase mt-2 bg-[#F5F5DC] w-fit px-2 py-1 rounded-md">{item.groupingLabel}</p>}</td>
                      <td className="py-8 text-center">{item.quantity}</td>
                      <td className="py-8 text-right tabular-nums">{item.price} <span className="text-[10px] opacity-30">{item.currency}</span></td>
                      <td className="py-8 text-right font-black tabular-nums">{item.total} <span className="text-[10px] opacity-30">{item.currency}</span></td>
                    </tr>
                  ))}
                </tbody>
              </table>
              <div className="flex justify-between items-end pt-10 border-t-4 border-[#3E2723]">
                 <div className="bg-[#F5F5DC]/40 p-6 rounded-[24px]">
                    <p className="text-[9px] font-black text-[#8D6E63] uppercase tracking-widest mb-1">Método de Pago</p>
                    <p className="text-sm font-black text-[#3E2723] uppercase">{selectedInvoice.paymentMethod}</p>
                 </div>
                <div className="text-right space-y-3">
                  <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Total Liquidado</p>
                  <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p>
                  {selectedInvoice.totalUsd > 0 && <p className="text-xl font-black text-[#AF6E4D] tracking-tighter">{selectedInvoice.totalUsd.toLocaleString()} <span className="text-sm opacity-30">USD</span></p>}
                </div>
              </div>
            </div>
            <div className="p-10 bg-[#F5F5DC]/40 border-t border-[#D7CCC8]/40 flex flex-col items-center gap-4 no-print shadow-inner">
              <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-7 rounded-[32px] font-black uppercase text-sm tracking-widest shadow-2xl hover:scale-105 transition-all flex items-center gap-4"><Printer size={22}/> Imprimir Factura / Guardar PDF</button>
              <p className="text-[10px] text-[#8D6E63] font-black uppercase tracking-[0.2em] opacity-60">Mercado PaTí - Calidad Garantizada</p>
            </div>
          </div>
        </div>
      )}

      {/* Pestañas restantes adaptadas... */}
      {activeTab === 'suppliers' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="flex justify-between items-end"><h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter">Directorio de Socios</h2><button onClick={() => setShowContactModal(true)} className="bg-[#3E2723] text-white px-8 py-5 rounded-[24px] font-black text-[10px] uppercase shadow-xl tracking-widest">+ Nuevo Contacto</button></div>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {contacts.map(c => (
                <div key={c.id} className="bg-white p-12 rounded-[60px] border border-[#D7CCC8]/20 shadow-sm flex flex-col justify-between h-[360px] hover:shadow-2xl hover:-translate-y-2 transition-all group">
                   <div className="flex justify-between mb-8"><div className="w-20 h-20 bg-[#F5F5DC] text-[#3E2723] rounded-[32px] flex items-center justify-center font-black text-4xl shadow-inner group-hover:bg-[#3E2723] group-hover:text-white transition-all">{c.name.charAt(0)}</div><span className="text-[10px] font-black uppercase px-6 py-2 bg-[#F5F5DC] text-[#3E2723] rounded-2xl border border-[#D7CCC8]/50 shadow-sm">{c.type}</span></div>
                   <div>
                     <h3 className="font-black text-[#3E2723] text-xl uppercase mb-6 tracking-tighter truncate">{c.name}</h3>
                     <div className="space-y-4">
                        <p className="text-xs font-bold text-[#8D6E63] uppercase flex items-center gap-4"><Phone size={20} className="text-[#AF6E4D]"/> {c.phone}</p>
                        <p className="text-[11px] font-black text-[#3E2723] uppercase flex items-center gap-4 bg-[#FCF9F7] p-5 rounded-3xl border border-[#D7CCC8]/10"><MapPin size={20} className="text-[#AF6E4D]"/> {c.address}</p>
                     </div>
                   </div>
                </div>
              ))}
           </div>
        </div>
      )}

      {activeTab === 'closure' && (
        <div className="max-w-3xl mx-auto py-12 animate-in fade-in zoom-in-95 duration-700">
          <div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl overflow-hidden">
            <div className="p-16 border-b bg-[#F5F5DC]/40 flex justify-between items-center shadow-inner">
               <div><h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Cierre de Caja</h2><p className="text-xs font-bold text-[#AF6E4D] uppercase mt-2 tracking-widest">Auditoría Diaria: {new Date().toLocaleDateString()}</p></div>
               <Wallet size={80} className="text-[#AF6E4D] opacity-20" strokeWidth={1}/>
            </div>
            <div className="p-16 space-y-12 bg-[#FCF9F7]/30">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                 {[
                   { label: 'Caja Efectivo (CUP)', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado' && t.paymentMethod === 'Efectivo').reduce((a, b) => a + b.totalCup, 0), icon: DollarSign, color: 'text-[#3E2723]' },
                   { label: 'Caja Bancaria (CUP)', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado' && t.paymentMethod === 'Transferencia').reduce((a, b) => a + b.totalCup, 0), icon: ArrowRight, color: 'text-[#AF6E4D]' },
                   { label: 'Fondo USD', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').reduce((a, b) => a + b.totalUsd, 0), icon: ShieldCheck, color: 'text-[#3E2723]' },
                   { label: 'Volumen de Ventas', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').length, icon: ShoppingBag, color: 'text-[#AF6E4D]' }
                 ].map((stat, i) => (
                   <div key={i} className="bg-white p-10 rounded-[40px] border border-[#D7CCC8]/30 shadow-sm">
                      <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-4 flex items-center gap-3"><stat.icon size={14} /> {stat.label}</p>
                      <p className={`text-3xl font-black tracking-tighter ${stat.color}`}>{stat.value.toLocaleString()}</p>
                   </div>
                 ))}
              </div>
              <div className="pt-12 border-t border-[#D7CCC8]/30 text-center">
                 <p className="text-sm font-medium text-[#8D6E63] leading-relaxed mb-10 italic">Al confirmar el cierre, se emitirá una proforma oficial para los registros contables de Mercado PaTí.</p>
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-8 rounded-[32px] font-black uppercase text-xs shadow-2xl flex items-center gap-6 mx-auto hover:bg-[#AF6E4D] transition-all hover:scale-[1.05] tracking-[0.2em]"><CheckCircle2 size={24}/> Generar Reporte Final de Caja</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeTab === 'maintenance' && (
        <div className="flex flex-col items-center justify-center py-40 bg-white rounded-[70px] border border-[#D7CCC8]/20 shadow-sm animate-in zoom-in-95 duration-500">
           <div className="p-10 bg-[#F5F5DC] rounded-full mb-12 shadow-inner"><Database size={80} className="text-[#3E2723] opacity-60" /></div>
           <h2 className="text-5xl font-black uppercase mb-8 text-[#3E2723] tracking-tighter">Resguardo de Sistema</h2>
