                      <button onClick={() => addToCart(p)} className="p-3 bg-[#3E2723] text-white rounded-2xl hover:bg-[#AF6E4D]">+ Unidad</button>
                   </div>
                   <div className="flex flex-wrap gap-2">
                      {p.groupings.map(g => (
                        <button key={g.id} onClick={() => addToCart(p, g)} className="px-4 py-2 bg-[#F5F5DC] rounded-xl text-[9px] font-black text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white border border-[#D7CCC8]/40 uppercase">
                          {g.label}: {g.price} {g.currency}
                        </button>
                      ))}
                   </div>
                </div>
              ))}
            </div>
          </div>
          {/* Carrito */}
          <div className="w-1/2 flex flex-col p-12 bg-white">
            <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] mb-10">Facturación Actual</h3>
            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 animate-in slide-in-from-right-4">
                   <div className="flex-1">
                      <p className="text-xs font-black text-[#3E2723] uppercase">{item.productName}</p>
                      <p className="text-[9px] font-black text-[#AF6E4D] uppercase">{item.groupingLabel || 'Unidad suelta'}</p>
                   </div>
                   <div className="flex items-center gap-6">
                      <div className="text-right"><p className="text-sm font-black text-[#3E2723]">{item.total} {item.currency}</p></div>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-rose-300"><Trash2 size={18}/></button>
                   </div>
                </div>
              ))}
              {cart.length === 0 && <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-40"><ShoppingCart size={64}/><p className="text-xs font-black uppercase mt-4">Carrito Vacío</p></div>}
            </div>
            <div className="space-y-6 pt-10 border-t border-[#D7CCC8]/30">
               <div className="flex justify-between items-end bg-[#3E2723] p-10 rounded-[44px] text-white shadow-2xl">
                  <div><p className="text-[10px] opacity-40 font-black uppercase mb-2">Total a Pagar</p><p className="text-4xl font-black tracking-tighter">{totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                  <button disabled={cart.length === 0} onClick={() => {
                    const trans: Transaction = {
                      id: Math.random().toString(), date: new Date().toISOString(), clientId: selectedClient,
                      clientName: contacts.find(c => c.id === selectedClient)?.name || 'Público Gral', items: cart,
                      totalCup, totalUsd, paymentMethod: 'Efectivo', status: 'Despachado', invoiceNumber: `F-${Date.now().toString().slice(-6)}`
                    };
                    setTransactions([trans, ...transactions]);
                    setProducts(prev => prev.map(p => {
                       const sold = cart.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
                       return sold > 0 ? { ...p, stock: p.stock - sold } : p;
                    }));
                    setCart([]); setShowSaleModal(false); setSelectedInvoice(trans);
                  }} className="bg-[#AF6E4D] text-white px-12 py-6 rounded-[28px] font-black uppercase text-xs shadow-xl hover:bg-white hover:text-[#3E2723] transition-all">Pagar Ahora</button>
               </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {/* VISTA DE INICIO (HERO) */}
      {activeTab === 'home' && (
        <div className="space-y-12 animate-in fade-in slide-in-from-bottom-6 duration-1000">
           <div className="relative h-[450px] rounded-[70px] overflow-hidden shadow-2xl border-4 border-white group">
              <img src="https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&q=80&w=1400" className="w-full h-full object-cover brightness-[0.4] transition-transform duration-[3s] group-hover:scale-105" />
              <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-8">
                 <div className="bg-white/10 backdrop-blur-xl p-8 rounded-[40px] border border-white/30 mb-10 shadow-2xl transform transition-transform group-hover:scale-110">
                    <img src={LOGO_URL} alt={STORE_NAME} className="h-32 w-auto object-contain" onError={e => (e.currentTarget.style.display='none')} />
