                 <h2 className="text-6xl font-black text-white uppercase tracking-tighter mb-4 drop-shadow-2xl">Mercado PaTí</h2>
                 <p className="text-white/80 text-xl font-medium max-w-2xl leading-relaxed italic">"Excelencia en cada entrega, transparencia en cada trato."</p>
              </div>
           </div>
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {[
                { icon: ShoppingBag, label: 'Ventas del Día', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0])).length, color: 'bg-amber-50 text-amber-600' },
                { icon: Package, label: 'Productos en Tienda', value: products.length, color: 'bg-[#5D4037]/10 text-[#5D4037]' },
