          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b text-[10px] uppercase text-[#AF6E4D] font-black tracking-widest">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Existencias</th><th className="px-10 py-8">Precios y Agrupaciones</th><th className="px-10 py-8 text-right">Acción</th></tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8 font-black uppercase text-sm tracking-tighter">{p.name}</td>
                    <td className="px-10 py-8 text-center"><span className={`text-lg font-black ${p.stock <= p.minStock ? 'text-rose-500 animate-pulse' : ''}`}>{p.stock} <span className="text-[10px] opacity-30">U.</span></span></td>
                    <td className="px-10 py-8 flex flex-wrap gap-2">
                       <span className="px-4 py-2 bg-[#FCF9F7] text-[10px] font-black rounded-xl border border-[#D7CCC8]/30 uppercase">Unit: {p.unitPrice} {p.unitCurrency}</span>
                       {p.groupings.map(g => <span key={g.id} className="px-4 py-2 bg-[#F5F5DC] text-[10px] font-black rounded-xl border border-[#D7CCC8]/40 uppercase">{g.label}: {g.price}</span>)}
                    </td>
                    <td className="px-10 py-8 text-right">
                       <div className="flex justify-end gap-3"><button onClick={() => setProductModal({show: true, product: p})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#AF6E4D] hover:text-white transition-all shadow-sm"><Edit2 size={18} /></button><button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-4 bg-rose-50 text-rose-300 rounded-2xl hover:bg-rose-500 hover:text-white transition-all shadow-sm"><Trash2 size={18} /></button></div>
                    </td>
