              </div>
              <div className="flex-1 overflow-y-auto p-16 bg-white">
                 <div className="flex justify-between items-start mb-16">
                    <div className="flex flex-col gap-6">
                       <div className="bg-[#3E2723] p-6 rounded-[32px] w-fit shadow-xl">
                          <img src={LOGO_URL} alt={STORE_NAME} className="h-24 w-auto object-contain brightness-[100]" />
                       </div>
                       <h3 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">{STORE_NAME}</h3>
                    </div>
                    <div className="text-right">
                       <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Nro Factura</p>
                       <p className="text-xl font-black text-[#3E2723] mb-8">{selectedInvoice.invoiceNumber}</p>
                       <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Fecha</p>
                       <p className="text-sm font-black text-[#3E2723] uppercase">{new Date(selectedInvoice.date).toLocaleDateString()}</p>
                    </div>
                 </div>
                 <table className="w-full mb-16 text-left">
                    <thead><tr className="border-b-4 border-[#3E2723] text-[10px] font-black text-gray-400 uppercase tracking-widest"><th className="py-6">Detalle</th><th className="py-6 text-center">Cant</th><th className="py-6 text-right">Precio</th><th className="py-6 text-right">Subtotal</th></tr></thead>
                    <tbody className="divide-y divide-[#F5F5DC]">
                       {selectedInvoice.items.map((item, idx) => (
                         <tr key={idx} className="text-sm font-bold text-[#3E2723]">
                            <td className="py-8 uppercase leading-tight"><p className="font-black">{item.productName}</p>{item.groupingLabel && <p className="text-[9px] text-[#AF6E4D] uppercase mt-1">{item.groupingLabel}</p>}</td>
                            <td className="py-8 text-center">{item.quantity}</td>
                            <td className="py-8 text-right tabular-nums">{item.price} {item.currency}</td>
                            <td className="py-8 text-right font-black tabular-nums">{item.total} {item.currency}</td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
                 <div className="flex justify-end pt-10 border-t-4 border-[#3E2723]">
                    <div className="text-right"><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Total Liquidado</p><p className="text-5xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                 </div>
              </div>
              <div className="p-10 bg-[#F5F5DC]/40 border-t flex flex-col items-center gap-4">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-7 rounded-[32px] font-black uppercase text-xs shadow-2xl tracking-widest hover:scale-105 transition-all flex items-center gap-4"><Printer size={22}/> Imprimir Factura PDF</button>
                 <p className="text-[10px] text-[#8D6E63] font-black uppercase opacity-60 tracking-[0.2em]">Mercado PaTí - Calidad Garantizada</p>
              </div>
           </div>
        </div>
      )}

      {/* Otras Vistas (Directorio, Mantenimiento, etc.) */}
      {activeTab === 'suppliers' && (
        <div className="space-y-8 animate-in fade-in duration-500">
           <div className="flex justify-between items-end"><h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter">Directorio PaTí</h2><button onClick={() => setShowContactModal(true)} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl">+ Nuevo Socio</button></div>
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {contacts.map(c => (
                <div key={c.id} className="bg-white p-12 rounded-[60px] border border-[#D7CCC8]/20 shadow-sm flex flex-col justify-between h-80 hover:shadow-2xl transition-all group">
                   <div className="flex justify-between mb-8"><div className="w-20 h-20 bg-[#F5F5DC] text-[#3E2723] rounded-[32px] flex items-center justify-center font-black text-4xl group-hover:bg-[#3E2723] group-hover:text-white transition-all">{c.name.charAt(0)}</div><span className="text-[10px] font-black uppercase px-6 py-2 bg-[#F5F5DC] text-[#3E2723] rounded-2xl border border-[#D7CCC8]/50 shadow-sm">{c.type}</span></div>
                   <div><h3 className="font-black text-[#3E2723] text-xl uppercase mb-6 tracking-tighter truncate">{c.name}</h3><div className="space-y-4"><p className="text-xs font-bold text-[#8D6E63] flex items-center gap-4"><Phone size={20} className="text-[#AF6E4D]"/> {c.phone}</p></div></div>
                </div>
              ))}
           </div>
        </div>
      )}
    </Layout>
  );
};

export default App;

import React from 'react';

// Logo oficial Mercado PaTí proporcionado por el usuario
export const LOGO_URL = "https://i.ibb.co/L6S9Dkz/pati-logo.jpg"; 

export const STORE_NAME = "Mercado PaTí";

export const CATEGORIES = [
  { id: '1', name: 'Alimentos' },
  { id: '2', name: 'Bebidas' },
  { id: '3', name: 'Hogar' },
  { id: '4', name: 'Aseo' },
  { id: '5', name: 'Otros' },
];

export const COLORS = {
  primary: '#3E2723',    // Marrón Extra Oscuro
  secondary: '#5D4037',  // Marrón Medio
  caramel: '#AF6E4D',    // Caramelo
  beige: '#F5F5DC',      // Beige
  accent: '#D7CCC8',     // Crema
  background: '#FCF9F7', // Blanco Cálido
