import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database
} from 'lucide-react';
import { LOGO_URL, STORE_NAME, CATEGORIES } from './constants';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions'
};

const loadFromStorage = <T,>(key: string, defaultValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage(STORAGE_KEYS.PRODUCTS, []));
  const [contacts, setContacts] = useState<Contact[]>(() => loadFromStorage(STORAGE_KEYS.CONTACTS, []));
  const [transactions, setTransactions] = useState<Transaction[]>(() => loadFromStorage(STORAGE_KEYS.TRANSACTIONS, []));
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Crítico', message: `${p.name} necesita reposición (${p.stock} u).`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      const days = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / 86400000);
      if (days <= 60 && days > 0) {
        newNotifs.push({ id: `exp-${p.id}`, title: 'Próximo a Vencer', message: `${p.name} vence en ${days} días.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // Si se cambia a la pestaña 'reception', abrimos el modal de creación al full
  useEffect(() => {
    if (activeTab === 'reception') {
      setProductModal({ show: true });
    }
  }, [activeTab]);

  const handleExport = () => {
    const data = { products, contacts, transactions };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.products) setProducts(data.products);
        if (data.contacts) setContacts(data.contacts);
        if (data.transactions) setTransactions(data.transactions);
        alert('Base de datos restaurada con éxito.');
      } catch (err) { alert('Error al procesar el archivo.'); }
    };
    reader.readAsText(file);
  };

  // --- FORMULARIO DE PRODUCTO (RECEPCIÓN FULL) ---
  const ProductForm = ({ initialData, onSave, onCancel }: { initialData?: Product, onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      receptionType: 'Consignación',
      unitCurrency: 'CUP',
      groupings: [],
      stock: 0,
      minStock: 5,
      receivedDate: new Date().toISOString().split('T')[0],
      categoryId: '1',
      unitPrice: 0
    });

    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const addGrouping = () => {
      if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
      const newGrouping = { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) };
      setFormData({ ...formData, groupings: [...(formData.groupings || []), newGrouping] });
      setTempGrouping({ id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP' });
    };

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-10 space-y-12 custom-scrollbar">
          <section className="space-y-8">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b border-[#D7CCC8]/30 pb-4">Detalles de Recepción</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Producto</label>
                <input value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold outline-none focus:border-[#AF6E4D]" placeholder="Nombre comercial..." />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Proveedor</label>
                <select value={formData.supplierId || ''} onChange={e => setFormData({...formData, supplierId: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold">
                  <option value="">Seleccione...</option>
                  {contacts.filter(c => c.type === 'Proveedor').map(s => <option key={s.id} value={s.id}>{s.name} {s.isConsignee ? '(Consignación)' : ''}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Modalidad</label>
                <select value={formData.receptionType} onChange={e => setFormData({...formData, receptionType: e.target.value as any})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold">
                  <option value="Consignación">Consignación</option>
                  <option value="Compra Directa">Compra Directa</option>
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Precio Base Unidad</label>
                <div className="flex gap-2">
                  <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold" />
                  <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-5 bg-[#F5F5DC] rounded-[24px] font-bold">
                    <option value="CUP">CUP</option><option value="USD">USD</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Stock Recibido</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Vencimiento</label>
                <input type="date" value={formData.expiryDate || ''} onChange={e => setFormData({...formData, expiryDate: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold" />
              </div>
            </div>
          </section>

          <section className="bg-[#F5F5DC]/40 p-8 rounded-[40px] border border-[#D7CCC8]/50 space-y-6">
            <div className="flex items-center gap-4"><Layers className="text-[#AF6E4D]" /><h3 className="text-xs font-black text-[#3E2723] uppercase tracking-widest">Agrupaciones Ilimitadas (Packs, Cajas, Palets)</h3></div>
            <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 items-end">
              <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Etiqueta</label><input placeholder="Ej: Caja x24" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" /></div>
              <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Contenido (U)</label><input type="number" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" /></div>
              <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Precio Pack</label><input type="number" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" /></div>
              <button onClick={addGrouping} className="bg-[#3E2723] text-white p-4 rounded-2xl text-[10px] font-black uppercase">+ Añadir</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mt-6">
              {formData.groupings?.map(g => (
                <div key={g.id} className="bg-white p-5 rounded-[24px] border border-[#D7CCC8]/30 flex justify-between items-center group">
                  <div><p className="text-[11px] font-black text-[#3E2723] uppercase">{g.label}</p><p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{g.price} {g.currency} | {g.quantity} Unid.</p></div>
                  <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-300 hover:text-rose-500 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
            </div>
          </section>
        </div>
        <div className="p-8 border-t bg-white flex justify-end gap-4 shadow-2xl">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs hover:text-[#3E2723] transition-colors">Cancelar</button>
          <button onClick={() => onSave(formData as Product)} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3 active:scale-95 transition-all"><Save size={18} /> Guardar Entrada</button>
        </div>
      </div>
    );
  };

  // --- PUNTO DE VENTA (EL MOTOR DE VENTAS) ---
  const SalesPanel = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');

    const addToCart = (p: Product, grouping?: GroupingPrice) => {
      const newItem: SaleItem = {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: grouping?.label,
        quantity: 1, price: grouping ? grouping.price : p.unitPrice,
        currency: grouping ? grouping.currency : p.unitCurrency,
        total: grouping ? grouping.price : p.unitPrice,
        unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/80 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[60px] w-full max-w-7xl h-[92vh] overflow-hidden flex shadow-2xl animate-in zoom-in-95 duration-300">
          <div className="w-1/2 border-r border-[#D7CCC8]/30 flex flex-col p-12 bg-[#FCF9F7]">
            <div className="flex justify-between items-center mb-10">
               <h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Caja PaTí</h2>
               <button onClick={() => setShowSaleModal(false)} className="p-3 bg-white rounded-full hover:bg-rose-50"><X size={20}/></button>
            </div>
            <div className="relative mb-8">
               <Search className="absolute left-6 top-6 text-[#D7CCC8]" size={20} />
               <input placeholder="Busque producto..." value={search} onChange={e => setSearch(e.target.value)} className="w-full p-6 pl-16 bg-white border border-[#D7CCC8]/30 rounded-[32px] font-bold text-sm outline-none focus:border-[#AF6E4D]" />
            </div>
            <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scrollbar">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-6 rounded-[32px] border border-[#D7CCC8]/20 hover:border-[#AF6E4D] transition-all shadow-sm">
                   <div className="flex justify-between mb-4">
                      <div><h4 className="font-black text-sm uppercase text-[#3E2723]">{p.name}</h4><p className="text-[9px] font-black text-[#AF6E4D] uppercase">Stock: {p.stock} U.</p></div>
                      <button onClick={() => addToCart(p)} className="p-3 bg-[#3E2723] text-white rounded-2xl hover:bg-[#AF6E4D] transition-all">+ Unidad</button>
                   </div>
                   <div className="flex flex-wrap gap-2">
                      {p.groupings.map(g => (
                        <button key={g.id} onClick={() => addToCart(p, g)} className="px-4 py-2 bg-[#F5F5DC] rounded-xl text-[9px] font-black text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white border border-[#D7CCC8]/40 uppercase transition-all">
                          {g.label}: {g.price} {g.currency}
                        </button>
                      ))}
                   </div>
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-12 bg-white">
            <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] mb-10">Resumen de Venta</h3>
            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 group">
                   <div className="flex-1">
                      <p className="text-xs font-black text-[#3E2723] uppercase">{item.productName}</p>
                      <p className="text-[9px] font-black text-[#AF6E4D] uppercase">{item.groupingLabel || 'Unidad suelta'}</p>
                   </div>
                   <div className="flex items-center gap-6">
                      <p className="text-sm font-black text-[#3E2723]">{item.total} {item.currency}</p>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-rose-300 hover:text-rose-500"><Trash2 size={18}/></button>
                   </div>
                </div>
              ))}
              {cart.length === 0 && <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-40"><ShoppingCart size={64}/><p className="text-xs font-black uppercase mt-4">Carrito Vacío</p></div>}
            </div>
            <div className="bg-[#3E2723] p-10 rounded-[44px] text-white shadow-2xl flex justify-between items-center border border-white/5">
               <div><p className="text-[10px] opacity-40 font-black uppercase mb-2">Total a Cobrar</p><p className="text-4xl font-black tracking-tighter">{totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
               <button disabled={cart.length === 0} onClick={() => {
                 const trans: Transaction = {
                   id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Público Gral',
                   items: cart, totalCup, totalUsd: 0, paymentMethod: 'Efectivo', status: 'Despachado', invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
                 };
                 setTransactions([trans, ...transactions]);
                 setProducts(prev => prev.map(p => {
                    const sold = cart.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
                    return sold > 0 ? { ...p, stock: p.stock - sold } : p;
                 }));
                 setCart([]); setShowSaleModal(false); setSelectedInvoice(trans);
               }} className="bg-[#AF6E4D] text-white px-12 py-6 rounded-[28px] font-black uppercase text-xs shadow-xl hover:bg-white hover:text-[#3E2723] disabled:opacity-20 transition-all">Pagar</button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-end"><h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Bodega PaTí</h2><button onClick={() => setProductModal({show: true})} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl tracking-widest hover:scale-105 transition-all">+ Registrar</button></div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b text-[10px] uppercase text-[#AF6E4D] font-black tracking-widest">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Stock</th><th className="px-10 py-8">Venta</th><th className="px-10 py-8 text-right">Acción</th></tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8 font-black uppercase text-sm">{p.name}</td>
                    <td className="px-10 py-8 text-center font-black">{p.stock} U.</td>
                    <td className="px-10 py-8"><span className="px-4 py-2 bg-[#FCF9F7] text-[10px] font-black rounded-xl border border-[#D7CCC8]/30 uppercase">U: {p.unitPrice} {p.unitCurrency}</span></td>
                    <td className="px-10 py-8 text-right"><div className="flex justify-end gap-3"><button onClick={() => setProductModal({show: true, product: p})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#AF6E4D] hover:text-white transition-all shadow-sm"><Edit2 size={18} /></button></div></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}
      {activeTab === 'sales' && <div className="p-20 text-center"><button onClick={() => setShowSaleModal(true)} className="bg-[#3E2723] text-white px-20 py-10 rounded-[40px] font-black uppercase text-xl shadow-2xl hover:scale-105 transition-all">Abrir Terminal de Ventas</button></div>}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/80 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[94vh] flex flex-col animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6">
                 <Truck size={32} className="text-[#AF6E4D]" />
                 <h2 className="text-2xl font-black uppercase text-[#3E2723] tracking-tighter">{productModal.product ? 'Editar Ficha' : 'Recepción PaTí'}</h2>
              </div>
              <button onClick={() => { setProductModal({show: false}); if(activeTab === 'reception') setActiveTab('inventory'); }} className="p-3 text-rose-400 hover:scale-110 transition-transform"><X size={32} /></button>
            </div>
            <ProductForm 
              initialData={productModal.product} 
              onSave={p => {
                const newP = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `SKU-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? newP : x));
                else setProducts([newP, ...products]);
                setProductModal({show: false});
                if(activeTab === 'reception') setActiveTab('inventory');
              }}
              onCancel={() => { setProductModal({show: false}); if(activeTab === 'reception') setActiveTab('inventory'); }}
            />
          </div>
        </div>
      )}

      {showSaleModal && <SalesPanel />}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md no-print">
           <div className="bg-white rounded-[60px] w-full max-w-3xl shadow-2xl overflow-hidden flex flex-col max-h-[96vh]">
              <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
                 <h2 className="text-2xl font-black text-[#3E2723] uppercase tracking-tighter">Documento de Venta</h2>
                 <button onClick={() => setSelectedInvoice(null)} className="p-3"><X size={32}/></button>
              </div>
              <div className="flex-1 overflow-y-auto p-16 bg-white">
                 <div className="flex justify-between items-start mb-16">
                    <div className="bg-[#3E2723] p-8 rounded-[40px] shadow-xl">
                       <img src={LOGO_URL} alt={STORE_NAME} className="h-24 w-auto object-contain brightness-[100]" />
                    </div>
                    <div className="text-right">
                       <p className="text-xl font-black text-[#3E2723] mb-4">{selectedInvoice.invoiceNumber}</p>
                       <p className="text-sm font-black text-[#3E2723] uppercase">{new Date(selectedInvoice.date).toLocaleDateString()}</p>
                    </div>
                 </div>
                 <table className="w-full mb-16 text-left">
                    <thead><tr className="border-b-4 border-[#3E2723] text-[10px] font-black text-gray-400 uppercase tracking-widest"><th className="py-6">Detalle</th><th className="py-6 text-center">Cant</th><th className="py-6 text-right">Total</th></tr></thead>
                    <tbody className="divide-y divide-[#F5F5DC]">
                       {selectedInvoice.items.map((item, idx) => (
                         <tr key={idx} className="text-sm font-bold text-[#3E2723]">
                            <td className="py-8 uppercase"><p className="font-black">{item.productName}</p>{item.groupingLabel && <p className="text-[9px] text-[#AF6E4D] uppercase">{item.groupingLabel}</p>}</td>
                            <td className="py-8 text-center">{item.quantity}</td>
                            <td className="py-8 text-right font-black">{item.total} {item.currency}</td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
                 <div className="flex justify-end pt-10 border-t-4 border-[#3E2723]">
                    <div className="text-right"><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Total Liquidado</p><p className="text-5xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                 </div>
              </div>
              <div className="p-10 bg-[#F5F5DC]/40 border-t text-center"><button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-7 rounded-[32px] font-black uppercase text-xs shadow-2xl hover:scale-105 transition-all">Imprimir PDF</button></div>
           </div>
        </div>
      )}

      {activeTab === 'maintenance' && (
        <div className="flex flex-col items-center justify-center py-40 bg-white rounded-[70px] border border-[#D7CCC8]/20 shadow-sm animate-in zoom-in-95 duration-500">
           <div className="p-10 bg-[#F5F5DC] rounded-full mb-12 shadow-inner"><Database size={80} className="text-[#3E2723] opacity-60" /></div>
           <h2 className="text-5xl font-black uppercase mb-8 text-[#3E2723] tracking-tighter">Sistema de Datos</h2>
           <p className="text-[#8D6E63] mb-16 max-w-lg text-center font-medium">Gestione la integridad de su información en Mercado PaTí.</p>
           <div className="flex gap-8">
              <button onClick={handleExport} className="bg-[#3E2723] text-white px-16 py-8 rounded-[32px] font-black uppercase text-xs flex items-center gap-6 shadow-2xl hover:scale-105 transition-all"><Download size={24}/> Exportar</button>
              <label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[32px] font-black uppercase text-xs flex items-center gap-6 cursor-pointer hover:bg-[#D7CCC8] transition-all"><Upload size={24}/> Importar <input type="file" className="hidden" accept=".json" onChange={handleImport} /></label>
           </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle
} from 'lucide-react';
import { LOGO_URL, STORE_NAME, CATEGORIES } from './constants';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions'
};

const loadFromStorage = <T,>(key: string, defaultValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage(STORAGE_KEYS.PRODUCTS, []));
  const [contacts, setContacts] = useState<Contact[]>(() => loadFromStorage(STORAGE_KEYS.CONTACTS, []));
  const [transactions, setTransactions] = useState<Transaction[]>(() => loadFromStorage(STORAGE_KEYS.TRANSACTIONS, []));
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product}>({show: false});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);

  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `El producto ${p.name} requiere reposición inmediata.`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      const daysToExpiry = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
      if (daysToExpiry <= 60 && daysToExpiry > 0) {
        newNotifs.push({ id: `exp-${p.id}`, title: 'Próximo a Vencer', message: `${p.name} vence en ${daysToExpiry} días.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // Si se cambia a la pestaña 'reception', abrimos automáticamente el panel de entrada
  useEffect(() => {
    if (activeTab === 'reception') {
      setProductModal({ show: true });
    }
  }, [activeTab]);

  // --- FORMULARIO DE RECEPCIÓN TÉCNICA (AL FULL) ---
  const ProductForm = ({ initialData, onSave, onCancel }: { initialData?: Product, onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      receptionType: 'Consignación',
      unitCurrency: 'CUP',
      groupings: [],
      stock: 0,
      minStock: 5,
      receivedDate: new Date().toISOString().split('T')[0],
      categoryId: '1',
      unitPrice: 0
    });

    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const addGrouping = () => {
      if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
      const newGrouping = { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) };
      setFormData({ ...formData, groupings: [...(formData.groupings || []), newGrouping] });
      setTempGrouping({ id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP' });
    };

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-10 space-y-12 custom-scrollbar">
          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b border-[#D7CCC8]/30 pb-4">Identificación y Contrato</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Nombre Comercial</label>
                <input value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold outline-none focus:border-[#AF6E4D]" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Proveedor Suministrador</label>
                <select value={formData.supplierId || ''} onChange={e => setFormData({...formData, supplierId: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold">
                  <option value="">Seleccione...</option>
                  {contacts.filter(c => c.type === 'Proveedor').map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Tipo de Entrada</label>
                <select value={formData.receptionType} onChange={e => setFormData({...formData, receptionType: e.target.value as any})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold">
                  <option value="Consignación">Consignación (Pago Post-Venta)</option>
                  <option value="Compra Directa">Compra Directa</option>
                </select>
              </div>
            </div>
          </section>

          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b border-[#D7CCC8]/30 pb-4">Logística y Precios</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Precio Unitario (CUP/USD)</label>
                <div className="flex gap-2">
                  <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold" />
                  <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-5 bg-[#F5F5DC] rounded-[24px] font-bold text-xs">
                    <option value="CUP">CUP</option><option value="USD">USD</option>
                  </select>
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Existencia Recibida (Unid)</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Stock Mínimo de Alerta</label>
                <input type="number" value={formData.minStock || ''} onChange={e => setFormData({...formData, minStock: parseInt(e.target.value)})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Fecha de Vencimiento</label>
                <input type="date" value={formData.expiryDate || ''} onChange={e => setFormData({...formData, expiryDate: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[24px] font-bold" />
              </div>
            </div>
          </section>

          <section className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30 space-y-6 shadow-sm">
            <div className="flex items-center gap-4"><Layers className="text-[#AF6E4D]" /><h3 className="text-xs font-black text-[#3E2723] uppercase tracking-widest">Agrupaciones Ilimitadas (Packs, Cajas, Palets)</h3></div>
            <div className="grid grid-cols-1 sm:grid-cols-4 gap-4 items-end">
              <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Etiqueta (Ej: Estuche 6u)</label><input placeholder="Descripción..." value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" /></div>
              <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Unidades Contenidas</label><input type="number" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" /></div>
              <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Precio de Agrupación</label><input type="number" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" /></div>
              <button onClick={addGrouping} className="bg-[#3E2723] text-white p-4 rounded-2xl text-[10px] font-black uppercase hover:bg-[#AF6E4D] transition-all">+ Añadir</button>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mt-6">
              {formData.groupings?.map(g => (
                <div key={g.id} className="bg-white p-5 rounded-[24px] border border-[#D7CCC8]/30 flex justify-between items-center group shadow-sm">
                  <div>
                    <p className="text-[11px] font-black text-[#3E2723] uppercase">{g.label}</p>
                    <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{g.price} {g.currency} | Contiene {g.quantity} Unid.</p>
                  </div>
                  <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-300 hover:text-rose-500 transition-colors"><Trash2 size={16}/></button>
                </div>
              ))}
            </div>
          </section>
        </div>
        <div className="p-8 border-t bg-white flex justify-end gap-4 shadow-2xl">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs hover:text-[#3E2723] transition-colors">Cerrar</button>
          <button onClick={() => onSave(formData as Product)} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3 active:scale-95 transition-all"><Save size={18} /> Registrar Mercancía</button>
        </div>
      </div>
    );
  };

  // --- TERMINAL DE VENTAS (MECANISMO DE AGRUPACIONES) ---
  const SalesTerminal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');

    const addItem = (p: Product, grouping?: GroupingPrice) => {
      const id = Math.random().toString();
      const newItem: SaleItem = {
        id, productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: grouping?.label,
        quantity: 1, price: grouping ? grouping.price : p.unitPrice,
        currency: grouping ? grouping.currency : p.unitCurrency,
        total: grouping ? grouping.price : p.unitPrice,
        unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/80 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[60px] w-full max-w-7xl h-[92vh] overflow-hidden flex shadow-2xl animate-in zoom-in-95 duration-300">
          {/* Panel de Catálogo */}
          <div className="w-1/2 border-r border-[#D7CCC8]/30 flex flex-col p-12 bg-[#FCF9F7]">
            <div className="flex justify-between items-center mb-10">
               <h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal PaTí</h2>
               <button onClick={() => setShowSaleModal(false)} className="p-3 bg-white rounded-full"><X size={20}/></button>
            </div>
            <div className="relative mb-8">
               <Search className="absolute left-6 top-6 text-[#D7CCC8]" size={20} />
               <input placeholder="Busque producto por nombre..." value={search} onChange={e => setSearch(e.target.value)} className="w-full p-6 pl-16 bg-white border border-[#D7CCC8]/30 rounded-[32px] font-bold text-sm outline-none focus:border-[#AF6E4D]" />
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pr-2 custom-scrollbar">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 hover:border-[#AF6E4D] transition-all shadow-sm group">
                   <div className="flex justify-between items-start mb-6">
                      <div>
                        <h4 className="font-black text-sm uppercase text-[#3E2723]">{p.name}</h4>
                        <p className={`text-[9px] font-black uppercase mt-1 ${p.stock <= p.minStock ? 'text-rose-500' : 'text-[#AF6E4D]'}`}>Stock: {p.stock} U.</p>
                      </div>
                      <button onClick={() => addItem(p)} className="p-4 bg-[#3E2723] text-white rounded-2xl hover:bg-[#AF6E4D] shadow-lg">+ Unidad</button>
                   </div>
                   {p.groupings.length > 0 && (
                     <div className="flex flex-wrap gap-2 pt-4 border-t border-gray-50">
                        {p.groupings.map(g => (
                          <button key={g.id} onClick={() => addItem(p, g)} className="px-5 py-3 bg-[#F5F5DC] rounded-2xl text-[9px] font-black text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white transition-all border border-[#D7CCC8]/40 uppercase shadow-sm">
                            {g.label}: {g.price} {g.currency}
                          </button>
                        ))}
                     </div>
                   )}
                </div>
              ))}
            </div>
          </div>
          {/* Panel de Carrito / Factura */}
          <div className="w-1/2 flex flex-col p-12 bg-white">
            <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] mb-10">Despacho en Proceso</h3>
            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 animate-in slide-in-from-right-4">
                   <div className="flex-1">
                      <p className="text-xs font-black text-[#3E2723] uppercase">{item.productName}</p>
                      <p className="text-[9px] font-black text-[#AF6E4D] uppercase">{item.groupingLabel || 'Venta Unitaria'}</p>
                   </div>
                   <div className="flex items-center gap-8">
                      <div className="text-right"><p className="text-sm font-black text-[#3E2723]">{item.total.toLocaleString()} {item.currency}</p></div>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-rose-300 hover:text-rose-500 transition-colors"><Trash2 size={20}/></button>
                   </div>
                </div>
              ))}
              {cart.length === 0 && <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-40"><ShoppingCart size={80}/><p className="text-xs font-black uppercase mt-4">Terminal lista para vender</p></div>}
            </div>
            <div className="bg-[#3E2723] p-12 rounded-[50px] text-white shadow-2xl flex justify-between items-center border border-white/5 relative overflow-hidden">
               <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-emerald-400 to-[#3E2723]"></div>
               <div><p className="text-[10px] opacity-40 font-black uppercase mb-2">Total Facturado</p><p className="text-5xl font-black tracking-tighter tabular-nums">{totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
               <button disabled={cart.length === 0} onClick={() => {
                 const trans: Transaction = {
                   id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Público General',
                   items: cart, totalCup, totalUsd: 0, paymentMethod: 'Efectivo', status: 'Despachado', invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
                 };
                 setTransactions([trans, ...transactions]);
                 // Actualización de Stock físico
                 setProducts(prev => prev.map(p => {
                    const soldUnits = cart.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
                    return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
                 }));
                 setCart([]); setShowSaleModal(false); setSelectedInvoice(trans);
               }} className="bg-[#AF6E4D] text-white px-14 py-7 rounded-[32px] font-black uppercase text-xs shadow-xl hover:bg-white hover:text-[#3E2723] disabled:opacity-20 transition-all active:scale-95">Finalizar Pago</button>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-end"><h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario de Mercancía</h2><button onClick={() => setProductModal({show: true})} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl tracking-widest hover:scale-105 transition-all">+ Nueva Entrada</button></div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b text-[10px] uppercase text-[#AF6E4D] font-black tracking-widest">
                <tr><th className="px-10 py-8">Producto / SKU</th><th className="px-10 py-8 text-center">Stock</th><th className="px-10 py-8">Precios / Grupos</th><th className="px-10 py-8 text-right">Gestión</th></tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8"><p className="font-black text-sm uppercase tracking-tighter">{p.name}</p><p className="text-[9px] font-bold text-gray-300 uppercase mt-1">Ref: {p.id.slice(0,6)}</p></td>
                    <td className="px-10 py-8 text-center font-black text-lg">{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                    <td className="px-10 py-8 flex flex-wrap gap-2">
                       <span className="px-4 py-2 bg-[#FCF9F7] text-[10px] font-black rounded-xl border border-[#D7CCC8]/30 uppercase">U: {p.unitPrice} {p.unitCurrency}</span>
                       {p.groupings.map(g => <span key={g.id} className="px-4 py-2 bg-[#F5F5DC] text-[10px] font-black rounded-xl border border-[#D7CCC8]/50 uppercase">{g.label}</span>)}
                    </td>
                    <td className="px-10 py-8 text-right"><div className="flex justify-end gap-3"><button onClick={() => setProductModal({show: true, product: p})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#AF6E4D] hover:text-white transition-all shadow-sm"><Edit2 size={18} /></button><button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-4 bg-rose-50 text-rose-300 rounded-2xl hover:bg-rose-500 hover:text-white transition-all"><Trash2 size={18}/></button></div></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}
      {activeTab === 'sales' && <div className="h-full flex items-center justify-center py-20"><button onClick={() => setShowSaleModal(true)} className="bg-[#3E2723] text-white px-24 py-12 rounded-[50px] font-black uppercase text-2xl shadow-2xl hover:scale-105 hover:bg-[#AF6E4D] transition-all flex items-center gap-6"><ShoppingCart size={40}/> Abrir Terminal de Ventas</button></div>}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/80 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[94vh] flex flex-col animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6">
                 <Truck size={36} className="text-[#AF6E4D]" />
                 <h2 className="text-3xl font-black uppercase text-[#3E2723] tracking-tighter">{productModal.product ? 'Actualizar Ficha Técnica' : 'Recepción de Mercancía PaTí'}</h2>
              </div>
              <button onClick={() => { setProductModal({show: false}); if(activeTab === 'reception') setActiveTab('inventory'); }} className="p-3 text-rose-400 hover:rotate-90 transition-transform"><X size={36} /></button>
            </div>
            <ProductForm 
              initialData={productModal.product} 
              onSave={p => {
                const newP = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `SKU-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? newP : x));
                else setProducts([newP, ...products]);
                setProductModal({show: false});
                if(activeTab === 'reception') setActiveTab('inventory');
              }}
              onCancel={() => { setProductModal({show: false}); if(activeTab === 'reception') setActiveTab('inventory'); }}
            />
          </div>
        </div>
      )}

      {showSaleModal && <SalesTerminal />}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md no-print">
           <div className="bg-white rounded-[60px] w-full max-w-4xl shadow-2xl overflow-hidden flex flex-col max-h-[96vh]">
              <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
                 <h2 className="text-2xl font-black text-[#3E2723] uppercase tracking-tighter">Documento Comercial PaTí</h2>
                 <button onClick={() => setSelectedInvoice(null)} className="p-3"><X size={32}/></button>
              </div>
              <div className="flex-1 overflow-y-auto p-16 bg-white">
                 <div className="flex justify-between items-start mb-20">
                    <div className="bg-[#3E2723] p-10 rounded-[40px] shadow-2xl">
                       <img src={LOGO_URL} alt={STORE_NAME} className="h-28 w-auto object-contain brightness-[100]" />
                    </div>
                    <div className="text-right">
                       <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mb-2">Comprobante No.</p>
                       <p className="text-3xl font-black text-[#3E2723] mb-8">{selectedInvoice.invoiceNumber}</p>
                       <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mb-2">Fecha de Emisión</p>
                       <p className="text-lg font-black text-[#3E2723] uppercase">{new Date(selectedInvoice.date).toLocaleDateString()}</p>
                    </div>
                 </div>
                 <table className="w-full mb-16 text-left">
                    <thead><tr className="border-b-4 border-[#3E2723] text-[10px] font-black text-gray-400 uppercase tracking-widest"><th className="py-6">Detalle de Productos</th><th className="py-6 text-center">Cant</th><th className="py-6 text-right">Total</th></tr></thead>
                    <tbody className="divide-y-2 divide-[#F5F5DC]">
                       {selectedInvoice.items.map((item, idx) => (
                         <tr key={idx} className="text-sm font-bold text-[#3E2723]">
                            <td className="py-8 uppercase leading-tight"><p className="font-black text-[#3E2723]">{item.productName}</p>{item.groupingLabel && <p className="text-[9px] text-[#AF6E4D] uppercase mt-2 bg-[#F5F5DC] px-2 py-1 rounded w-fit">{item.groupingLabel}</p>}</td>
                            <td className="py-8 text-center">{item.quantity}</td>
                            <td className="py-8 text-right font-black tabular-nums">{item.total.toLocaleString()} {item.currency}</td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
                 <div className="flex justify-between items-end pt-12 border-t-4 border-[#3E2723]">
                    <div className="bg-[#F5F5DC]/50 p-6 rounded-[24px] border border-[#D7CCC8]/20">
                       <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Método de Pago</p>
                       <p className="text-sm font-black text-[#3E2723] uppercase">{selectedInvoice.paymentMethod}</p>
                    </div>
                    <div className="text-right"><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Monto Total Liquidado</p><p className="text-6xl font-black text-[#3E2723] tracking-tighter tabular-nums">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                 </div>
              </div>
              <div className="p-12 bg-[#F5F5DC]/30 border-t flex flex-col items-center gap-4">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-24 py-8 rounded-[40px] font-black uppercase text-sm tracking-widest shadow-2xl hover:scale-105 transition-all flex items-center gap-6"><Printer size={24}/> Generar Impresión / PDF</button>
                 <p className="text-[10px] text-[#8D6E63] font-black uppercase opacity-60 tracking-[0.2em]">Mercado PaTí - Calidad Garantizada</p>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'maintenance' && (
        <div className="flex flex-col items-center justify-center py-40 bg-white rounded-[80px] border border-[#D7CCC8]/20 shadow-sm animate-in zoom-in-95 duration-500">
           <div className="p-12 bg-[#F5F5DC] rounded-full mb-12 shadow-inner"><Database size={100} className="text-[#3E2723] opacity-60" /></div>
           <h2 className="text-5xl font-black uppercase mb-8 text-[#3E2723] tracking-tighter">Bóveda de Datos PaTí</h2>
           <p className="text-[#8D6E63] mb-16 max-w-lg text-center font-medium leading-relaxed">Resguarde la integridad de su negocio. Exporte o restaure la información crítica del inventario y ventas.</p>
           <div className="flex flex-col sm:flex-row gap-8">
              <button onClick={() => {
                const data = { products, contacts, transactions };
                const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="bg-[#3E2723] text-white px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6 shadow-2xl hover:bg-[#AF6E4D] transition-all"><Download size={24}/> Exportar Respaldo</button>
              <label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6 cursor-pointer hover:bg-[#D7CCC8] transition-all border border-[#D7CCC8]/40"><Upload size={24}/> Restaurar Datos <input type="file" className="hidden" accept=".json" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (event) => {
                  try {
