          </section>
        </div>
        <div className="p-8 border-t bg-white flex justify-end gap-4 shadow-2xl">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs hover:text-[#3E2723]">Descartar</button>
          <button onClick={() => onSave(formData as Product)} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3 active:scale-95 transition-all"><Save size={18} /> Registrar en PaTí</button>
        </div>
      </div>
    );
  };

  // --- TERMINAL DE VENTAS (CONTROLES DE CANTIDAD INTELIGENTES) ---
  const SalesTerminal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [saleStatus, setSaleStatus] = useState<'Solicitud' | 'Despachado'>('Despachado');

    const addItem = (p: Product, grouping?: GroupingPrice) => {
      const existing = cart.find(i => i.productId === p.id && i.groupingId === grouping?.id);
      if (existing) {
        updateQty(existing.id, 1);
        return;
      }

      const initialQty = grouping?.minOrderQuantity || 1;
      const newItem: SaleItem = {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: grouping?.label,
        quantity: initialQty, price: grouping ? grouping.price : p.unitPrice,
        currency: grouping ? grouping.currency : p.unitCurrency,
        total: (grouping ? grouping.price : p.unitPrice) * initialQty,
        unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
    };

    const updateQty = (id: string, delta: number) => {
      setCart(prev => prev.map(item => {
        if (item.id === id) {
          const product = products.find(p => p.id === item.productId);
          const grouping = product?.groupings.find(g => g.id === item.groupingId);
          const minRequired = grouping?.minOrderQuantity || 1;
          const newQty = Math.max(minRequired, item.quantity + delta);
          return { ...item, quantity: newQty, total: newQty * item.price };
        }
        return item;
      }));
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/80 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[60px] w-full max-w-7xl h-[92vh] overflow-hidden flex shadow-2xl animate-in zoom-in-95 duration-300">
          <div className="w-1/2 border-r border-[#D7CCC8]/30 flex flex-col p-12 bg-[#FCF9F7]">
            <div className="flex justify-between items-center mb-10">
               <h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Caja PaTí</h2>
               <button onClick={() => setShowSaleModal(false)} className="p-3 bg-white rounded-full hover:bg-rose-50 transition-colors"><X size={20}/></button>
            </div>
            <div className="relative mb-8">
               <Search className="absolute left-6 top-6 text-[#D7CCC8]" size={20} />
               <input placeholder="Busque producto..." value={search} onChange={e => setSearch(e.target.value)} className="w-full p-6 pl-16 bg-white border border-[#D7CCC8]/30 rounded-[32px] font-bold text-sm outline-none focus:border-[#AF6E4D] shadow-sm" />
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pr-2 custom-scrollbar">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 hover:border-[#AF6E4D] transition-all shadow-sm group">
                   <div className="flex justify-between items-start mb-6">
                      <div>
                        <h4 className="font-black text-sm uppercase text-[#3E2723]">{p.name}</h4>
                        <p className={`text-[9px] font-black uppercase mt-1 ${p.stock <= p.minStock ? 'text-rose-500 animate-pulse' : 'text-[#AF6E4D]'}`}>Stock: {p.stock} Unid.</p>
                      </div>
                      <button onClick={() => addItem(p)} className="p-4 bg-[#3E2723] text-white rounded-2xl hover:bg-[#AF6E4D] shadow-xl transition-all">+ Unidad</button>
                   </div>
                   {p.groupings.length > 0 && (
                     <div className="flex flex-wrap gap-2 pt-4 border-t border-gray-50">
                        {p.groupings.map(g => (
                          <button key={g.id} onClick={() => addItem(p, g)} className="px-5 py-3 bg-[#F5F5DC] rounded-2xl text-[9px] font-black text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white transition-all border border-[#D7CCC8]/40 uppercase shadow-sm">
                            {g.label}: {g.price} {g.currency} {g.minOrderQuantity ? `(Mín: ${g.minOrderQuantity})` : ''}
                          </button>
                        ))}
                     </div>
                   )}
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-12 bg-white">
            <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] mb-10">Despacho Actual</h3>
            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 animate-in slide-in-from-right-4">
                   <div className="flex-1">
                      <p className="text-xs font-black text-[#3E2723] uppercase">{item.productName}</p>
                      <p className="text-[9px] font-black text-[#AF6E4D] uppercase">{item.groupingLabel || 'Venta Unitaria'}</p>
                   </div>
                   <div className="flex items-center gap-6">
                      <div className="flex items-center bg-white rounded-2xl border border-[#D7CCC8]/30 p-1.5 shadow-sm">
                         <button onClick={() => updateQty(item.id, -1)} className="p-2 text-[#D7CCC8] hover:text-rose-400 transition-colors"><Minus size={14}/></button>
                         <span className="w-10 text-center font-black text-sm text-[#3E2723]">{item.quantity}</span>
                         <button onClick={() => updateQty(item.id, 1)} className="p-2 text-[#3E2723] hover:text-[#AF6E4D] transition-all"><Plus size={14}/></button>
                      </div>
                      <div className="text-right w-24"><p className="text-sm font-black text-[#3E2723]">{item.total.toLocaleString()} {item.currency}</p></div>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-rose-300 hover:text-rose-500 transition-colors"><Trash2 size={20}/></button>
                   </div>
                </div>
              ))}
              {cart.length === 0 && <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-40"><ShoppingCart size={80}/><p className="text-xs font-black uppercase mt-4">Carrito de Venta Vacío</p></div>}
            </div>
            <div className="space-y-6">
               <div className="flex gap-4">
                  <button onClick={() => setSaleStatus('Solicitud')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase border transition-all ${saleStatus === 'Solicitud' ? 'bg-[#F5F5DC] border-[#AF6E4D] text-[#3E2723] shadow-md' : 'bg-white border-gray-100 text-gray-300'}`}>Pre-Factura</button>
                  <button onClick={() => setSaleStatus('Despachado')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase border transition-all ${saleStatus === 'Despachado' ? 'bg-[#3E2723] border-[#3E2723] text-white shadow-xl' : 'bg-white border-gray-100 text-gray-300'}`}>Factura Final</button>
               </div>
               <div className="bg-[#3E2723] p-12 rounded-[50px] text-white shadow-2xl flex justify-between items-center border border-white/5 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-emerald-400 to-[#3E2723]"></div>
                  <div><p className="text-[10px] opacity-40 font-black uppercase mb-2">Total a Cobrar</p><p className="text-5xl font-black tracking-tighter tabular-nums">{totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                  <button disabled={cart.length === 0} onClick={() => {
                    const trans: Transaction = {
                      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Público Gral',
                      items: cart, totalCup, totalUsd: 0, paymentMethod: 'Efectivo', status: saleStatus, invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
                    };
                    setTransactions([trans, ...transactions]);
                    if (saleStatus === 'Despachado') {
                      setProducts(prev => prev.map(p => {
                        const soldUnits = cart.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
                        return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
                      }));
                    }
                    setCart([]); setShowSaleModal(false); setSelectedInvoice(trans);
                  }} className="bg-[#AF6E4D] text-white px-14 py-7 rounded-[32px] font-black uppercase text-xs shadow-xl hover:bg-white hover:text-[#3E2723] disabled:opacity-20 transition-all active:scale-95">Procesar {saleStatus}</button>
               </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-end"><h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario de Mercancía</h2><button onClick={() => setProductModal({show: true})} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl tracking-widest hover:scale-105 transition-all">+ Nueva Entrada</button></div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b text-[10px] uppercase text-[#AF6E4D] font-black tracking-widest">
                <tr><th className="px-10 py-8">Producto / SKU</th><th className="px-10 py-8 text-center">Stock</th><th className="px-10 py-8">Venta Unit.</th><th className="px-10 py-8">Agrupaciones</th><th className="px-10 py-8 text-right">Gestión</th></tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8"><p className="font-black text-sm uppercase tracking-tighter">{p.name}</p><p className="text-[9px] font-bold text-gray-300 uppercase mt-1">{p.sku}</p></td>
                    <td className="px-10 py-8 text-center font-black text-lg">{p.stock} <span className="text-[10px] opacity-30 uppercase">Unid.</span></td>
                    <td className="px-10 py-8 font-black uppercase text-xs">{p.unitPrice} {p.unitCurrency}</td>
                    <td className="px-10 py-8 flex flex-wrap gap-2">
                       {p.groupings.map(g => <span key={g.id} className="px-3 py-1 bg-[#F5F5DC] text-[9px] font-black rounded-lg border border-[#D7CCC8]/50 uppercase">{g.label}</span>)}
                       {p.groupings.length === 0 && <span className="text-[9px] text-gray-300 italic">Sólo unitario</span>}
                    </td>
                    <td className="px-10 py-8 text-right"><div className="flex justify-end gap-3"><button onClick={() => setProductModal({show: true, product: p})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#AF6E4D] hover:text-white transition-all"><Edit2 size={18} /></button><button onClick={() => setProducts(products.filter(x => x.id !== p.id))} className="p-4 bg-rose-50 text-rose-300 rounded-2xl hover:bg-rose-500 hover:text-white transition-all"><Trash2 size={18}/></button></div></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'closure' && (
        <div className="max-w-4xl mx-auto py-12 animate-in zoom-in-95 duration-500">
           <div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl overflow-hidden">
              <div className="p-16 border-b bg-[#F5F5DC]/40 flex justify-between items-center shadow-inner">
                 <div>
                    <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Cierre del Día</h2>
                    <p className="text-xs font-bold text-[#AF6E4D] uppercase mt-2 tracking-widest">Auditoría Operativa: {new Date().toLocaleDateString()}</p>
                 </div>
                 <Wallet size={80} className="text-[#AF6E4D] opacity-20" strokeWidth={1}/>
              </div>
              <div className="p-16 grid grid-cols-1 md:grid-cols-2 gap-10 bg-[#FCF9F7]/30">
                 {[
                   { label: 'Caja Efectivo Hoy (CUP)', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado' && t.paymentMethod === 'Efectivo').reduce((a, b) => a + b.totalCup, 0), icon: DollarSign, color: 'text-[#3E2723]' },
                   { label: 'Pre-Facturas (Solicitudes)', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Solicitud').length, icon: FileText, color: 'text-[#AF6E4D]' },
                   { label: 'Facturas Emitidas', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').length, icon: ShoppingCart, color: 'text-[#3E2723]' },
                   { label: 'Unidades Despachadas', value: transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').reduce((acc, t) => acc + t.items.reduce((s, i) => s + (i.unitQuantity * i.quantity), 0), 0), icon: Package, color: 'text-[#AF6E4D]' }
                 ].map((stat, i) => (
                   <div key={i} className="bg-white p-10 rounded-[40px] border border-[#D7CCC8]/30 shadow-sm">
                      <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-4 flex items-center gap-3"><stat.icon size={14} /> {stat.label}</p>
                      <p className={`text-3xl font-black tracking-tighter tabular-nums ${stat.color}`}>{stat.value.toLocaleString()}</p>
                   </div>
                 ))}
                 <div className="col-span-full pt-10 flex flex-col items-center">
                    <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl hover:scale-105 transition-all flex items-center gap-6"><CheckCircle2 size={24}/> Generar Reporte de Cierre Oficial</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}
      {activeTab === 'sales' && (
        <div className="h-full flex flex-col items-center justify-center py-20 space-y-12">
           <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal de Ventas PaTí</h2>
              <p className="text-xl text-[#AF6E4D] font-medium italic">Seleccione mercancía para facturar o generar solicitudes.</p>
           </div>
           <button onClick={() => setShowSaleModal(true)} className="bg-[#3E2723] text-white px-24 py-12 rounded-[50px] font-black uppercase text-2xl shadow-2xl hover:scale-105 hover:bg-[#AF6E4D] transition-all flex items-center gap-8 group">
              <div className="bg-white/10 p-5 rounded-full group-hover:bg-white/20 transition-all"><ShoppingCart size={48}/></div>
              Iniciar Operación de Caja
           </button>
        </div>
      )}

      {productModal.show && (
        <div className="fixed inset-0 bg-black/80 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[94vh] flex flex-col animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6">
                 <Truck size={36} className="text-[#AF6E4D]" />
                 <h2 className="text-3xl font-black uppercase text-[#3E2723] tracking-tighter">{productModal.product ? 'Actualizar Ficha Técnica' : 'Recepción de Mercancía PaTí'}</h2>
              </div>
              <button onClick={() => { setProductModal({show: false}); if(activeTab === 'reception') setActiveTab('inventory'); }} className="p-3 text-rose-400 hover:rotate-90 transition-transform"><X size={36} /></button>
            </div>
            <ProductForm 
              initialData={productModal.product} 
              onSave={p => {
                const newP = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `SKU-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? newP : x));
                else setProducts([newP, ...products]);
                setProductModal({show: false});
                if(activeTab === 'reception') setActiveTab('inventory');
              }}
              onCancel={() => { setProductModal({show: false}); if(activeTab === 'reception') setActiveTab('inventory'); }}
            />
          </div>
        </div>
      )}

      {showSaleModal && <SalesTerminal />}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md no-print">
           <div className="bg-white rounded-[60px] w-full max-w-4xl shadow-2xl overflow-hidden flex flex-col max-h-[96vh]">
              <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
                 <h2 className="text-2xl font-black text-[#3E2723] uppercase tracking-tighter">Documento Comercial PaTí</h2>
                 <button onClick={() => setSelectedInvoice(null)} className="p-3 hover:bg-rose-50 rounded-full transition-all"><X size={32}/></button>
              </div>
              <div className="flex-1 overflow-y-auto p-16 bg-white print:p-0">
                 <div className="flex justify-between items-start mb-20">
                    <div className="bg-[#3E2723] p-10 rounded-[40px] shadow-2xl">
                       <img src={LOGO_URL} alt={STORE_NAME} className="h-28 w-auto object-contain brightness-[100]" onError={(e) => e.currentTarget.style.display='none'} />
                    </div>
                    <div className="text-right">
                       <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mb-2">Comprobante No.</p>
                       <p className="text-3xl font-black text-[#3E2723] mb-8">{selectedInvoice.invoiceNumber}</p>
                       <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mb-2">Tipo de Documento</p>
                       <p className="text-lg font-black text-[#AF6E4D] uppercase">{selectedInvoice.status === 'Solicitud' ? 'Pre-Factura / Cotización' : 'Factura de Despacho'}</p>
                       <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mt-4 mb-2">Fecha de Emisión</p>
                       <p className="text-lg font-black text-[#3E2723] uppercase">{new Date(selectedInvoice.date).toLocaleDateString()}</p>
                    </div>
                 </div>
                 <table className="w-full mb-16 text-left">
                    <thead><tr className="border-b-4 border-[#3E2723] text-[10px] font-black text-gray-400 uppercase tracking-widest"><th className="py-6">Detalle de Productos</th><th className="py-6 text-center">Cantidad</th><th className="py-6 text-right">Precio</th><th className="py-6 text-right">Subtotal</th></tr></thead>
                    <tbody className="divide-y-2 divide-[#F5F5DC]">
                       {selectedInvoice.items.map((item, idx) => (
                         <tr key={idx} className="text-sm font-bold text-[#3E2723]">
                            <td className="py-8 uppercase leading-tight"><p className="font-black text-[#3E2723]">{item.productName}</p>{item.groupingLabel && <p className="text-[9px] text-[#AF6E4D] uppercase mt-2 bg-[#F5F5DC] px-2 py-1 rounded w-fit">{item.groupingLabel}</p>}</td>
                            <td className="py-8 text-center">{item.quantity}</td>
                            <td className="py-8 text-right tabular-nums">{item.price.toLocaleString()} {item.currency}</td>
                            <td className="py-8 text-right font-black tabular-nums">{item.total.toLocaleString()} {item.currency}</td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
                 <div className="flex justify-between items-end pt-12 border-t-4 border-[#3E2723]">
                    <div className="bg-[#F5F5DC]/50 p-6 rounded-[24px] border border-[#D7CCC8]/20 text-center">
                       <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Caja Operativa</p>
                       <p className="text-sm font-black text-[#3E2723] uppercase">{selectedInvoice.paymentMethod}</p>
                    </div>
                    <div className="text-right"><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Monto Total Liquidado</p><p className="text-6xl font-black text-[#3E2723] tracking-tighter tabular-nums">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                 </div>
              </div>
              <div className="p-12 bg-[#F5F5DC]/30 border-t flex flex-col items-center gap-4">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-24 py-8 rounded-[40px] font-black uppercase text-sm tracking-widest shadow-2xl hover:scale-105 transition-all flex items-center gap-6"><Printer size={24}/> Generar Impresión / PDF Oficial</button>
                 <p className="text-[10px] text-[#8D6E63] font-black uppercase opacity-60 tracking-[0.2em]">Mercado PaTí - Gracias por su confianza</p>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'maintenance' && (
        <div className="flex flex-col items-center justify-center py-40 bg-white rounded-[80px] border border-[#D7CCC8]/20 shadow-sm animate-in zoom-in-95 duration-500">
           <div className="p-12 bg-[#F5F5DC] rounded-full mb-12 shadow-inner"><Database size={100} className="text-[#3E2723] opacity-60" /></div>
           <h2 className="text-5xl font-black uppercase mb-8 text-[#3E2723] tracking-tighter">Gestión de Datos PaTí</h2>
           <p className="text-[#8D6E63] mb-16 max-w-lg text-center font-medium leading-relaxed">Administre la integridad de su sistema. Exporte respaldos o restaure la base de datos de inventario y socios comerciales.</p>
           <div className="flex flex-col sm:flex-row gap-8">
              <button onClick={() => {
                const data = { products, contacts, transactions };
                const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
                const url = URL.createObjectURL(blob);
                const link = document.createElement('a');
                link.href = url;
                link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="bg-[#3E2723] text-white px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6 shadow-2xl hover:bg-[#AF6E4D] transition-all"><Download size={24}/> Exportar Base de Datos</button>
              <label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6 cursor-pointer hover:bg-[#D7CCC8] transition-all border border-[#D7CCC8]/40"><Upload size={24}/> Importar Respaldo <input type="file" className="hidden" accept=".json" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (event) => {
                  try {
                    const data = JSON.parse(event.target?.result as string);
                    if (data.products) setProducts(data.products);
                    if (data.contacts) setContacts(data.contacts);
                    if (data.transactions) setTransactions(data.transactions);
                    alert('Restauración completada con éxito en PaTí.');
                  } catch (err) { alert('Error al procesar el archivo.'); }
                };
                reader.readAsText(file);
              }} /></label>
           </div>
        </div>
      )}
    </Layout>
  );
};

