                  <button onClick={() => setSaleStatus('Despachado')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase border transition-all ${saleStatus === 'Despachado' ? 'bg-[#3E2723] border-[#3E2723] text-white shadow-xl' : 'bg-white border-gray-100 text-gray-300'}`}>Factura de Despacho</button>
