    const addItem = (p: Product, grouping?: GroupingPrice) => {
      const existing = cart.find(i => i.productId === p.id && i.groupingId === grouping?.id);
      if (existing) {
        updateQty(existing.id, 1);
        return;
      }

      const initialQty = grouping?.minOrderQuantity || 1;
      const newItem: SaleItem = {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: grouping?.label,
        quantity: initialQty, price: grouping ? grouping.price : p.unitPrice,
        currency: grouping ? grouping.currency : p.unitCurrency,
        total: (grouping ? grouping.price : p.unitPrice) * initialQty,
        unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
    };

    const updateQty = (id: string, delta: number) => {
      setCart(prev => prev.map(item => {
        if (item.id === id) {
          const product = products.find(p => p.id === item.productId);
          const grouping = product?.groupings.find(g => g.id === item.groupingId);
          const minRequired = grouping?.minOrderQuantity || 1;
          const newQty = Math.max(minRequired, item.quantity + delta);
          return { ...item, quantity: newQty, total: newQty * item.price };
        }
        return item;
      }));
    };

