                  <div><p className="text-[10px] opacity-40 font-black uppercase mb-2">Monto Total</p><p className="text-5xl font-black tracking-tighter tabular-nums">{totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
