                 <button type="submit" className="w-full bg-[#3E2723] text-white py-8 rounded-[36px] font-black uppercase text-xs shadow-2xl hover:bg-[#AF6E4D] transition-all active:scale-95">Registrar en Directorio</button>
              </form>
           </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

export type Currency = 'CUP' | 'USD';
export type PaymentMethod = 'Efectivo' | 'Transferencia';
export type ReceptionType = 'Consignación' | 'Compra Directa';

export interface GroupingPrice {
  id: string;
  label: string; // e.g., "Estuche de 6u", "Palet"
  quantity: number; // units included in one group
  price: number;
  currency: Currency;
  minOrderQuantity?: number; // Minimum groups needed for this price
}

export interface StoreConfig {
  logoUrl: string;
  storeName: string;
  aboutText: string;
  address: string;
  phone: string;
  email: string;
  facebookUrl: string;
  instagramUrl: string;
  websiteUrl: string;
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  description: string;
  categoryId: string;
  supplierId: string;
  receptionType: ReceptionType;
  unitPrice: number; // Selling price
  unitCurrency: Currency;
  costPrice: number; // Cost price (added)
  groupings: GroupingPrice[];
  stock: number;
  minStock: number;
  expiryDate: string;
  receivedDate: string;
  isOffer?: boolean;
}

export interface Contact {
  id: string;
  name: string;
  contactName: string;
  phone: string;
  email: string;
  address: string;
  type: 'Proveedor' | 'Cliente';
  isConsignee?: boolean;
  pendingBalanceCup: number;
  pendingBalanceUsd: number;
}

export interface SaleItem {
  id: string;
  productId: string;
  productName: string;
  groupingId?: string; 
  groupingLabel?: string;
  quantity: number;
  price: number;
  total: number;
  currency: Currency;
  unitQuantity: number;
}

export interface Transaction {
  id: string;
  date: string;
  clientId: string;
  clientName: string;
  items: SaleItem[];
  totalCup: number;
  totalUsd: number;
  paymentMethod: PaymentMethod;
  status: 'Solicitud' | 'Despachado' | 'Anulado';
  invoiceNumber: string;
}

export interface Notification {
  id: string;
  title: string;
  message: string;
  type: 'warning' | 'info' | 'error' | 'success';
  date: string;
  read: boolean;
}

