                        {p.groupings.map(g => (
                          <button key={g.id} onClick={() => addItem(p, g)} className="px-5 py-3 bg-[#F5F5DC] rounded-2xl text-[9px] font-black text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white transition-all border border-[#D7CCC8]/40 uppercase">
                            {g.label}: {g.price} {g.currency}
                          </button>
                        ))}
                     </div>
                   )}
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-12 bg-white">
            <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] mb-10">Cesta de Venta</h3>
            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10">
                   <div className="flex-1">
                      <p className="text-xs font-black text-[#3E2723] uppercase">{item.productName}</p>
                      <p className="text-[9px] font-black text-[#AF6E4D] uppercase">{item.groupingLabel || 'Unitario'}</p>
                   </div>
                   <div className="flex items-center gap-6">
                      <div className="flex items-center bg-white rounded-2xl border border-[#D7CCC8]/30 p-1.5">
                         <button onClick={() => updateQty(item.id, -1)} className="p-2 text-[#D7CCC8] hover:text-rose-400"><Minus size={14}/></button>
                         <span className="w-10 text-center font-black text-sm">{item.quantity}</span>
                         <button onClick={() => updateQty(item.id, 1)} className="p-2 text-[#3E2723] hover:text-[#AF6E4D]"><Plus size={14}/></button>
                      </div>
                      <div className="text-right w-24 font-black">{item.total.toLocaleString()} {item.currency}</div>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-rose-300 hover:text-rose-500"><Trash2 size={20}/></button>
                   </div>
                </div>
              ))}
              {cart.length === 0 && <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-40"><ShoppingCart size={80}/><p className="text-xs font-black mt-4 uppercase">Listo para facturar</p></div>}
            </div>
            <div className="space-y-6">
               <div className="flex gap-4">
                  <button onClick={() => setSaleStatus('Solicitud')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase transition-all ${saleStatus === 'Solicitud' ? 'bg-[#F5F5DC] border-[#AF6E4D] text-[#3E2723] shadow-md' : 'bg-white border-gray-100 text-gray-300 border'}`}>Pre-Factura</button>
                  <button onClick={() => setSaleStatus('Despachado')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase transition-all ${saleStatus === 'Despachado' ? 'bg-[#3E2723] text-white shadow-xl' : 'bg-white border-gray-100 text-gray-300 border'}`}>Factura Final</button>
               </div>
               <div className="bg-[#3E2723] p-12 rounded-[50px] text-white shadow-2xl flex justify-between items-center relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-[#AF6E4D] to-[#3E2723]"></div>
                  <div><p className="text-[10px] opacity-40 font-black uppercase mb-2">Total</p><p className="text-5xl font-black">{totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                  <button disabled={cart.length === 0} onClick={() => {
                    const trans: Transaction = {
                      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Público Gral',
                      items: cart, totalCup, totalUsd: 0, paymentMethod: 'Efectivo', status: saleStatus, invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
                    };
                    setTransactions([trans, ...transactions]);
                    if (saleStatus === 'Despachado') {
                      setProducts(prev => prev.map(p => {
                        const soldUnits = cart.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
                        return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
                      }));
                    }
                    setCart([]); setShowSaleModal(false); setSelectedInvoice(trans);
                  }} className="bg-[#AF6E4D] text-white px-14 py-7 rounded-[32px] font-black uppercase text-xs shadow-xl hover:bg-white hover:text-[#3E2723] disabled:opacity-20 transition-all">Cobrar {saleStatus}</button>
               </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'about' && (
        <div className="max-w-5xl mx-auto space-y-16 py-10 animate-in fade-in duration-700">
           <div className="relative h-[500px] rounded-[80px] overflow-hidden shadow-2xl border-[12px] border-white">
              <img src="https://images.unsplash.com/photo-1578916171728-46686eac8d58?auto=format&fit=crop&q=80&w=1400" className="w-full h-full object-cover brightness-[0.5]" />
              <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-12">
                 <div className="bg-white/10 backdrop-blur-2xl p-8 rounded-[40px] border border-white/30 mb-10 shadow-2xl">
                    <img src={config.logoUrl} alt={config.storeName} className="h-32 w-auto object-contain brightness-110" />
                 </div>
                 <h2 className="text-6xl font-black text-white uppercase tracking-tighter mb-4">Sobre {config.storeName}</h2>
                 <p className="text-white/80 text-xl font-medium max-w-2xl leading-relaxed italic">"{config.aboutText}"</p>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'contact' && (
        <div className="max-w-6xl mx-auto py-10 animate-in zoom-in-95 duration-500">
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="bg-[#3E2723] rounded-[70px] p-16 text-white shadow-2xl relative overflow-hidden">
                 <h2 className="text-5xl font-black uppercase mb-10">Contacto</h2>
                 <div className="space-y-10">
                    <div className="flex items-center gap-8 group">
                       <div className="w-16 h-16 bg-white/10 rounded-[28px] flex items-center justify-center group-hover:bg-[#AF6E4D] transition-all"><Phone size={24}/></div>
                       <div><p className="text-[10px] font-black uppercase opacity-40 mb-1">Teléfono</p><p className="text-2xl font-black">{config.phone}</p></div>
                    </div>
                    <div className="flex items-center gap-8 group">
                       <div className="w-16 h-16 bg-white/10 rounded-[28px] flex items-center justify-center group-hover:bg-[#AF6E4D] transition-all"><Mail size={24}/></div>
                       <div><p className="text-[10px] font-black uppercase opacity-40 mb-1">Correo</p><p className="text-2xl font-black">{config.email}</p></div>
                    </div>
                    <div className="flex items-center gap-8 group">
                       <div className="w-16 h-16 bg-white/10 rounded-[28px] flex items-center justify-center group-hover:bg-[#AF6E4D] transition-all"><MapPin size={24}/></div>
                       <div><p className="text-[10px] font-black uppercase opacity-40 mb-1">Dirección</p><p className="text-2xl font-black leading-tight">{config.address}</p></div>
                    </div>
                 </div>
              </div>
              <div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 p-16">
                 <h3 className="text-2xl font-black text-[#3E2723] uppercase mb-10">Redes Sociales</h3>
                 <div className="space-y-6">
                    <a href={config.facebookUrl} target="_blank" className="flex items-center gap-6 p-6 bg-[#FCF9F7] rounded-[32px] hover:bg-[#F5F5DC] transition-all"><Facebook className="text-[#AF6E4D]"/><span className="font-black uppercase text-xs">Facebook</span></a>
                    <a href={config.instagramUrl} target="_blank" className="flex items-center gap-6 p-6 bg-[#FCF9F7] rounded-[32px] hover:bg-[#F5F5DC] transition-all"><Instagram className="text-[#AF6E4D]"/><span className="font-black uppercase text-xs">Instagram</span></a>
                    <a href={config.websiteUrl} target="_blank" className="flex items-center gap-6 p-6 bg-[#FCF9F7] rounded-[32px] hover:bg-[#F5F5DC] transition-all"><Globe className="text-[#AF6E4D]"/><span className="font-black uppercase text-xs">Sitio Web</span></a>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-end">
             <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario y Logística</h2>
             <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl hover:scale-105 transition-all">+ Nueva Recepción</button>
          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b text-[10px] uppercase text-[#AF6E4D] font-black tracking-widest">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Stock</th><th className="px-10 py-8">Costo</th><th className="px-10 py-8">Venta Unit.</th><th className="px-10 py-8">Agrupaciones</th><th className="px-10 py-8 text-right">Acción</th></tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8">
                      <p className="font-black text-sm uppercase">{p.name}</p>
                      {p.unitPrice <= 0 && <span className="text-[8px] font-black bg-rose-100 text-rose-600 px-2 py-0.5 rounded uppercase mt-1 inline-block">Falta Precio Venta</span>}
                    </td>
                    <td className="px-10 py-8 text-center font-black text-lg">{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                    <td className="px-10 py-8 font-black text-xs">{p.costPrice} CUP</td>
                    <td className="px-10 py-8 font-black text-xs text-[#AF6E4D]">{p.unitPrice > 0 ? `${p.unitPrice} ${p.unitCurrency}` : '--'}</td>
                    <td className="px-10 py-8 flex flex-wrap gap-2">
                       {p.groupings.map(g => <span key={g.id} className="px-3 py-1 bg-[#F5F5DC] text-[9px] font-black rounded-lg border border-[#D7CCC8]/50 uppercase">{g.label}</span>)}
                    </td>
                    <td className="px-10 py-8 text-right">
                       <button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#AF6E4D] hover:text-white transition-all"><Edit2 size={18} /></button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* VISTA CONFIGURACIÓN (NUEVA) */}
      {activeTab === 'config' && (
        <div className="max-w-4xl mx-auto space-y-10 py-10 animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-white rounded-[60px] border border-[#D7CCC8]/30 shadow-2xl p-16">
            <h2 className="text-4xl font-black text-[#3E2723] uppercase mb-12 flex items-center gap-6"><Settings size={40} className="text-[#AF6E4D]"/> Configuración de la Tienda</h2>
            <div className="space-y-12">
               <section className="space-y-6">
                  <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] border-b pb-4">Identidad Visual</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                     <div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">URL del Logo</label><input value={config.logoUrl} onChange={e => setConfig({...config, logoUrl: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[28px] font-bold" /></div>
                     <div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Nombre de la Tienda</label><input value={config.storeName} onChange={e => setConfig({...config, storeName: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[28px] font-bold" /></div>
                  </div>
               </section>
               <section className="space-y-6">
                  <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] border-b pb-4">Contacto y Ubicación</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                     <div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Teléfono</label><input value={config.phone} onChange={e => setConfig({...config, phone: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[28px] font-bold" /></div>
                     <div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Email</label><input value={config.email} onChange={e => setConfig({...config, email: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[28px] font-bold" /></div>
                     <div className="col-span-full space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Dirección Física</label><input value={config.address} onChange={e => setConfig({...config, address: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[28px] font-bold" /></div>
                     <div className="col-span-full space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Texto "Nosotros"</label><textarea value={config.aboutText} onChange={e => setConfig({...config, aboutText: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-[28px] h-32 font-bold" /></div>
                  </div>
               </section>
               <section className="space-y-6">
                  <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] border-b pb-4">Redes Sociales</h3>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                     <div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Facebook URL</label><input value={config.facebookUrl} onChange={e => setConfig({...config, facebookUrl: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold text-xs" /></div>
                     <div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Instagram URL</label><input value={config.instagramUrl} onChange={e => setConfig({...config, instagramUrl: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold text-xs" /></div>
                     <div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Website URL</label><input value={config.websiteUrl} onChange={e => setConfig({...config, websiteUrl: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold text-xs" /></div>
                  </div>
               </section>
            </div>
          </div>
        </div>
      )}

      {/* MODAL DE PRODUCTO (RECEPCIÓN O EDICIÓN) */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/80 z-[150] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[94vh] flex flex-col animate-in zoom-in-95 duration-300">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6">
                 {productModal.mode === 'reception' ? <Truck size={36} className="text-[#AF6E4D]" /> : <Edit2 size={36} className="text-[#AF6E4D]"/>}
                 <h2 className="text-3xl font-black uppercase text-[#3E2723] tracking-tighter">
                   {productModal.mode === 'reception' ? 'Nueva Recepción' : `Editando Logística: ${productModal.product?.name}`}
                 </h2>
              </div>
              <button onClick={() => { setProductModal({show: false, mode: 'reception'}); if(activeTab === 'reception') setActiveTab('inventory'); }} className="p-3 text-rose-400 hover:rotate-90 transition-transform"><X size={36} /></button>
            </div>
            <ProductForm 
              mode={productModal.mode}
              initialData={productModal.product} 
              onSave={p => {
                const newP = { ...p, id: p.id || Math.random().toString(36).substr(2, 9), sku: p.sku || `SKU-${Date.now().toString().slice(-4)}` };
                if (productModal.product) setProducts(products.map(x => x.id === p.id ? newP : x));
                else setProducts([newP, ...products]);
                setProductModal({show: false, mode: 'reception'});
                if(activeTab === 'reception') setActiveTab('inventory');
              }}
              onCancel={() => { setProductModal({show: false, mode: 'reception'}); if(activeTab === 'reception') setActiveTab('inventory'); }}
            />
          </div>
        </div>
      )}

      {showSaleModal && <SalesTerminal />}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md no-print">
           <div className="bg-white rounded-[60px] w-full max-w-4xl shadow-2xl overflow-hidden flex flex-col max-h-[96vh]">
              <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
                 <h2 className="text-2xl font-black text-[#3E2723] uppercase tracking-tighter">Comprobante de Operación</h2>
                 <button onClick={() => setSelectedInvoice(null)} className="p-3"><X size={32}/></button>
              </div>
              <div className="flex-1 overflow-y-auto p-16 bg-white">
                 <div className="flex justify-between items-start mb-20">
                    <div className="bg-[#3E2723] p-10 rounded-[40px] shadow-2xl">
                       <img src={config.logoUrl} alt={config.storeName} className="h-28 w-auto object-contain brightness-[100]" />
                    </div>
                    <div className="text-right">
                       <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest mb-2">Folio Interno</p>
                       <p className="text-3xl font-black text-[#3E2723] mb-8">{selectedInvoice.invoiceNumber}</p>
                       <p className="text-lg font-black text-[#AF6E4D] uppercase">{selectedInvoice.status === 'Solicitud' ? 'Pre-Factura' : 'Factura de Venta'}</p>
                       <p className="text-lg font-black text-[#3E2723] uppercase mt-2">{new Date(selectedInvoice.date).toLocaleDateString()}</p>
                    </div>
                 </div>
                 <table className="w-full mb-16 text-left">
                    <thead><tr className="border-b-4 border-[#3E2723] text-[10px] font-black text-gray-400 uppercase tracking-widest"><th className="py-6">Concepto</th><th className="py-6 text-center">Cantidad</th><th className="py-6 text-right">Subtotal</th></tr></thead>
                    <tbody className="divide-y-2 divide-[#F5F5DC]">
                       {selectedInvoice.items.map((item, idx) => (
                         <tr key={idx} className="text-sm font-bold text-[#3E2723]">
                            <td className="py-8 uppercase leading-tight"><p className="font-black">{item.productName}</p>{item.groupingLabel && <p className="text-[9px] text-[#AF6E4D] uppercase mt-1">{item.groupingLabel}</p>}</td>
                            <td className="py-8 text-center">{item.quantity}</td>
                            <td className="py-8 text-right font-black tabular-nums">{item.total.toLocaleString()} {item.currency}</td>
                         </tr>
                       ))}
                    </tbody>
                 </table>
                 <div className="text-right pt-12 border-t-4 border-[#3E2723]"><p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Total Liquidado</p><p className="text-6xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
              </div>
              <div className="p-12 bg-[#F5F5DC]/30 border-t flex flex-col items-center">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-24 py-8 rounded-[40px] font-black uppercase text-sm shadow-2xl hover:scale-105 transition-all flex items-center gap-6"><Printer size={24}/> Imprimir Documento</button>
              </div>
           </div>
        </div>
      )}

    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { 
  Home,
  Info,
  PhoneCall,
  Package, 
  Truck, 
  ShoppingCart, 
  Users, 
  Database, 
  BarChart3, 
  Bell,
  Menu,
  X,
  Wallet,
  Settings
} from 'lucide-react';
import { Notification, StoreConfig } from '../types';

const STORAGE_KEYS = {
  CONFIG: 'pati_v3_config'
};

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  notifications: Notification[];
  onNotificationRead: (id: string) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, notifications, onNotificationRead }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isNotifOpen, setIsNotifOpen] = useState(false);
  const [config, setConfig] = useState<StoreConfig>({ 
    logoUrl: "https://i.ibb.co/L6S9Dkz/pati-logo.jpg", 
    storeName: "PaTí",
    aboutText: "", address: "", phone: "", email: "", facebookUrl: "", instagramUrl: "", websiteUrl: ""
  });

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CONFIG);
    if (saved) setConfig(JSON.parse(saved));
  }, [activeTab]); // Actualizar logo si cambia el tab (podría ser después de guardar config)

  const unreadCount = notifications.filter(n => !n.read).length;

  const menuItems = [
    { id: 'home', label: 'Inicio', icon: Home, section: 'Explorar' },
    { id: 'about', label: 'Nosotros', icon: Info, section: 'Explorar' },
    { id: 'contact', label: 'Contactos', icon: PhoneCall, section: 'Explorar' },
    { id: 'inventory', label: 'Inventario', icon: Package, section: 'Gestión' },
    { id: 'reception', label: 'Recepción', icon: Truck, section: 'Gestión' },
    { id: 'sales', label: 'Ventas', icon: ShoppingCart, section: 'Gestión' },
    { id: 'suppliers', label: 'Directorio', icon: Users, section: 'Gestión' },
    { id: 'statistics', label: 'Estadísticas', icon: BarChart3, section: 'Análisis' },
    { id: 'closure', label: 'Cierre del Día', icon: Wallet, section: 'Análisis' },
    { id: 'config', label: 'Configuración', icon: Settings, section: 'Sistema' },
    { id: 'maintenance', label: 'Mantenimiento', icon: Database, section: 'Sistema' },
  ];

  const sections = Array.from(new Set(menuItems.map(item => item.section)));

  return (
    <div className="flex h-screen bg-[#FCF9F7] overflow-hidden font-['Inter']">
      {!isSidebarOpen && (
        <div className="fixed inset-0 bg-black/60 z-20 md:hidden backdrop-blur-sm" onClick={() => setIsSidebarOpen(true)} />
      )}

      <aside className={`${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} fixed md:relative z-30 w-72 h-full bg-white border-r border-[#D7CCC8]/30 transition-transform duration-300 shadow-xl md:shadow-none`}>
        <div className="flex flex-col h-full">
          <div className="p-8 border-b border-[#D7CCC8]/20 flex flex-col items-center bg-[#F5F5DC]/10">
            <div className="relative group">
              <img 
                src={config.logoUrl} 
                alt={config.storeName} 
                className="h-24 w-auto object-contain transition-all group-hover:scale-105"
                onError={(e) => (e.currentTarget.src = "https://via.placeholder.com/150?text=PaTí")}
              />
            </div>
            <p className="mt-3 text-[12px] font-black text-[#3E2723] uppercase tracking-widest">{config.storeName}</p>
          </div>

          <nav className="flex-1 overflow-y-auto py-6 px-4 space-y-8 custom-scrollbar">
            {sections.map(section => (
              <div key={section} className="space-y-1">
                <p className="px-4 text-[9px] font-black text-[#AF6E4D] uppercase tracking-[0.2em] mb-3 opacity-60">{section}</p>
                {menuItems.filter(item => item.section === section).map((item) => (
                  <button
                    key={item.id}
                    onClick={() => {
                      setActiveTab(item.id);
                      if (window.innerWidth < 768) setIsSidebarOpen(false);
                    }}
                    className={`w-full flex items-center px-4 py-3.5 text-[11px] font-black uppercase tracking-widest rounded-2xl transition-all duration-200
                      ${activeTab === item.id 
                        ? 'bg-[#5D4037] text-white shadow-lg' 
                        : 'text-[#8D6E63] hover:bg-[#F5F5DC]/50 hover:text-[#3E2723]'}
                    `}
                  >
                    <item.icon className={`w-5 h-5 mr-4 ${activeTab === item.id ? 'text-white' : 'text-[#D7CCC8]'}`} />
                    {item.label}
                  </button>
                ))}
              </div>
