                   </div>
                   {p.groupings.length > 0 && (
                     <div className="flex flex-wrap gap-2 pt-4 border-t border-gray-50">
                        {p.groupings.map(g => (
                          <button key={g.id} onClick={() => addItem(p, g)} className="px-5 py-3 bg-[#F5F5DC] rounded-2xl text-[9px] font-black text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white transition-all border border-[#D7CCC8]/40 uppercase">
                            {g.label}: {g.price} {g.currency}
                          </button>
                        ))}
                     </div>
                   )}
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-12 bg-white">
            <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] mb-10">Cesta de Venta</h3>
            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 animate-in slide-in-from-right-4">
                   <div className="flex-1">
                      <p className="text-xs font-black text-[#3E2723] uppercase">{item.productName}</p>
                      <p className="text-[9px] font-black text-[#AF6E4D] uppercase">{item.groupingLabel || 'Unitario'}</p>
                   </div>
                   <div className="flex items-center gap-6">
                      <div className="flex items-center bg-white rounded-2xl border border-[#D7CCC8]/30 p-1.5">
                         <button onClick={() => updateQty(item.id, -1)} className="p-2 text-[#D7CCC8] hover:text-rose-400"><Minus size={14}/></button>
                         <span className="w-10 text-center font-black text-sm">{item.quantity}</span>
                         <button onClick={() => updateQty(item.id, 1)} className="p-2 text-[#3E2723] hover:text-[#AF6E4D]"><Plus size={14}/></button>
