const loadFromStorage = <T,>(key: string, defaultValue: T): T => {
  try {
    const saved = localStorage.getItem(key);
    return saved ? JSON.parse(saved) : defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>(() => loadFromStorage(STORAGE_KEYS.PRODUCTS, []));
  const [contacts, setContacts] = useState<Contact[]>(() => loadFromStorage(STORAGE_KEYS.CONTACTS, []));
  const [transactions, setTransactions] = useState<Transaction[]>(() => loadFromStorage(STORAGE_KEYS.TRANSACTIONS, []));
  const [config, setConfig] = useState<StoreConfig>(() => loadFromStorage(STORAGE_KEYS.CONFIG, DEFAULT_CONFIG));
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [isGeneratingSocial, setIsGeneratingSocial] = useState(false);

  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config)); }, [config]);

  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `${p.name} requiere reposición inmediata.`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      if (p.unitPrice <= 0) {
        newNotifs.push({ id: `price-${p.id}`, title: 'Pendiente de Precio', message: `El producto ${p.name} no tiene precio de venta asignado en Inventario.`, type: 'error', date: new Date().toISOString(), read: false });
      }
      const daysToExpiry = Math.ceil((new Date(p.expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
      if (daysToExpiry <= 60 && daysToExpiry > 0) {
        newNotifs.push({ id: `exp-${p.id}`, title: 'Vencimiento Cercano', message: `${p.name} vence en ${daysToExpiry} días.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // Al cambiar a pestaña de ventas, abrir el modal de ventas directo
  useEffect(() => {
    if (activeTab === 'sales') {
      setShowSaleModal(true);
    }
    if (activeTab === 'reception') {
      setProductModal({ show: true, mode: 'reception' });
    }
  }, [activeTab]);

  // --- FORMULARIO PRODUCTO (RECEPCIÓN VS LOGÍSTICA DE PRECIOS) ---
  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      receptionType: 'Consignación',
      unitCurrency: 'CUP',
      groupings: [],
      stock: 0,
      minStock: 5,
      receivedDate: new Date().toISOString().split('T')[0],
      categoryId: '1',
      unitPrice: 0,
      costPrice: 0
    });

    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP', minOrderQuantity: 0 });

    const addGrouping = () => {
      if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
      const newGrouping = { ...tempGrouping, id: Math.random().toString(36).substr(2, 9) };
      setFormData({ ...formData, groupings: [...(formData.groupings || []), newGrouping] });
      setTempGrouping({ id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP', minOrderQuantity: 0 });
    };

    return (
      <div className="flex flex-col h-full bg-white overflow-hidden">
        <div className="flex-1 overflow-y-auto p-10 space-y-12 custom-scrollbar">

          {/* SECCIÓN RECEPCIÓN (ENTRADA DE MERCANCÍA) */}
          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b border-[#D7CCC8]/30 pb-4 flex items-center gap-3">
               <Truck size={14}/> {mode === 'reception' ? 'Recepción de Mercancía' : 'Ficha de Identificación'}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Nombre Comercial del Producto</label>
                <input value={formData.name || ''} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Precio de Costo Unitario</label>
                <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]" placeholder="Precio pagado al proveedor" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Cantidad Recibida (Unidades)</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]" />
              </div>
            </div>

            {mode === 'reception' && (
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-[#3E2723] uppercase">Proveedor Suministrador</label>
                  <select value={formData.supplierId || ''} onChange={e => setFormData({...formData, supplierId: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]">
                    <option value="">Seleccione proveedor...</option>
                    {contacts.filter(c => c.type === 'Proveedor').map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-[#3E2723] uppercase">Tipo de Contrato</label>
                  <select value={formData.receptionType} onChange={e => setFormData({...formData, receptionType: e.target.value as any})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold text-xs">
                    <option value="Consignación">En Consignación</option>
                    <option value="Compra Directa">Compra Directa</option>
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-[#3E2723] uppercase">Vencimiento</label>
                  <input type="date" value={formData.expiryDate || ''} onChange={e => setFormData({...formData, expiryDate: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]" />
                </div>
              </div>
            )}
          </section>

          {/* SECCIÓN LOGÍSTICA DE PRECIOS (EXCLUSIVA DE EDICIÓN EN INVENTARIO) */}
          {mode === 'edit' && (
            <>
              <section className="space-y-6">
                <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b border-[#D7CCC8]/30 pb-4 flex items-center gap-3">
                  <DollarSign size={14}/> Logística de Precios de Venta PaTí
                </h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#3E2723] uppercase">Precio de Venta Unitario</label>
                    <div className="flex gap-2">
                      <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]" placeholder="Precio al público" />
                      <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-4 bg-[#F5F5DC] rounded-[20px] font-black text-[10px]"><option value="CUP">CUP</option><option value="USD">USD</option></select>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#3E2723] uppercase">Stock Mínimo de Aviso</label>
                    <input type="number" value={formData.minStock || ''} onChange={e => setFormData({...formData, minStock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]" />
                  </div>
                </div>
              </section>

              <section className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30 space-y-6 shadow-sm">
                <div className="flex items-center gap-4"><Layers className="text-[#AF6E4D]" /><h3 className="text-xs font-black text-[#3E2723] uppercase tracking-widest">Agrupaciones y Packs (Mayoreo Ilimitado)</h3></div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Etiqueta (Ej: Caja x24)</label><input placeholder="Nombre pack..." value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold outline-none focus:border-[#AF6E4D]" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Cant. Contenida</label><input type="number" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold outline-none" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Precio Pack</label><input type="number" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold outline-none" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black uppercase text-gray-400">Mín. Pedido</label><input type="number" value={tempGrouping.minOrderQuantity || ''} onChange={e => setTempGrouping({...tempGrouping, minOrderQuantity: parseInt(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold outline-none" /></div>
                  <button onClick={addGrouping} className="bg-[#3E2723] text-white p-4 rounded-2xl text-[10px] font-black uppercase shadow-lg hover:bg-[#AF6E4D] transition-all">+ Añadir Agrupación</button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mt-6">
                  {formData.groupings?.map(g => (
                    <div key={g.id} className="bg-white p-5 rounded-[24px] border border-[#D7CCC8]/30 flex justify-between items-center shadow-sm hover:border-[#AF6E4D] transition-all">
                      <div>
                        <p className="text-[11px] font-black text-[#3E2723] uppercase">{g.label}</p>
                        <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{g.price} {g.currency} | {g.quantity} Unid. {g.minOrderQuantity ? `| Mín: ${g.minOrderQuantity}` : ''}</p>
                      </div>
                      <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-300 hover:text-rose-500 transition-colors p-2"><Trash2 size={16}/></button>
                    </div>
                  ))}
                  {formData.groupings?.length === 0 && <p className="col-span-full py-6 text-center text-[10px] text-gray-300 font-black uppercase tracking-widest italic">No hay agrupaciones definidas para este producto.</p>}
                </div>
              </section>
            </>
          )}
        </div>
        <div className="p-8 border-t bg-white flex justify-end gap-4 shadow-2xl relative z-10">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs hover:text-[#3E2723] transition-colors">Cancelar</button>
          <button onClick={() => onSave(formData as Product)} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3 active:scale-95 transition-all"><Save size={18} /> {mode === 'reception' ? 'Completar Recepción' : 'Actualizar Ficha Técnica'}</button>
        </div>
      </div>
    );
  };

  // --- TERMINAL DE VENTAS (FULL EXPERIENCE) ---
  const SalesTerminal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [saleStatus, setSaleStatus] = useState<'Solicitud' | 'Despachado'>('Despachado');

    const addItem = (p: Product, grouping?: GroupingPrice) => {
      if (p.unitPrice <= 0 && !grouping) {
        alert("Atención: Este producto no tiene precio de venta asignado. Por favor, asigne un precio en la sección de Inventario antes de venderlo.");
        return;
      }
      const existing = cart.find(i => i.productId === p.id && i.groupingId === grouping?.id);
      if (existing) {
        updateQty(existing.id, 1);
        return;
      }

      const initialQty = grouping?.minOrderQuantity || 1;
      const newItem: SaleItem = {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: grouping?.label,
        quantity: initialQty, price: grouping ? grouping.price : p.unitPrice,
        currency: grouping ? grouping.currency : p.unitCurrency,
        total: (grouping ? grouping.price : p.unitPrice) * initialQty,
        unitQuantity: grouping ? grouping.quantity : 1
      };
      setCart([...cart, newItem]);
    };

    const updateQty = (id: string, delta: number) => {
      setCart(prev => prev.map(item => {
        if (item.id === id) {
          const product = products.find(p => p.id === item.productId);
          const grouping = product?.groupings.find(g => g.id === item.groupingId);
          const minRequired = grouping?.minOrderQuantity || 1;
          const newQty = Math.max(minRequired, item.quantity + delta);
          return { ...item, quantity: newQty, total: newQty * item.price };
        }
        return item;
      }));
    };

    const totalCup = cart.filter(i => i.currency === 'CUP').reduce((a, b) => a + b.total, 0);

    return (
      <div className="fixed inset-0 bg-black/80 z-[120] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[60px] w-full max-w-7xl h-[92vh] overflow-hidden flex shadow-2xl animate-in zoom-in-95 duration-300">
          <div className="w-1/2 border-r border-[#D7CCC8]/30 flex flex-col p-12 bg-[#FCF9F7]">
            <div className="flex justify-between items-center mb-10">
               <h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal PaTí</h2>
               <button onClick={() => { setShowSaleModal(false); setActiveTab('home'); }} className="p-3 bg-white rounded-full hover:bg-rose-50 transition-colors shadow-sm"><X size={20}/></button>
            </div>
            <div className="relative mb-8">
               <Search className="absolute left-6 top-6 text-[#D7CCC8]" size={20} />
               <input placeholder="Buscar producto por nombre..." value={search} onChange={e => setSearch(e.target.value)} className="w-full p-6 pl-16 bg-white border border-[#D7CCC8]/30 rounded-[32px] font-bold text-sm outline-none focus:border-[#AF6E4D] shadow-inner" />
            </div>
            <div className="flex-1 overflow-y-auto space-y-6 pr-2 custom-scrollbar">
              {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                <div key={p.id} className="bg-white p-8 rounded-[40px] border border-[#D7CCC8]/20 hover:border-[#AF6E4D] transition-all shadow-sm group">
                   <div className="flex justify-between items-start mb-6">
                      <div>
                        <h4 className="font-black text-sm uppercase text-[#3E2723]">{p.name}</h4>
                        <p className={`text-[9px] font-black uppercase mt-1 ${p.stock <= p.minStock ? 'text-rose-500 animate-pulse' : 'text-[#AF6E4D]'}`}>Inventario: {p.stock} U.</p>
                      </div>
                      <div className="flex flex-col items-end gap-2">
                        {p.unitPrice <= 0 && <span className="text-[8px] font-black bg-rose-500 text-white px-3 py-1 rounded-full uppercase">Pendiente Precio</span>}
                        <button disabled={p.unitPrice <= 0} onClick={() => addItem(p)} className="p-4 bg-[#3E2723] text-white rounded-2xl hover:bg-[#AF6E4D] shadow-xl disabled:opacity-20 transition-all">+ Unidad</button>
                      </div>
                   </div>
                   {p.groupings.length > 0 && (
                     <div className="flex flex-wrap gap-2 pt-4 border-t border-gray-50">
                        {p.groupings.map(g => (
                          <button key={g.id} onClick={() => addItem(p, g)} className="px-5 py-3 bg-[#F5F5DC] rounded-2xl text-[9px] font-black text-[#3E2723] hover:bg-[#AF6E4D] hover:text-white transition-all border border-[#D7CCC8]/40 uppercase shadow-sm">
                            {g.label}: {g.price} {g.currency}
                          </button>
                        ))}
                     </div>
                   )}
                </div>
              ))}
            </div>
          </div>
          <div className="w-1/2 flex flex-col p-12 bg-white">
            <h3 className="text-[10px] font-black text-[#AF6E4D] uppercase tracking-[0.4em] mb-10">Cesta de Venta</h3>
            <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
              {cart.map(item => (
                <div key={item.id} className="flex items-center justify-between p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 animate-in slide-in-from-right-4">
                   <div className="flex-1">
                      <p className="text-xs font-black text-[#3E2723] uppercase">{item.productName}</p>
                      <p className="text-[9px] font-black text-[#AF6E4D] uppercase">{item.groupingLabel || 'Unidad Individual'}</p>
                   </div>
                   <div className="flex items-center gap-6">
                      <div className="flex items-center bg-white rounded-2xl border border-[#D7CCC8]/30 p-1.5 shadow-sm">
                         <button onClick={() => updateQty(item.id, -1)} className="p-2 text-[#D7CCC8] hover:text-rose-400 transition-colors"><Minus size={14}/></button>
                         <span className="w-10 text-center font-black text-sm text-[#3E2723]">{item.quantity}</span>
                         <button onClick={() => updateQty(item.id, 1)} className="p-2 text-[#3E2723] hover:text-[#AF6E4D] transition-all"><Plus size={14}/></button>
                      </div>
                      <div className="text-right w-24 font-black">{item.total.toLocaleString()} {item.currency}</div>
                      <button onClick={() => setCart(cart.filter(i => i.id !== item.id))} className="text-rose-300 hover:text-rose-500 transition-colors"><Trash2 size={20}/></button>
                   </div>
                </div>
              ))}
              {cart.length === 0 && <div className="h-full flex flex-col items-center justify-center text-gray-300 opacity-40"><ShoppingCart size={80}/><p className="text-xs font-black uppercase mt-4">Lista de cobro vacía</p></div>}
            </div>
            <div className="space-y-6">
               <div className="flex gap-4">
                  <button onClick={() => setSaleStatus('Solicitud')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase border transition-all ${saleStatus === 'Solicitud' ? 'bg-[#F5F5DC] border-[#AF6E4D] text-[#3E2723] shadow-md' : 'bg-white border-gray-100 text-gray-300'}`}>Solicitud / Pre-Factura</button>
                  <button onClick={() => setSaleStatus('Despachado')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase border transition-all ${saleStatus === 'Despachado' ? 'bg-[#3E2723] border-[#3E2723] text-white shadow-xl' : 'bg-white border-gray-100 text-gray-300'}`}>Factura de Despacho</button>
               </div>
               <div className="bg-[#3E2723] p-12 rounded-[50px] text-white shadow-2xl flex justify-between items-center border border-white/5 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-[#AF6E4D] to-[#3E2723]"></div>
                  <div><p className="text-[10px] opacity-40 font-black uppercase mb-2">Total a Cobrar</p><p className="text-5xl font-black tracking-tighter tabular-nums">{totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                  <button disabled={cart.length === 0} onClick={() => {
                    const trans: Transaction = {
                      id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Público General',
                      items: cart, totalCup, totalUsd: 0, paymentMethod: 'Efectivo', status: saleStatus, invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
                    };
                    setTransactions([trans, ...transactions]);
                    if (saleStatus === 'Despachado') {
                      setProducts(prev => prev.map(p => {
                        const soldUnits = cart.filter(i => i.productId === p.id).reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
                        return soldUnits > 0 ? { ...p, stock: p.stock - soldUnits } : p;
                      }));
                    }
                    setCart([]); setShowSaleModal(false); setSelectedInvoice(trans);
                  }} className="bg-[#AF6E4D] text-white px-14 py-7 rounded-[32px] font-black uppercase text-xs shadow-xl hover:bg-white hover:text-[#3E2723] disabled:opacity-20 transition-all active:scale-95">Finalizar Cobro {saleStatus}</button>
               </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {/* VISTA INICIO */}
      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {/* VISTA NOSOTROS */}
      {activeTab === 'about' && (
        <div className="max-w-5xl mx-auto space-y-16 py-10 animate-in fade-in duration-700">
           <div className="relative h-[500px] rounded-[80px] overflow-hidden shadow-2xl border-[12px] border-white">
              <img src="https://images.unsplash.com/photo-1578916171728-46686eac8d58?auto=format&fit=crop&q=80&w=1400" className="w-full h-full object-cover brightness-[0.5]" />
              <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-12">
                 <div className="bg-white/10 backdrop-blur-2xl p-8 rounded-[40px] border border-white/30 mb-10 shadow-2xl transform hover:scale-105 transition-transform">
                    <img src={config.logoUrl} alt={config.storeName} className="h-32 w-auto object-contain brightness-110" />
                 </div>
                 <h2 className="text-6xl font-black text-white uppercase tracking-tighter mb-4">Sobre {config.storeName}</h2>
                 <p className="text-white/80 text-xl font-medium max-w-2xl leading-relaxed italic">"{config.aboutText}"</p>
              </div>
           </div>
        </div>
      )}

      {/* VISTA CONTACTOS */}
      {activeTab === 'contact' && (
        <div className="max-w-6xl mx-auto py-10 animate-in zoom-in-95 duration-500">
           <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="bg-[#3E2723] rounded-[70px] p-16 text-white shadow-2xl relative overflow-hidden">
                 <h2 className="text-5xl font-black uppercase mb-10 tracking-tighter">Contacto Directo</h2>
                 <div className="space-y-10">
                    <div className="flex items-center gap-8 group">
                       <div className="w-16 h-16 bg-white/10 rounded-[28px] flex items-center justify-center group-hover:bg-[#AF6E4D] transition-all"><Phone size={24}/></div>
                       <div><p className="text-[10px] font-black uppercase opacity-40 mb-1">Teléfono Directo</p><p className="text-2xl font-black">{config.phone}</p></div>
                    </div>
