interface StatisticsProps {
  products: Product[];
  transactions: Transaction[];
  contacts: Contact[];
}

const Statistics: React.FC<StatisticsProps> = ({ products, transactions, contacts }) => {
  // 1. Rentabilidad y Liquidez Real (Solo transacciones despachadas)
  const totalSalesCup = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((acc, t) => acc + t.totalCup, 0), [transactions]);

  // 2. Cálculo de Costo de Mercancía Vendida (Para Rentabilidad Real)
  const totalCostOfSales = useMemo(() => {
    let totalCost = 0;
    transactions.filter(t => t.status === 'Despachado').forEach(t => {
      t.items.forEach(item => {
        const product = products.find(p => p.id === item.productId);
        const costPerUnit = product?.costPrice || 0;
        const totalUnits = item.unitQuantity * item.quantity;
        totalCost += (costPerUnit * totalUnits);
      });
    });
    return totalCost;
  }, [transactions, products]);

  // 3. Deuda a Consignatarios (Productos vendidos de tipo Consignación)
  const debtToConsignees = useMemo(() => {
    let debt = 0;
    transactions.filter(t => t.status === 'Despachado').forEach(t => {
      t.items.forEach(item => {
        const product = products.find(p => p.id === item.productId);
        if (product?.receptionType === 'Consignación') {
           const costPerUnit = product?.costPrice || 0;
           const totalUnits = item.unitQuantity * item.quantity;
           debt += (costPerUnit * totalUnits);
        }
      });
    });
    return debt;
  }, [transactions, products]);

  // 4. Productos de Lento Movimiento (Sin ventas en 30 días)
  const slowMoving = useMemo(() => {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);
    return products.filter(p => {
       const soldRecently = transactions.some(t => 
          t.status === 'Despachado' && 
          new Date(t.date) > thirtyDaysAgo && 
          t.items.some(i => i.productId === p.id)
       );
       return !soldRecently && p.stock > 0;
    }).slice(0, 5);
  }, [products, transactions]);

  const chartData = useMemo(() => {
    const days = ['Dom', 'Lun', 'Mar', 'Mie', 'Jue', 'Vie', 'Sab'];
    const data = days.map(d => ({ name: d, ventas: 0 }));
    transactions.filter(t => t.status === 'Despachado').forEach(t => {
      const dayIndex = new Date(t.date).getDay();
      data[dayIndex].ventas += t.totalCup;
    });
    return data;
  }, [transactions]);

  return (
    <div className="space-y-12 animate-in fade-in duration-700 pb-20">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        <div className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm">
           <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-[24px] flex items-center justify-center mb-6 shadow-inner"><TrendingUp size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Caja Total (CUP)</p>
           <p className="text-3xl font-black text-[#3E2723] tracking-tighter tabular-nums">{totalSalesCup.toLocaleString()}</p>
        </div>
        <div className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm">
           <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-[24px] flex items-center justify-center mb-6 shadow-inner"><Wallet size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Deuda Consignatarios</p>
           <p className="text-3xl font-black text-rose-500 tracking-tighter tabular-nums">{debtToConsignees.toLocaleString()}</p>
        </div>
        <div className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm">
           <div className="w-16 h-16 bg-[#F5F5DC] text-[#3E2723] rounded-[24px] flex items-center justify-center mb-6 shadow-inner"><Activity size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Rentabilidad Real</p>
           <p className="text-3xl font-black text-[#3E2723] tracking-tighter tabular-nums">{(totalSalesCup - totalCostOfSales).toLocaleString()}</p>
        </div>
        <div className="bg-[#5D4037] p-10 rounded-[50px] shadow-2xl text-white">
           <div className="w-16 h-16 bg-white/10 text-white rounded-[24px] flex items-center justify-center mb-6"><Package size={32}/></div>
           <p className="text-[10px] font-black uppercase text-white/40 tracking-widest mb-1">Valor Inventario (P. Venta)</p>
           <p className="text-3xl font-black tracking-tighter tabular-nums">{products.reduce((acc, p) => acc + (p.stock * p.unitPrice), 0).toLocaleString()}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
         <div className="bg-white p-10 rounded-[60px] border border-[#D7CCC8]/20 shadow-sm">
            <h3 className="text-sm font-black text-[#3E2723] uppercase tracking-widest mb-12 flex items-center gap-4"><Clock size={20} className="text-[#AF6E4D]"/> Lento Movimiento (Sugerencias de Oferta)</h3>
            <div className="space-y-4">
               {slowMoving.map(p => (
                 <div key={p.id} className="flex justify-between items-center p-6 bg-[#FCF9F7] rounded-[32px] border border-[#D7CCC8]/10 group hover:border-[#AF6E4D] transition-all">
                    <div>
                       <p className="text-[11px] font-black text-[#3E2723] uppercase">{p.name}</p>
                       <p className="text-[9px] font-bold text-[#AF6E4D] uppercase mt-1">Existencia detenida: {p.stock} U.</p>
                    </div>
                    <button className="bg-white text-[#AF6E4D] text-[10px] font-black px-6 py-3 rounded-2xl border border-[#AF6E4D]/20 group-hover:bg-[#AF6E4D] group-hover:text-white transition-all uppercase">Ver Detalle</button>
                 </div>
               ))}
               {slowMoving.length === 0 && <p className="text-center py-10 text-[10px] font-black text-gray-300 uppercase italic">Toda la mercancía tiene rotación saludable.</p>}
            </div>
         </div>
         <div className="bg-white p-10 rounded-[60px] border border-[#D7CCC8]/20 shadow-sm flex flex-col justify-center">
            <h3 className="text-sm font-black text-[#3E2723] uppercase tracking-widest mb-12">Rendimiento Semanal de Ventas</h3>
            <div className="h-72">
               <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient id="colorV" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#AF6E4D" stopOpacity={0.2}/>
                        <stop offset="95%" stopColor="#AF6E4D" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f5f5f5" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 900, fill: '#D7CCC8'}} />
                    <YAxis axisLine={false} tickLine={false} tick={{fontSize: 10, fontWeight: 900, fill: '#D7CCC8'}} />
                    <Tooltip contentStyle={{ borderRadius: '24px', border: 'none', boxShadow: '0 20px 40px rgba(0,0,0,0.05)', textTransform: 'uppercase', fontSize: '10px', fontWeight: '900' }} />
                    <Area type="monotone" dataKey="ventas" stroke="#AF6E4D" strokeWidth={5} fillOpacity={1} fill="url(#colorV)" />
                  </AreaChart>
               </ResponsiveContainer>
            </div>
         </div>
      </div>
    </div>
  );
};

