import React, { useMemo } from 'react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer 
} from 'recharts';
import { 
  TrendingUp, Package, DollarSign, Wallet, Activity, Clock, Truck, ShieldCheck
} from 'lucide-react';
import { Product, Transaction, Contact } from '../types';

interface StatisticsProps {
  products: Product[];
  transactions: Transaction[];
  contacts: Contact[];
}

const Statistics: React.FC<StatisticsProps> = ({ products, transactions, contacts }) => {
  // 1. Ingresos Totales Reales
  const totalSalesCup = useMemo(() => transactions.filter(t => t.status === 'Despachado').reduce((acc, t) => acc + t.totalCup, 0), [transactions]);

  // 2. Costo Total Logístico (Transportación acumulada de todos los lotes de todos los productos)
  const totalTransportCosts = useMemo(() => {
    return products.reduce((acc, p) => acc + (p.lots?.reduce((sum, lot) => sum + lot.transportCost, 0) || 0), 0);
  }, [products]);

  // 3. Costo de Mercancía Vendida (COGS)
  const totalCostOfSales = useMemo(() => {
    let totalCost = 0;
    transactions.filter(t => t.status === 'Despachado').forEach(t => {
      t.items.forEach(item => {
        const product = products.find(p => p.id === item.productId);
        const costPerUnit = product?.costPrice || 0;
        totalCost += (costPerUnit * item.unitQuantity * item.quantity);
      });
    });
    return totalCost;
  }, [transactions, products]);

  // 4. Rentabilidad Real (Ventas - Costos de Mercancía - Costos de Transporte)
  const realProfit = totalSalesCup - totalCostOfSales - totalTransportCosts;

  return (
    <div className="space-y-12 animate-in fade-in duration-700 pb-20">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
        <div className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 rounded-full -mr-16 -mt-16 group-hover:scale-110 transition-transform"></div>
           <div className="w-16 h-16 bg-emerald-50 text-emerald-600 rounded-[24px] flex items-center justify-center mb-6 shadow-inner"><TrendingUp size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Ingresos de Caja (CUP)</p>
           <p className="text-3xl font-black text-[#3E2723] tracking-tighter">{totalSalesCup.toLocaleString()}</p>
        </div>
        <div className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm relative overflow-hidden group">
           <div className="absolute top-0 right-0 w-32 h-32 bg-amber-500/5 rounded-full -mr-16 -mt-16 group-hover:scale-110 transition-transform"></div>
           <div className="w-16 h-16 bg-amber-50 text-amber-600 rounded-[24px] flex items-center justify-center mb-6 shadow-inner"><Truck size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Gastos de Transportación</p>
           <p className="text-3xl font-black text-[#3E2723] tracking-tighter">{totalTransportCosts.toLocaleString()}</p>
        </div>
        <div className="bg-[#3E2723] p-10 rounded-[50px] shadow-2xl text-white relative overflow-hidden group">
