           <div className="w-16 h-16 bg-white/10 text-[#AF6E4D] rounded-[24px] flex items-center justify-center mb-6"><Activity size={32}/></div>
           <p className="text-[10px] font-black uppercase text-white/40 tracking-widest mb-1">Rentabilidad Neta Real</p>
           <p className="text-3xl font-black tracking-tighter">{realProfit.toLocaleString()} <span className="text-xs opacity-30">CUP</span></p>
        </div>
        <div className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/30 shadow-sm relative overflow-hidden group">
           <div className="w-16 h-16 bg-rose-50 text-rose-500 rounded-[24px] flex items-center justify-center mb-6 shadow-inner"><ShieldCheck size={32}/></div>
           <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1">Inversión en Almacén</p>
           <p className="text-3xl font-black text-[#3E2723] tracking-tighter">{totalCostOfSales.toLocaleString()}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
         <div className="lg:col-span-2 bg-white p-12 rounded-[60px] border border-[#D7CCC8]/20 shadow-sm">
            <h3 className="text-sm font-black text-[#3E2723] uppercase tracking-widest mb-12 flex items-center gap-4"><Activity size={20} className="text-[#AF6E4D]"/> Análisis de Márgenes y Logística</h3>
            <div className="space-y-8">
               {products.filter(p => p.lots?.length > 0).slice(0, 5).map(p => {
                 const pTransport = p.lots?.reduce((s, l) => s + l.transportCost, 0) || 0;
                 const pSales = transactions.filter(t => t.status === 'Despachado' && t.items.some(i => i.productId === p.id)).reduce((a, b) => a + b.totalCup, 0);
                 const progress = Math.min((pSales / (pTransport || 1)) * 100, 100);

                 return (
                   <div key={p.id} className="space-y-4">
                      <div className="flex justify-between items-end">
                         <div>
                            <p className="text-[10px] font-black text-[#3E2723] uppercase">{p.name}</p>
                            <p className="text-[9px] font-bold text-[#AF6E4D] uppercase">Costo Transporte Lote: {pTransport.toLocaleString()} CUP</p>
                         </div>
                         <div className="text-right">
                            <p className="text-[9px] font-black text-emerald-500 uppercase">Recuperado: {progress.toFixed(0)}%</p>
                         </div>
                      </div>
                      <div className="w-full h-3 bg-[#FCF9F7] rounded-full overflow-hidden border border-[#D7CCC8]/20">
                         <div className="h-full bg-[#AF6E4D] rounded-full" style={{ width: `${progress}%` }}></div>
                      </div>
                   </div>
                 );
               })}
               {products.length === 0 && <p className="text-center py-20 text-[10px] font-black text-gray-300 uppercase italic">Esperando datos de lotes y ventas...</p>}
            </div>
         </div>
         <div className="bg-[#3E2723] p-12 rounded-[60px] text-white flex flex-col justify-between">
            <div>
               <h3 className="text-[10px] font-black uppercase tracking-[0.2em] mb-10 text-white/40">Resumen Operativo</h3>
               <div className="space-y-8">
                  <div>
                     <p className="text-[8px] font-black uppercase text-[#AF6E4D] mb-1">Suministradores Activos</p>
                     <p className="text-4xl font-black">{contacts.filter(c => c.type === 'Proveedor').length}</p>
                  </div>
                  <div>
                     <p className="text-[8px] font-black uppercase text-[#AF6E4D] mb-1">Lotes en Almacén</p>
                     <p className="text-4xl font-black">{products.reduce((acc, p) => acc + (p.lots?.length || 0), 0)}</p>
                  </div>
               </div>
            </div>
            <div className="pt-10 border-t border-white/5">
               <button className="w-full py-6 bg-white text-[#3E2723] rounded-[28px] font-black uppercase text-[10px] shadow-2xl hover:scale-105 transition-all">Exportar Auditoría PDF</button>
            </div>
         </div>
      </div>
    </div>
  );
};

