                link.href = URL.createObjectURL(blob);
                link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="bg-[#3E2723] text-white px-16 py-8 rounded-[36px] font-black uppercase text-xs shadow-2xl hover:bg-[#AF6E4D] transition-all flex items-center gap-6"><Download size={24}/> Exportar Todo</button>
              <label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[36px] font-black uppercase text-xs shadow-xl flex items-center gap-6 cursor-pointer border border-[#D7CCC8]/40 hover:bg-[#D7CCC8] transition-all"><Upload size={24}/> Importar Datos <input type="file" className="hidden" accept=".json" onChange={(e) => {
                const file = e.target.files?.[0];
