import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  Minus, FileText, History, Info, Facebook, Instagram, Mail, Star, Globe, Settings, ImageIcon, Copy, Share2, TrendingUp, Percent
} from 'lucide-react';
import { LOGO_URL, STORE_NAME } from './constants';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions',
  CONFIG: 'pati_v3_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: LOGO_URL,
  storeName: STORE_NAME,
  aboutText: "Mercado PaTí es su socio de confianza para productos frescos y de calidad. Gestionamos mercancías en consignación con total transparencia.",
  address: "Calle Real #123, Habana Vieja",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    return saved ? JSON.parse(saved) : [];
  });
  const [contacts, setContacts] = useState<Contact[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    return saved ? JSON.parse(saved) : [];
  });
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    return saved ? JSON.parse(saved) : [];
  });
  const [config, setConfig] = useState<StoreConfig>(() => {
    const saved = localStorage.getItem(STORAGE_KEYS.CONFIG);
    return saved ? JSON.parse(saved) : DEFAULT_CONFIG;
  });

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showContactModal, setShowContactModal] = useState(false);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');

  // Persistencia
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts)); }, [contacts]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions)); }, [transactions]);
  useEffect(() => { localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config)); }, [config]);

  // Alertas
  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `${p.name} requiere reposición inmediata.`, type: 'warning', date: new Date().toISOString(), read: false });
      }
      if (p.unitPrice <= 0) {
        newNotifs.push({ id: `price-${p.id}`, title: 'Precio Pendiente', message: `Asigne precio de venta a ${p.name} en Inventario.`, type: 'error', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // Navegación rápida
  useEffect(() => {
    if (activeTab === 'sales') setShowSaleModal(true);
    if (activeTab === 'reception') setProductModal({ show: true, mode: 'reception' });
  }, [activeTab]);

  // --- COMPONENTE FORMULARIO PRODUCTO (LOGÍSTICA) ---
  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      receptionType: 'Consignación',
      unitCurrency: 'CUP',
      groupings: [],
      stock: 0,
      minStock: 5,
      unitPrice: 0,
      costPrice: 0,
      lots: []
    });
    const [transportCost, setTransportCost] = useState(0);
    const [nameSearch, setNameSearch] = useState(initialData?.name || '');
    const [showNameDropdown, setShowNameDropdown] = useState(false);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP', minOrderQuantity: 0 });

    const marginPercent = useMemo(() => {
      if (!formData.unitPrice || !formData.costPrice || formData.unitPrice <= 0) return 0;
      return ((formData.unitPrice - formData.costPrice) / formData.unitPrice) * 100;
    }, [formData.unitPrice, formData.costPrice]);

    const suggestions = products.filter(p => p.name.toLowerCase().includes(nameSearch.toLowerCase()));

    return (
      <div className="flex flex-col h-full bg-white overflow-hidden">
        <div className="flex-1 overflow-y-auto p-10 space-y-12 custom-scrollbar">
          {/* SECCIÓN 1: DATOS BÁSICOS / RECEPCIÓN */}
          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b border-[#D7CCC8]/30 pb-4 flex items-center gap-3">
               <Truck size={14}/> {mode === 'reception' ? 'Recepción de Mercancía' : 'Ficha Técnica'}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div className="space-y-2 relative">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Nombre Comercial</label>
                <input 
                  value={nameSearch} 
                  onChange={e => { setNameSearch(e.target.value); setFormData({...formData, name: e.target.value}); setShowNameDropdown(true); }}
                  className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none focus:border-[#AF6E4D]" 
                  placeholder="Escriba el nombre..."
                  disabled={mode === 'edit'}
                />
                {showNameDropdown && nameSearch.length > 0 && mode === 'reception' && suggestions.length > 0 && (
                  <div className="absolute top-full left-0 w-full bg-white border border-[#D7CCC8]/30 rounded-[24px] shadow-2xl z-50 mt-2 overflow-hidden max-h-60 overflow-y-auto">
                    {suggestions.map(p => (
                      <button key={p.id} onClick={() => { setFormData({...p, stock: 0}); setNameSearch(p.name); setShowNameDropdown(false); }} className="w-full p-4 text-left hover:bg-[#F5F5DC] flex justify-between border-b">
                         <span className="font-bold text-xs uppercase">{p.name}</span>
                         <span className="text-[9px] font-black text-[#AF6E4D]">ALMACÉN: {p.stock}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">Costo Unitario (CUP)</label>
                <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-[#3E2723] uppercase">{mode === 'reception' ? 'Cantidad a Recibir' : 'Existencia Actual'}</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold" />
              </div>
              {mode === 'reception' && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-[#AF6E4D] uppercase">Costo Transportación Lote</label>
                  <input type="number" value={transportCost} onChange={e => setTransportCost(parseFloat(e.target.value))} className="w-full p-4 bg-[#F5F5DC]/50 border border-[#D7CCC8]/40 rounded-[20px] font-bold outline-none" placeholder="Costo del viaje..." />
                </div>
              )}
            </div>
          </section>

          {/* SECCIÓN 2: LOGÍSTICA DE PRECIOS (EXCLUSIVO INVENTARIO) */}
          {mode === 'edit' && (
            <>
              <section className="space-y-6">
                <div className="flex justify-between items-center border-b border-[#D7CCC8]/30 pb-4">
                  <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] flex items-center gap-3"><DollarSign size={14}/> Logística de Venta y Márgenes</h3>
                  <div className={`px-4 py-2 rounded-full font-black text-[10px] uppercase ${marginPercent > 20 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>Margen Real: {marginPercent.toFixed(1)}%</div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#3E2723] uppercase">Precio de Venta Unitario</label>
                    <div className="flex gap-2">
                      <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold" />
                      <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-4 bg-[#F5F5DC] rounded-[20px] font-black text-[10px]"><option value="CUP">CUP</option><option value="USD">USD</option></select>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-[#3E2723] uppercase">Aviso Stock Crítico</label>
                    <input type="number" value={formData.minStock || ''} onChange={e => setFormData({...formData, minStock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[20px] font-bold" />
                  </div>
                </div>
              </section>

              <section className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30 space-y-6 shadow-inner">
                <div className="flex items-center gap-4"><Layers className="text-[#AF6E4D]" /><h3 className="text-xs font-black text-[#3E2723] uppercase tracking-widest">Agrupaciones y Packs Ilimitados</h3></div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
                  <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Etiqueta</label><input placeholder="Ej: Caja x12" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="w-full p-4 bg-white border rounded-2xl text-xs font-bold" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Contenido</label><input type="number" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="w-full p-4 bg-white border rounded-2xl text-xs font-bold" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Precio Pack</label><input type="number" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="w-full p-4 bg-white border rounded-2xl text-xs font-bold" /></div>
                  <button onClick={() => {
                    if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
                    setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                    setTempGrouping({id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP'});
                  }} className="bg-[#3E2723] text-white p-4 rounded-2xl text-[10px] font-black uppercase">+ Añadir Pack</button>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4">
                  {formData.groupings?.map(g => (
                    <div key={g.id} className="bg-white p-5 rounded-3xl border border-[#D7CCC8]/30 flex justify-between items-center shadow-sm hover:border-[#AF6E4D] transition-all">
                       <div><p className="text-[11px] font-black text-[#3E2723] uppercase">{g.label}</p><p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{g.price} {g.currency}</p></div>
                       <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-300 hover:text-rose-500"><Trash2 size={16}/></button>
                    </div>
                  ))}
                </div>
              </section>
            </>
          )}
        </div>
        <div className="p-8 border-t bg-white flex justify-end gap-4">
          <button onClick={onCancel} className="px-8 py-4 text-[#D7CCC8] font-black uppercase text-xs">Cancelar</button>
          <button onClick={() => {
            const final = {...formData} as Product;
            if (mode === 'reception') {
              final.lots = [...(final.lots || []), { id: Math.random().toString(), date: new Date().toISOString(), quantityReceived: final.stock, currentStock: final.stock, unitCost: final.costPrice, transportCost: transportCost, totalInvestment: (final.stock * final.costPrice) + transportCost }];
            }
            onSave(final);
          }} className="bg-[#3E2723] text-white px-10 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3"><Save size={18}/> {mode === 'reception' ? 'Procesar Lote' : 'Guardar Inventario'}</button>
        </div>
      </div>
    );
  };

  // --- TERMINAL DE VENTAS DINÁMICO ---
  const SalesTerminal = () => {
    const [cart, setCart] = useState<SaleItem[]>([]);
    const [search, setSearch] = useState('');
    const [payment, setPayment] = useState<PaymentMethod>('Efectivo');

    const addToCart = (p: Product, grouping?: GroupingPrice) => {
      const existing = cart.find(i => i.productId === p.id && i.groupingId === grouping?.id);
      if (existing) {
        setCart(cart.map(i => i.id === existing.id ? {...i, quantity: i.quantity + 1, total: (i.quantity + 1) * i.price} : i));
      } else {
        const item: SaleItem = {
          id: Math.random().toString(), productId: p.id, productName: p.name, groupingId: grouping?.id, groupingLabel: grouping?.label,
          quantity: 1, price: grouping ? grouping.price : p.unitPrice, currency: grouping ? grouping.currency : p.unitCurrency,
          total: grouping ? grouping.price : p.unitPrice, unitQuantity: grouping ? grouping.quantity : 1
        };
        setCart([...cart, item]);
      }
    };

    const total = cart.reduce((acc, i) => acc + i.total, 0);

    return (
      <div className="fixed inset-0 bg-black/80 z-[200] flex items-center justify-center p-4 backdrop-blur-md">
        <div className="bg-white rounded-[60px] w-full max-w-7xl h-[92vh] overflow-hidden flex shadow-2xl">
          <div className="w-1/2 bg-[#FCF9F7] p-12 flex flex-col border-r">
             <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black text-[#3E2723] uppercase">Terminal de Cobro</h2><button onClick={() => { setShowSaleModal(false); setActiveTab('home'); }}><X size={32}/></button></div>
             <div className="relative mb-8"><Search className="absolute left-6 top-6 text-[#D7CCC8]" size={20}/><input placeholder="Producto a vender..." value={search} onChange={e => setSearch(e.target.value)} className="w-full p-6 pl-16 bg-white border border-[#D7CCC8]/30 rounded-[32px] font-bold outline-none" /></div>
             <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar">
                {products.filter(p => p.name.toLowerCase().includes(search.toLowerCase())).map(p => (
                   <div key={p.id} className="bg-white p-6 rounded-[32px] border border-[#D7CCC8]/20 shadow-sm">
                      <div className="flex justify-between items-start">
                         <div><p className="font-black text-sm uppercase">{p.name}</p><p className="text-[9px] font-black text-[#AF6E4D] uppercase">Stock: {p.stock} U.</p></div>
                         <button disabled={p.unitPrice <= 0} onClick={() => addToCart(p)} className="p-3 bg-[#3E2723] text-white rounded-xl hover:bg-[#AF6E4D] disabled:opacity-20">+ Unidad</button>
                      </div>
                      <div className="flex flex-wrap gap-2 mt-4 border-t pt-4">
                         {p.groupings?.map(g => <button key={g.id} onClick={() => addToCart(p, g)} className="px-4 py-2 bg-[#F5F5DC] rounded-xl text-[9px] font-black uppercase hover:bg-[#AF6E4D] hover:text-white">{g.label}: {g.price} {g.currency}</button>)}
                      </div>
                   </div>
                ))}
             </div>
          </div>
          <div className="w-1/2 p-12 flex flex-col bg-white">
             <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-widest mb-8">Cesta de Venta</h3>
             <div className="flex-1 overflow-y-auto space-y-3 mb-8">
                {cart.map(i => (
                  <div key={i.id} className="flex justify-between items-center p-4 bg-[#FCF9F7] rounded-2xl">
                     <div><p className="text-xs font-black uppercase">{i.productName}</p><p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{i.groupingLabel || 'Unidad'}</p></div>
                     <div className="flex items-center gap-6"><p className="font-black text-sm">{i.quantity} x {i.price} {i.currency}</p><button onClick={() => setCart(cart.filter(x => x.id !== i.id))} className="text-rose-300"><Trash2 size={16}/></button></div>
                  </div>
                ))}
             </div>
             <div className="space-y-6 pt-6 border-t">
                <div className="flex gap-4"><button onClick={() => setPayment('Efectivo')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase border transition-all ${payment === 'Efectivo' ? 'bg-[#3E2723] text-white' : 'bg-white text-gray-400'}`}>Efectivo</button><button onClick={() => setPayment('Transferencia')} className={`flex-1 p-5 rounded-3xl font-black text-[10px] uppercase border transition-all ${payment === 'Transferencia' ? 'bg-[#3E2723] text-white' : 'bg-white text-gray-400'}`}>Transferencia</button></div>
                <div className="bg-[#3E2723] p-10 rounded-[40px] text-white flex justify-between items-center">
                   <div><p className="text-[10px] opacity-40 font-black uppercase mb-1">Total Cobro</p><p className="text-5xl font-black tracking-tighter">{total.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
                   <button disabled={cart.length === 0} onClick={() => {
                     const trans: Transaction = { id: Math.random().toString(), date: new Date().toISOString(), clientId: 'Gral', clientName: 'Público', items: cart, totalCup: total, totalUsd: 0, paymentMethod: payment, status: 'Despachado', invoiceNumber: `PATI-${Date.now().toString().slice(-6)}` };
                     setTransactions([trans, ...transactions]);
                     setProducts(products.map(p => {
                        const cartItems = cart.filter(i => i.productId === p.id);
                        const sold = cartItems.reduce((acc, i) => acc + (i.unitQuantity * i.quantity), 0);
                        return sold > 0 ? {...p, stock: p.stock - sold} : p;
                     }));
                     setCart([]); setShowSaleModal(false); setSelectedInvoice(trans);
                   }} className="bg-[#AF6E4D] px-10 py-6 rounded-[28px] font-black uppercase text-xs hover:scale-105 active:scale-95 transition-all">Finalizar Factura</button>
                </div>
             </div>
          </div>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 pb-20 animate-in fade-in duration-500">
           <div className="flex justify-between items-end">
              <div className="space-y-4 flex-1 max-w-2xl">
                 <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario y Logística</h2>
                 <div className="relative group">
                    <Search className="absolute left-6 top-1/2 -translate-y-1/2 text-[#D7CCC8]" size={20}/>
                    <input placeholder="Buscar producto en almacén..." value={inventorySearch} onChange={e => setInventorySearch(e.target.value)} className="w-full pl-16 pr-8 py-5 bg-white border border-[#D7CCC8]/30 rounded-[32px] font-bold text-sm outline-none focus:border-[#AF6E4D] shadow-sm transition-all" />
                 </div>
              </div>
              <div className="flex gap-4">
                 <button onClick={async () => { const post = await generateSocialMediaPost(products); setSocialPost(post); }} className="bg-[#AF6E4D] text-white px-8 py-6 rounded-[28px] text-[10px] font-black uppercase tracking-widest flex items-center gap-4 shadow-xl hover:bg-[#3E2723] transition-all"><Instagram size={18}/> Marketing IA</button>
                 <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="bg-[#3E2723] text-white px-8 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl hover:scale-105 transition-all flex items-center gap-4"><Plus size={20}/> Recepción</button>
              </div>
           </div>

           <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl">
             <table className="w-full text-left">
               <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black tracking-[0.2em]">
                 <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Stock</th><th className="px-10 py-8">Costo Maestro</th><th className="px-10 py-8">Venta Unit.</th><th className="px-10 py-8">Margen</th><th className="px-10 py-8 text-right">Gestión</th></tr>
               </thead>
               <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                 {products.filter(p => p.name.toLowerCase().includes(inventorySearch.toLowerCase())).map(p => {
                    const margin = p.unitPrice > 0 ? (((p.unitPrice - p.costPrice) / p.unitPrice) * 100) : 0;
                    return (
                      <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors group">
                        <td className="px-10 py-8 font-black text-sm uppercase">{p.name}</td>
                        <td className="px-10 py-8 text-center text-xl font-black">{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                        <td className="px-10 py-8 font-black text-xs">{p.costPrice.toLocaleString()} CUP</td>
                        <td className="px-10 py-8 font-black text-xs text-[#AF6E4D]">{p.unitPrice > 0 ? `${p.unitPrice.toLocaleString()} ${p.unitCurrency}` : '--'}</td>
                        <td className="px-10 py-8 font-black text-xs"><span className={margin > 20 ? 'text-emerald-500' : 'text-rose-400'}>{margin.toFixed(1)}%</span></td>
                        <td className="px-10 py-8 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC]/50 text-[#3E2723] rounded-2xl hover:bg-[#3E2723] hover:text-white transition-all shadow-sm"><Edit2 size={20} /></button></td>
                      </tr>
                    );
                 })}
                 {products.length === 0 && <tr><td colSpan={6} className="py-20 text-center text-gray-300 font-black uppercase text-xs italic">No hay productos. Inicie una recepción de mercancía.</td></tr>}
               </tbody>
             </table>
           </div>
        </div>
      )}

      {/* MODAL PRODUCTO (RECEPCIÓN O INVENTARIO) */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/80 z-[250] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[94vh] flex flex-col animate-in zoom-in-95 duration-300 border-b-[12px] border-[#3E2723]">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6">{productModal.mode === 'reception' ? <Truck size={36} className="text-[#AF6E4D]" /> : <Package size={36} className="text-[#AF6E4D]"/>}<h2 className="text-3xl font-black uppercase text-[#3E2723]">{productModal.mode === 'reception' ? 'Entrada por Lote' : `Logística: ${productModal.product?.name}`}</h2></div>
              <button onClick={() => { setProductModal({show: false, mode: 'reception'}); if(activeTab === 'reception') setActiveTab('inventory'); }} className="p-3 text-rose-400"><X size={36} /></button>
            </div>
            <ProductForm 
              mode={productModal.mode} initialData={productModal.product} 
              onSave={p => {
                const existingIdx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                let list = [...products];
                if (existingIdx > -1) {
                  list[existingIdx] = { ...list[existingIdx], ...p, stock: productModal.mode === 'reception' ? (list[existingIdx].stock + p.stock) : p.stock, costPrice: p.costPrice > list[existingIdx].costPrice ? p.costPrice : list[existingIdx].costPrice };
                } else {
                  list = [{ ...p, id: Math.random().toString(), sku: `SKU-${Date.now().toString().slice(-4)}` }, ...list];
                }
                setProducts(list); setProductModal({show: false, mode: 'reception'}); if(activeTab === 'reception') setActiveTab('inventory');
              }}
              onCancel={() => { setProductModal({show: false, mode: 'reception'}); if(activeTab === 'reception') setActiveTab('inventory'); }}
            />
          </div>
        </div>
      )}

      {showSaleModal && <SalesTerminal />}

      {/* MODAL FACTURA */}
      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/90 z-[300] flex items-center justify-center p-4 backdrop-blur-md no-print">
           <div className="bg-white rounded-[60px] w-full max-w-4xl shadow-2xl p-16 overflow-hidden flex flex-col">
              <div className="flex justify-between items-start mb-16">
                 <div className="bg-[#3E2723] p-8 rounded-[32px]"><img src={config.logoUrl} alt="Logo" className="h-20 w-auto brightness-[100]" /></div>
                 <div className="text-right"><p className="text-[10px] font-black uppercase text-gray-400 mb-2">Folio Operativo</p><p className="text-3xl font-black text-[#3E2723]">{selectedInvoice.invoiceNumber}</p><p className="text-sm font-black text-[#AF6E4D] uppercase mt-2">Factura de Despacho PaTí</p></div>
              </div>
              <div className="flex-1 space-y-8 overflow-y-auto">
                 <table className="w-full text-left">
                    <thead><tr className="border-b-4 border-[#3E2723] text-[10px] uppercase font-black text-gray-400"><th className="py-4">Producto</th><th className="py-4 text-center">Cant.</th><th className="py-4 text-right">Subtotal</th></tr></thead>
                    <tbody className="divide-y text-sm font-bold">
                       {selectedInvoice.items.map((i, idx) => (
                         <tr key={idx}><td className="py-6 uppercase">{i.productName} <span className="text-[9px] text-[#AF6E4D] ml-2">({i.groupingLabel || 'Unid'})</span></td><td className="py-6 text-center">{i.quantity}</td><td className="py-6 text-right tabular-nums">{i.total.toLocaleString()} {i.currency}</td></tr>
                       ))}
                    </tbody>
                 </table>
                 <div className="pt-8 border-t-4 border-[#3E2723] text-right"><p className="text-[10px] font-black uppercase text-gray-400 mb-2">Total Liquidado</p><p className="text-6xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-30">CUP</span></p></div>
              </div>
              <div className="mt-12 flex justify-center gap-6"><button onClick={() => window.print()} className="bg-[#3E2723] text-white px-16 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl flex items-center gap-4"><Printer size={20}/> Imprimir Factura</button><button onClick={() => setSelectedInvoice(null)} className="px-10 py-8 font-black uppercase text-xs text-gray-400">Cerrar</button></div>
           </div>
        </div>
      )}

      {socialPost && (
        <div className="fixed inset-0 bg-black/80 z-[250] flex items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white rounded-[60px] w-full max-w-2xl shadow-2xl p-12 animate-in zoom-in-95 border-4 border-[#F5F5DC]">
              <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black uppercase text-[#3E2723] flex items-center gap-4"><Share2 size={32} className="text-[#AF6E4D]"/> Marketing PaTí</h2><button onClick={() => setSocialPost(null)}><X size={36}/></button></div>
              <div className="bg-[#FCF9F7] p-10 rounded-[40px] border-2 border-[#D7CCC8]/30 mb-10"><textarea className="w-full h-80 bg-transparent font-medium text-lg text-[#3E2723] outline-none leading-relaxed" value={socialPost} readOnly /></div>
              <button onClick={() => { navigator.clipboard.writeText(socialPost); alert("Contenido copiado."); }} className="w-full bg-[#3E2723] text-white py-6 rounded-[28px] font-black uppercase text-xs flex items-center justify-center gap-4 shadow-xl active:scale-95 transition-all"><Copy size={20}/> Copiar Texto</button>
           </div>
        </div>
      )}

      {/* RESTO DE MODULOS CARGADOS DESDE COMPONENTES EXTERNOS O LÓGICA PREVIA */}
      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}
      {activeTab === 'closure' && (
        <div className="max-w-4xl mx-auto py-12"><div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl p-16 flex flex-col items-center"><div className="p-10 bg-[#F5F5DC] rounded-full mb-8"><Wallet size={80} className="text-[#3E2723] opacity-60"/></div><h2 className="text-4xl font-black text-[#3E2723] uppercase mb-12">Cierre de Caja</h2><div className="w-full grid grid-cols-2 gap-8 mb-12"><div className="bg-[#FCF9F7] p-8 rounded-[40px] text-center"><p className="text-[10px] font-black text-gray-400 uppercase mb-2">Recaudación (CUP)</p><p className="text-4xl font-black text-[#3E2723]">{transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').reduce((a, b) => a + b.totalCup, 0).toLocaleString()} CUP</p></div><div className="bg-[#FCF9F7] p-8 rounded-[40px] text-center"><p className="text-[10px] font-black text-gray-400 uppercase mb-2">Facturas</p><p className="text-4xl font-black text-[#3E2723]">{transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').length}</p></div></div><button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl flex items-center gap-6"><Printer size={24}/> Imprimir Auditoría Diario</button></div></div>
      )}
      {activeTab === 'suppliers' && (
        <div className="space-y-8 pb-10">
           <div className="flex justify-between items-end"><h2 className="text-4xl font-black uppercase text-[#3E2723]">Directorio Comercial</h2><button onClick={() => setShowContactModal(true)} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl">+ Nuevo Socio</button></div>
