      )}
      {activeTab === 'maintenance' && (
        <div className="max-w-4xl mx-auto py-40 bg-white rounded-[80px] border border-[#D7CCC8]/20 shadow-2xl flex flex-col items-center"><div className="p-12 bg-[#F5F5DC] rounded-full mb-10"><Database size={100} className="text-[#3E2723] opacity-60"/></div><h2 className="text-4xl font-black uppercase text-[#3E2723] mb-8">Bóveda de Datos PaTí</h2><div className="flex gap-8"><button onClick={() => { const data = { products, contacts, transactions }; const blob = new Blob([JSON.stringify(data)], { type: 'application/json' }); const link = document.createElement('a'); link.href = URL.createObjectURL(blob); link.download = `pati_backup.json`; link.click(); }} className="bg-[#3E2723] text-white px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6"><Download size={24}/> Exportar Respaldo</button><label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6 cursor-pointer"><Upload size={24}/> Importar Datos <input type="file" className="hidden" accept=".json" onChange={(e) => { const file = e.target.files?.[0]; if (!file) return; const r = new FileReader(); r.onload = (ev) => { const data = JSON.parse(ev.target?.result as string); if (data.products) setProducts(data.products); if (data.contacts) setContacts(data.contacts); if (data.transactions) setTransactions(data.transactions); alert("Datos restaurados."); }; r.readAsText(file); }} /></label></div></div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/80 z-[160] flex items-center justify-center p-4"><div className="bg-white rounded-[60px] w-full max-w-lg p-16"><h2 className="text-3xl font-black uppercase text-[#3E2723] mb-12">Nuevo Socio</h2><form onSubmit={(e) => { e.preventDefault(); const fd = new FormData(e.currentTarget); const newC: Contact = { id: Math.random().toString(), name: fd.get('name') as string, contactName: fd.get('name') as string, phone: fd.get('phone') as string, email: '', address: fd.get('address') as string, type: fd.get('type') as any, isConsignee: fd.get('type') === 'Proveedor', pendingBalanceCup: 0, pendingBalanceUsd: 0 }; setContacts([...contacts, newC]); setShowContactModal(false); }} className="space-y-8"><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Nombre / Razón Social</label><input name="name" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Teléfono</label><input name="phone" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Dirección</label><input name="address" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Perfil</label><select name="type" className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-black uppercase text-xs"><option value="Proveedor">Proveedor</option><option value="Cliente">Cliente</option></select></div><button type="submit" className="w-full bg-[#3E2723] text-white py-8 rounded-[36px] font-black uppercase text-xs shadow-2xl">Registrar Socio</button></form></div></div>
      )}

    </Layout>
  );
};

