import React, { useState, useEffect, useMemo, useCallback } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  Minus, FileText, History, Info, Facebook, Instagram, Mail, Star, Globe, Settings, ImageIcon, Copy, Share2, TrendingUp, Percent, RefreshCw
} from 'lucide-react';
import { LOGO_URL, STORE_NAME } from './constants';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions',
  CONFIG: 'pati_v3_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: LOGO_URL,
  storeName: STORE_NAME,
  aboutText: "Mercado PaTí es su socio de confianza para productos frescos y de calidad. Gestión profesional de inventarios y consignaciones.",
  address: "Calle Real #123, Habana Vieja",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [isDataLoaded, setIsDataLoaded] = useState(false);

  // CARGA INICIAL ROBUSTA
  useEffect(() => {
    const loadData = () => {
      try {
        const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
        const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
        const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
        const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

        if (p) setProducts(JSON.parse(p));
        if (c) setContacts(JSON.parse(c));
        if (t) setTransactions(JSON.parse(t));
        if (cfg) setConfig(JSON.parse(cfg));

        setIsDataLoaded(true);
      } catch (e) {
        console.error("Error cargando base de datos local:", e);
      }
    };
    loadData();
  }, []);

  // PERSISTENCIA AUTOMÁTICA (Sincronización en tiempo real)
  useEffect(() => {
    if (isDataLoaded) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataLoaded]);

  // GESTIÓN DE NOTIFICACIONES
  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `${p.name} necesita reposición.`, type: 'warning', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // FILTRADO DE INVENTARIO
  const filteredProducts = useMemo(() => {
    const search = inventorySearch.toLowerCase().trim();
    if (!search) return products;
    return products.filter(p => p.name.toLowerCase().includes(search));
  }, [products, inventorySearch]);

  // --- FORMULARIO DE PRODUCTO Y LOGÍSTICA DE PRECIOS ---
  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', receptionType: 'Consignación', unitCurrency: 'CUP', groupings: [],
      stock: 0, minStock: 5, unitPrice: 0, costPrice: 0, lots: []
    });
    const [transportCost, setTransportCost] = useState(0);
    const [nameSearch, setNameSearch] = useState(initialData?.name || '');
    const [showNameDropdown, setShowNameDropdown] = useState(false);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const margin = useMemo(() => {
      if (!formData.unitPrice || !formData.costPrice || formData.unitPrice <= 0) return 0;
      return ((formData.unitPrice - formData.costPrice) / formData.unitPrice) * 100;
    }, [formData.unitPrice, formData.costPrice]);

    const handleSave = () => {
      if (!formData.name) { alert("El nombre es obligatorio"); return; }
      const finalProduct = { ...formData } as Product;

      if (mode === 'reception') {
        const newLot: ReceptionLot = {
          id: Math.random().toString(), date: new Date().toISOString(),
          quantityReceived: finalProduct.stock, currentStock: finalProduct.stock,
          unitCost: finalProduct.costPrice, transportCost: transportCost,
          totalInvestment: (finalProduct.stock * finalProduct.costPrice) + transportCost
        };
        finalProduct.lots = [...(finalProduct.lots || []), newLot];
      }
      onSave(finalProduct);
    };

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-6 md:p-12 space-y-10 custom-scrollbar">
          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b pb-4 flex items-center gap-3">
              <Package size={14}/> {mode === 'reception' ? 'Recepción de Mercancía' : 'Ficha de Producto'}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div className="relative">
                <label className="text-[9px] font-black text-gray-400 uppercase">Nombre Comercial</label>
                <input 
                  value={nameSearch} 
                  onChange={e => { setNameSearch(e.target.value); setFormData({...formData, name: e.target.value}); setShowNameDropdown(true); }}
                  className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" 
                  placeholder="Ej: Aceite Vegetal 1L"
                  disabled={mode === 'edit'}
                />
                {showNameDropdown && nameSearch && mode === 'reception' && (
                  <div className="absolute top-full left-0 w-full bg-white border border-[#D7CCC8]/30 rounded-2xl shadow-xl z-50 mt-1 max-h-48 overflow-y-auto">
                    {products.filter(p => p.name.toLowerCase().includes(nameSearch.toLowerCase())).map(p => (
                      <button key={p.id} onClick={() => { setFormData({...p, stock: 0}); setNameSearch(p.name); setShowNameDropdown(false); }} className="w-full p-4 text-left hover:bg-[#F5F5DC] border-b text-xs font-bold uppercase flex justify-between">
                        {p.name} <span className="text-[#AF6E4D]">ALM: {p.stock}</span>
                      </button>
                    ))}
                  </div>
                )}
              </div>
              <div>
                <label className="text-[9px] font-black text-gray-400 uppercase">Costo Unitario (CUP)</label>
                <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
              <div>
                <label className="text-[9px] font-black text-gray-400 uppercase">{mode === 'reception' ? 'Cantidad Recibida' : 'Existencia Almacén'}</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
            </div>
            {mode === 'reception' && (
              <div className="bg-[#F5F5DC]/30 p-6 rounded-2xl border border-[#D7CCC8]/20">
                <label className="text-[9px] font-black text-[#AF6E4D] uppercase flex items-center gap-2"><Truck size={12}/> Costo Logístico de Transportación (Viaje/Lote)</label>
                <input type="number" value={transportCost} onChange={e => setTransportCost(parseFloat(e.target.value))} className="w-full mt-2 p-4 bg-white border border-[#D7CCC8]/30 rounded-xl font-bold" placeholder="Importe del flete..." />
              </div>
            )}
          </section>

          {mode === 'edit' && (
            <section className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
              <div className="flex justify-between items-center bg-[#3E2723] p-6 rounded-[32px] text-white">
                <div className="flex items-center gap-4"><DollarSign className="text-[#AF6E4D]" /><h3 className="text-xs font-black uppercase tracking-widest">Logística de Venta</h3></div>
                <div className={`px-4 py-2 rounded-full font-black text-[10px] uppercase ${margin > 20 ? 'bg-emerald-500/20 text-emerald-400' : 'bg-rose-500/20 text-rose-400'}`}>Margen Real: {margin.toFixed(1)}%</div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Precio Venta (Unidad)</label>
                  <div className="flex gap-2">
                    <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                    <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-5 bg-[#F5F5DC] rounded-2xl font-black text-[10px]"><option value="CUP">CUP</option><option value="USD">USD</option></select>
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Aviso de Existencia Crítica</label>
                  <input type="number" value={formData.minStock || ''} onChange={e => setFormData({...formData, minStock: parseInt(e.target.value)})} className="w-full p-5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                </div>
              </div>

              <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30 space-y-6">
                <div className="flex items-center gap-4"><Layers className="text-[#AF6E4D]" /><h3 className="text-xs font-black text-[#3E2723] uppercase tracking-widest">Agrupaciones de Precio (Packs, Cajas, Palets)</h3></div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 items-end">
                  <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Etiqueta</label><input placeholder="Ej: Caja x24" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="w-full p-4 bg-white border border-[#D7CCC8]/20 rounded-xl text-xs font-bold outline-none focus:border-[#AF6E4D]" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Unidades</label><input type="number" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/20 rounded-xl text-xs font-bold outline-none focus:border-[#AF6E4D]" /></div>
                  <div className="space-y-1"><label className="text-[8px] font-black text-gray-400 uppercase">Precio Pack</label><input type="number" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="w-full p-4 bg-white border border-[#D7CCC8]/20 rounded-xl text-xs font-bold outline-none focus:border-[#AF6E4D]" /></div>
                  <button onClick={() => {
                    if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
                    setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                    setTempGrouping({id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP'});
