                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-6">
                  {formData.groupings?.map(g => (
                    <div key={g.id} className="bg-white p-5 rounded-2xl border border-[#D7CCC8]/20 flex justify-between items-center shadow-sm">
