          <button onClick={handleSave} className="bg-[#3E2723] text-white px-10 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3 active:scale-95 transition-all"><Save size={18}/> {mode === 'reception' ? 'Finalizar Recepción' : 'Guardar Cambios'}</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>
      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500 pb-20">
          <div className="flex flex-col md:flex-row justify-between items-end gap-6">
            <div className="space-y-4 flex-1 w-full max-w-2xl">
              <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Control de Almacén</h2>
