              >
                <Instagram size={18}/> Marketing
              </button>
              <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="flex-1 md:flex-none bg-[#3E2723] text-white px-8 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl hover:scale-105 transition-all flex items-center justify-center gap-4"><Plus size={20}/> Recepción</button>
            </div>
          </div>

          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl overflow-x-auto">
            <table className="w-full text-left min-w-[900px]">
              <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black tracking-[0.2em]">
                <tr>
                  <th className="px-10 py-8">Producto</th>
                  <th className="px-10 py-8 text-center">Existencia</th>
                  <th className="px-10 py-8">Costo Maestro</th>
                  <th className="px-10 py-8">Precio Venta</th>
