                  <th className="px-10 py-8 text-right">Gestión</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-[#D7CCC8]/10 text-[#3E2723]">
                {filteredProducts.map(p => {
                  const m = p.unitPrice > 0 ? (((p.unitPrice - p.costPrice) / p.unitPrice) * 100) : 0;
                  return (
                    <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors group">
                      <td className="px-10 py-8"><p className="font-black text-sm uppercase tracking-tight">{p.name}</p></td>
                      <td className="px-10 py-8 text-center text-xl font-black">{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                      <td className="px-10 py-8 font-black text-xs">{p.costPrice.toLocaleString()} CUP</td>
                      <td className="px-10 py-8 font-black text-xs text-[#AF6E4D]">{p.unitPrice > 0 ? `${p.unitPrice.toLocaleString()} ${p.unitCurrency}` : '--'}</td>
                      <td className="px-10 py-8 font-black text-xs"><span className={m > 20 ? 'text-emerald-500' : 'text-rose-400'}>{m.toFixed(1)}%</span></td>
                      <td className="px-10 py-8 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC]/50 text-[#3E2723] rounded-2xl hover:bg-[#3E2723] hover:text-white transition-all shadow-sm"><Edit2 size={20} /></button></td>
                    </tr>
                  );
                })}
                {filteredProducts.length === 0 && (
                  <tr><td colSpan={6} className="py-32 text-center text-gray-300 font-black uppercase text-xs italic tracking-widest flex flex-col items-center gap-6"><Package size={40} className="opacity-20"/> {products.length === 0 ? "Inicie su inventario con una Recepción" : "Sin coincidencias de búsqueda"}</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* MODAL MAESTRO DE PRODUCTO */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/90 z-[250] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[96vh] flex flex-col animate-in zoom-in-95 duration-300 border-b-[16px] border-[#3E2723]">
            <div className="p-10 border-b border-[#D7CCC8]/20 flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6">{productModal.mode === 'reception' ? <Truck size={36} className="text-[#AF6E4D]" /> : <Package size={36} className="text-[#AF6E4D]"/>}<h2 className="text-3xl font-black uppercase text-[#3E2723]">{productModal.mode === 'reception' ? 'Entrada de Mercancía' : `Edición Logística: ${productModal.product?.name}`}</h2></div>
              <button onClick={() => setProductModal({show: false, mode: 'reception'})} className="p-3 text-rose-400 hover:rotate-90 transition-transform"><X size={36} /></button>
            </div>
            <ProductForm 
              mode={productModal.mode} 
              initialData={productModal.product} 
              onSave={p => {
                const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                let newList = [...products];
                if (idx > -1) {
                  newList[idx] = { 
                    ...newList[idx], 
                    ...p, 
                    stock: productModal.mode === 'reception' ? (newList[idx].stock + p.stock) : p.stock,
                    costPrice: p.costPrice > newList[idx].costPrice ? p.costPrice : newList[idx].costPrice
                  };
                } else {
                  newList = [{ ...p, id: Math.random().toString() }, ...newList];
                }
                setProducts(newList);
                setProductModal({show: false, mode: 'reception'});
              }}
              onCancel={() => setProductModal({show: false, mode: 'reception'})}
            />
          </div>
        </div>
      )}

      {/* MARKETING MODAL */}
      {socialPost && (
        <div className="fixed inset-0 bg-black/80 z-[300] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-2xl shadow-2xl p-12 animate-in zoom-in-95 duration-300 border-4 border-[#F5F5DC]">
            <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black uppercase text-[#3E2723] flex items-center gap-4"><Share2 size={32} className="text-[#AF6E4D]"/> Marketing PaTí</h2><button onClick={() => setSocialPost(null)}><X size={36}/></button></div>
            <div className="bg-[#FCF9F7] p-10 rounded-[40px] border-2 border-[#D7CCC8]/30 mb-10"><textarea className="w-full h-80 bg-transparent font-medium text-lg text-[#3E2723] outline-none leading-relaxed resize-none custom-scrollbar" value={socialPost} onChange={e => setSocialPost(e.target.value)} /></div>
            <button onClick={() => { navigator.clipboard.writeText(socialPost); alert("Copiado al portapapeles"); }} className="w-full bg-[#3E2723] text-white py-6 rounded-[28px] font-black uppercase text-xs flex items-center justify-center gap-4 shadow-xl active:scale-95 transition-all"><Copy size={20}/> Copiar Contenido</button>
          </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}

      {activeTab === 'maintenance' && (
        <div className="max-w-4xl mx-auto py-40 bg-white rounded-[80px] border border-[#D7CCC8]/20 shadow-2xl flex flex-col items-center animate-in zoom-in-95 duration-500">
          <div className="p-12 bg-[#F5F5DC] rounded-full mb-10 shadow-inner"><Database size={100} className="text-[#3E2723] opacity-60"/></div>
          <h2 className="text-4xl font-black uppercase text-[#3E2723] mb-8 tracking-tighter">Bóveda de Respaldo PaTí</h2>
          <div className="flex flex-col md:flex-row gap-8">
            <button onClick={() => {
              const data = { products, contacts, transactions, config };
              const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
              const url = URL.createObjectURL(blob);
              const link = document.createElement('a');
              link.href = url;
              link.download = `pati_base_datos_${new Date().toISOString().split('T')[0]}.json`;
              link.click();
            }} className="bg-[#3E2723] text-white px-16 py-8 rounded-[36px] font-black uppercase text-xs shadow-2xl hover:bg-[#AF6E4D] transition-all flex items-center gap-6"><Download size={24}/> Exportar DB</button>
            <label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[36px] font-black uppercase text-xs shadow-xl flex items-center gap-6 cursor-pointer border border-[#D7CCC8]/40 hover:bg-[#D7CCC8] transition-all">
              <Upload size={24}/> Importar DB 
              <input type="file" className="hidden" accept=".json" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const r = new FileReader();
                r.onload = (ev) => {
                  try {
                    const data = JSON.parse(ev.target?.result as string);
                    if (data.products) setProducts(data.products);
                    if (data.contacts) setContacts(data.contacts);
                    if (data.transactions) setTransactions(data.transactions);
                    if (data.config) setConfig(data.config);
                    alert("Base de datos restaurada con éxito. El inventario se ha actualizado.");
                  } catch(e) { alert("Error al leer el archivo. Formato no válido."); }
                };
                r.readAsText(file);
              }} />
            </label>
          </div>
        </div>
      )}

      {/* ... Otros módulos (About, Config, etc) manteniendo el estilo visual profesional ... */}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  Minus, FileText, History, Info, Facebook, Instagram, Mail, Star, Globe, Settings, ImageIcon, Copy, Share2, TrendingUp, Percent
} from 'lucide-react';
import { LOGO_URL, STORE_NAME } from './constants';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions',
  CONFIG: 'pati_v3_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: LOGO_URL,
  storeName: STORE_NAME,
  aboutText: "Mercado PaTí es su socio de confianza para productos frescos y de calidad. Gestionamos mercancías en consignación con total transparencia.",
  address: "Calle Real #123, Habana Vieja",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);
  const [isDataLoaded, setIsDataLoaded] = useState(false);

  // Modales y estados de UI
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showContactModal, setShowContactModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  // CARGA INICIAL Y PERSISTENCIA
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);
    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (cfg) setConfig(JSON.parse(cfg));
    setIsDataLoaded(true);
  }, []);

  useEffect(() => {
    if (isDataLoaded) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataLoaded]);

  // NOTIFICACIONES AUTOMÁTICAS
  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `${p.name} requiere reposición.`, type: 'warning', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // --- LÓGICA DE VENTA ---
  const addToCart = (p: Product, grouping?: GroupingPrice) => {
    const price = grouping ? grouping.price : p.unitPrice;
    const currency = grouping ? grouping.currency : p.unitCurrency;
    const label = grouping ? grouping.label : 'Unidad';
    const unitQty = grouping ? grouping.quantity : 1;

    const existingIdx = cart.findIndex(i => i.productId === p.id && i.groupingId === grouping?.id);
    if (existingIdx > -1) {
      const newCart = [...cart];
      newCart[existingIdx].quantity += 1;
      newCart[existingIdx].total = newCart[existingIdx].quantity * newCart[existingIdx].price;
      setCart(newCart);
    } else {
      setCart([...cart, {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: label, quantity: 1,
        price, total: price, currency, unitQuantity: unitQty
      }]);
    }
  };

  const processSale = () => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);

    const newTransaction: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(),
      clientId: 'Gral', clientName: 'Consumidor Final', items: [...cart],
      totalCup, totalUsd, paymentMethod, status: 'Despachado',
      invoiceNumber: `FAC-${Date.now().toString().slice(-6)}`
    };

    setTransactions([newTransaction, ...transactions]);
    // Descontar Stock
    const updatedProducts = products.map(p => {
      const soldItems = cart.filter(i => i.productId === p.id);
      const totalSoldUnits = soldItems.reduce((acc, i) => acc + (i.quantity * i.unitQuantity), 0);
      return totalSoldUnits > 0 ? { ...p, stock: Math.max(0, p.stock - totalSoldUnits) } : p;
    });
    setProducts(updatedProducts);
    setCart([]);
    setSelectedInvoice(newTransaction);
  };

  // --- COMPONENTE FORMULARIO PRODUCTO ---
  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', receptionType: 'Consignación', unitCurrency: 'CUP', groupings: [],
      stock: 0, minStock: 5, unitPrice: 0, costPrice: 0, lots: []
    });
    const [transportCost, setTransportCost] = useState(0);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const margin = useMemo(() => {
      if (!formData.unitPrice || !formData.costPrice || formData.unitPrice <= 0) return 0;
      return ((formData.unitPrice - formData.costPrice) / formData.unitPrice) * 100;
    }, [formData.unitPrice, formData.costPrice]);

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-12 space-y-12 custom-scrollbar">
          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b pb-4">Datos del Lote / Producto</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Nombre Comercial</label>
                <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold outline-none" placeholder="Ej: Café Serrano 250g" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Costo Maestro (CUP)</label>
                <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">{mode === 'reception' ? 'Cantidad Recibida' : 'Stock Actual'}</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
            </div>
          </section>

          {mode === 'edit' && (
            <section className="space-y-10 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30">
                  <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Precio y Rentabilidad</h4>
                  <div className="space-y-4">
                     <div className="flex gap-2">
                        <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" placeholder="Precio Unidad" />
                        <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-4 bg-[#F5F5DC] rounded-2xl font-black text-xs"><option value="CUP">CUP</option><option value="USD">USD</option></select>
                     </div>
                     <div className="flex justify-between items-center p-4 bg-white rounded-2xl border border-[#D7CCC8]/10">
                        <span className="text-[10px] font-black uppercase text-gray-400">Margen de Ganancia:</span>
                        <span className={`text-sm font-black ${margin > 20 ? 'text-emerald-500' : 'text-rose-400'}`}>{margin.toFixed(1)}%</span>
                     </div>
                  </div>
                </div>
                <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30">
                   <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Logística de Precio (Packs)</h4>
                   <div className="grid grid-cols-2 gap-4">
                      <input placeholder="Caja x24" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" />
                      <input type="number" placeholder="Precio" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" />
                      <input type="number" placeholder="Unidades" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" />
                      <button onClick={() => {
                        if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
                        setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                        setTempGrouping({id: '', label: '', quantity: 0, price: 0, currency: 'CUP'});
                      }} className="bg-[#3E2723] text-white rounded-2xl font-black text-[10px] uppercase">+ Añadir</button>
                   </div>
                   <div className="mt-4 flex flex-wrap gap-2">
                      {formData.groupings?.map(g => (
                        <div key={g.id} className="bg-white px-3 py-2 rounded-xl border border-[#D7CCC8]/30 text-[9px] font-black flex items-center gap-2 uppercase">
                          {g.label} ({g.price} {g.currency})
                          <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-400"><X size={12}/></button>
                        </div>
                      ))}
                   </div>
                </div>
              </div>
            </section>
          )}
        </div>
        <div className="p-8 border-t flex justify-end gap-4 shadow-2xl bg-white">
          <button onClick={onCancel} className="px-8 py-4 text-[#D7CCC8] font-black uppercase text-xs">Cerrar</button>
          <button onClick={() => {
            const final = {...formData} as Product;
            if (mode === 'reception') {
              final.lots = [...(final.lots || []), { id: Math.random().toString(), date: new Date().toISOString(), quantityReceived: final.stock, currentStock: final.stock, unitCost: final.costPrice, transportCost: transportCost, totalInvestment: (final.stock * final.costPrice) + transportCost }];
            }
            onSave(final);
          }} className="bg-[#3E2723] text-white px-10 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl"><Save size={18} className="inline mr-2"/> Guardar Todo</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500 pb-20">
          <div className="flex justify-between items-end">
            <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Control de Inventario</h2>
            <div className="flex gap-4">
              <button onClick={async () => { const post = await generateSocialMediaPost(products); setSocialPost(post); }} className="bg-[#AF6E4D] text-white px-8 py-5 rounded-[28px] text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-3"><Instagram size={18}/> Marketing IA</button>
              <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="bg-[#3E2723] text-white px-8 py-5 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center gap-3"><Plus size={20}/> Entrada Lote</button>
            </div>
          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Existencia</th><th className="px-10 py-8">Costo Maestro</th><th className="px-10 py-8">Venta Unit.</th><th className="px-10 py-8">Margen</th><th className="px-10 py-8 text-right">Gestión</th></tr>
              </thead>
              <tbody className="divide-y text-[#3E2723]">
                {products.map(p => {
                  const m = p.unitPrice > 0 ? (((p.unitPrice - p.costPrice) / p.unitPrice) * 100) : 0;
                  return (
                    <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                      <td className="px-10 py-8 font-black text-sm uppercase">{p.name}</td>
                      <td className="px-10 py-8 text-center text-xl font-black">{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                      <td className="px-10 py-8 font-black text-xs">{p.costPrice.toLocaleString()} CUP</td>
                      <td className="px-10 py-8 font-black text-xs text-[#AF6E4D]">{p.unitPrice > 0 ? `${p.unitPrice.toLocaleString()} ${p.unitCurrency}` : '--'}</td>
                      <td className="px-10 py-8"><span className={`text-xs font-black ${m > 20 ? 'text-emerald-500' : 'text-rose-400'}`}>{m.toFixed(1)}%</span></td>
                      <td className="px-10 py-8 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC]/50 text-[#3E2723] rounded-2xl hover:bg-[#3E2723] hover:text-white transition-all"><Edit2 size={20}/></button></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-[calc(100vh-140px)] gap-8 animate-in zoom-in-95 duration-500">
           <div className="w-2/3 bg-white rounded-[60px] border border-[#D7CCC8]/20 p-10 flex flex-col shadow-2xl">
              <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal Punto de Venta</h2><div className="relative w-72"><Search className="absolute left-4 top-4 text-[#D7CCC8]" size={18}/><input placeholder="Buscar producto..." className="w-full pl-12 pr-4 py-4 bg-[#FCF9F7] rounded-2xl font-bold border-none outline-none" onChange={e => setInventorySearch(e.target.value)} /></div></div>
              <div className="flex-1 overflow-y-auto grid grid-cols-2 gap-6 custom-scrollbar pr-4">
                 {products.filter(p => p.name.toLowerCase().includes(inventorySearch.toLowerCase())).map(p => (
