              <div className="mt-12 flex justify-center gap-6"><button onClick={() => window.print()} className="bg-[#3E2723] text-white px-16 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl flex items-center gap-4"><Printer size={20}/> Imprimir Factura</button><button onClick={() => setSelectedInvoice(null)} className="px-10 py-8 font-black uppercase text-xs text-gray-400">Cerrar</button></div>
           </div>
