              <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black uppercase text-[#3E2723] flex items-center gap-4"><Share2 size={32} className="text-[#AF6E4D]"/> Marketing PaTí</h2><button onClick={() => setSocialPost(null)}><X size={36}/></button></div>
              <div className="bg-[#FCF9F7] p-10 rounded-[40px] border-2 border-[#D7CCC8]/30 mb-10"><textarea className="w-full h-80 bg-transparent font-medium text-lg text-[#3E2723] outline-none leading-relaxed resize-none" value={socialPost} readOnly /></div>
              <button onClick={() => { navigator.clipboard.writeText(socialPost); alert("Copiado."); }} className="w-full bg-[#3E2723] text-white py-6 rounded-[28px] font-black uppercase text-xs flex items-center justify-center gap-4 shadow-xl active:scale-95 transition-all"><Copy size={20}/> Copiar Contenido</button>
