           <form onSubmit={(e) => { e.preventDefault(); const fd = new FormData(e.currentTarget); const newC: Contact = { id: Math.random().toString(), name: fd.get('name') as string, contactName: fd.get('name') as string, phone: fd.get('phone') as string, email: '', address: fd.get('address') as string, type: fd.get('type') as any, isConsignee: fd.get('type') === 'Proveedor', pendingBalanceCup: 0, pendingBalanceUsd: 0 }; setContacts([...contacts, newC]); setShowContactModal(false); }} className="space-y-8"><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Razón Social</label><input name="name" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Teléfono</label><input name="phone" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Ubicación</label><input name="address" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Perfil</label><select name="type" className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-black uppercase text-xs"><option value="Proveedor">Proveedor</option><option value="Cliente">Cliente</option></select></div><button type="submit" className="w-full bg-[#3E2723] text-white py-8 rounded-[36px] font-black uppercase text-xs shadow-2xl">Vincular Socio</button></form></div>
