import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  Minus, FileText, History, Info, Facebook, Instagram, Mail, Star, Globe, Settings, ImageIcon, Copy, Share2, TrendingUp, Percent,
  Users
} from 'lucide-react';
import { LOGO_URL, STORE_NAME } from './constants';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v3_products',
  CONTACTS: 'pati_v3_contacts',
  TRANSACTIONS: 'pati_v3_transactions',
  CONFIG: 'pati_v3_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: LOGO_URL,
  storeName: STORE_NAME,
  aboutText: "Mercado PaTí es su socio de confianza para productos frescos y de calidad. Gestionamos mercancías en consignación con total transparencia.",
  address: "Calle Real #123, Habana Vieja",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/mercadopati",
  instagramUrl: "https://instagram.com/mercadopati",
  websiteUrl: "https://mercadopati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);
  const [isDataLoaded, setIsDataLoaded] = useState(false);

  // Modales y estados de UI
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showContactModal, setShowContactModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  // CARGA INICIAL Y PERSISTENCIA
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);
    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (cfg) setConfig(JSON.parse(cfg));
    setIsDataLoaded(true);
  }, []);

  useEffect(() => {
    if (isDataLoaded) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataLoaded]);

  // NOTIFICACIONES AUTOMÁTICAS
  useEffect(() => {
    const newNotifs: Notification[] = [];
    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Bajo Stock', message: `${p.name} requiere reposición.`, type: 'warning', date: new Date().toISOString(), read: false });
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // --- LÓGICA DE VENTA ---
  const addToCart = (p: Product, grouping?: GroupingPrice) => {
    const price = grouping ? grouping.price : p.unitPrice;
    const currency = grouping ? grouping.currency : p.unitCurrency;
    const label = grouping ? grouping.label : 'Unidad';
    const unitQty = grouping ? grouping.quantity : 1;

    const existingIdx = cart.findIndex(i => i.productId === p.id && i.groupingId === grouping?.id);
    if (existingIdx > -1) {
      const newCart = [...cart];
      newCart[existingIdx].quantity += 1;
      newCart[existingIdx].total = newCart[existingIdx].quantity * newCart[existingIdx].price;
      setCart(newCart);
    } else {
      setCart([...cart, {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: label, quantity: 1,
        price, total: price, currency, unitQuantity: unitQty
      }]);
    }
  };

  const processSale = () => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);

    const newTransaction: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(),
      clientId: 'Gral', clientName: 'Consumidor Final', items: [...cart],
      totalCup, totalUsd, paymentMethod, status: 'Despachado',
      invoiceNumber: `FAC-${Date.now().toString().slice(-6)}`
    };

    setTransactions([newTransaction, ...transactions]);
    // Descontar Stock
    const updatedProducts = products.map(p => {
      const soldItems = cart.filter(i => i.productId === p.id);
      const totalSoldUnits = soldItems.reduce((acc, i) => acc + (i.quantity * i.unitQuantity), 0);
      return totalSoldUnits > 0 ? { ...p, stock: Math.max(0, p.stock - totalSoldUnits) } : p;
    });
    setProducts(updatedProducts);
    setCart([]);
    setSelectedInvoice(newTransaction);
  };

  // --- COMPONENTE FORMULARIO PRODUCTO ---
  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', receptionType: 'Consignación', unitCurrency: 'CUP', groupings: [],
      stock: 0, minStock: 5, unitPrice: 0, costPrice: 0, lots: []
    });
    const [transportCost, setTransportCost] = useState(0);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const margin = useMemo(() => {
      if (!formData.unitPrice || !formData.costPrice || formData.unitPrice <= 0) return 0;
      return ((formData.unitPrice - formData.costPrice) / formData.unitPrice) * 100;
    }, [formData.unitPrice, formData.costPrice]);

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-12 space-y-12 custom-scrollbar">
          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b pb-4">Datos del Lote / Producto</h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Nombre Comercial</label>
                <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold outline-none" placeholder="Ej: Café Serrano 250g" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Costo Maestro (CUP)</label>
                <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">{mode === 'reception' ? 'Cantidad Recibida' : 'Stock Actual'}</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
            </div>
          </section>

          {mode === 'edit' && (
            <section className="space-y-10 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30">
                  <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Precio y Rentabilidad</h4>
                  <div className="space-y-4">
                     <div className="flex gap-2">
                        <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" placeholder="Precio Unidad" />
                        <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-4 bg-[#F5F5DC] rounded-2xl font-black text-xs"><option value="CUP">CUP</option><option value="USD">USD</option></select>
                     </div>
                     <div className="flex justify-between items-center p-4 bg-white rounded-2xl border border-[#D7CCC8]/10">
                        <span className="text-[10px] font-black uppercase text-gray-400">Margen de Ganancia:</span>
                        <span className={`text-sm font-black ${margin > 20 ? 'text-emerald-500' : 'text-rose-400'}`}>{margin.toFixed(1)}%</span>
                     </div>
                  </div>
                </div>
                <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/30">
                   <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Logística de Precio (Packs)</h4>
                   <div className="grid grid-cols-2 gap-4">
                      <input placeholder="Caja x24" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" />
                      <input type="number" placeholder="Precio" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" />
                      <input type="number" placeholder="Unidades" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl text-xs font-bold" />
                      <button onClick={() => {
                        if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
                        setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                        setTempGrouping({id: '', label: '', quantity: 0, price: 0, currency: 'CUP'});
                      }} className="bg-[#3E2723] text-white rounded-2xl font-black text-[10px] uppercase">+ Añadir</button>
                   </div>
                   <div className="mt-4 flex flex-wrap gap-2">
                      {formData.groupings?.map(g => (
                        <div key={g.id} className="bg-white px-3 py-2 rounded-xl border border-[#D7CCC8]/30 text-[9px] font-black flex items-center gap-2 uppercase">
                          {g.label} ({g.price} {g.currency})
                          <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-400"><X size={12}/></button>
                        </div>
                      ))}
                   </div>
                </div>
              </div>
            </section>
          )}
        </div>
        <div className="p-8 border-t flex justify-end gap-4 shadow-2xl bg-white">
          <button onClick={onCancel} className="px-8 py-4 text-[#D7CCC8] font-black uppercase text-xs">Cerrar</button>
          <button onClick={() => {
            const final = {...formData} as Product;
            if (mode === 'reception') {
              final.lots = [...(final.lots || []), { id: Math.random().toString(), date: new Date().toISOString(), quantityReceived: final.stock, currentStock: final.stock, unitCost: final.costPrice, transportCost: transportCost, totalInvestment: (final.stock * final.costPrice) + transportCost }];
            }
            onSave(final);
          }} className="bg-[#3E2723] text-white px-10 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl"><Save size={18} className="inline mr-2"/> Guardar Todo</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500 pb-20">
          <div className="flex justify-between items-end">
            <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Control de Inventario</h2>
            <div className="flex gap-4">
              <button onClick={async () => { const post = await generateSocialMediaPost(products); setSocialPost(post); }} className="bg-[#AF6E4D] text-white px-8 py-5 rounded-[28px] text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-3"><Instagram size={18}/> Marketing IA</button>
              <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="bg-[#3E2723] text-white px-8 py-5 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center gap-3"><Plus size={20}/> Entrada Lote</button>
            </div>
          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Existencia</th><th className="px-10 py-8">Costo Maestro</th><th className="px-10 py-8">Venta Unit.</th><th className="px-10 py-8">Margen</th><th className="px-10 py-8 text-right">Gestión</th></tr>
              </thead>
              <tbody className="divide-y text-[#3E2723]">
                {products.map(p => {
                  const m = p.unitPrice > 0 ? (((p.unitPrice - p.costPrice) / p.unitPrice) * 100) : 0;
                  return (
                    <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                      <td className="px-10 py-8 font-black text-sm uppercase">{p.name}</td>
                      <td className="px-10 py-8 text-center text-xl font-black">{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                      <td className="px-10 py-8 font-black text-xs">{p.costPrice.toLocaleString()} CUP</td>
                      <td className="px-10 py-8 font-black text-xs text-[#AF6E4D]">{p.unitPrice > 0 ? `${p.unitPrice.toLocaleString()} ${p.unitCurrency}` : '--'}</td>
                      <td className="px-10 py-8"><span className={`text-xs font-black ${m > 20 ? 'text-emerald-500' : 'text-rose-400'}`}>{m.toFixed(1)}%</span></td>
                      <td className="px-10 py-8 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC]/50 text-[#3E2723] rounded-2xl hover:bg-[#3E2723] hover:text-white transition-all"><Edit2 size={20}/></button></td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-[calc(100vh-140px)] gap-8 animate-in zoom-in-95 duration-500">
           <div className="w-2/3 bg-white rounded-[60px] border border-[#D7CCC8]/20 p-10 flex flex-col shadow-2xl">
              <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal Punto de Venta</h2><div className="relative w-72"><Search className="absolute left-4 top-4 text-[#D7CCC8]" size={18}/><input placeholder="Buscar producto..." className="w-full pl-12 pr-4 py-4 bg-[#FCF9F7] rounded-2xl font-bold border-none outline-none" onChange={e => setInventorySearch(e.target.value)} /></div></div>
              <div className="flex-1 overflow-y-auto grid grid-cols-2 gap-6 custom-scrollbar pr-4">
                 {products.filter(p => p.name.toLowerCase().includes(inventorySearch.toLowerCase())).map(p => (
                   <div key={p.id} className="bg-[#FCF9F7] p-6 rounded-[40px] border border-[#D7CCC8]/10 hover:border-[#AF6E4D] transition-all flex flex-col justify-between h-72 group">
                      <div><p className="font-black text-sm uppercase mb-1">{p.name}</p><p className="text-[9px] font-black text-[#AF6E4D] uppercase">Stock: {p.stock} U. | Almacén</p></div>
                      <div className="space-y-3">
                         <button onClick={() => addToCart(p)} disabled={p.unitPrice <= 0} className="w-full py-4 bg-[#3E2723] text-white rounded-2xl font-black text-[10px] uppercase disabled:opacity-20 group-hover:bg-[#AF6E4D] transition-all">Unidad: {p.unitPrice} {p.unitCurrency}</button>
                         <div className="flex flex-wrap gap-2">
                            {p.groupings?.map(g => (
                              <button key={g.id} onClick={() => addToCart(p, g)} className="flex-1 py-3 bg-white border border-[#D7CCC8]/30 rounded-xl text-[8px] font-black uppercase hover:bg-[#3E2723] hover:text-white transition-all">{g.label}</button>
                            ))}
                         </div>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
           <div className="w-1/3 bg-[#3E2723] rounded-[60px] p-10 text-white flex flex-col shadow-2xl relative overflow-hidden">
              <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -mr-32 -mt-32 blur-3xl"></div>
              <h3 className="text-xs font-black uppercase tracking-[0.2em] mb-10 text-[#AF6E4D]">Cesta de Facturación</h3>
              <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
                 {cart.map(i => (
                   <div key={i.id} className="bg-white/5 p-5 rounded-[32px] border border-white/10 flex justify-between items-center group">
                      <div><p className="text-[11px] font-black uppercase">{i.productName}</p><p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{i.groupingLabel} x {i.quantity}</p></div>
                      <div className="flex items-center gap-4"><p className="font-black text-xs">{i.total.toLocaleString()} {i.currency}</p><button onClick={() => setCart(cart.filter(x => x.id !== i.id))} className="text-rose-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16}/></button></div>
                   </div>
                 ))}
                 {cart.length === 0 && <p className="text-center py-20 text-[10px] font-black uppercase opacity-20 tracking-widest">Esperando Productos...</p>}
              </div>
              <div className="pt-8 border-t border-white/10 space-y-6">
                 <div className="flex gap-4"><button onClick={() => setPaymentMethod('Efectivo')} className={`flex-1 py-4 rounded-2xl font-black text-[9px] uppercase border transition-all ${paymentMethod === 'Efectivo' ? 'bg-[#AF6E4D] text-white border-[#AF6E4D]' : 'bg-white/5 text-white/40 border-white/10'}`}>Efectivo</button><button onClick={() => setPaymentMethod('Transferencia')} className={`flex-1 py-4 rounded-2xl font-black text-[9px] uppercase border transition-all ${paymentMethod === 'Transferencia' ? 'bg-[#AF6E4D] text-white border-[#AF6E4D]' : 'bg-white/5 text-white/40 border-white/10'}`}>Transferencia</button></div>
                 <div className="flex justify-between items-end"><p className="text-[10px] font-black uppercase opacity-40">Importe Final</p><p className="text-5xl font-black tracking-tighter tabular-nums">{cart.reduce((a,b)=>a+b.total,0).toLocaleString()} <span className="text-sm opacity-20">CUP</span></p></div>
                 <button onClick={processSale} disabled={cart.length === 0} className="w-full py-8 bg-white text-[#3E2723] rounded-[40px] font-black uppercase text-xs shadow-2xl shadow-black/30 hover:scale-105 active:scale-95 transition-all">Despachar Factura</button>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'suppliers' && (
        <div className="space-y-10 animate-in fade-in duration-500">
           <div className="flex justify-between items-end"><h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter">Directorio Comercial</h2><button onClick={() => setShowContactModal(true)} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center gap-3"><Plus size={20}/> Nuevo Socio</button></div>
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {contacts.map(c => (
                <div key={c.id} className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/20 flex flex-col h-80 justify-between shadow-sm hover:shadow-xl transition-all">
                   <div className="flex justify-between items-start"><div className="w-16 h-16 bg-[#F5F5DC] rounded-2xl flex items-center justify-center font-black text-2xl text-[#3E2723]">{c.name.charAt(0)}</div><span className="text-[9px] font-black uppercase px-4 py-1.5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-full">{c.type}</span></div>
                   <div><h3 className="font-black text-[#3E2723] text-lg uppercase mb-2 truncate">{c.name}</h3><p className="text-xs font-bold text-[#8D6E63] flex items-center gap-2"><Phone size={14}/> {c.phone}</p><p className="text-[10px] font-black text-[#3E2723] uppercase flex items-center gap-2 mt-4 bg-[#FCF9F7] p-4 rounded-2xl"><MapPin size={14}/> {c.address}</p></div>
                </div>
              ))}
              {contacts.length === 0 && <p className="col-span-full py-32 text-center text-[10px] font-black uppercase text-gray-300 tracking-[0.4em] italic">No hay socios comerciales registrados.</p>}
           </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}

      {activeTab === 'maintenance' && (
        <div className="max-w-4xl mx-auto py-32 bg-white rounded-[80px] border border-[#D7CCC8]/20 shadow-2xl flex flex-col items-center animate-in zoom-in-95 duration-500">
           <div className="p-12 bg-[#F5F5DC] rounded-full mb-10"><Database size={100} className="text-[#3E2723] opacity-60"/></div>
           <h2 className="text-4xl font-black uppercase text-[#3E2723] mb-8">Bóveda de Datos PaTí</h2>
           <div className="flex gap-8">
              <button onClick={() => {
                const data = { products, contacts, transactions, config };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const link = document.createElement('a');
                link.href = URL.createObjectURL(blob);
                link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="bg-[#3E2723] text-white px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6"><Download size={24}/> Exportar DB</button>
              <label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6 cursor-pointer"><Upload size={24}/> Importar DB <input type="file" className="hidden" accept=".json" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                   const data = JSON.parse(ev.target?.result as string);
                   if (data.products) setProducts(data.products);
                   if (data.contacts) setContacts(data.contacts);
                   if (data.transactions) setTransactions(data.transactions);
                   if (data.config) setConfig(data.config);
                   alert("Base de datos sincronizada con éxito.");
                };
                reader.readAsText(file);
              }} /></label>
           </div>
        </div>
      )}

      {activeTab === 'config' && (
        <div className="max-w-4xl mx-auto py-10 animate-in slide-in-from-bottom-6 duration-500">
           <div className="bg-white rounded-[60px] border border-[#D7CCC8]/30 shadow-2xl p-16">
              <h2 className="text-4xl font-black text-[#3E2723] uppercase mb-12 flex items-center gap-6"><Settings size={40} className="text-[#AF6E4D]"/> Configuración Maestra</h2>
              <div className="space-y-12">
                 <section className="space-y-6"><h3 className="text-[10px] font-black text-[#AF6E4D] uppercase border-b pb-4">Identidad de Marca</h3><div className="grid grid-cols-1 md:grid-cols-2 gap-8"><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Logo URL</label><input value={config.logoUrl} onChange={e => setConfig({...config, logoUrl: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] font-bold" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Nombre de la Tienda</label><input value={config.storeName} onChange={e => setConfig({...config, storeName: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] font-bold" /></div></div></section>
                 <section className="space-y-6"><h3 className="text-[10px] font-black text-[#AF6E4D] uppercase border-b pb-4">Información de Nosotros</h3><textarea value={config.aboutText} onChange={e => setConfig({...config, aboutText: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] h-40 font-bold custom-scrollbar" /></section>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'about' && (
        <div className="max-w-5xl mx-auto space-y-16 py-10 animate-in fade-in duration-700">
           <div className="relative h-[600px] rounded-[80px] overflow-hidden shadow-2xl border-[12px] border-white">
              <img src="https://images.unsplash.com/photo-1578916171728-46686eac8d58?auto=format&fit=crop&q=80&w=1400" className="w-full h-full object-cover brightness-[0.5]" />
              <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-12">
                 <div className="bg-white/10 backdrop-blur-2xl p-8 rounded-[40px] border border-white/30 mb-10 shadow-2xl"><img src={config.logoUrl} alt="Logo" className="h-32 w-auto brightness-110" /></div>
                 <h2 className="text-6xl font-black text-white uppercase tracking-tighter mb-4">Sobre {config.storeName}</h2>
                 <p className="text-white/80 text-xl font-medium max-w-2xl leading-relaxed italic">"{config.aboutText}"</p>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'closure' && (
        <div className="max-w-4xl mx-auto py-12"><div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl p-16 flex flex-col items-center"><div className="p-10 bg-[#F5F5DC] rounded-full mb-8"><Wallet size={80} className="text-[#3E2723] opacity-60"/></div><h2 className="text-4xl font-black text-[#3E2723] uppercase mb-12">Cierre de Caja Operativo</h2><div className="w-full grid grid-cols-2 gap-8 mb-12"><div className="bg-[#FCF9F7] p-8 rounded-[40px] text-center"><p className="text-[10px] font-black text-gray-400 uppercase mb-2">Recaudación Diario (CUP)</p><p className="text-4xl font-black text-[#3E2723]">{transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').reduce((a, b) => a + b.totalCup, 0).toLocaleString()} <span className="text-xs opacity-20">CUP</span></p></div><div className="bg-[#FCF9F7] p-8 rounded-[40px] text-center"><p className="text-[10px] font-black text-gray-400 uppercase mb-2">Facturas Emitidas</p><p className="text-4xl font-black text-[#3E2723]">{transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').length}</p></div></div><button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl flex items-center gap-6"><Printer size={24}/> Imprimir Auditoría</button></div></div>
      )}

      {/* MODALES GLOBALES */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/90 z-[250] flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white rounded-[60px] w-full max-w-6xl shadow-2xl overflow-hidden max-h-[96vh] flex flex-col animate-in zoom-in-95 border-b-[16px] border-[#3E2723]">
            <div className="p-10 border-b flex justify-between items-center bg-[#F5F5DC]/20">
              <div className="flex items-center gap-6"><Package size={36} className="text-[#AF6E4D]"/><h2 className="text-3xl font-black uppercase text-[#3E2723]">{productModal.mode === 'reception' ? 'Nueva Recepción' : `Gestión Logística: ${productModal.product?.name}`}</h2></div>
              <button onClick={() => setProductModal({show: false, mode: 'reception'})} className="p-3 text-rose-400 hover:rotate-90 transition-transform"><X size={36} /></button>
            </div>
            <ProductForm 
              mode={productModal.mode} initialData={productModal.product} 
              onSave={p => {
                const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                let list = [...products];
                if (idx > -1) {
                  list[idx] = { ...list[idx], ...p, stock: productModal.mode === 'reception' ? (list[idx].stock + p.stock) : p.stock, costPrice: p.costPrice > list[idx].costPrice ? p.costPrice : list[idx].costPrice };
                } else {
                  list = [{ ...p, id: Math.random().toString(), sku: `SKU-${Date.now().toString().slice(-4)}` }, ...list];
                }
                setProducts(list); setProductModal({show: false, mode: 'reception'});
              }}
              onCancel={() => setProductModal({show: false, mode: 'reception'})}
            />
          </div>
        </div>
      )}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/95 z-[300] flex items-center justify-center p-4 no-print">
           <div className="bg-white rounded-[60px] w-full max-w-4xl shadow-2xl p-16 flex flex-col animate-in slide-in-from-bottom-10">
              <div className="flex justify-between items-start mb-16"><div className="bg-[#3E2723] p-8 rounded-[32px]"><img src={config.logoUrl} className="h-20 w-auto brightness-[100]" /></div><div className="text-right"><p className="text-[10px] font-black uppercase text-gray-400">Comprobante Oficial</p><p className="text-3xl font-black text-[#3E2723]">{selectedInvoice.invoiceNumber}</p><p className="text-sm font-black text-[#AF6E4D] uppercase mt-2">Mercado PaTí</p></div></div>
              <div className="flex-1 space-y-8 overflow-y-auto"><table className="w-full text-left"><thead><tr className="border-b-4 border-[#3E2723] text-[10px] uppercase font-black text-gray-400"><th className="py-4">Detalle</th><th className="py-4 text-center">Cant.</th><th className="py-4 text-right">Importe</th></tr></thead><tbody className="divide-y font-bold uppercase">{selectedInvoice.items.map((i, idx) => (<tr key={idx}><td className="py-6">{i.productName} <span className="text-[9px] text-[#AF6E4D]">({i.groupingLabel})</span></td><td className="py-6 text-center">{i.quantity}</td><td className="py-6 text-right">{i.total.toLocaleString()} {i.currency}</td></tr>))}</tbody></table><div className="pt-8 border-t-4 border-[#3E2723] text-right"><p className="text-[10px] font-black uppercase text-gray-400">Total Liquidado</p><p className="text-6xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-20">CUP</span></p></div></div>
              <div className="mt-12 flex justify-center gap-6"><button onClick={() => window.print()} className="bg-[#3E2723] text-white px-16 py-8 rounded-[40px] font-black uppercase text-xs shadow-2xl flex items-center gap-4"><Printer size={20}/> Imprimir Factura</button><button onClick={() => setSelectedInvoice(null)} className="px-10 py-8 font-black uppercase text-xs text-gray-400">Cerrar</button></div>
           </div>
        </div>
      )}

      {socialPost && (
        <div className="fixed inset-0 bg-black/80 z-[300] flex items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white rounded-[60px] w-full max-w-2xl shadow-2xl p-12 animate-in zoom-in-95 border-4 border-[#F5F5DC]">
              <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black uppercase text-[#3E2723] flex items-center gap-4"><Share2 size={32} className="text-[#AF6E4D]"/> Marketing PaTí</h2><button onClick={() => setSocialPost(null)}><X size={36}/></button></div>
              <div className="bg-[#FCF9F7] p-10 rounded-[40px] border-2 border-[#D7CCC8]/30 mb-10"><textarea className="w-full h-80 bg-transparent font-medium text-lg text-[#3E2723] outline-none leading-relaxed resize-none" value={socialPost} readOnly /></div>
              <button onClick={() => { navigator.clipboard.writeText(socialPost); alert("Copiado."); }} className="w-full bg-[#3E2723] text-white py-6 rounded-[28px] font-black uppercase text-xs flex items-center justify-center gap-4 shadow-xl active:scale-95 transition-all"><Copy size={20}/> Copiar Contenido</button>
           </div>
        </div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/80 z-[250] flex items-center justify-center p-4 backdrop-blur-md">
           <div className="bg-white rounded-[60px] w-full max-w-lg p-16 animate-in zoom-in-95"><h2 className="text-3xl font-black uppercase text-[#3E2723] mb-12 flex items-center gap-4"><Users className="text-[#AF6E4D]"/> Nuevo Socio</h2>
           <form onSubmit={(e) => { e.preventDefault(); const fd = new FormData(e.currentTarget); const newC: Contact = { id: Math.random().toString(), name: fd.get('name') as string, contactName: fd.get('name') as string, phone: fd.get('phone') as string, email: '', address: fd.get('address') as string, type: fd.get('type') as any, isConsignee: fd.get('type') === 'Proveedor', pendingBalanceCup: 0, pendingBalanceUsd: 0 }; setContacts([...contacts, newC]); setShowContactModal(false); }} className="space-y-8"><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Razón Social</label><input name="name" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Teléfono</label><input name="phone" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Ubicación</label><input name="address" required className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-bold outline-none" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Perfil</label><select name="type" className="w-full p-6 bg-[#FCF9F7] border rounded-[28px] font-black uppercase text-xs"><option value="Proveedor">Proveedor</option><option value="Cliente">Cliente</option></select></div><button type="submit" className="w-full bg-[#3E2723] text-white py-8 rounded-[36px] font-black uppercase text-xs shadow-2xl">Vincular Socio</button></form></div>
        </div>
      )}

    </Layout>
  );
};

export default App;

import React from 'react';

// Logo oficial Mercado PaTí proporcionado por el usuario
export const LOGO_URL = "https://i.ibb.co/L6S9Dkz/pati-logo.jpg"; 

export const STORE_NAME = "PaTí"; // El nombre se usa internamente, el logo lo muestra visualmente.

export const CATEGORIES = [
  { id: '1', name: 'Alimentos' },
  { id: '2', name: 'Bebidas' },
  { id: '3', name: 'Hogar' },
  { id: '4', name: 'Aseo' },
  { id: '5', name: 'Otros' },
];

export const COLORS = {
  primary: '#3E2723',    // Marrón Extra Oscuro (del logo)
  secondary: '#5D4037',  // Marrón Medio
  caramel: '#AF6E4D',    // Caramelo (del logo)
  beige: '#F5F5DC',      // Beige Fondo
  accent: '#D7CCC8',     // Crema
  background: '#FCF9F7', // Blanco Cálido
};

import React, { useState, useEffect, useMemo } from 'react';
import Layout from './components/Layout';
import Statistics from './components/Statistics';
import Dashboard from './components/Dashboard';
import { 
  Product, Contact, Transaction, Notification, 
  GroupingPrice, Currency, PaymentMethod, SaleItem, StoreConfig, ReceptionLot 
} from './types';
import { 
  Plus, Search, Trash2, Edit2, X, Printer, 
  Save, Truck, ShoppingCart, Layers, Package,
  DollarSign, ShieldCheck, ArrowRight, Wallet, CheckCircle2,
  Phone, MapPin, Download, Upload, Database, Tag, AlertCircle,
  Minus, FileText, History, Info, Facebook, Instagram, Mail, Star, Globe, Settings, ImageIcon, Copy, Share2, TrendingUp, Percent,
  Users
} from 'lucide-react';
import { LOGO_URL, STORE_NAME } from './constants';
import { generateSocialMediaPost } from './services/geminiService';

const STORAGE_KEYS = {
  PRODUCTS: 'pati_v4_products',
  CONTACTS: 'pati_v4_contacts',
  TRANSACTIONS: 'pati_v4_transactions',
  CONFIG: 'pati_v4_config'
};

const DEFAULT_CONFIG: StoreConfig = {
  logoUrl: LOGO_URL,
  storeName: STORE_NAME,
  aboutText: "Gestionamos productos en consignación y venta directa con transparencia y eficiencia.",
  address: "Calle Real #123, Habana Vieja",
  phone: "+53 5 123 4567",
  email: "contacto@mercadopati.cu",
  facebookUrl: "https://facebook.com/pati",
  instagramUrl: "https://instagram.com/pati",
  websiteUrl: "https://pati.cu"
};

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('home');
  const [isInitialized, setIsInitialized] = useState(false);

  // Estados de Datos
  const [products, setProducts] = useState<Product[]>([]);
  const [contacts, setContacts] = useState<Contact[]>([]);
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [config, setConfig] = useState<StoreConfig>(DEFAULT_CONFIG);

  // Estados de UI
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [productModal, setProductModal] = useState<{show: boolean, product?: Product, mode: 'reception' | 'edit'}>({show: false, mode: 'reception'});
  const [showContactModal, setShowContactModal] = useState(false);
  const [selectedInvoice, setSelectedInvoice] = useState<Transaction | null>(null);
  const [socialPost, setSocialPost] = useState<string | null>(null);
  const [inventorySearch, setInventorySearch] = useState('');
  const [cart, setCart] = useState<SaleItem[]>([]);
  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  // 1. CARGA INICIAL (Solo una vez al montar)
  useEffect(() => {
    const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
    const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
    const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
    const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

    if (p) setProducts(JSON.parse(p));
    if (c) setContacts(JSON.parse(c));
    if (t) setTransactions(JSON.parse(t));
    if (cfg) setConfig(JSON.parse(cfg));

    setIsInitialized(true);
  }, []);

  // 2. GUARDADO AUTOMÁTICO (Solo si ya se inicializó para no borrar con arrays vacíos)
  useEffect(() => {
    if (isInitialized) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isInitialized]);

  // 3. GENERADOR DE NOTIFICACIONES (Bajo stock y vencimientos)
  useEffect(() => {
    const newNotifs: Notification[] = [];
    const today = new Date();
    const limitDate = new Date();
    limitDate.setDate(today.getDate() + 60);

    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Bajo', message: `El producto ${p.name} tiene solo ${p.stock} unidades.`, type: 'error', date: new Date().toISOString(), read: false });
      }
      if (p.expiryDate) {
        const exp = new Date(p.expiryDate);
        if (exp <= limitDate && exp > today) {
          newNotifs.push({ id: `exp-${p.id}`, title: 'Próximo a Vencer', message: `${p.name} vence en menos de 60 días (${p.expiryDate}).`, type: 'warning', date: new Date().toISOString(), read: false });
        }
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // --- LÓGICA DE VENTA ---
  const addToCart = (p: Product, grouping?: GroupingPrice) => {
    const price = grouping ? grouping.price : p.unitPrice;
    const currency = grouping ? grouping.currency : p.unitCurrency;
    const label = grouping ? grouping.label : 'Unidad';
    const unitQty = grouping ? grouping.quantity : 1;

    if (p.stock < unitQty) { alert("Stock insuficiente para esta agrupación."); return; }

    const existingIdx = cart.findIndex(i => i.productId === p.id && i.groupingId === grouping?.id);
    if (existingIdx > -1) {
      const newCart = [...cart];
      newCart[existingIdx].quantity += 1;
      newCart[existingIdx].total = newCart[existingIdx].quantity * newCart[existingIdx].price;
      setCart(newCart);
    } else {
      setCart([...cart, {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: label, quantity: 1,
        price, total: price, currency, unitQuantity: unitQty
      }]);
    }
  };

  const handleProcessSale = () => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);

    const newTransaction: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(),
      clientId: 'Gral', clientName: 'Público General', items: [...cart],
      totalCup, totalUsd, paymentMethod, status: 'Despachado',
      invoiceNumber: `PATI-${Date.now().toString().slice(-6)}`
    };

    setTransactions([newTransaction, ...transactions]);
    const updatedProducts = products.map(p => {
      const soldItems = cart.filter(i => i.productId === p.id);
      const totalSoldUnits = soldItems.reduce((acc, i) => acc + (i.quantity * i.unitQuantity), 0);
      return totalSoldUnits > 0 ? { ...p, stock: Math.max(0, p.stock - totalSoldUnits) } : p;
    });
    setProducts(updatedProducts);
    setCart([]);
    setSelectedInvoice(newTransaction);
  };

  // --- COMPONENTE FORMULARIO PRODUCTO ---
  const ProductForm = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', receptionType: 'Consignación', unitCurrency: 'CUP', groupings: [],
      stock: 0, minStock: 5, unitPrice: 0, costPrice: 0, expiryDate: '', lots: []
    });
    const [transportCost, setTransportCost] = useState(0);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const margin = useMemo(() => {
      if (!formData.unitPrice || !formData.costPrice || formData.unitPrice <= 0) return 0;
      return ((formData.unitPrice - formData.costPrice) / formData.unitPrice) * 100;
    }, [formData.unitPrice, formData.costPrice]);

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-12 space-y-12 custom-scrollbar">
          <section className="space-y-6">
            <h3 className="text-[10px] font-black uppercase text-[#AF6E4D] tracking-[0.4em] border-b pb-4">
               {mode === 'reception' ? 'Nueva Recepción de Mercancía' : 'Ficha Técnica del Producto'}
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Nombre del Producto</label>
                <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Costo de Compra (CUP)</label>
                <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">{mode === 'reception' ? 'Cantidad Recibida' : 'Existencia Almacén'}</label>
                <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Fecha de Vencimiento</label>
                <input type="date" value={formData.expiryDate} onChange={e => setFormData({...formData, expiryDate: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
              </div>
              {mode === 'reception' && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-[#AF6E4D]">Costo Transportación Lote</label>
                  <input type="number" value={transportCost} onChange={e => setTransportCost(parseFloat(e.target.value))} className="w-full p-4 bg-[#F5F5DC] border border-[#D7CCC8]/30 rounded-2xl font-bold" placeholder="Costo del flete..." />
                </div>
              )}
            </div>
          </section>

          {mode === 'edit' && (
            <section className="space-y-10 border-t pt-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20 shadow-inner">
                  <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Precios y Márgenes</h4>
                  <div className="flex gap-4 items-center">
                    <div className="flex-1">
                       <label className="text-[9px] font-black uppercase text-gray-400 mb-2 block">Precio Unidad</label>
                       <div className="flex gap-2">
                         <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                         <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-4 bg-[#D7CCC8] rounded-2xl font-black text-xs"><option value="CUP">CUP</option><option value="USD">USD</option></select>
                       </div>
                    </div>
                    <div className="text-center pt-6">
                       <p className="text-[9px] font-black uppercase text-gray-400">Rentabilidad</p>
                       <p className={`text-xl font-black ${margin > 15 ? 'text-emerald-500' : 'text-rose-400'}`}>{margin.toFixed(1)}%</p>
                    </div>
                  </div>
                </div>
                <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
                   <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Agrupaciones (Estuches/Cajas)</h4>
                   <div className="grid grid-cols-2 gap-3 mb-6">
                      <input placeholder="Etiqueta (Caja x10)" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-xl text-xs font-bold" />
                      <input type="number" placeholder="Precio" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-xl text-xs font-bold" />
                      <input type="number" placeholder="Cantidad" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-4 bg-white border border-[#D7CCC8]/30 rounded-xl text-xs font-bold" />
                      <button onClick={() => {
                        if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
                        setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                        setTempGrouping({id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP'});
                      }} className="bg-[#3E2723] text-white rounded-xl font-black text-[10px] uppercase">+ Añadir Formato</button>
                   </div>
                   <div className="flex flex-wrap gap-2">
                      {formData.groupings?.map(g => (
                        <div key={g.id} className="bg-white px-3 py-2 rounded-xl border border-[#D7CCC8]/30 text-[9px] font-black flex items-center gap-3 uppercase">
                          {g.label} ({g.price} {g.currency})
                          <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-400"><X size={12}/></button>
                        </div>
                      ))}
                   </div>
                </div>
              </div>
            </section>
          )}
        </div>
        <div className="p-8 border-t flex justify-end gap-4 shadow-2xl bg-white">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs hover:text-[#3E2723]">Cerrar</button>
          <button onClick={() => {
            const final = {...formData} as Product;
            if (mode === 'reception') {
              final.lots = [...(final.lots || []), { id: Math.random().toString(), date: new Date().toISOString(), quantityReceived: final.stock, currentStock: final.stock, unitCost: final.costPrice, transportCost: transportCost, totalInvestment: (final.stock * final.costPrice) + transportCost }];
            }
            onSave(final);
          }} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl"><Save size={18} className="inline mr-2"/> Guardar Información</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500 pb-20">
          <div className="flex justify-between items-end">
            <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Inventario General</h2>
            <div className="flex gap-4">
              <button onClick={async () => { const post = await generateSocialMediaPost(products); setSocialPost(post); }} className="bg-[#AF6E4D] text-white px-8 py-5 rounded-[28px] text-[10px] font-black uppercase tracking-widest shadow-xl flex items-center gap-3"><Instagram size={18}/> Redes Sociales IA</button>
              <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="bg-[#3E2723] text-white px-8 py-5 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center gap-3"><Plus size={20}/> Entrada Lote</button>
            </div>
          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl overflow-x-auto">
            <table className="w-full text-left min-w-[800px]">
              <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black">
