  const [paymentMethod, setPaymentMethod] = useState<PaymentMethod>('Efectivo');

  // --- PERSISTENCIA INTELIGENTE ---
  useEffect(() => {
    const load = () => {
      const p = localStorage.getItem(STORAGE_KEYS.PRODUCTS);
      const c = localStorage.getItem(STORAGE_KEYS.CONTACTS);
      const t = localStorage.getItem(STORAGE_KEYS.TRANSACTIONS);
      const cfg = localStorage.getItem(STORAGE_KEYS.CONFIG);

      if (p) setProducts(JSON.parse(p));
      if (c) setContacts(JSON.parse(c));
      if (t) setTransactions(JSON.parse(t));
      if (cfg) setConfig(JSON.parse(cfg));

      setIsDataReady(true);
    };
    load();
  }, []);

  useEffect(() => {
    if (isDataReady) {
      localStorage.setItem(STORAGE_KEYS.PRODUCTS, JSON.stringify(products));
      localStorage.setItem(STORAGE_KEYS.CONTACTS, JSON.stringify(contacts));
      localStorage.setItem(STORAGE_KEYS.TRANSACTIONS, JSON.stringify(transactions));
      localStorage.setItem(STORAGE_KEYS.CONFIG, JSON.stringify(config));
    }
  }, [products, contacts, transactions, config, isDataReady]);

  // --- NOTIFICACIONES Y ALERTAS (Stock y Vencimiento) ---
  useEffect(() => {
    const newNotifs: Notification[] = [];
    const limitDate = new Date();
    limitDate.setDate(limitDate.getDate() + 60);

    products.forEach(p => {
      if (p.stock <= p.minStock) {
        newNotifs.push({ id: `stk-${p.id}`, title: 'Stock Crítico', message: `${p.name} tiene solo ${p.stock} unidades.`, type: 'error', date: new Date().toISOString(), read: false });
      }
      if (p.expiryDate) {
        const exp = new Date(p.expiryDate);
        if (exp <= limitDate && exp > new Date()) {
          newNotifs.push({ id: `exp-${p.id}`, title: 'Próximo a Vencer', message: `${p.name} vence el ${p.expiryDate}.`, type: 'warning', date: new Date().toISOString(), read: false });
        }
      }
    });
    setNotifications(newNotifs);
  }, [products]);

  // --- LÓGICA DE VENTA ---
  const addToCart = (p: Product, grouping?: GroupingPrice) => {
    const price = grouping ? grouping.price : p.unitPrice;
    const currency = grouping ? grouping.currency : p.unitCurrency;
    const label = grouping ? grouping.label : 'Unidad';
    const unitQty = grouping ? grouping.quantity : 1;

    if (p.stock < unitQty) { alert("¡Alerta! No hay suficiente existencia."); return; }

    const existingIdx = cart.findIndex(i => i.productId === p.id && i.groupingId === grouping?.id);
    if (existingIdx > -1) {
      const newCart = [...cart];
      newCart[existingIdx].quantity += 1;
      newCart[existingIdx].total = newCart[existingIdx].quantity * newCart[existingIdx].price;
      setCart(newCart);
    } else {
      setCart([...cart, {
        id: Math.random().toString(), productId: p.id, productName: p.name,
        groupingId: grouping?.id, groupingLabel: label, quantity: 1,
        price, total: price, currency, unitQuantity: unitQty
      }]);
    }
  };

  const processTransaction = (status: 'Solicitud' | 'Despachado') => {
    if (cart.length === 0) return;
    const totalCup = cart.reduce((acc, i) => acc + (i.currency === 'CUP' ? i.total : 0), 0);
    const totalUsd = cart.reduce((acc, i) => acc + (i.currency === 'USD' ? i.total : 0), 0);

    const newTx: Transaction = {
      id: Math.random().toString(), date: new Date().toISOString(),
      clientId: 'Gral', clientName: 'Consumidor', items: [...cart],
      totalCup, totalUsd, paymentMethod, status,
      invoiceNumber: `${status === 'Solicitud' ? 'PRE' : 'FAC'}-${Date.now().toString().slice(-6)}`
    };

    setTransactions([newTx, ...transactions]);
    if (status === 'Despachado') {
      const updatedProducts = products.map(p => {
        const soldItems = cart.filter(i => i.productId === p.id);
        const totalSoldUnits = soldItems.reduce((acc, i) => acc + (i.quantity * i.unitQuantity), 0);
        return { ...p, stock: Math.max(0, p.stock - totalSoldUnits) };
      });
      setProducts(updatedProducts);
    }
    setCart([]);
    setSelectedInvoice(newTx);
  };

  // --- FORMULARIO DE PRODUCTO (RECEPCIÓN Y EDICIÓN) ---
  const ProductFormContent = ({ initialData, mode, onSave, onCancel }: { initialData?: Product, mode: 'reception' | 'edit', onSave: (p: Product) => void, onCancel: () => void }) => {
    const [formData, setFormData] = useState<Partial<Product>>(initialData || {
      name: '', receptionType: 'Consignación', unitCurrency: 'CUP', groupings: [],
      stock: 0, minStock: 5, unitPrice: 0, costPrice: 0, expiryDate: '', lots: []
    });
    const [transportCost, setTransportCost] = useState(0);
    const [tempGrouping, setTempGrouping] = useState<GroupingPrice>({ id: '', label: '', quantity: 0, price: 0, currency: 'CUP' });

    const margin = useMemo(() => {
      if (!formData.unitPrice || !formData.costPrice || formData.unitPrice <= 0) return 0;
      return ((formData.unitPrice - formData.costPrice) / formData.unitPrice) * 100;
    }, [formData.unitPrice, formData.costPrice]);

    return (
      <div className="flex flex-col h-full bg-white">
        <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Producto</label>
              <input value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" placeholder="Ej: Jabón de Tocador" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">Costo Base (CUP)</label>
              <input type="number" value={formData.costPrice || ''} onChange={e => setFormData({...formData, costPrice: parseFloat(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black uppercase text-gray-400">{mode === 'reception' ? 'Cantidad Recibida' : 'Existencia'}</label>
              <input type="number" value={formData.stock || ''} onChange={e => setFormData({...formData, stock: parseInt(e.target.value)})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
              <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Precios de Venta</h4>
              <div className="flex gap-4">
                <input type="number" value={formData.unitPrice || ''} onChange={e => setFormData({...formData, unitPrice: parseFloat(e.target.value)})} className="flex-1 p-4 bg-white border border-[#D7CCC8]/30 rounded-2xl font-bold" placeholder="Precio Unidad" />
                <select value={formData.unitCurrency} onChange={e => setFormData({...formData, unitCurrency: e.target.value as any})} className="p-4 bg-[#D7CCC8] rounded-2xl font-black text-xs"><option value="CUP">CUP</option><option value="USD">USD</option></select>
              </div>
              <div className="mt-4 p-4 bg-white rounded-2xl flex justify-between items-center border border-[#D7CCC8]/10">
                <span className="text-[10px] font-black uppercase text-gray-400">Margen Real:</span>
                <span className={`text-lg font-black ${margin > 20 ? 'text-emerald-500' : 'text-rose-400'}`}>{margin.toFixed(1)}%</span>
              </div>
            </div>

            <div className="bg-[#FCF9F7] p-8 rounded-[40px] border border-[#D7CCC8]/20">
               <h4 className="text-[10px] font-black uppercase text-[#AF6E4D] mb-6 tracking-widest">Agrupaciones (Paquetes/Cajas)</h4>
               <div className="grid grid-cols-2 gap-2 mb-4">
                  <input placeholder="Formato" value={tempGrouping.label} onChange={e => setTempGrouping({...tempGrouping, label: e.target.value})} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                  <input type="number" placeholder="Precio" value={tempGrouping.price || ''} onChange={e => setTempGrouping({...tempGrouping, price: parseFloat(e.target.value)})} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                  <input type="number" placeholder="Cant. U" value={tempGrouping.quantity || ''} onChange={e => setTempGrouping({...tempGrouping, quantity: parseInt(e.target.value)})} className="p-3 bg-white border rounded-xl text-xs font-bold" />
                  <button onClick={() => {
                    if (!tempGrouping.label || tempGrouping.quantity <= 0) return;
                    setFormData({...formData, groupings: [...(formData.groupings || []), {...tempGrouping, id: Math.random().toString()}]});
                    setTempGrouping({id: '', label: '', quantity: 0, price: 0, currency: formData.unitCurrency || 'CUP'});
                  }} className="bg-[#3E2723] text-white rounded-xl font-black text-[9px] uppercase">+ Añadir</button>
               </div>
               <div className="flex flex-wrap gap-2">
                  {formData.groupings?.map(g => (
                    <div key={g.id} className="bg-white px-3 py-1.5 rounded-lg border border-[#D7CCC8]/40 text-[9px] font-black flex items-center gap-2">
                      {g.label} ({g.price} {g.currency})
                      <button onClick={() => setFormData({...formData, groupings: formData.groupings?.filter(x => x.id !== g.id)})} className="text-rose-400">×</button>
                    </div>
                  ))}
               </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-2">
                <label className="text-[10px] font-black uppercase text-gray-400">Vencimiento</label>
                <input type="date" value={formData.expiryDate} onChange={e => setFormData({...formData, expiryDate: e.target.value})} className="w-full p-4 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
             </div>
             {mode === 'reception' && (
                <div className="space-y-2">
                  <label className="text-[10px] font-black uppercase text-[#AF6E4D]">Costo Flete/Transporte</label>
                  <input type="number" value={transportCost} onChange={e => setTransportCost(parseFloat(e.target.value))} className="w-full p-4 bg-[#F5F5DC] border border-[#D7CCC8]/30 rounded-2xl font-bold" />
                </div>
             )}
          </div>
        </div>
        <div className="p-8 border-t flex justify-end gap-4 bg-white">
          <button onClick={onCancel} className="px-10 py-5 text-[#D7CCC8] font-black uppercase text-xs">Cancelar</button>
          <button onClick={() => onSave({...formData} as Product)} className="bg-[#3E2723] text-white px-12 py-5 rounded-[24px] font-black uppercase text-xs shadow-xl flex items-center gap-3"><Save size={18}/> Guardar Registro</button>
        </div>
      </div>
    );
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} notifications={notifications} onNotificationRead={id => setNotifications(prev => prev.map(n => n.id === id ? {...n, read: true} : n))}>

      {activeTab === 'home' && <Dashboard products={products} transactions={transactions} suppliers={contacts} />}

      {activeTab === 'inventory' && (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="flex justify-between items-end">
            <h2 className="text-4xl font-black text-[#3E2723] uppercase tracking-tighter">Control de Inventario</h2>
            <div className="flex gap-4">
              <button onClick={async () => { const post = await generateSocialMediaPost(products); setSocialPost(post); }} className="bg-[#AF6E4D] text-white px-8 py-5 rounded-[28px] text-[10px] font-black uppercase shadow-xl flex items-center gap-3"><Instagram size={18}/> Marketing IA</button>
              <button onClick={() => setProductModal({show: true, mode: 'reception'})} className="bg-[#3E2723] text-white px-8 py-5 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center gap-3"><Plus size={20}/> Entrada Lote</button>
            </div>
          </div>
          <div className="bg-white rounded-[50px] border border-[#D7CCC8]/20 overflow-hidden shadow-2xl overflow-x-auto">
            <table className="w-full text-left min-w-[800px]">
              <thead className="bg-[#F5F5DC]/40 border-b-2 border-[#D7CCC8]/20 text-[10px] uppercase text-[#AF6E4D] font-black">
                <tr><th className="px-10 py-8">Producto</th><th className="px-10 py-8 text-center">Existencia</th><th className="px-10 py-8">Costo Maestro</th><th className="px-10 py-8">P. Venta</th><th className="px-10 py-8">Vencimiento</th><th className="px-10 py-8 text-right">Acciones</th></tr>
              </thead>
              <tbody className="divide-y text-[#3E2723]">
                {products.map(p => (
                  <tr key={p.id} className="hover:bg-[#F5F5DC]/10 transition-colors">
                    <td className="px-10 py-8 font-black text-sm uppercase">{p.name}</td>
                    <td className={`px-10 py-8 text-center text-xl font-black ${p.stock <= p.minStock ? 'text-rose-500' : ''}`}>{p.stock} <span className="text-[10px] opacity-30">U.</span></td>
                    <td className="px-10 py-8 font-black text-xs">{p.costPrice.toLocaleString()} CUP</td>
                    <td className="px-10 py-8 font-black text-xs text-[#AF6E4D]">{p.unitPrice.toLocaleString()} {p.unitCurrency}</td>
                    <td className="px-10 py-8 font-bold text-[10px] uppercase text-gray-400">{p.expiryDate || 'N/A'}</td>
                    <td className="px-10 py-8 text-right"><button onClick={() => setProductModal({show: true, product: p, mode: 'edit'})} className="p-4 bg-[#F5F5DC] text-[#3E2723] rounded-2xl hover:bg-[#3E2723] hover:text-white transition-all"><Edit2 size={20}/></button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {activeTab === 'sales' && (
        <div className="flex h-[calc(100vh-140px)] gap-8 animate-in zoom-in-95 duration-500">
           <div className="w-2/3 bg-white rounded-[60px] border border-[#D7CCC8]/20 p-10 flex flex-col shadow-2xl">
              <div className="flex justify-between items-center mb-10"><h2 className="text-3xl font-black text-[#3E2723] uppercase tracking-tighter">Terminal de Ventas POS</h2><div className="relative w-72"><Search className="absolute left-4 top-4 text-[#D7CCC8]" size={18}/><input placeholder="Buscar..." className="w-full pl-12 pr-4 py-4 bg-[#FCF9F7] rounded-2xl font-bold border-none" onChange={e => setInventorySearch(e.target.value)} /></div></div>
              <div className="flex-1 overflow-y-auto grid grid-cols-2 gap-6 custom-scrollbar pr-4">
                 {products.filter(p => p.name.toLowerCase().includes(inventorySearch.toLowerCase())).map(p => (
                   <div key={p.id} className="bg-[#FCF9F7] p-6 rounded-[40px] border border-[#D7CCC8]/10 hover:border-[#AF6E4D] transition-all flex flex-col justify-between h-80">
                      <div><p className="font-black text-sm uppercase mb-1">{p.name}</p><p className="text-[9px] font-black text-[#AF6E4D] uppercase">En Almacén: {p.stock} U.</p></div>
                      <div className="space-y-3">
                         <button onClick={() => addToCart(p)} className="w-full py-4 bg-[#3E2723] text-white rounded-2xl font-black text-[10px] uppercase hover:bg-[#AF6E4D] transition-all">Unidad: {p.unitPrice} {p.unitCurrency}</button>
                         <div className="flex flex-wrap gap-2">
                            {p.groupings?.map(g => (
                              <button key={g.id} onClick={() => addToCart(p, g)} className="flex-1 py-3 bg-white border border-[#D7CCC8]/30 rounded-xl text-[8px] font-black uppercase hover:bg-[#3E2723] hover:text-white transition-all">{g.label}</button>
                            ))}
                         </div>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
           <div className="w-1/3 bg-[#3E2723] rounded-[60px] p-10 text-white flex flex-col shadow-2xl">
              <h3 className="text-xs font-black uppercase tracking-[0.2em] mb-10 text-[#AF6E4D]">Facturación Actual</h3>
              <div className="flex-1 overflow-y-auto space-y-4 custom-scrollbar mb-10">
                 {cart.map(i => (
                   <div key={i.id} className="bg-white/5 p-5 rounded-[32px] border border-white/10 flex justify-between items-center">
                      <div className="flex-1"><p className="text-[11px] font-black uppercase">{i.productName}</p><p className="text-[9px] font-bold text-[#AF6E4D] uppercase">{i.groupingLabel} x {i.quantity}</p></div>
                      <div className="flex items-center gap-4"><p className="font-black text-xs">{i.total.toLocaleString()} {i.currency}</p><button onClick={() => setCart(cart.filter(x => x.id !== i.id))} className="text-rose-400"><Trash2 size={16}/></button></div>
                   </div>
                 ))}
              </div>
              <div className="pt-8 border-t border-white/10 space-y-6">
                 <div className="flex gap-4"><button onClick={() => setPaymentMethod('Efectivo')} className={`flex-1 py-4 rounded-2xl font-black text-[9px] uppercase border transition-all ${paymentMethod === 'Efectivo' ? 'bg-[#AF6E4D] text-white border-[#AF6E4D]' : 'bg-white/5 text-white/40 border-white/10'}`}>Efectivo</button><button onClick={() => setPaymentMethod('Transferencia')} className={`flex-1 py-4 rounded-2xl font-black text-[9px] uppercase border transition-all ${paymentMethod === 'Transferencia' ? 'bg-[#AF6E4D] text-white border-[#AF6E4D]' : 'bg-white/5 text-white/40 border-white/10'}`}>Transferencia</button></div>
                 <div className="flex justify-between items-end"><p className="text-[10px] font-black uppercase opacity-40">Importe Total</p><p className="text-5xl font-black tracking-tighter tabular-nums">{cart.reduce((a,b)=>a+b.total,0).toLocaleString()} <span className="text-sm opacity-20">CUP</span></p></div>
                 <div className="flex gap-3">
                    <button onClick={() => processTransaction('Solicitud')} disabled={cart.length === 0} className="flex-1 py-6 bg-white/10 text-white rounded-[30px] font-black uppercase text-[10px] hover:bg-white/20 transition-all">Pre-Factura</button>
                    <button onClick={() => processTransaction('Despachado')} disabled={cart.length === 0} className="flex-[2] py-6 bg-white text-[#3E2723] rounded-[30px] font-black uppercase text-[10px] shadow-2xl hover:scale-105 transition-all">Despachar Venta</button>
                 </div>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'suppliers' && (
        <div className="space-y-10 animate-in fade-in duration-500">
           <div className="flex justify-between items-end"><h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter">Directorio Comercial</h2><button onClick={() => setShowContactModal(true)} className="bg-[#3E2723] text-white px-10 py-6 rounded-[28px] font-black text-xs uppercase shadow-xl flex items-center gap-3"><Plus size={20}/> Nuevo Socio</button></div>
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
              {contacts.map(c => (
                <div key={c.id} className="bg-white p-10 rounded-[50px] border border-[#D7CCC8]/20 flex flex-col h-80 justify-between shadow-sm hover:shadow-xl transition-all">
                   <div className="flex justify-between items-start"><div className="w-16 h-16 bg-[#F5F5DC] rounded-2xl flex items-center justify-center font-black text-2xl text-[#3E2723]">{c.name.charAt(0)}</div><span className="text-[9px] font-black uppercase px-4 py-1.5 bg-[#FCF9F7] border border-[#D7CCC8]/30 rounded-full">{c.type}</span></div>
                   <div><h3 className="font-black text-[#3E2723] text-lg uppercase mb-2 truncate">{c.name}</h3><p className="text-xs font-bold text-[#8D6E63] flex items-center gap-2"><Phone size={14}/> {c.phone}</p><p className="text-[10px] font-black text-[#3E2723] uppercase flex items-center gap-2 mt-4 bg-[#FCF9F7] p-4 rounded-2xl"><MapPin size={14}/> {c.address}</p></div>
                </div>
              ))}
           </div>
        </div>
      )}

      {activeTab === 'reception' && (
        <div className="max-w-4xl mx-auto animate-in slide-in-from-bottom-10 duration-500">
          <div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl overflow-hidden">
             <div className="p-12 border-b bg-[#F5F5DC]/30 flex justify-between items-center"><h2 className="text-4xl font-black uppercase text-[#3E2723] tracking-tighter flex items-center gap-4"><Truck size={40} className="text-[#AF6E4D]"/> Recepción de Mercancía</h2></div>
             <ProductFormContent 
                mode="reception" 
                onSave={p => {
                  const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                  let newList = [...products];
                  if (idx > -1) {
                    newList[idx] = { ...newList[idx], stock: newList[idx].stock + p.stock, costPrice: p.costPrice };
                  } else {
                    newList = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}` }, ...newList];
                  }
                  setProducts(newList);
                  alert("¡Lote registrado con éxito!");
                  setActiveTab('inventory');
                }}
                onCancel={() => setActiveTab('inventory')}
             />
          </div>
        </div>
      )}

      {activeTab === 'statistics' && <Statistics products={products} transactions={transactions} contacts={contacts} />}

      {activeTab === 'maintenance' && (
        <div className="max-w-4xl mx-auto py-32 bg-white rounded-[80px] border border-[#D7CCC8]/20 shadow-2xl flex flex-col items-center animate-in zoom-in-95 duration-500">
           <div className="p-12 bg-[#F5F5DC] rounded-full mb-10"><Database size={100} className="text-[#3E2723] opacity-60"/></div>
           <h2 className="text-4xl font-black uppercase text-[#3E2723] mb-8">Bóveda de Respaldo PaTí</h2>
           <div className="flex gap-8">
              <button onClick={() => {
                const data = { products, contacts, transactions, config };
                const blob = new Blob([JSON.stringify(data)], { type: 'application/json' });
                const link = document.createElement('a');
                link.href = URL.createObjectURL(blob);
                link.download = `pati_backup_${new Date().toISOString().split('T')[0]}.json`;
                link.click();
              }} className="bg-[#3E2723] text-white px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6"><Download size={24}/> Exportar DB</button>
              <label className="bg-[#F5F5DC] text-[#3E2723] px-16 py-8 rounded-[36px] font-black uppercase text-xs flex items-center gap-6 cursor-pointer border border-[#D7CCC8]/40"><Upload size={24}/> Importar DB <input type="file" className="hidden" accept=".json" onChange={(e) => {
                const file = e.target.files?.[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                   const data = JSON.parse(ev.target?.result as string);
                   if (data.products) setProducts(data.products);
                   if (data.contacts) setContacts(data.contacts);
                   if (data.transactions) setTransactions(data.transactions);
                   if (data.config) setConfig(data.config);
                   alert("Base de datos restaurada correctamente.");
                };
                reader.readAsText(file);
              }} /></label>
           </div>
        </div>
      )}

      {activeTab === 'config' && (
        <div className="max-w-4xl mx-auto py-10 animate-in slide-in-from-bottom-6 duration-500">
           <div className="bg-white rounded-[60px] border border-[#D7CCC8]/30 shadow-2xl p-16">
              <h2 className="text-4xl font-black text-[#3E2723] uppercase mb-12 flex items-center gap-6"><Settings size={40} className="text-[#AF6E4D]"/> Ajustes de la Tienda</h2>
              <div className="space-y-12">
                 <section className="space-y-6"><h3 className="text-[10px] font-black text-[#AF6E4D] uppercase border-b pb-4">Identidad Corporativa</h3><div className="grid grid-cols-1 md:grid-cols-2 gap-8"><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Ruta del Logo</label><input value={config.logoUrl} onChange={e => setConfig({...config, logoUrl: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] font-bold" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Nombre de Tienda</label><input value={config.storeName} onChange={e => setConfig({...config, storeName: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] font-bold" /></div></div></section>
                 <section className="space-y-6"><h3 className="text-[10px] font-black text-[#AF6E4D] uppercase border-b pb-4">Ubicación y Contacto</h3><div className="grid grid-cols-1 md:grid-cols-2 gap-8"><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Dirección</label><input value={config.address} onChange={e => setConfig({...config, address: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] font-bold" /></div><div className="space-y-2"><label className="text-[10px] font-black uppercase text-gray-400">Teléfono</label><input value={config.phone} onChange={e => setConfig({...config, phone: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] font-bold" /></div></div></section>
                 <section className="space-y-6"><h3 className="text-[10px] font-black text-[#AF6E4D] uppercase border-b pb-4">Sobre Nosotros</h3><textarea value={config.aboutText} onChange={e => setConfig({...config, aboutText: e.target.value})} className="w-full p-5 bg-[#FCF9F7] border rounded-[28px] h-40 font-bold custom-scrollbar" /></section>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'about' && (
        <div className="max-w-5xl mx-auto py-10 animate-in fade-in duration-1000">
           <div className="relative h-[650px] rounded-[100px] overflow-hidden shadow-2xl border-[20px] border-white">
              <img src="https://images.unsplash.com/photo-1542838132-92c53300491e?auto=format&fit=crop&q=80&w=1600" className="w-full h-full object-cover brightness-[0.4]" />
              <div className="absolute inset-0 flex flex-col items-center justify-center text-center p-20">
                 <div className="bg-white p-10 rounded-[50px] mb-12 shadow-2xl"><img src={LOGO_URL} className="h-40 w-auto" /></div>
                 <h2 className="text-7xl font-black text-white uppercase tracking-tighter mb-6">Misión PaTí</h2>
                 <p className="text-white/80 text-2xl font-medium max-w-3xl leading-relaxed italic">"{config.aboutText}"</p>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'contact' && (
        <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-2 gap-12 py-10 animate-in zoom-in-95">
           <div className="bg-white p-20 rounded-[80px] border border-[#D7CCC8]/30 shadow-2xl space-y-12">
              <h2 className="text-5xl font-black uppercase text-[#3E2723] tracking-tighter">Hablemos</h2>
              <div className="space-y-8">
                 <div className="flex items-center gap-8"><div className="p-6 bg-[#F5F5DC] rounded-full text-[#AF6E4D]"><Phone size={32}/></div><div><p className="text-[10px] font-black uppercase text-gray-400">Atención Directa</p><p className="text-2xl font-black text-[#3E2723]">{config.phone}</p></div></div>
                 <div className="flex items-center gap-8"><div className="p-6 bg-[#F5F5DC] rounded-full text-[#AF6E4D]"><MapPin size={32}/></div><div><p className="text-[10px] font-black uppercase text-gray-400">Visítenos</p><p className="text-2xl font-black text-[#3E2723]">{config.address}</p></div></div>
                 <div className="flex items-center gap-8"><div className="p-6 bg-[#F5F5DC] rounded-full text-[#AF6E4D]"><MailCheck size={32}/></div><div><p className="text-[10px] font-black uppercase text-gray-400">Correo Electrónico</p><p className="text-2xl font-black text-[#3E2723]">{config.email}</p></div></div>
              </div>
           </div>
           <div className="bg-[#3E2723] rounded-[80px] p-20 text-white flex flex-col justify-center items-center text-center space-y-10 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-80 h-80 bg-[#AF6E4D] rounded-full -mr-40 -mt-40 blur-[100px] opacity-30"></div>
              <h2 className="text-4xl font-black uppercase tracking-widest leading-tight">Síguenos en <br/><span className="text-[#AF6E4D]">Redes Sociales</span></h2>
              <div className="flex gap-10">
                 <a href={config.facebookUrl} className="p-8 bg-white/5 rounded-full hover:bg-white hover:text-[#3E2723] transition-all border border-white/10"><Facebook size={48}/></a>
                 <a href={config.instagramUrl} className="p-8 bg-white/5 rounded-full hover:bg-white hover:text-[#3E2723] transition-all border border-white/10"><Instagram size={48}/></a>
                 <a href={config.websiteUrl} className="p-8 bg-white/5 rounded-full hover:bg-white hover:text-[#3E2723] transition-all border border-white/10"><Globe size={48}/></a>
              </div>
           </div>
        </div>
      )}

      {activeTab === 'closure' && (
        <div className="max-w-4xl mx-auto py-12 animate-in zoom-in-95">
           <div className="bg-white rounded-[70px] border border-[#D7CCC8]/30 shadow-2xl p-20 flex flex-col items-center">
              <div className="p-10 bg-[#F5F5DC] rounded-full mb-10"><Wallet size={100} className="text-[#AF6E4D]"/></div>
              <h2 className="text-5xl font-black text-[#3E2723] uppercase mb-16 tracking-tighter">Cierre de Caja Operativo</h2>
              <div className="w-full grid grid-cols-2 gap-10 mb-16">
                 <div className="bg-[#FCF9F7] p-10 rounded-[50px] text-center border border-[#D7CCC8]/20"><p className="text-[10px] font-black text-gray-400 uppercase mb-4 tracking-widest">Recaudación (CUP)</p><p className="text-5xl font-black text-[#3E2723]">{transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').reduce((a, b) => a + b.totalCup, 0).toLocaleString()} <span className="text-sm opacity-20">CUP</span></p></div>
                 <div className="bg-[#FCF9F7] p-10 rounded-[50px] text-center border border-[#D7CCC8]/20"><p className="text-[10px] font-black text-gray-400 uppercase mb-4 tracking-widest">Ventas Despachadas</p><p className="text-6xl font-black text-[#AF6E4D]">{transactions.filter(t => t.date.startsWith(new Date().toISOString().split('T')[0]) && t.status === 'Despachado').length}</p></div>
              </div>
              <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-24 py-10 rounded-[40px] font-black uppercase text-sm shadow-2xl flex items-center gap-6 active:scale-95 transition-all"><Printer size={32}/> Imprimir Auditoría Diaria</button>
           </div>
        </div>
      )}

      {/* MODALES GLOBALES */}
      {productModal.show && (
        <div className="fixed inset-0 bg-black/95 z-[500] flex items-center justify-center p-4 backdrop-blur-xl">
          <div className="bg-white rounded-[60px] w-full max-w-5xl shadow-2xl overflow-hidden max-h-[96vh] flex flex-col border-b-[20px] border-[#3E2723]">
            <div className="p-10 border-b flex justify-between items-center bg-[#F5F5DC]/40">
              <div className="flex items-center gap-6"><Package size={40} className="text-[#AF6E4D]"/><h2 className="text-3xl font-black uppercase text-[#3E2723]">{productModal.mode === 'reception' ? 'Nueva Entrada' : `Gestión: ${productModal.product?.name}`}</h2></div>
              <button onClick={() => setProductModal({show: false, mode: 'reception'})} className="p-3 text-rose-400 hover:rotate-90 transition-transform"><X size={40} /></button>
            </div>
            <ProductFormContent 
              mode={productModal.mode} initialData={productModal.product} 
              onSave={p => {
                const idx = products.findIndex(x => x.name.toLowerCase() === p.name.toLowerCase());
                let list = [...products];
                if (idx > -1) {
                  list[idx] = { ...list[idx], ...p, stock: productModal.mode === 'reception' ? (list[idx].stock + p.stock) : p.stock };
                } else {
                  list = [{ ...p, id: Math.random().toString(), sku: `PATI-${Date.now().toString().slice(-4)}` }, ...list];
                }
                setProducts(list); setProductModal({show: false, mode: 'reception'});
              }}
              onCancel={() => setProductModal({show: false, mode: 'reception'})}
            />
          </div>
        </div>
      )}

      {selectedInvoice && (
        <div className="fixed inset-0 bg-black/98 z-[600] flex items-center justify-center p-4 no-print backdrop-blur-3xl">
           <div className="bg-white rounded-[70px] w-full max-w-4xl shadow-2xl p-20 flex flex-col animate-in slide-in-from-bottom-20">
              <div className="flex justify-between items-start mb-20">
                <div className="bg-[#3E2723] p-10 rounded-[40px] shadow-2xl"><img src={LOGO_URL} className="h-28 w-auto brightness-[100]" /></div>
                <div className="text-right">
                  <p className="text-[12px] font-black uppercase text-gray-400 tracking-widest">Documento Institucional</p>
                  <p className="text-4xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.invoiceNumber}</p>
                  <p className="text-sm font-black text-[#AF6E4D] uppercase mt-2">{selectedInvoice.status === 'Solicitud' ? 'Cotización / Pre-Factura' : 'Factura de Venta'}</p>
                </div>
              </div>
              <div className="flex-1 space-y-10 overflow-y-auto">
                 <table className="w-full text-left">
                   <thead><tr className="border-b-4 border-[#3E2723] text-[10px] uppercase font-black text-gray-400"><th className="py-6">Detalle Producto</th><th className="py-6 text-center">Cant.</th><th className="py-6 text-right">Precio</th><th className="py-6 text-right">Importe</th></tr></thead>
                   <tbody className="divide-y font-bold uppercase text-sm">
                     {selectedInvoice.items.map((i, idx) => (
                       <tr key={idx}><td className="py-8">{i.productName} <br/><span className="text-[9px] text-[#AF6E4D]">{i.groupingLabel}</span></td><td className="py-8 text-center">{i.quantity}</td><td className="py-8 text-right">{i.price.toLocaleString()}</td><td className="py-8 text-right">{i.total.toLocaleString()} {i.currency}</td></tr>
                     ))}
                   </tbody>
                 </table>
                 <div className="pt-10 border-t-8 border-[#3E2723] flex justify-between items-end">
                    <div className="text-[10px] font-black text-[#3E2723] uppercase opacity-40">Condición: {selectedInvoice.paymentMethod}</div>
                    <div className="text-right">
                       <p className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Total Liquidado</p>
                       <p className="text-7xl font-black text-[#3E2723] tracking-tighter">{selectedInvoice.totalCup.toLocaleString()} <span className="text-sm opacity-20">CUP</span></p>
                    </div>
                 </div>
              </div>
              <div className="mt-16 flex justify-center gap-10">
                 <button onClick={() => window.print()} className="bg-[#3E2723] text-white px-20 py-10 rounded-[40px] font-black uppercase text-sm shadow-2xl flex items-center gap-6 active:scale-95 transition-all"><Printer size={32}/> Imprimir Documento</button>
                 <button onClick={() => setSelectedInvoice(null)} className="px-12 py-10 font-black uppercase text-sm text-gray-400 hover:text-[#3E2723]">Cerrar</button>
              </div>
           </div>
        </div>
      )}

      {socialPost && (
        <div className="fixed inset-0 bg-black/90 z-[700] flex items-center justify-center p-4 backdrop-blur-2xl">
           <div className="bg-white rounded-[70px] w-full max-w-2xl shadow-2xl p-16 animate-in zoom-in-95 border-b-[15px] border-[#AF6E4D]">
              <div className="flex justify-between items-center mb-12"><h2 className="text-3xl font-black uppercase text-[#3E2723] flex items-center gap-6"><Share2 size={40} className="text-[#AF6E4D]"/> Marketing Inteligente</h2><button onClick={() => setSocialPost(null)} className="text-rose-400 hover:rotate-90 transition-transform"><X size={40}/></button></div>
              <div className="bg-[#FCF9F7] p-12 rounded-[50px] border-2 border-[#D7CCC8]/30 mb-12 shadow-inner"><textarea className="w-full h-[450px] bg-transparent font-medium text-xl text-[#3E2723] outline-none leading-relaxed resize-none custom-scrollbar" value={socialPost} readOnly /></div>
              <button onClick={() => { navigator.clipboard.writeText(socialPost || ''); alert("¡Texto copiado! Listo para pegar en Facebook o Instagram."); }} className="w-full bg-[#3E2723] text-white py-8 rounded-[36px] font-black uppercase text-sm flex items-center justify-center gap-6 shadow-2xl active:scale-95 transition-all"><Copy size={32}/> Copiar Contenido</button>
           </div>
        </div>
      )}

      {showContactModal && (
        <div className="fixed inset-0 bg-black/90 z-[500] flex items-center justify-center p-4 backdrop-blur-xl">
           <div className="bg-white rounded-[70px] w-full max-w-lg p-20 animate-in zoom-in-95 border-b-[20px] border-[#AF6E4D]">
              <h2 className="text-4xl font-black uppercase text-[#3E2723] mb-16 flex items-center gap-6"><Users className="text-[#AF6E4D]" size={40}/> Nuevo Socio</h2>
              <form onSubmit={(e) => { e.preventDefault(); const fd = new FormData(e.currentTarget); const newC: Contact = { id: Math.random().toString(), name: fd.get('name') as string, contactName: fd.get('name') as string, phone: fd.get('phone') as string, email: '', address: fd.get('address') as string, type: fd.get('type') as any, pendingBalanceCup: 0, pendingBalanceUsd: 0 }; setContacts([...contacts, newC]); setShowContactModal(false); }} className="space-y-10">
                 <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Razón Social / Nombre</label><input name="name" required className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[30px] font-bold outline-none" /></div>
                 <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Teléfono de Contacto</label><input name="phone" required className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[30px] font-bold outline-none" /></div>
                 <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Ubicación Física</label><input name="address" required className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[30px] font-bold outline-none" /></div>
                 <div className="space-y-3"><label className="text-[10px] font-black uppercase text-gray-400 tracking-widest">Tipo de Vínculo</label><select name="type" className="w-full p-6 bg-[#FCF9F7] border border-[#D7CCC8]/40 rounded-[30px] font-black uppercase text-xs"><option value="Proveedor">Proveedor (Consignación)</option><option value="Cliente">Cliente Directo</option></select></div>
                 <div className="pt-6 flex gap-4"><button type="button" onClick={() => setShowContactModal(false)} className="px-10 py-8 font-black uppercase text-xs text-gray-400">Cerrar</button><button type="submit" className="flex-1 bg-[#3E2723] text-white py-8 rounded-[36px] font-black uppercase text-xs shadow-2xl active:scale-95 transition-all">Registrar Socio</button></div>
              </form>
           </div>
        </div>
      )}

    </Layout>
  );
};

export default App;
